window.METHODEN = [{"id":"agenda-design-mit-fragen","name":"Agenda-Design mit Fragen","feld":"G","kurz":"Agenda-Punkte werden als zu beantwortende Fragen formuliert statt als Stichworte. Pro Punkt stehen Zweck (informieren / Input holen / entscheiden), Zeit und Verantwortliche:r dabei.","schritte":["Themen sammeln und prüfen: betrifft das alle Anwesenden?","Jedes Thema als Frage formulieren („Unter welchen Bedingungen verlegen wir den Termin?\" statt „Terminfrage\").","Pro Frage markieren: Information, Input oder Entscheidung.","Realistische Zeit und verantwortliche Person zuordnen.","Agenda vorab verschicken, damit alle vorbereitet kommen.","Im Treffen: Frage beantwortet = Punkt abgeschlossen."],"zweck":"Meetings bekommen ein klares Ende-Kriterium pro Punkt und die richtige Teilnehmer:innen-Liste.","hinweise":"Häufigster Fehler: Agenda als Themenliste ohne Zweckangabe – dann diskutiert die Gruppe ohne Ziel. Wer die Frage nicht formulieren kann, hat das Thema noch nicht durchdacht – das ist bereits die Diagnose.","phasen":["planen"],"ebenen":["team","organisation"],"modi":["klaerung"],"formate":["meeting"],"dauer_min":10,"dauer_max":30,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"How to Design an Agenda for an Effective Meeting – HBR","url":"https://hbr.org/2015/03/how-to-design-an-agenda-for-an-effective-meeting"},{"typ":"buch","titel":"Roger Schwarz: Smart Leaders, Smarter Teams"}],"wann_passt":["Wiederkehrendes Teammeeting, das regelmäßig zu lang dauert oder ohne klares Ergebnis endet – die Fragformulierung zwingt die einbringende Person, vorab zu klären, was sie eigentlich braucht (Information, Feedback oder Entscheidung).","Neues Team oder neue Moderation: die Agenda als sichtbares Planungsdokument signalisiert Struktur ohne Kontrolle – alle sehen vorab, was auf sie zukommt.","Entscheidungstreffen mit mehreren Punkten unterschiedlicher Tragweite – die Zweckmarkierung (informieren / Input / entscheiden) hilft, die richtige Energie pro Punkt aufzurufen und nicht alles gleichzeitig zu diskutieren."],"wann_nicht":["Informelle Austauschrunden oder Community-Treffen ohne feste Ergebniserwartung – Fragenstruktur wirkt dort bürokratisch.","Wenn die Person, die das Thema einbringt, die Frage nicht formulieren kann – dann ist das Thema nicht reif für die Agenda, und das Format löst die Vorbereitung nicht."],"fokusfragen":["„Was genau wollen wir am Ende dieses Punktes wissen, entschieden oder getan haben?\" (Zweck klären)","„Wer muss dafür wirklich dabei sein – und wer könnte die Ergebnisse asynchron erhalten?\" (richtige Einladungsliste)","„Wie viel Zeit brauchen wir realistisch – und was lassen wir weg, wenn es zu viel wird?\""],"beispiel":"Statt Agendapunkt „Finanzen\" → „Unter welchen Bedingungen beantragen wir die Mittelverschiebung zwischen Posten A und B?\" – Zweck: Entscheidung. Ergebnis: klares Ja/Nein + Begründung. Zeit: 15 Min. Verantwortlich: Schatzmeisterin. Die Frage macht sofort sichtbar, dass die Buchhalterin vorab Zahlen aufbereiten muss – sonst tagt die Gruppe ohne Grundlage.","mini_form":"5-Min-Agenda-Audit vor dem Treffen: bestehende Agendapunkte als Fragen reformulieren und pro Punkt markieren: I (informieren) / F (Feedback) / E (entscheiden). Punkte ohne Antwort streichen oder vertagen.","anlass_typen":["regeltermin","entscheidungstreffen","kickoff","krisensitzung"],"typ":"werkzeug","gruppen_sweetspot":"3–15 Personen, für jede Gruppengröße geeignet – Aufwand skaliert mit Vorbereitungszeit","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"check-in-check-out","name":"Check-in / Check-out (Meeting-Kurzform)","feld":"G","kurz":"Bewusster Anfang und Schluss eines Treffens: Jede Person sagt kurz, wie sie ankommt bzw. womit sie geht. Macht alle Stimmen einmal hörbar, bevor die Sacharbeit beginnt.","schritte":["Eine Frage stellen (z.B. „Was beschäftigt dich gerade?\" / „Was brauchst du, um präsent zu sein?\").","Reihum oder per Popcorn-Prinzip antwortet jede:r in 1–2 Sätzen, unkommentiert.","Moderation bedankt sich, kein Nachfragen.","Am Ende analog: Check-out-Frage („Was nimmst du mit?\", „Was bleibt offen?\")."],"zweck":"Präsenz, Sichtbarkeit und Übergang in den gemeinsamen Arbeitsmodus – besonders bei wiederkehrenden Meetings.","hinweise":"„Warum\"-Fragen öffnen tiefer, „Was\"-Fragen bleiben sachnah – Frage zur Meeting-Art passend wählen. Bei großen Gruppen Ein-Wort-Variante nutzen, sonst frisst der Check-in die Agenda.","phasen":["ankommen","reflektieren"],"ebenen":["person","team"],"modi":["verbindung","vertrauen"],"formate":["meeting","workshop","reflexionsrunde"],"dauer_min":3,"dauer_max":15,"gruppe_min":2,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["einstieg","abschluss"],"quellen":[{"typ":"online","titel":"Check-in / Check-out – SessionLab Library","url":"https://www.sessionlab.com/methods/check-in-check-out"},{"typ":"buch","titel":"Jim & Michele McCarthy: The Core Protocols"}],"wann_passt":["Wiederkehrendes Teammeeting, in dem die Gruppe ohne Übergang von der E-Mail direkt in Sacharbeit fällt – 2–3 Minuten Check-in senken die Streuung im Kopf und erhöhen die tatsächliche Präsenz.","Gruppe nach längerem Trennungszeitraum (nach Ferien, nach Krisenwoche) – kurzes Ankommen macht das Unausgesprochene hörbar, bevor es die Sacharbeit untergräbt.","Workshop mit neuen oder gemischten Teilnehmer:innen – alle Stimmen einmal gehört zu haben, senkt die Hemmschwelle für späteren Beitrag."],"wann_nicht":["Gruppen über 20 Personen mit mündlicher Runde – dann frisst der Check-in die Agenda; stattdessen Chat-Wasserfall oder Ein-Wort-Variante.","Wenn der Check-in seit Monaten dieselbe Frage hat – dann ist er Pflichtübung geworden und verliert seinen Sinn."],"fokusfragen":["„Was beschäftigt dich gerade außerhalb dieser Runde, das du vielleicht mitbringst?\" (Präsenz-Check)","„Was brauchst du, um heute wirklich dabei zu sein?\" (Bedürfnis-Check für anspruchsvolle Inhalte)","„Was nimmst du aus diesem Treffen mit – und was bleibt offen?\" (Check-out)"],"beispiel":"Check-out in einer Planungsklausur: „In einem Satz: Was war heute dein wichtigster Gedanke – und was beschäftigt dich noch?\" Reihum, unkommentiert. Ergibt häufig, dass eine ungelöste Frage mehrere Personen bewegt – die Moderation notiert sie sichtbar für den nächsten Tag, ohne jetzt weiter zu diskutieren.","mini_form":"Ein-Wort-Check-in: alle nennen gleichzeitig (oder im Chat-Wasserfall) ein Wort für ihre aktuelle Stimmung – 90 Sekunden, gibt sofort ein Stimmungsbild ohne Redezeit-Ungleichgewicht.","anlass_typen":["regeltermin","teamtag","retro"],"typ":"werkzeug","gruppen_sweetspot":"4–15 für mündliche Runde, bis 100 für Chat-Variante","stimmung_geeignet":["angespannt","muede","belastet","frisch"]},{"id":"lean-coffee","name":"Lean Coffee","feld":"G","kurz":"Strukturiertes Treffen ohne vorbereitete Agenda: Die Teilnehmer:innen schlagen Themen vor, priorisieren per Abstimmung und arbeiten sie in Timeboxen ab. Demokratisch erzeugte Agenda in Echtzeit.","schritte":["Einfaches Kanban-Board aufbauen (zu besprechen / in Diskussion / besprochen).","Alle schreiben Themenvorschläge auf Karten (2–3 Min).","Jede Karte in einem Satz vorstellen, dann Dot-Voting.","Top-Thema 5–8 Min diskutieren.","Daumen-Abstimmung: weiter (Daumen hoch) oder nächstes Thema (Daumen runter).","Wiederholen bis Zeit um; Karten wandern über das Board."],"zweck":"Austauschrunden, Communities of Practice und Team-Treffen, bei denen die Gruppe selbst bestimmt, was wichtig ist.","hinweise":"Online sehr gut mit digitalem Board. Stolperstein: Timebox aufweichen – dann kippt es in eine unstrukturierte Diskussion. Eignet sich weniger, wenn eine konkrete Entscheidung getroffen werden muss.","phasen":["verstehen","vertiefen"],"ebenen":["team","netzwerk"],"modi":["klaerung"],"formate":["meeting","workshop"],"dauer_min":30,"dauer_max":60,"gruppe_min":4,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Lean Coffee","url":"https://leancoffee.org/"},{"typ":"online","titel":"Lean Coffee Facilitator's Guide – Medium (Agile Outside the Box)","url":"https://medium.com/agile-outside-the-box/lean-coffee-facilitator-s-guide-d79d9f13d0a9"}],"wann_passt":["Community of Practice oder Netzwerktreffen ohne feste Tagesordnung, bei dem niemand allein die Agenda setzen soll – die Gruppe priorisiert selbst, was heute zählt.","Regelmäßiges Teamtreffen, bei dem immer dieselben Themen vorgebracht werden, aber nie Zeit für das ist, was die Einzelnen wirklich bewegt – Lean Coffee löst die Vorab-Agenda auf und gibt Raum für das, was gerade drückt.","Retrospektive oder informeller Wissenstaustausch in einer Gruppe, die Struktur braucht, aber keine Konferenzanmutung will."],"wann_nicht":["Wenn eine konkrete Entscheidung getroffen werden muss – das Timebox-Format erzeugt kein Entscheidungsverfahren, nur Gesprächszeit.","Unter 5 oder über 15 Personen ohne Moderationserfahrung: bei kleinen Gruppen ist die Struktur Overhead, bei großen kollabiert die Timebox-Disziplin.","Wenn Teilnehmer:innen nicht bereit sind, Themen offen zu benennen (Hierarchiedruck, mangelndes Vertrauen) – dann entstehen nur sichere, unverfängliche Karten."],"fokusfragen":["„Welches Thema bewegt dich gerade am meisten – was möchtest du heute unbedingt besprechen?\" (Karten-Prompt)","„Wir haben 5 Minuten – was ist die eine Sache, die wir zu diesem Thema klären sollten?\""],"beispiel":"Community of Practice (10 Personen, monatlich): Jede:r schreibt 2 Karten. Nach Dot-Voting landen die Top-3-Themen auf dem Board. Erstes Thema: „Was tun wir, wenn ein Sponsor aussteigt?\" – 7 Minuten Diskussion, Daumen-Check: 8 hoch, 2 runter → weiter. Ergebnis: Verabredung, einen Notfallplan bis zum nächsten Treffen zu skizzieren. Karte landet in „besprochen\" mit Action Item.","mini_form":"„Mini-Lean\": Nur Karten schreiben + Dot-Voting (5 Min), dann ein einziges Top-Thema 10 Min diskutieren – reicht als Auftakt für ein reguläres Teammeeting, um das dringlichste Anliegen der Gruppe sichtbar zu machen.","anlass_typen":["netzwerktreffen","regeltermin","retro","krisensitzung"],"typ":"methode","gruppen_sweetspot":"5–12 ideal, ab 4 möglich, über 15 nur mit Untergruppen","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"elmo","name":"ELMO (Enough, Let's Move On)","feld":"G","kurz":"Vereinbartes Signal, mit dem jede:r im Meeting anzeigen kann, dass eine Diskussion ihren produktiven Punkt überschritten hat – per Zuruf, Handzeichen oder Karte.","schritte":["Zu Beginn (einmalig) vereinbaren: Jede:r darf ELMO rufen oder die Karte heben, unabhängig von Rolle und Hierarchie.","Wenn eine Diskussion kreist: Signal geben.","Moderation fragt kurz: Punkt abschließen, vertagen oder in den Parkplatz?","Weiter mit der Agenda; geparkte Punkte am Ende sichten."],"zweck":"Ausufernde Detail- und Wiederholungsdiskussionen beenden, ohne die Person abzuwerten, die spricht.","hinweise":"Braucht eine einmalige gemeinsame Vereinbarung, sonst wirkt es ruppig. Am besten kombiniert mit Parkplatz, damit „beendet\" nicht „verloren\" heißt. Online als Chat-Signal oder Reaktions-Emoji.","phasen":["vertiefen"],"ebenen":["team"],"modi":["klaerung","energie"],"formate":["meeting","workshop"],"dauer_min":1,"dauer_max":2,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["spielerisch","strukturiert"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"What does the E.L.M.O acronym mean? – Facilitator School","url":"https://www.facilitator.school/glossary/elmo"}],"wann_passt":["Gestandenes Arbeitsteam mit gutem Vertrauen, das erkannt hat, dass Meetings regelmäßig zu lang dauern – ELMO als gemeinsam vereinbartes Signal verhindert, dass eine Einzelperson immer die Stoppschildrolle übernehmen muss.","Workshoptag mit vielen Agenda-Punkten, bei dem die ersten Punkte sonst die späteren auffressen – ELMO schützt das Zeitbudget ohne Autorität der Moderation zu beanspruchen."],"wann_nicht":["Neue oder noch nicht eingespielte Gruppe – das Signal kann als Abwürgung erlebt werden, wenn das gemeinsame Verständnis fehlt.","Wenn kein Parkplatz existiert: dann bedeutet ELMO für Teilnehmer:innen „mein Beitrag wird ignoriert\" – das erzeugt Rückzug statt Fokus."],"fokusfragen":["„Haben wir diesen Punkt so weit, dass wir handeln oder entscheiden können – oder reden wir uns im Kreis?\" (Selbstcheck vor ELMO)","„Was bräuchten wir, um diesen Punkt jetzt abzuschließen?\" (nach ELMO-Signal)"],"beispiel":"Team vereinbart zu Beginn: „Jede:r kann ELMO signalisieren – im Chat 'E', Handzeichen oder laut sagen. Dann entscheiden wir gemeinsam: abschließen, parken oder 3 Minuten verlängern.\" In der Sitzung kreist eine Diskussion zum dritten Mal. Person A schreibt 'E' in den Chat. Moderation: „ELMO – sind wir einig, das zu parken?\" 5 von 6 nicken. Parkplatz-Karte: „Technik-Frage – wer klärt das bis Freitag?\" → Person B.","mini_form":"Als Einstieg-Vereinbarung in 2 Minuten: Karte mit 'ELMO' auf den Tisch oder in den Chat – fertig. Braucht keine Erklärung wenn der Zweck kurz benannt ist.","anlass_typen":["regeltermin","entscheidungstreffen"],"typ":"werkzeug","gruppen_sweetspot":"4–20, beliebig skalierbar wenn Vereinbarung klar ist","stimmung_geeignet":["muede","frisch","neugierig"]},{"id":"parkplatz","name":"Parkplatz (Parking Lot)","feld":"G","kurz":"Sichtbarer Themenspeicher (Flipchart, Board-Bereich) für Punkte, die wichtig sind, aber nicht zur aktuellen Agenda gehören. Würdigt den Beitrag und schützt den Fokus.","schritte":["Zu Beginn erklären und Fläche sichtbar einrichten.","Off-Topic-Punkt taucht auf → auf Karte schreiben und parken (Moderation oder Teilnehmer:innen selbst).","Vor Schluss 5 Min einplanen: Parkplatz durchgehen.","Pro Punkt entscheiden: jetzt kurz klären, in nächste Agenda, an Person delegieren oder streichen.","Verbleibende Punkte mit Verantwortlichen ins Protokoll."],"zweck":"Meetings auf Kurs halten, ohne Beiträge abzuwürgen.","hinweise":"Häufigster Fehler: den Parkplatz nie wieder anschauen – dann lernt die Gruppe, dass Parken Beerdigen heißt, und das Vertrauen kippt. Schluss-Sichtung fest einplanen.","phasen":["vertiefen","verstetigen"],"ebenen":["team","organisation"],"modi":["klaerung"],"formate":["meeting","workshop","klausur"],"dauer_min":5,"dauer_max":10,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["uebergang","abschluss"],"quellen":[{"typ":"online","titel":"Parking Lot – SessionLab Library","url":"https://www.sessionlab.com/methods/parking-lot"}],"wann_passt":["Workshop oder Klausur mit breitem Themenspektrum, bei dem Querverbindungen und Assoziationen natürlich entstehen – Parkplatz signalisiert Wertschätzung des Beitrags ohne den Fokus zu verlieren.","Meetingkultur, in der Off-Topic-Kommentare regelmäßig zu langen Abschweifungen führen – der Parkplatz gibt der Moderation ein legitimes, nicht-abwürgendes Steuerungsmittel.","Mehrtägige Klausur: Parkplatz am Ende von Tag 1 als Einstieg in Tag 2 nutzbar."],"wann_nicht":["Wenn am Ende keine Zeit eingeplant ist, den Parkplatz zu sichten – dann lernt die Gruppe, dass parken gleich beerdigen ist, und das Vertrauen bricht weg.","Online ohne sichtbares Board – unsichtbare Parkplätze existieren nicht."],"fokusfragen":["„Wichtiges Thema – gehört das zu unserem heutigen Fokus, oder parken wir es für später?\" (Parkier-Entscheidung)","„Was davon wollen wir jetzt klären, was delegieren, was streichen?\" (Sichtung am Ende)"],"mini_form":"Post-it oder digitales Sticky sichtbar an Boardrand: reicht als Parkplatz. Ankündigung: „Wichtige Punkte außerhalb der Agenda kommen dort drauf – wir sehen sie uns in den letzten 5 Minuten an.\"","anlass_typen":["regeltermin","strategie","entscheidungstreffen"],"typ":"werkzeug","gruppen_sweetspot":"beliebig – Werkzeug der Moderation, unabhängig von Größe","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"wer-macht-was-bis-wann","name":"Wer-macht-was-bis-wann (3W-Beschluss-Sicherung)","feld":"G","kurz":"Jede Vereinbarung wird vor Meeting-Ende als Ein-Satz-Action-Item festgehalten: eine verantwortliche Person (Wer), eine Aufgabe mit Verb (Was), ein konkretes Datum (bis Wann).","schritte":["Während des Meetings jede Zusage sofort sichtbar notieren.","Pro Item genau eine Person als verantwortlich benennen – „wir\" gilt nicht.","Aufgabe mit Verb formulieren („Entwurf schicken\", nicht „Entwurf\").","Konkretes Datum statt „demnächst\".","Vor Schluss die Liste laut vorlesen, jede:r bestätigt die eigenen Punkte.","Liste im Protokoll/Tool festhalten und beim nächsten Treffen zuerst aufrufen."],"zweck":"Beschlüsse und Zusagen überleben das Meeting – Verbindlichkeit statt kollektiver Erinnerungslücke.","hinweise":"Das laute Vorlesen am Ende ist der wirksamste Schritt und wird am häufigsten weggelassen. Stolperstein: zu viele Action Items pro Treffen – lieber wenige, die wirklich passieren.","phasen":["entscheiden","verstetigen"],"ebenen":["team","organisation"],"modi":["klaerung"],"formate":["meeting","workshop","klausur"],"dauer_min":5,"dauer_max":10,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["abschluss"],"quellen":[{"typ":"online","titel":"What is an Action Item? – Lucid Meetings Glossary","url":"https://www.lucidmeetings.com/glossary/action-item"}],"wann_passt":["Jedes Meeting, das Beschlüsse oder Zusagen erzeugt – 3W ist der Mindeststandard, um aus Gespräch Handlung zu machen.","Teams mit langer Geschichte von Beschlüssen, die nicht umgesetzt werden – das laute Vorlesen am Ende erzeugt eine kollektive Verbindlichkeit, die stille Protokollnotizen nicht leisten.","Klausur am Ende des letzten Blocks: alle Action Items sammeln, laut vorlesen, jede:r bestätigt die eigenen – das ist der wirksamste Abschluss eines Mehrtagesprozesses."],"wann_nicht":["Wenn zu viele Action Items entstehen – dann lieber auswählen: maximal 5 wirklich verbindliche Punkte statt 20 Wünsche.","Als Ersatz für fehlende Entscheidungskultur – 3W dokumentiert Beschlüsse, kann aber das Fehlen klarer Mandate nicht beheben."],"fokusfragen":["„Wer übernimmt das – genau eine Person, nicht 'wir'?\" (Verbindlichkeitstest)","„Was ist die konkrete Handlung – mit Verb?\" (Formulierungscheck)","„Bis wann? Nicht 'demnächst' – welches Datum?\""],"beispiel":"Meeting-Abschluss: Moderation liest vor: „Maike schickt den Entwurf bis Donnerstag 12 Uhr an alle. Tom fragt bis Freitag beim Lieferanten nach dem Termin.\" Maike und Tom bestätigen je: „Ja, mach ich.\" Protokoll enthält nur diese zwei Zeilen – kein Diskussionsprotokoll. Beim nächsten Treffen sind diese zwei Punkte der erste Agenda-Punkt.","mini_form":"2-Min-Abschlussrunde: „Bevor wir gehen – jede:r sagt in einem Satz, was sie/er als Nächstes tut.\" Kein Board nötig, erzeugt trotzdem Verbindlichkeit durch öffentliche Benennung.","anlass_typen":["regeltermin","entscheidungstreffen","strategie","krisensitzung"],"typ":"werkzeug","gruppen_sweetspot":"beliebig – je kleiner die Gruppe, desto schneller","stimmung_geeignet":["frisch","muede","neugierig"]},{"id":"delegation-poker","name":"Delegation Poker","feld":"G","kurz":"Kartenspiel (Management 3.0), mit dem Team und Führung pro Entscheidungsfeld klären, auf welcher der sieben Delegationsstufen (Tell, Sell, Consult, Agree, Advise, Inquire, Delegate) eine Entscheidung liegt.","schritte":["Konkrete Entscheidungsfälle sammeln („Wer entscheidet über Urlaubsplanung / Tool-Auswahl / Budget X?\").","Fall vorlesen.","Alle wählen verdeckt eine Karte 1–7 und decken gleichzeitig auf.","Höchste und niedrigste Stimme begründen ihre Wahl.","Ggf. erneut spielen, bis ein gemeinsames Bild entsteht.","Ergebnis auf einem Delegation Board festhalten (Felder × Stufen)."],"zweck":"Implizite Erwartungen über Entscheidungsbefugnisse explizit machen und schrittweise Selbstorganisation aufbauen.","hinweise":"Es geht um das Gespräch, nicht um Punkte – die Diskussion der Ausreißer ist der eigentliche Wert. Delegation ist kein Schalter, sondern eine Stufenleiter; Board regelmäßig aktualisieren.","phasen":["planen","entscheiden"],"ebenen":["team","organisation"],"modi":["klaerung","vertrauen"],"formate":["meeting","workshop","teamentwicklung","klausur"],"dauer_min":45,"dauer_max":90,"gruppe_min":3,"gruppe_max":7,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["spielerisch","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Delegation Poker & Delegation Board – Management 3.0","url":"https://management30.com/practice/delegation-poker/"},{"typ":"buch","titel":"Jurgen Appelo: Management 3.0"}],"wann_passt":["Team in der Gründungsphase oder nach Umstrukturierung: implizite Erwartungen über Entscheidungsbefugnisse (Wer entscheidet über Tool-Auswahl? Über Urlaub? Über Budget bis 500 €?) werden explizit – das verhindert später Ärger über Kompetenzüberschreitung oder Nichtentscheidung.","Wachsendes Team, das von Führung delegieren möchte, aber unklar ist, wie weit – das Spiel macht sichtbar, wo Führung und Team verschieden einschätzen, und erzeugt ein gemeinsames Bild statt einseitiger Ansage.","Retrospektive nach Entscheidungskonflikten: statt Schuldfragen spielen Team und Führung dieselben Fälle durch und finden die Lücke im gemeinsamen Verständnis."],"wann_nicht":["Wenn Führung nicht bereit ist, tatsächlich zu delegieren – dann erzeugt das Spiel Erwartungen, die anschließend enttäuscht werden.","Bei über 8 Personen ohne Kleingruppen-Struktur – zu viele Einzel-Begründungen bei Ausreißern zermürben die Gruppe."],"fokusfragen":["„Welche Stufe würde dir hier die Arbeit am meisten erleichtern – und welche würde dir Sicherheit geben?\" (Doppelperspektive einnehmen)","„Was bräuchte das Team, um eine Stufe höher zu delegieren als bisher?\""],"beispiel":"Fall: „Wer entscheidet, welche Software wir für Projektmanagement nutzen?\" Team-Karten: 5, 6, 4. Führungskarte: 3. Diskussion: Person mit 6 (vollständige Delegation) erklärt, das Team nutze die Tools täglich, die Führung nie. Person mit 4 (Agree) ergänzt, sie wolle bei der Wahl mitsprechen. Führung erklärt, sie wolle informiert werden, bevor entschieden wird (=4, Consult/Agree). Ergebnis: Stufe 4 festgehalten – Team entwickelt Vorschlag und informiert Führung eine Woche vor Entscheidung.","mini_form":"Nur 3 Fälle statt einem vollständigen Delegation Board: 20 Min reichen, um die häufigsten Missverständnisse sichtbar zu machen – gut als Teambesprechungs-Element ohne Workshop-Aufwand.","anlass_typen":["kickoff","teamtag","entscheidungstreffen"],"typ":"methode","gruppen_sweetspot":"3–8 ideal (direkte Führungsbeziehung + Team), bis 12 in Kleingruppen","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"silent-start-6-pager","name":"Silent Start / 6-Pager (Memo-Lesen)","feld":"G","kurz":"Das Meeting beginnt mit stillem Lesen: Statt Präsentation schreibt die einbringende Person vorab ein narratives Memo (max. sechs Seiten); die ersten 10–30 Minuten lesen alle schweigend und notieren Anmerkungen.","schritte":["Verantwortliche Person schreibt das Memo als Fließtext mit ganzen Sätzen und Argumentation – keine Stichpunkt-Folien.","Meeting startet mit stiller Lesezeit, alle kommentieren schriftlich am Rand/im Dokument.","Moderation geht das Memo abschnittsweise durch und ruft Kommentare auf.","Offene Fragen diskutieren, Entscheidung treffen.","Beschlüsse als Action Items sichern."],"zweck":"Entscheidungen auf Basis durchdachter Argumente statt Präsentations-Charisma; alle starten mit demselben Informationsstand.","hinweise":"Qualität steht und fällt mit dem Memo – Schreiben erzwingt Denken, kostet aber Vorbereitungszeit. Kurzform: 1–2-seitiges Memo mit 10 Min Lesezeit. Online stark, weil alle parallel im selben Dokument kommentieren.","phasen":["verstehen","entscheiden"],"ebenen":["team","organisation"],"modi":["klaerung","entscheidung"],"formate":["meeting","klausur"],"dauer_min":30,"dauer_max":60,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["schriftlich","strukturiert"],"blocktyp":["einstieg","kern"],"quellen":[{"typ":"online","titel":"6 Page Memo – Async-First Method Stack","url":"https://www.asyncagile.org/method-stack/6-page-memo"},{"typ":"buch","titel":"Colin Bryar & Bill Carr: Working Backwards"}],"wann_passt":["Entscheidungsmeeting mit komplexer Vorlage, bei dem Präsentationscharisma sonst die Diskussion dominiert – das Memo zwingt die Autorin, das Argument schriftlich durchzuhalten, und gibt allen denselben Informationsstand.","Remote-Team mit unterschiedlichen Zeitzonen oder asynchronen Präferenzen: Memo kann vorab gelesen werden, synchrone Zeit konzentriert sich auf Klärung und Entscheidung.","Gruppe, die regelmäßig in Meetings 20 Minuten Kontext nachfrägt, der vorab hätte klar sein können – das Format diszipliniert die einbringende Person und entlastet die Gruppe."],"wann_nicht":["Spontane oder emergente Fragen, die keine Vorbereitungszeit erlauben.","Wenn das Schreiben des Memos mehr kostet als der Gesprächswert – bei kleinen operativen Fragen ist es Overhead."],"fokusfragen":["„Was ist nach dem Lesen noch unklar – und was ist schon entschieden?\" (Lesephase-Abschluss)","„Welche Annahme im Memo haltet ihr für am riskantesten?\" (Diskussionseinstieg)"],"beispiel":"Kurzform in einem Teammeeting: 1-seitiges Memo zu einer Partnerschaftsanfrage. 10 Minuten stilles Lesen, alle kommentieren im Dokument. Dann: „Was überrascht euch?\" – 3 Wortmeldungen. „Was fehlt, um zu entscheiden?\" – 2 Ergänzungen. „Sind wir bereit zu entscheiden?\" – Fist-to-Five. Dauer Gesamt: 35 Minuten statt 60-minütiger Präsentation.","mini_form":"Nur 1 Seite + 10 Min Lesen: die volle 6-Pager-Logik gilt auch für kurze Memos – schon ein gut geschriebener A4-Text, der 10 Minuten gelesen wird, erzeugt qualitativ bessere Diskussionen.","anlass_typen":["entscheidungstreffen","strategie"],"typ":"methode","gruppen_sweetspot":"3–15, besonders stark bei 4–8","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"timeboxing","name":"Timeboxing","feld":"G","kurz":"Jeder Agenda-Punkt bekommt ein festes Zeitfenster, das sichtbar mitläuft und konsequent gehalten wird. Die Zeitgrenze erzeugt Fokus und schützt spätere Punkte.","schritte":["Beim Agenda-Design jedem Punkt realistische Zeit zuordnen.","Timeboxen zu Beginn transparent machen und vereinbaren, ob hart oder weich.","Timer sichtbar laufen lassen (Time Timer, Bildschirm-Timer).","Vorwarnung geben (z.B. „noch 2 Minuten\").","Bei Ablauf: abschließen, bewusst verlängern (zulasten welches Punkts?) oder in den Parkplatz."],"zweck":"Meetings enden pünktlich und wichtige spätere Agenda-Punkte werden nicht von frühen Diskussionen aufgefressen.","hinweise":"Harte Timeboxen für Status-Formate, weiche für kreative Arbeit. Stolperstein: Timer stellen, aber nie durchsetzen – dann verliert das Instrument seine Wirkung. Verlängerung immer als explizite Gruppen-Entscheidung.","phasen":["planen","vertiefen"],"ebenen":["team"],"modi":["klaerung","energie"],"formate":["meeting","workshop"],"dauer_min":0,"dauer_max":5,"gruppe_min":2,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Timeboxing: How to Work Faster and Stay Focused – Asana","url":"https://asana.com/resources/what-is-timeboxing"}],"wann_passt":["Meetings mit mehreren Agenda-Punkten unterschiedlicher Wichtigkeit – ohne Timeboxen fressen frühe Punkte die späteren auf, die oft strategisch wichtiger sind.","Workshopdesign: Timeboxen als Skelett jeder Session-Planung – ohne sie entsteht kein valides Drehbuch.","Kreativphasen mit Tendenz zum Endlosoptimieren – harte Timebox erzeugt produktiven Druck und verhindert Perfektionismus."],"wann_nicht":["Tiefe Klärungsgespräche in Konflikten oder schwierigen Zwischenmenschlichkeiten – strenge Timeboxen signalisieren dort: dein Thema ist nicht wichtig genug.","Wenn die Zeit nie durchgesetzt wird – ein aufgezogener Timer ohne Konsequenz erzieht die Gruppe, Timeboxen zu ignorieren."],"fokusfragen":["„Wie viel Zeit brauchen wir wirklich für diesen Punkt – und was lassen wir weg, wenn wir zu wenig Zeit einplanen?\""],"beispiel":"Explizite Verlängerungs-Entscheidung: Timer läuft ab, Diskussion ist nicht fertig. Moderation: „Zeit ist um – wir könnten 5 Minuten verlängern, das geht zulasten des nächsten Punkts, oder wir entscheiden jetzt mit dem, was wir haben. Was wollen wir?\" Gruppe entscheidet bewusst – das verhindert stillschweigendes Überziehen.","mini_form":"Allein die sichtbare Uhr auf dem Tisch oder Bildschirm – ohne Moderation, ohne Erklärung. Erzeugt bereits Fokus.","anlass_typen":["regeltermin","entscheidungstreffen","strategie","krisensitzung"],"typ":"werkzeug","gruppen_sweetspot":"beliebig – Werkzeug der Raumgestaltung","stimmung_geeignet":["frisch","muede","neugierig"]},{"id":"roti","name":"ROTI (Return on Time Invested)","feld":"G","kurz":"Blitz-Feedback am Meeting-Ende: Alle bewerten auf einer Skala 1–5, ob sich die investierte Zeit gelohnt hat. Macht Meeting-Qualität messbar und verbesserbar.","schritte":["2–3 Minuten vor Schluss die Skala erklären (1 = Zeit verloren, 3 = ausgewogen, 5 = sehr lohnend).","Alle stimmen gleichzeitig ab – Finger heben, Punkt kleben oder anonymes Online-Tool.","Bild kurz anschauen: Wo liegt die Gruppe?","1–2 niedrige Stimmen fragen: „Was hätte den Wert erhöht?\"","Eine konkrete Verbesserung für das nächste Treffen festhalten."],"zweck":"Wiederkehrende Meetings kontinuierlich verbessern statt sie still zu erleiden.","hinweise":"Anonyme Abgabe erhöht die Ehrlichkeit, besonders bei Hierarchiegefälle. Wirkt nur, wenn aus dem Feedback sichtbar etwas folgt – sonst Ritual ohne Konsequenz.","phasen":["reflektieren"],"ebenen":["team"],"modi":["reflexion"],"formate":["meeting","workshop","reflexionsrunde"],"dauer_min":2,"dauer_max":5,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["abschluss"],"quellen":[{"typ":"online","titel":"What is ROTI? – Lucid Meetings Glossary","url":"https://www.lucidmeetings.com/glossary/roti"}],"wann_passt":["Wiederkehrendes Meeting, das sich eingeschlichen hat, ohne je gefragt zu werden ob es nützt – ROTI erzwingt sichtbares Feedback und macht Verbesserung zum Normalfall.","Team, das nie über Meetingqualität redet, weil 'immer dasselbe kommt' – die Skala gibt der Unzufriedenheit eine Zahl und die Moderation einen Gesprächseinstieg.","Workshop am Ende jedes Halbtages als Lernschleife für das Facilitationsteam."],"wann_nicht":["Wenn auf das Feedback nie sichtbar reagiert wird – dann signalisiert ROTI nur, dass Unzufriedenheit registriert und ignoriert wird.","Einmaliger Workshop ohne Folgetreffen – dann ist das Feedback wertlos für die Verbesserung."],"fokusfragen":["„Was hätte den Wert dieses Treffens für dich erhöht?\" (an 1–2 niedrige Stimmen)","„Was war der wertvollste Moment?\" (optional für 4–5-Stimmen)"],"beispiel":"ROTI-Ergebnis: 2 × 5, 4 × 3, 1 × 2. Moderation fragt die Person mit 2: „Was hätte heute besser sein können?\" Antwort: „Wir haben den gleichen Punkt wie letzten Monat diskutiert – ohne Ergebnis.\" Konkrete Verbesserung: nächstes Meeting startet mit: Was war das Ergebnis vom letzten Mal dazu? → einminütige Erinnerung.","mini_form":"5-Finger-ROTI: alle heben die Hand mit 1–5 Fingern gleichzeitig. 30 Sekunden. Kein Gespräch nötig, wenn alle ≥ 3 zeigen.","anlass_typen":["regeltermin","retro"],"typ":"werkzeug","gruppen_sweetspot":"3–30, beliebig skalierbar","stimmung_geeignet":["muede","frisch","neugierig"]},{"id":"konsent","name":"Konsent (Soziokratie, Kurzform)","feld":"G","kurz":"Soziokratisches Entscheidungsverfahren: Ein Vorschlag gilt als angenommen, wenn niemand einen schwerwiegenden, begründeten Einwand hat – gefragt wird „Spricht etwas Gravierendes dagegen?\" statt „Bist du dafür?\".","schritte":["Vorschlag vorstellen, Verständnisfragen klären (Informationsrunde).","Meinungsrunde: alle äußern sich reihum kurz, ggf. Vorschlag anpassen.","Konsentrunde: jede Person sagt „Konsent\" oder nennt ihren Einwand.","Einwände integrieren: Vorschlag so anpassen, dass der Einwand aufgehoben ist.","Erneute Konsentrunde, bis kein schwerwiegender Einwand bleibt.","Entscheidung mit Überprüfungsdatum festhalten."],"zweck":"Tragfähige Team-Entscheidungen ohne Endlos-Konsens und ohne Mehrheits-Überstimmen.","hinweise":"Konsent ist nicht Konsens: Es reicht „gut genug für jetzt, sicher genug zum Ausprobieren\". Einwände sind Geschenke, brauchen aber Begründung am gemeinsamen Ziel. Runden strikt reihum moderieren, sonst dominieren laute Stimmen.","phasen":["entscheiden"],"ebenen":["team","organisation"],"modi":["entscheidung","klaerung"],"formate":["meeting","workshop","klausur"],"dauer_min":15,"dauer_max":45,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"KonsenT-Moderation – Soziokratie.org","url":"https://www.soziokratie.org/konsentmoderation/"},{"typ":"online","titel":"Consent Decision Making – Sociocracy For All","url":"https://www.sociocracyforall.org/consent-decision-making/"},{"typ":"buch","titel":"Christian Rüther: KonsenT-Moderation"},{"typ":"online","titel":"Konsens und Konsent – s3lf.org","url":"https://s3lf.org/erklaerungen/konsens-und-konsent/"}],"wann_passt":["Team mit soziokratischer oder selbstorganisierter Arbeitsweise, das einen konkreten Vorschlag verabschieden will – Konsent ist schneller als Konsens-Suche und legitimierter als Mehrheitsvotum, wenn die Gruppe das Verfahren kennt.","Entscheidung mit mittlerer Tragweite (Richtlinie, Rollenverteilung, Projektentscheid), bei der echte Einwände erwartet werden – der Meinungsrunde-Schritt gibt alle Einwände Raum, bevor abgestimmt wird.","Gruppe, die Endlosdiskussionen kennt und einen strukturierten Ausweg sucht – die Frage 'Spricht etwas Gravierendes dagegen?' ist präziser und schneller als 'Sind alle dafür?'."],"wann_nicht":["Gruppe ohne Vorerfahrung mit soziokratischen Verfahren in einer Hochdruck-Situation – die Unterscheidung Einwand vs. Meinung muss vorher gelernt sein, sonst entstehen Frustration und endlose Integrations-Runden.","Sehr große Gruppen (>20) ohne Facilitationserfahrung – die Einwand-Integrationsschleife ist in der Großgruppe ohne Übung nicht steuerbar.","Wenn die Entscheidung tatsächlich einer einzigen Person obliegt (Führungsmandat) – Konsent in einem hierarchischen Setting ohne echtes Mandat für die Gruppe ist Pseudobeteiligung."],"fokusfragen":["„Hat jemand einen schwerwiegenden Einwand – also etwas, das uns am gemeinsamen Ziel schaden würde?\" (Konsent-Runde)","„Was bräuchte der Vorschlag, damit dein Einwand aufgehoben wäre?\" (nach einem Einwand)","„Ist dieser Vorschlag gut genug für jetzt, sicher genug zum Ausprobieren?\" (Entscheidungsformulierung)"],"beispiel":"Team von 6 entscheidet über neue Meeting-Struktur. Vorschlag: „Wir treffen uns künftig montags 9–10 Uhr statt freitags 16 Uhr.\" Informationsrunde: Alle verstehen die Implikationen. Meinungsrunde: Person A: „Ich fände Dienstag besser, aber ok.\" Person B: „Montag morgens sind meine Kinderübergaben – das geht nicht für mich.\" Das ist ein Einwand. Integration: Vorschlag angepasst auf dienstags 9 Uhr. Zweite Konsent-Runde: kein Einwand. Beschlossen. Überprüfungsdatum: in 3 Monaten.","mini_form":"Blitz-Konsent für Kleinentscheidungen: Vorschlag benennen, eine Runde „Einwand oder nicht?\" – wer nein sagt, sagt kurz warum. Unter 5 Minuten möglich für unkritische operative Fragen.","anlass_typen":["entscheidungstreffen","regeltermin","teamtag"],"typ":"methode","gruppen_sweetspot":"4–12 ideal, bis 20 mit Erfahrung","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"systemisches-konsensieren","name":"Systemisches Konsensieren (Widerstandsabfrage)","feld":"G","kurz":"Entscheidungsverfahren, das Widerstand statt Zustimmung misst: Alle bewerten jede Option mit 0–10 Widerstandspunkten; gewählt wird die Option mit dem geringsten Gesamtwiderstand – die konfliktärmste Lösung.","schritte":["Fragestellung und unveränderliche Rahmenbedingungen klären.","Lösungsoptionen sammeln (inkl. Passiv-Lösung „alles bleibt, wie es ist\").","Widerstandsabfrage: jede Person vergibt pro Option 0 (kein Widerstand) bis 10 Punkte (starke Ablehnung).","Punkte pro Option summieren.","Option mit geringstem Gesamtwiderstand wählen; bei hohen Einzelwiderständen nachfragen und Optionen weiterentwickeln."],"zweck":"Gruppenentscheidungen mit vielen Optionen, bei denen Akzeptanz wichtiger ist als Mehrheit – verhindert knappe Abstimmungssiege mit großer verärgerter Minderheit.","hinweise":"Die Passiv-Lösung als Vergleichsmaßstab gehört immer dazu. Schnellvariante: Widerstand per Handzeichen 0–5 Finger. Stolperstein: Widerstandspunkte als Taktik-Instrument – durch Nachfragen nach Gründen abfedern.","phasen":["entscheiden"],"ebenen":["team","organisation","netzwerk"],"modi":["entscheidung","konflikt"],"formate":["meeting","workshop","klausur","grossgruppe"],"dauer_min":20,"dauer_max":60,"gruppe_min":4,"gruppe_max":50,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Die Methode Systemisches Konsensieren – SK-Prinzip","url":"https://sk-prinzip.eu/methode/"},{"typ":"buch","titel":"Erich Visotschnig & Siegfried Schrotta: Systemisches Konsensieren"},{"typ":"online","titel":"Systemisches Konsensieren – Karl Hosang Anleitung","url":"https://karlhosang.de/systemisches-konsensieren/"}],"wann_passt":["Gruppe mit mehreren konkurrierenden Optionen (3 oder mehr Vorschläge) und erkennbaren Lagern – die Widerstandsabfrage verhindert, dass eine knappe Mehrheit eine große, verärgnete Minderheit überstimmt.","Entscheidungen in Netzwerken und losen Kooperationen, bei denen keine Mehrheitslogik gilt, aber ein Ergebnis gebraucht wird – SK ohne Hierarchie und ohne Konsens-Pflicht.","Konfliktgeladene Situation, in der klassische Abstimmung Sieger und Verlierer produzieren würde – die Fokussierung auf Widerstand statt Zustimmung senkt emotionale Eskalation."],"wann_nicht":["Wenn eine der Optionen strategisch gesetzt ist und die Moderation das Ergebnis eigentlich schon kennt – dann ist SK Theater.","Wenn Teilnehmer:innen taktisch abstimmen (hohe Punkte auf Konkurrenzoptionen, um die eigene zu bevorzugen) und keine Grundlage der Begründungspflicht besteht – Anonymität hilft, aber Nachfragen nach hohen Einzel-Widerständen ist Pflicht.","Für Entscheidungen, die rechtlich oder fachlich klar sind – SK ist ein Konsens-Annäherungsverfahren, kein Ersatz für Expertise."],"fokusfragen":["„Auf einer Skala von 0 (kein Widerstand) bis 10 (starke Ablehnung): Wie hoch ist dein Widerstand gegen Option X?\" (Abfrage-Formulierung)","„Wer hat 8 oder mehr Punkte vergeben – was steckt dahinter?\" (Nachfrage bei hohen Einzelwiderständen)","„Passt die Passiv-Lösung (alles bleibt wie es ist) auch als Vergleichspunkt mit aufs Board?\" (Vollständigkeit)"],"beispiel":"4 Optionen für den Veranstaltungsort. Widerstandsabfrage (0–10, je Person, je Option). Ergebnis: Option A: ∑ 12, Option B: ∑ 28, Option C: ∑ 7, Option D: ∑ 19. Option C gewinnt. Aber: Person X hat 9 Punkte auf C vergeben. Nachfrage: „X, was stört dich an C so stark?\" Antwort: Barrierefreiheit fehlt. Anpassung von Option C: Barrierefreiheit prüfen, neues Voting. Option C angepasst: ∑ 4. Beschlossen – mit Bedingung.","mini_form":"Handzeichen-Variante: Widerstand 0–5 Finger statt 0–10 Punkte. Pro Option einmal in die Runde: alle zeigen gleichzeitig. Sichtbares Ergebnis in 2 Minuten pro Option.","anlass_typen":["entscheidungstreffen","konfliktklaerung","beteiligung"],"typ":"methode","gruppen_sweetspot":"6–30 ideal, bis 50 mit digitaler Abstimmung","stimmung_geeignet":["skeptisch","angespannt","frisch"]},{"id":"dot-voting","name":"Dot-Voting (mit Varianten)","feld":"G","kurz":"Schnelle Priorisierung: Jede Person bekommt eine feste Anzahl Klebepunkte (oder digitale Votes) und verteilt sie auf die ausliegenden Optionen; die Punktdichte zeigt die Präferenz der Gruppe.","schritte":["Optionen sichtbar aufhängen/aufs Board bringen und kurz durchgehen.","Punktzahl festlegen (Faustregel: etwa ein Viertel der Optionsanzahl pro Person).","Still und möglichst gleichzeitig kleben – ohne Diskussion.","Auszählen und Top-Optionen markieren.","Ergebnis besprechen: Priorisierung, nicht automatisch Beschluss."],"zweck":"Aus vielen Ideen oder Themen schnell die wichtigsten herausfiltern (z.B. nach Brainstorming, für Lean-Coffee-Agenda).","hinweise":"Varianten: Cumulative Voting, Farb-Punkte (grün = wichtig, rot = riskant), nummerierte Punkte für Rangfolge, Junior-zuerst gegen Ankereffekte. Stolperstein: Dot-Voting als Entscheidungsverfahren missverstehen – es priorisiert, es legitimiert nicht.","phasen":["entscheiden","oeffnen"],"ebenen":["team","netzwerk"],"modi":["entscheidung","klaerung"],"formate":["meeting","workshop","grossgruppe"],"dauer_min":5,"dauer_max":15,"gruppe_min":3,"gruppe_max":50,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Dot Voting: A Simple Decision-Making and Prioritizing Technique – Nielsen Norman Group","url":"https://www.nngroup.com/articles/dot-voting/"}],"wann_passt":["Nach einem Brainstorming oder einer Ideensammlung mit 8–25 Optionen: Dot-Voting filtert schnell die 3–5 für die Gruppe wichtigsten heraus, ohne Diskussion und ohne Zeitverlust.","Lean-Coffee-Agenda zu Beginn: Karten werden gepunktet, und die Reihenfolge steht in 5 Minuten.","Workshopdesign mit Entscheidungsmoment zwischen Themen-Clustern – Punkte geben ein sofortiges visuelles Bild der Gruppenenergie."],"wann_nicht":["Als Entscheidungsverfahren für wichtige Beschlüsse – Dot-Voting priorisiert, legitimiert aber nicht. Eine knappe Punktemehrheit gibt keiner Option eine tragfähige Basis.","Wenn die Gruppe unter Hierarchiedruck steht – alle warten auf die Führungsperson, bevor sie Punkte setzen. Abhilfe: zuerst alle kleben, dann Führung.","Bei weniger als 4 Optionen – direktes Gespräch ist schneller und ehrlicher."],"fokusfragen":["„Ihr habt je X Punkte – setzt sie dort, wo ihr die meiste Energie oder den größten Bedarf seht.\" (Abstimmungs-Ansage)","„Was überrascht euch am Ergebnis? Wo erwartet ihr mehr oder weniger Punkte?\" (nach dem Kleben)"],"beispiel":"Retrospektive, 12 Ideen für Verbesserungen auf Post-its. Jede:r bekommt 3 Punkte. Alle kleben gleichzeitig (Führung zuletzt). Ergebnis: 2 Ideen haben je 6+ Punkte, der Rest je 0–2. Moderation: „Die Gruppe ist sich einig über die Top 2. Nehmen wir beide – oder wählen wir eine?\" Daraus entsteht ein Gespräch über Priorisierung, kein Mehrheitsvotum. Wichtig: explizit sagen, dass Punkte keine Beschlüsse sind.","mini_form":"Digitaler Emoji-Reaction-Vote in Zoom oder Teams: alle setzen Reaktionen auf die Optionen in Chat oder Präsentation. Ergebnis sofort sichtbar, kein Tool-Wechsel nötig.","anlass_typen":["retro","strategie","beteiligung"],"typ":"werkzeug","gruppen_sweetspot":"4–50, digital bis beliebig – Warnung: ab 20 Personen visuell unübersichtlich","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"fist-to-five","name":"Fist to Five","feld":"G","kurz":"Schneller Konsens-Check per Handzeichen: Faust (Veto/Nein) bis fünf Finger (volle Begeisterung) zeigen gleichzeitig den Zustimmungsgrad aller zu einem Vorschlag.","schritte":["Vorschlag klar formulieren und Skala erklären (Faust = Nein/Blockade, 1–2 = Bedenken, 3 = kann mittragen, 4–5 = Zustimmung/Begeisterung).","Auf Kommando zeigen alle gleichzeitig ihre Hand – hoch und sichtbar.","Raum lesen: alle ≥ 3 → angenommen.","Personen mit 0–2 fragen: „Was bräuchtest du, um auf eine 3 zu kommen?\"","Vorschlag anpassen und erneut abfragen."],"zweck":"In Minuten sichtbar machen, wie tragfähig ein Beschluss wirklich ist – statt schweigender Schein-Zustimmung.","hinweise":"Gleichzeitiges Zeigen ist entscheidend, sonst orientieren sich alle an den Ersten. Online per Reaktions-Emojis, Zahlen in den Chat oder Kamera-Handzeichen. Vorher klären, ob die Faust ein echtes Veto ist.","phasen":["entscheiden"],"ebenen":["team"],"modi":["entscheidung","klaerung"],"formate":["meeting","workshop"],"dauer_min":2,"dauer_max":10,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["koerperlich","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Fist to five – SessionLab Library","url":"https://www.sessionlab.com/methods/fist-to-five"},{"typ":"online","titel":"Fist to Five – Civic Canopy Tool Sheet","url":"https://www.civiccanopy.org/wp-content/uploads/2023/04/Dialogue_FisttoFive_En_2022_v1.pdf"}],"wann_passt":["Ein konkreter Vorschlag liegt auf dem Tisch, der angenommen oder weiterentwickelt werden soll – Fist to Five zeigt in Sekunden, wie weit die Gruppe ist, ohne lange Diskussionsrunden.","Am Ende einer Konsent- oder Diskussionsrunde: Test, ob der Vorschlag jetzt tragfähig ist oder noch integriert werden muss (0–2 = nochmal besprechen, 3–5 = angenommen).","Energiecheck in langen Workshops: kurze Stimmungs-Abfrage zu einem Vorschlag, bevor Zeit investiert wird."],"wann_nicht":["Wenn zwischen vielen Optionen gewählt werden soll – dann ist Dot-Voting besser (Priorisierung), Fist to Five nur für Einzelvorschläge.","Online ohne klares Simultanzeigen – wenn eine Person zuerst zeigt, richten sich alle anderen danach (Ankereffekt). Lösung: alle zeigen auf Zählung 3.","Als Entscheidungsverfahren für Fragen mit starker Minderheit und echten Konsequenzen – dann besser Konsent (Einwand-Integration möglich)."],"fokusfragen":["„Faust heißt Nein und Blockade, 1–2 bedeutet ernste Bedenken, 3 heißt 'ich kann damit leben', 4–5 heißt Zustimmung – alle zeigen auf 3-2-1.\" (Ansage)","„Wer zeigt 1 oder 2 – was bräuchtest du, um auf 3 zu kommen?\" (nach dem Zeigen)"],"beispiel":"Team von 8 diskutiert, ob die Jahresplanung auf einen vierteljährlichen Rhythmus umgestellt wird. Vorschlag liegt vor. Moderation: „Ich zähle 3-2-1 – alle zeigen gleichzeitig.\" Ergebnis: 3 × 5, 3 × 4, 1 × 3, 1 × 1. Moderation zu Person mit 1: „Was besorgt dich?\" Antwort: „Mir fehlt noch ein klares Übergabeprotokoll zwischen den Quartalen.\" Moderation: „Können wir den Vorschlag annehmen und das Protokoll bis Ende November ergänzen?\" Neues Voting: 7 × 4–5, 1 × 3 → angenommen.","mini_form":"Als schneller Stimmungstest ohne Konsequenz: „Wie fühlt ihr euch zu diesem Vorschlag – zeigt kurz eure Finger.\" Kein Entscheidungscharakter, nur Wahrnehmung der Raumstimmung.","anlass_typen":["entscheidungstreffen","regeltermin","krisensitzung"],"typ":"werkzeug","gruppen_sweetspot":"3–25, online mit Chat-Zahl oder Reaktion","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"gradients-of-agreement","name":"Gradients of Agreement","feld":"G","kurz":"Acht-stufige Zustimmungsskala nach Sam Kaner (von „voll dafür\" bis „blockiere\"), mit der Gruppenmitglieder ihre Haltung zu einem Vorschlag differenziert statt nur Ja/Nein ausdrücken.","schritte":["Skala sichtbar aufhängen (8 Stufen von begeisterter Zustimmung über „enthalte mich\" und „ernsthafte Bedenken\" bis Veto).","Vorschlag formulieren.","Alle positionieren sich gleichzeitig (Karte, Punkt, Aufstellung).","Verteilung gemeinsam anschauen: Wo liegt der Schwerpunkt, wo die Ausreißer?","Untere Stufen anhören, Vorschlag nachschärfen.","Entscheidungsregel anwenden (z.B. niemand unter Stufe 5)."],"zweck":"Die echte Unterstützungslandschaft hinter einem „Ja\" sichtbar machen – besonders in der zähen Phase vor dem Abschluss („Groan Zone\").","hinweise":"Stimmungsbild-Werkzeug, kein Abstimmungsverfahren – die Entscheidungsregel muss separat vereinbart sein. Skala darf auf 4–6 Stufen vereinfacht werden.","phasen":["entscheiden","vertiefen"],"ebenen":["team","organisation"],"modi":["entscheidung","klaerung"],"formate":["meeting","workshop","klausur"],"dauer_min":10,"dauer_max":25,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Gradients of Agreement – SessionLab Library","url":"https://www.sessionlab.com/methods/gradients-of-agreement"},{"typ":"buch","titel":"Sam Kaner: Facilitator's Guide to Participatory Decision-Making"},{"typ":"online","titel":"Gradients of Agreement – MSU Facilitation Tool","url":"https://www.canr.msu.edu/news/gradients_of_agreement_can_help_move_groups_forward"},{"typ":"online","titel":"Gradients of Agreement Scale – Wikipedia","url":"https://en.wikipedia.org/wiki/Gradients_of_agreement_scale"}],"wann_passt":["Wichtige Entscheidung mit erkennbarer Zustimmungslandschaft, bei der 'Ja/Nein' zu grob ist: die Skala macht sichtbar, ob die Gruppe begeistert ist oder nur resigniert zustimmt – beides zählt als Ja, hat aber völlig unterschiedliche Implikationen für die Umsetzung.","Konsensfindung in der 'Groan Zone' (Sam Kaner): Gruppe ist erschöpft, das Gespräch dreht sich, niemand blockiert aber niemand ist wirklich dabei – Gradients macht das Bild explizit und gibt der Moderation einen Eingriffspunkt.","Wenn eine knappe Mehrheitsentscheidung droht und die Minderheit stark genug ist, die Umsetzung zu sabotieren – die Skala zeigt, wie tief die Skepsis geht, bevor abgestimmt wird."],"wann_nicht":["Als eigenständiges Entscheidungsverfahren ohne vorher vereinbarte Entscheidungsregel – die Skala ist ein Diagnosewerkzeug, kein Abstimmungsverfahren.","Für operative Klein-Entscheidungen ohne strategische Bedeutung – der Aufwand übersteigt den Nutzen.","Online ohne Whiteboard oder Abstimmungstool – ohne sichtbares Bild verliert die Skala ihren Wert."],"fokusfragen":["„Positioniert euch auf der Skala – von 'Ich blockiere' bis 'Ich bin voll dabei': Wo steht ihr jetzt zu diesem Vorschlag?\" (Ansage)","„Wer steht auf den unteren drei Stufen – was bräuchte es, um einen Schritt höher zu gehen?\" (nach dem Bild)","„Wie viel Zustimmung brauchen wir, um jetzt zu entscheiden?\" (Entscheidungsregel klären)"],"beispiel":"8 Personen, Entscheidung über neues Governance-Dokument. Skala von 1 (blockiere) bis 8 (volle Begeisterung) auf Whiteboard. Verteilung: 1 × 3, 2 × 5, 4 × 6, 1 × 7. Moderation: „Wir haben eine Person auf 3 – was bräuchtest du?\" Antwort: „Die Haftungsklausel ist unklar.\" Klärung folgt, neues Dokument mit Ergänzung. Neues Gradient: Streuung jetzt 5–7. Entscheidungsregel (niemand unter 5) erfüllt – angenommen.","mini_form":"4-Stufen-Variante: A = voll dafür / B = kann damit leben / C = Bedenken / D = blockiere. Per Karte oder Chat. Schneller als 8 Stufen, fast gleich informativ.","anlass_typen":["entscheidungstreffen","strategie","konfliktklaerung"],"typ":"werkzeug","gruppen_sweetspot":"4–25, mit Whiteboard oder Tool","stimmung_geeignet":["skeptisch","frisch","neugierig"]},{"id":"advice-process","name":"Advice Process","feld":"G","kurz":"Dezentrales Entscheidungsprinzip (Frédéric Laloux): Jede Person darf jede Entscheidung treffen, muss aber vorher Rat einholen – bei Betroffenen und Fachkundigen. Der Rat fließt ein, entschieden wird selbst.","schritte":["Person erkennt Problem/Chance und übernimmt die Initiative.","Sie skizziert einen Entscheidungsentwurf.","Sie holt aktiv Rat ein: bei Betroffenen und bei Fachkundigen (je größer die Entscheidung, desto weiter der Kreis).","Sie wägt den Rat ernsthaft ab – ohne Pflicht, ihm zu folgen.","Sie entscheidet und informiert alle, die Rat gegeben haben, inkl. Begründung."],"zweck":"Schnelle, eigenverantwortliche Entscheidungen in Teams und Organisationen, ohne Konsens-Flaschenhals und ohne Top-down-Anordnung.","hinweise":"Häufiges Missverständnis: weder Konsens (niemand muss zustimmen) noch Alleingang (Rat einholen ist Pflicht). Braucht Vertrauenskultur und klare Vereinbarung, sonst wird es als Durchregieren mit Alibi-Anhörung erlebt.","phasen":["entscheiden","verstetigen"],"ebenen":["organisation","netzwerk"],"modi":["entscheidung","vertrauen"],"formate":["meeting","prozessbegleitung"],"dauer_min":30,"dauer_max":120,"gruppe_min":2,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Decision Making – Reinventing Organizations Wiki","url":"https://reinventingorganizationswiki.com/en/theory/decision-making/"},{"typ":"buch","titel":"Frédéric Laloux: Reinventing Organizations"}],"wann_passt":["Selbstorganisierte oder teal-orientierte Organisation, die formale Hierarchieentscheidungen abbaut – Advice Process ist kein Workshop-Element, sondern Betriebssystem für Entscheidungen im Alltag.","Wenn eine Person in einer Organisation Entscheidungen eigenverantwortlich treffen soll, aber unklar ist, wen sie vorher fragen muss – das Verfahren gibt Struktur ohne Zustimmungspflicht.","Als Einführungselement in einer Klausur zur Selbstorganisation: das Prinzip wird erklärt und an einem konkreten Fall durchgespielt, um das gemeinsame Verständnis zu etablieren."],"wann_nicht":["Ohne vorherige kulturelle Vorbereitung – der Advice Process funktioniert nur, wenn die Pflicht zum Rat-Einholen tatsächlich gelebt wird. Ohne diese Basis wird er als Alibi-Beteiligung erlebt.","Bei Entscheidungen, die rechtliche oder sicherheitsrelevante Konsequenzen haben – dort ist klare Mandatsstruktur (nicht Ratgeberprozess) erforderlich.","Als Sofortlösung in einer Krise – bei akutem Zeitdruck funktioniert das Konsultieren von Betroffenen und Fachkundigen nicht."],"fokusfragen":["„Wen betrifft diese Entscheidung – wen musst du befragen, bevor du entscheidest?\" (Mapping der Ratgeber:innen)","„Wie wirst du den Rat einbeziehen – und wen informierst du nach der Entscheidung, inklusive Begründung?\""],"beispiel":"Person A will ein neues Tool für die Team-Kommunikation einführen (Budget: 600 €/Jahr). Advice Process: A fragt das IT-Team (Fachkunde), drei Teammitglieder die täglich damit arbeiten (Betroffene) und Schatzmeisterin (Budgetrelevanz). Rat: IT warnt vor Datenschutzproblem bei Option 1. Teammitglieder bevorzugen Option 2. A entscheidet für Option 2, informiert alle mit Begründung. Kein Konsens nötig, aber transparenter Prozess.","mini_form":"Als Reflexionsfrage im Meeting: „Wer in diesem Raum ist von dieser Entscheidung betroffen und noch nicht gefragt worden?\" – öffnet den Advice-Process-Gedanken ohne vollständiges Verfahren.","anlass_typen":["entscheidungstreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"Einzelperson + Kreis von 2–10 Beratenden, kein klassisches Gruppenformat","stimmung_geeignet":["frisch","neugierig"]},{"id":"online-energizer-scavenger-hunt","name":"Online-Energizer: Scavenger Hunt","feld":"G","kurz":"Bewegungs-Energizer für Videocalls: Alle holen in kurzer Zeit einen Gegenstand nach Ansage („etwas Blaues\", „etwas, das dir wichtig ist\") und zeigen ihn in die Kamera.","schritte":["Ansage: „Ihr habt 60 Sekunden – holt etwas, das …\".","Alle stehen auf und suchen, Kamera bleibt an.","Zurück: alle halten den Gegenstand gleichzeitig in die Kamera.","2–3 Personen erzählen in einem Satz, was sie mitgebracht haben.","Optional zweite Runde mit persönlicherer Kategorie."],"zweck":"Körper aktivieren und Energie heben nach langen Sitz-Phasen; mit persönlicher Kategorie zugleich Verbindung stiften.","hinweise":"Kategorie bestimmt die Tiefe: „etwas Rotes\" = reine Energie, „etwas, das deine Woche beschreibt\" = Mini-Check-in. Auf Barrierefreiheit achten (nicht alle können schnell aufstehen) – Alternativ-Aufgabe anbieten.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["energie","verbindung"],"formate":["meeting","workshop","fortbildung"],"dauer_min":3,"dauer_max":7,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich","spielerisch"],"blocktyp":["energizer"],"quellen":[{"typ":"online","titel":"29 online energizers for more engaging meetings – SessionLab Blog","url":"https://www.sessionlab.com/blog/online-energizers/"}],"wann_passt":["Einstieg in einen Online-Workshop, bei dem Teilnehmer:innen zu Hause oder im Büro und physisch erreichbar sind – Bewegung vor langer Sitzphase.","Mitte eines langen Webinars als Aktivierungspause nach 60+ Minuten ruhigem Zuhören.","Kennenlernsituation: mit persönlicher Kategorie ('etwas, das deine Woche beschreibt') wird Scavenger Hunt zu einem Mini-Check-in mit visuellem Anker."],"wann_nicht":["Wenn Teilnehmer:innen in Großraumbüros oder öffentlichen Räumen sitzen und nicht aufstehen können.","Gruppe ohne Kameras – das Format lebt von der gleichzeitigen Präsentation des Gegenstands."],"fokusfragen":["„Ihr habt 60 Sekunden – holt etwas, das [Kategorie] ist. Auf 3-2-1 los.\" (Ansage)"],"mini_form":"Ein-Runden-Variante ohne zweite Runde: 60 Sek holen, 30 Sek zeigen, 3 Personen in einem Satz erzählen. 3 Minuten gesamt.","anlass_typen":["netzwerktreffen","lernformat"],"typ":"methode","gruppen_sweetspot":"5–25, online, Kameras an","stimmung_geeignet":["muede","frisch"]},{"id":"online-energizer-stretch-shake","name":"Online-Energizer: Stretch & Shake","feld":"G","kurz":"Geführte 2–3-minütige Bewegungspause im Videocall: gemeinsames Aufstehen, Strecken, Schultern kreisen, Ausschütteln – die Moderation macht vor, alle machen mit.","schritte":["Ansagen: „Alle aufstehen, wir bewegen uns 2 Minuten.\"","Einfache Sequenz vormachen: nach oben strecken, zur Seite lehnen, Schultern kreisen.","Arme und Beine ausschütteln, dabei gern Ton an und gemeinsam stöhnen/lachen lassen.","Tief ein- und ausatmen.","Hinsetzen und direkt mit dem nächsten Punkt weitermachen."],"zweck":"Konzentration zurückholen, wenn Bildschirm-Starre und Nachmittags-Tief einsetzen – ohne inhaltlichen Aufwand.","hinweise":"Wirkt am besten regelmäßig (z.B. alle 60–90 Min) statt einmalig als Gag. Niemanden zwingen, die Kamera anzulassen – Mitmachen ohne Bühne ist erlaubt.","phasen":["ankommen","vertiefen"],"ebenen":["person"],"modi":["energie"],"formate":["meeting","workshop","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":5,"gruppe_min":2,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich"],"blocktyp":["energizer"],"quellen":[{"typ":"online","titel":"29 online energizers for more engaging meetings – SessionLab Blog","url":"https://www.sessionlab.com/blog/online-energizers/"}],"wann_passt":["Nach 50–60 Minuten kontinuierlicher Bildschirmarbeit – Körperpause ohne inhaltlichen Umstieg.","Nachmittags-Loch (14–15 Uhr): Konzentration bricht weg, Energie-Intervall vor nächstem Thema.","Als regelmäßige Einheit in langen Online-Trainingstagen: Teilnehmer:innen erwarten die Pause und kalibrieren ihren Energiehaushalt entsprechend."],"wann_nicht":["Als einmaliger Gag zu Beginn einer Session – ohne Wiederholung verpufft der Effekt.","In sehr formellen Settings mit externen Gästen ohne Vorabankündigung."],"mini_form":"90-Sekunden-Variante: nur Schultern kreisen + ausschütteln + tief atmen. Keine Moderation nötig, einfach ansagen und mitmachen.","anlass_typen":["lernformat"],"typ":"methode","gruppen_sweetspot":"beliebig, bis 100+","stimmung_geeignet":["muede","belastet"]},{"id":"online-energizer-virtual-wave","name":"Online-Energizer: Virtual Wave / Reihen-Impuls","feld":"G","kurz":"Die Gruppe schickt eine „Welle\" durch die Video-Kacheln: In vereinbarter Reihenfolge machen alle nacheinander dieselbe kurze Bewegung oder Geste.","schritte":["Reihenfolge klären (Namensliste in den Chat oder „jede:r ruft die nächste Person auf\").","Bewegung vereinbaren (Arme hoch, Winken, ein Geräusch).","Welle starten und einmal durch alle laufen lassen.","Steigerung: schneller, rückwärts oder mit eigener Variation pro Person.","Mit Applaus-Welle abschließen."],"zweck":"Aufmerksamkeit und Gruppengefühl in Sekunden herstellen – jede Person ist einmal dran und sichtbar.","hinweise":"Funktioniert nur mit Kameras an; bei großen Gruppen Untergruppen-Wellen parallel in Breakouts. Die Namens-Zuruf-Variante trainiert nebenbei, dass alle die Namen kennen.","phasen":["ankommen"],"ebenen":["team"],"modi":["energie","verbindung"],"formate":["meeting","workshop","fortbildung"],"dauer_min":3,"dauer_max":5,"gruppe_min":5,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich","spielerisch"],"blocktyp":["energizer"],"quellen":[{"typ":"online","titel":"29 online energizers for more engaging meetings – SessionLab Blog","url":"https://www.sessionlab.com/blog/online-energizers/"}],"wann_passt":["Einstieg in ein Online-Meeting mit einer Gruppe, die sich noch nicht gut kennt – die Welle erzeugt in 3 Minuten Gruppengefühl und macht jede:n einmal sichtbar.","Übergang zwischen zwei schweren Inhaltsphasen: Welle als spielerisches Signal, dass ein neues Kapitel beginnt."],"wann_nicht":["Ohne Kameras – das Format funktioniert nur mit Bild.","Gruppen über 25 Personen ohne Untergruppen-Split – die Welle dauert sonst 10 Minuten und verliert die Energie."],"mini_form":"Klatsch-Welle statt Bewegungswelle: alle klatschen nacheinander in der vereinbarten Reihenfolge einmal – noch schneller, funktioniert auch mit Audio-Only.","anlass_typen":["netzwerktreffen","lernformat"],"typ":"methode","gruppen_sweetspot":"5–20 mit Kameras, in Untergruppen bis 50","stimmung_geeignet":["muede","frisch"]},{"id":"breakout-design","name":"Breakout-Design (Kleingruppen online)","feld":"G","kurz":"Methodische Gestaltung von Breakout-Räumen: klare Aufgabe, passende Gruppengröße, Rollen und Ernte-Format werden vor dem Split festgelegt – die Kleingruppe ist online der wichtigste Ort für echte Beteiligung.","schritte":["Ziel der Kleingruppenphase definieren (Brainstorm, Vertiefung, Peer-Feedback, Kennenlernen).","Gruppengröße wählen: Paare für Tiefe/Vertrauen, 3–4 für Diskussion, 5–6 nur mit Moderationsrolle.","Auftrag schriftlich mitgeben (Folie, Chat oder Board): Aufgabe, Zeit, erwartetes Ergebnis, Rollen.","Zeit ansagen inkl. 1-Min-Warnung; Moderation besucht Räume stichprobenartig.","Ernte im Plenum bewusst gestalten: ein Satz pro Gruppe, Board-Gallery oder Chat-Sammlung – nie alle alles berichten lassen."],"zweck":"Redeanteil und Sicherheit für alle erhöhen – in der Großgruppe online sprechen sonst nur wenige.","hinweise":"Häufigster Fehler: Aufgabe nur mündlich ansagen – in den Räumen weiß dann niemand mehr, was zu tun ist. Zweiter Stolperstein: Ernte-Phase länger als die Breakouts selbst; Berichtformat vorher radikal begrenzen.","phasen":["oeffnen","vertiefen"],"ebenen":["team","netzwerk"],"modi":["verbindung","klaerung"],"formate":["meeting","workshop","fortbildung","grossgruppe"],"dauer_min":10,"dauer_max":30,"gruppe_min":6,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Virtual Breakout Room Best Practices – Facilitation First","url":"https://facilitationfirst.com/virtual-breakout-room-best-practices/"}],"wann_passt":["Online-Workshop ab 8 Personen, bei dem in der Großgruppe nur 3–4 Personen regelmäßig sprechen – Breakouts erhöhen den Redeanteil und die Sicherheit aller.","Lernformat mit vertiefenden Peer-Gesprächen: Paare oder 3er-Gruppen bearbeiten denselben Fall und bringen unterschiedliche Perspektiven zurück.","Großgruppen-Konferenz (20–100): Breakouts als strukturierter Kern, Plenum nur für Einstieg und Ernte."],"wann_nicht":["Wenn die Aufgabe nicht schriftlich mitgegeben werden kann – mündliche Ansage geht in Breakouts verloren.","Wenn die Ernte danach mehr Zeit braucht als die Breakouts selbst – dann lieber weniger Gruppen oder radikal kürzere Berichte."],"fokusfragen":["„Was soll am Ende der Breakout-Phase im Plenum sichtbar sein – ein Satz, eine Karte, ein Ergebnis?\" (Ernte-Design)","„Wer moderiert in der Kleingruppe, wer dokumentiert?\" (Rollenverteilung vorab)"],"beispiel":"10-Min-Breakout in 3er-Gruppen: Aufgabe als Folie sichtbar: „Diskutiert 8 Minuten: Was ist die größte Hürde bei X für euren Kontext? Notiert einen Satz auf Miro-Sticky.\" Plenum: jede Gruppe liest ihren einen Satz vor (3 × 30 Sek). Moderation clustert live. Ergebnis: 3 Sätze in 3 Minuten Ernte.","mini_form":"Pair-Share in 5 Minuten: 2 Personen, 1 Frage, 4 Min Gespräch, 1 Min Ergebnis-Notiz. Kein Breakout-Room nötig – Paar im Chat zugewiesen oder spontan gebildet.","anlass_typen":["beteiligung","lernformat","netzwerktreffen"],"typ":"werkzeug","gruppen_sweetspot":"ab 6 Personen, ideal 8–30 im Plenum","stimmung_geeignet":["muede","frisch","neugierig"]},{"id":"digitales-whiteboard-arbeiten","name":"Digitales Whiteboard-Arbeiten (methodisch)","feld":"G","kurz":"Methodische Grundregeln für gemeinsames Arbeiten auf digitalen Whiteboards (Miro, Mural, FigJam u.a.): vorbereitete Struktur, Technik-Onboarding, stilles paralleles Schreiben und klare Navigation statt freiem Gewusel.","schritte":["Board vorab strukturieren: Frames/Bereiche pro Arbeitsschritt, Ziel oben sichtbar, Beispiel-Sticky als Muster.","Board vor der Session teilen und ein 5-Min-Technik-Warm-up einbauen (Sticky schreiben, bewegen, zoomen).","Arbeitsphasen als stilles paralleles Schreiben starten (ein Gedanke pro Sticky), erst danach sprechen und clustern.","Navigation führen: „Wir sind jetzt im Frame X\" oder Teilnehmer:innen zum Frame holen.","Ergebnis am Ende gemeinsam sichten und festhalten, was ins Protokoll/in die nächste Session wandert."],"zweck":"Sichtbares, gleichberechtigtes Mitarbeiten online – Schreiben statt Reden senkt die Dominanz einzelner Stimmen.","hinweise":"Stolpersteine: überladene Boards (kognitive Überforderung) und fehlendes Technik-Onboarding (ein Drittel steigt still aus). Bei >15 Personen Co-Facilitation einplanen. Faustregel: ein Gedanke pro Sticky, lesbar groß.","phasen":["verstehen","vertiefen","planen"],"ebenen":["team","organisation"],"modi":["klaerung"],"formate":["meeting","workshop","fortbildung"],"dauer_min":10,"dauer_max":60,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["schriftlich","strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Tips for Creating Interactive Online Workshops – Miro Facilitation Guide","url":"https://miro.com/virtual-workshops/guide-to-workshop-facilitation/"}],"wann_passt":["Workshop mit gleichzeitig schreibender Gruppe: stilles paralleles Schreiben auf Stickies gibt ruhigeren Teilnehmer:innen Raum, ohne dass die Lauten dominieren.","Remote-Team, das gemeinsam strukturieren, clustern oder planen will – digitales Whiteboard ersetzt Flipchart und macht das Ergebnis sofort archiviert.","Fortbildungen mit vielen Teilnehmer:innen und mehreren parallelen Gruppenarbeiten – jede Gruppe hat ihren Frame, Moderation sieht alle gleichzeitig."],"wann_nicht":["Wenn ein Drittel der Gruppe nicht technikaffin ist und kein Technik-Onboarding eingeplant ist – dann brechen stille Aussteiger die Beteiligung.","Für schnelle operative Entscheidungen – Overhead überwiegt den Nutzen."],"fokusfragen":["„Wir sind jetzt in Frame X – bitte scrollt dorthin.\" (Navigation)","„Ein Gedanke pro Sticky – und bitte groß genug schreiben, dass die anderen es lesen können.\" (Schreibregel)"],"mini_form":"5-Min-Technik-Warm-up: „Schreibt ein Sticky mit eurem Namen und einem Emoji – bewegt es in das gelbe Feld.\" 5 Minuten reichen, damit alle die Grundfunktionen kennen, bevor die Arbeitsphase beginnt.","anlass_typen":["strategie","lernformat","beteiligung"],"typ":"werkzeug","gruppen_sweetspot":"4–30, ab 15 mit Co-Facilitation","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"online-check-in-varianten","name":"Online-Check-in-Varianten","feld":"G","kurz":"An den Online-Raum angepasste Check-in-Formate: Chat-Wasserfall (alle tippen, auf Kommando gleichzeitig senden), Emoji-/GIF-Stimmungsbild, Skala per Reaktion, Foto-Check-in („zeig deinen Schreibtisch-Gegenstand\").","schritte":["Format zur Gruppengröße wählen: bis 8 Personen mündliche Runde, darüber Chat-Wasserfall oder Emoji.","Frage klar einblenden (Folie/Chat).","Beim Chat-Wasserfall: alle schreiben, senden erst auf „3-2-1-los\" – verhindert Anker-Effekte.","2–3 Antworten laut aufgreifen, damit der Chat nicht ins Leere läuft.","Übergang in die Agenda benennen."],"zweck":"Auch in großen Online-Runden in 5 Minuten jede Person einmal aktiv beteiligen und Präsenz herstellen.","hinweise":"Der Chat-Wasserfall ist das vielseitigste Format und skaliert bis in Webinar-Größe. Persönliche Tiefe der Frage an Vertrautheit der Gruppe anpassen; im Zweifel leichter starten.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["verbindung","vertrauen"],"formate":["meeting","workshop","fortbildung","grossgruppe"],"dauer_min":3,"dauer_max":10,"gruppe_min":3,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"neutral","stil":["schriftlich","gespraechsnah"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"Check-in Workshop Activities – SessionLab Library","url":"https://www.sessionlab.com/library/check-in"}],"wann_passt":["Online-Workshop mit 10–50 Personen: Chat-Wasserfall gibt allen eine Stimme, ohne dass 45 Minuten mündliche Runde draufgehen.","Webinar-Format, bei dem Teilnehmer:innen nicht sprechen (Mikrofone aus): Emoji- oder Skalen-Check-in als einziger niedrigschwelliger Beteiligungsmoment.","Erste Sitzung einer Lernreihe, in der sich die Gruppe noch nicht kennt – Foto-Check-in als visueller Gesprächsöffner."],"wann_nicht":["Wenn dieselbe Frage jede Woche benutzt wird – dann ist es Pflichtübung ohne Erkenntnisgewinn.","Wenn die Antworten im Chat nicht aufgegriffen werden – dann signalisiert der Check-in, dass Beiträge ins Leere laufen."],"fokusfragen":["„Tippt eure Antwort – sendet alle auf mein Zeichen: 3-2-1-jetzt.\" (Chat-Wasserfall-Ansage)"],"beispiel":"Chat-Wasserfall, 20 Personen: Frage eingeblendet: „In einem Wort oder Satz: Was bringt ihr heute mit?\" Alle tippen. Moderation: „3-2-1-los.\" 20 Antworten erscheinen gleichzeitig. Moderation liest 3–4 laut vor und kommentiert kurz: „Ich höre viel Energie, ein bisschen Müdigkeit – das passt zu einem Montag. Danke.\" Übergang: „Dann legen wir los.\" Dauer: 3 Minuten.","mini_form":"Emoji-Check-in: Frage per Bildschirm, Teilnehmer:innen nutzen Meeting-Reaktionen oder tippen ein Emoji. 60 Sekunden, keine Auswertung nötig – das Bild spricht.","anlass_typen":["netzwerktreffen","lernformat"],"typ":"werkzeug","gruppen_sweetspot":"8–100, Chat-Wasserfall bis beliebig","stimmung_geeignet":["muede","frisch","neugierig"]},{"id":"kamera-energie-hygiene","name":"Kamera- & Energie-Hygiene (lange Online-Treffen)","feld":"G","kurz":"Gestaltungsregeln gegen Videocall-Erschöpfung („Zoom Fatigue\"), abgeleitet aus der Stanford-Forschung (Bailenson): Selbstansicht ausblenden, Audio-only-Phasen, Bewegungsfreiheit und echte Pausen einplanen.","schritte":["Zu Beginn Vereinbarungen treffen: Selbstansicht ausblenden erlaubt/empfohlen, Kamera-aus-Phasen sind legitim.","Bei Treffen über 60 Min: alle 50–60 Min eine 5–10-Min-Pause weg vom Bildschirm (Körper vom Schirm abwenden).","Zuhör-Phasen als Audio-only ansagen („nächste 15 Min: Kameras aus, gern bewegen\").","Fenster verkleinern statt Vollbild, um Gesichter auf natürliche Größe zu bringen.","Bewegungselemente einstreuen (Stretch-Pause, Aufstehen beim Nachdenken)."],"zweck":"Konzentration und Beteiligungsqualität über lange Online-Treffen halten statt sie durch Dauer-Kamera zu verbrennen.","hinweise":"Kamera gezielt für Verbindungsmomente einfordern (Check-in, Entscheidung, Abschluss), für Zuhör-Phasen freigeben. Die vier Stressoren nach Bailenson: Dauerblickkontakt, erhöhter Nonverbal-Aufwand, Selbstansicht, Bewegungslosigkeit.","phasen":["ankommen","vertiefen","verstetigen"],"ebenen":["person","team"],"modi":["energie"],"formate":["meeting","workshop","fortbildung","grossgruppe"],"dauer_min":0,"dauer_max":10,"gruppe_min":2,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["strukturiert"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Four causes for 'Zoom fatigue' and their solutions – Stanford Report","url":"https://news.stanford.edu/stories/2021/02/four-causes-zoom-fatigue-solutions"}],"wann_passt":["Ganztägige oder mehrstündige Online-Workshops: strukturierte Kamera-Pausen und Bewegungsinterventionen erhalten Beteiligungsqualität über den ganzen Tag.","Etablierung einer neuen Online-Meeting-Kultur im Team: einmalig die Bailenson-Erkenntnisse erklären und gemeinsam Regeln vereinbaren (Selbstansicht aus, Kamera-Pausen legitim).","Großgruppen-Konferenzen online: Zoom-Fatigue-Prävention von Anfang an einplanen statt am Nachmittag zu reparieren."],"wann_nicht":["Kurze Meetings unter 30 Minuten – Overhead nicht gerechtfertigt.","Als Regelwerk ohne Erklärung – Kamera-Regeln wirken ohne Kontext kontrollierend."],"fokusfragen":["„Wann brauchen wir Kameras – und wann können wir sie bewusst freigeben?\" (Team-Vereinbarung)"],"mini_form":"Eine Vereinbarung zu Beginn: „Selbstansicht ausblenden empfohlen – wir schauen uns nicht selbst zu. Kamera-Pause in der nächsten Zuhörphase erlaubt.\" 30 Sekunden Ansage, sofortige Wirkung.","anlass_typen":["lernformat","netzwerktreffen"],"typ":"rahmenmodell","gruppen_sweetspot":"beliebig, besonders relevant ab 60 Min Dauer","stimmung_geeignet":["muede","belastet"]},{"id":"smart-ziele","name":"SMART-Ziele","feld":"A","kurz":"Vage Absichten in spezifische, messbare, attraktive, realistische und terminierte Ziele übersetzen – der Klassiker der Zielklärung.","schritte":["Zielentwurf formulieren lassen: Was wollen wir erreichen?","Entwurf gegen die fünf Kriterien prüfen: spezifisch, messbar, attraktiv/erreichbar, realistisch, terminiert.","Pro Kriterium nachschärfen: Woran messen wir das? Bis wann?","Finales Ziel ausformulieren und sichtbar festhalten.","Optional: Verantwortlichkeit und ersten Schritt klären."],"zweck":"Vage Absichten in überprüfbare, terminierte Ziele übersetzen.","hinweise":"Gefahr der Schein-Präzision bei komplexen Vorhaben – SMART passt für Ergebnisse, weniger für emergente Prozesse. Variante: SMARTER (+ evaluiert, angepasst).","phasen":["planen","entscheiden"],"ebenen":["person","team","organisation"],"modi":["klaerung"],"formate":["meeting","workshop","coaching","prozessbegleitung"],"dauer_min":15,"dauer_max":45,"gruppe_min":1,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"SMART (Projektmanagement) – Wikipedia","url":"https://de.wikipedia.org/wiki/SMART_(Projektmanagement)"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"}],"wann_passt":["Coaching-Setting oder Einzelbegleitung, in der eine Person eine vage Absicht in einen handlungsfähigen Plan übersetzen will – die fünf Kriterien als Checkliste funktionieren gut als 1:1-Gesprächsstruktur.","Planungsmeeting eines Teams, das ein konkretes Teilziel für ein laufendes Projekt schärfen will – nicht für die Gesamtstrategie, sondern für den nächsten 4-Wochen-Block.","Abschluss einer Brainstorming-Phase: die beste Idee in ein SMART-Ziel übersetzen, um den Übergang von Kreativphase zur Umsetzungsplanung zu markieren."],"wann_nicht":["Für komplexe gesellschaftliche Veränderungsprozesse, bei denen der Weg emergent ist – SMART erzeugt dort Schein-Präzision und verhindert Anpassungsbereitschaft. Eine Theory of Change oder Emergent Strategy ist hier besser.","Wenn die Gruppe eigentlich zuerst klären muss, WAS sie will, bevor sie klärt, wie messbar es ist – dann ist SMART zu früh. Zuerst Richtung, dann Präzision.","Als Dauerwerkzeug in jeder Planungssitzung – SMART-Formulierungen, die nicht mehr hinterfragt werden, sind leere Ritual-Prosa ohne Steuerungswert.","Bei Zielen, die soziale Beziehungen oder kulturellen Wandel beschreiben – Messbarkeit ist dort entweder trivial oder unmöglich."],"fokusfragen":["„Woran würdest du in 3 Monaten erkennen, dass wir dieses Ziel erreicht haben – ganz konkret?\" (Messbarkeit)","„Ist das in unserer Hand – also realistisch unter den Bedingungen, die wir kontrollieren?\" (Realismus-Check)","„Bis wann genau? Ein Datum, kein 'bald'.\" (Terminierung)"],"beispiel":"Vage Absicht: „Wir wollen die Mitgliederbindung verbessern.\" SMART-Schärfung: „Bis zum 30. September steigt die aktive Teilnahme an unseren monatlichen Netzwerktreffen von durchschnittlich 12 auf mindestens 20 Personen, gemessen über die Anmeldezahlen der nächsten 3 Treffen.\" Formulierung macht sofort sichtbar: Wer ist verantwortlich für die Einladungsstrategie? Welche Daten haben wir schon? Was fehlt?","mini_form":"SMART-Schnelltest: Zielentwurf laut vorlesen, dann drei Fragen: „Woran messen wir's? Wann? Wer ist verantwortlich?\" – 5 Minuten, ohne Framework-Erklärung.","anlass_typen":["coaching","strategie","kickoff"],"typ":"werkzeug","gruppen_sweetspot":"1–6 Personen (Coaching bis kleines Team), in Großgruppen nur als Gruppenaufgabe","stimmung_geeignet":["frisch","neugierig"]},{"id":"logframe","name":"LogFrame","feld":"A","kurz":"Planungsmatrix von Aktivitäten über Outputs und Outcome bis Impact – mit Indikatoren, Nachweisquellen und Annahmen.","schritte":["Zielhierarchie klären: Impact, Outcome, Outputs, Aktivitäten.","Wenn-dann-Logik zwischen den Ebenen prüfen.","Pro Ebene Indikatoren definieren: Woran erkennen wir Erreichung?","Nachweisquellen (Means of Verification) festlegen.","Annahmen und Risiken pro Ebene eintragen.","Matrix gemeinsam auf Plausibilität durchgehen."],"zweck":"Projektlogik in einer 4×4-Matrix planbar, steuerbar und berichtbar machen.","hinweise":"Wird leicht zur Pflichtübung für Geldgeber statt zum Denkwerkzeug; Annahmen-Spalte nicht überspringen, dort liegt der Erkenntnisgewinn. In der Session am besten rückwärts vom Impact her bauen.","phasen":["planen","entscheiden"],"ebenen":["organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":2,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"How to write a logical framework (logframe) – tools4dev","url":"https://tools4dev.org/resources/how-to-write-a-logical-framework-logframe/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"online","titel":"Logframe – BetterEvaluation","url":"https://www.betterevaluation.org/methods-approaches/methods/logframe"},{"typ":"online","titel":"Logical Framework – INTRAC Guide","url":"https://www.intrac.org/app/uploads/2017/01/The-Logical-Framework.pdf"}],"wann_passt":["Antragsworkshop mit einem Projektteam, das einen Geldgeber mit strukturierter Wirkungslogik überzeugen muss – LogFrame in der Session rückwärts vom Impact her aufbauen (nicht von den Aktivitäten).","Frühes Projektdesign mit mehreren Partnerorganisationen: gemeinsames Ausfüllen macht Annahmen sichtbar, über die die Beteiligten unterschiedliche Vorstellungen haben.","Monitoring-Review eines laufenden Projekts: die Annahmen-Spalte durchgehen und prüfen, welche sich als falsch erwiesen haben."],"wann_nicht":["Als Pflichtübung am Schreibtisch nach abgeschlossener Planung – dann ist die Matrix Bürokratie, kein Denkwerkzeug.","Für adaptive oder emergente Vorhaben, bei denen der Weg per Definition offen ist – LogFrame zwingt eine lineare Wenn-Dann-Kausalität auf, die dort nicht passt. Besser: Theory of Change oder Outcome Mapping.","Wenn das Team nicht versteht, wozu der Frame dient – ohne Sinn hinter der Struktur entstehen inhaltsleere Boxen."],"fokusfragen":["„Wenn wir diese Outputs liefern – was verändert sich dann tatsächlich? Und welche Annahmen stecken dahinter?\" (Wenn-Dann-Prüfung)","„Welche Annahme in unserer Wirkungslogik ist am riskantesten – und was machen wir, wenn sie sich als falsch erweist?\""],"mini_form":"Wirkungskette in 15 Minuten: Nur die vertikale Logik skizzieren – Aktivitäten → Outputs → Outcomes → Impact – ohne Indikatoren und Nachweise. Reicht als Planungsbasis für eine frühe Diskussion.","anlass_typen":["strategie","kickoff"],"typ":"werkzeug","gruppen_sweetspot":"3–10, mit Facilitator der die Struktur kennt","stimmung_geeignet":["frisch","neugierig"]},{"id":"theory-of-change","name":"Theory of Change / Wirkungslogik","feld":"A","kurz":"Narratives Modell der kausalen Pfade und Annahmen einer Intervention – rückwärts vom langfristigen Ziel her gedacht.","schritte":["Langfristiges Ziel (Long-term Outcome) gemeinsam formulieren.","Rückwärts kartieren: Welche Vorbedingungen müssen erfüllt sein? (Outcomes Pathway)","Annahmen hinter jedem Kausalpfeil explizit machen.","Interventionen den Pfaden zuordnen.","Indikatoren für zentrale Outcomes bestimmen.","Narrativ formulieren: Wenn wir X tun, dann Y, weil Z."],"zweck":"Kausale Pfade und Annahmen einer Intervention sichtbar und diskutierbar machen.","hinweise":"Stärke liegt im gemeinsamen Aushandeln der Annahmen, nicht im fertigen Diagramm; ToC ist das Denkmodell hinter dem LogFrame. Lebendiges Dokument, regelmäßig revidieren.","phasen":["planen","entscheiden"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":90,"dauer_max":240,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"What is Theory of Change? – Center for Theory of Change","url":"https://www.theoryofchange.org/what-is-theory-of-change/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"online","titel":"Theory of Change Workshop Guidance – EIF","url":"https://www.eif.org.uk/resource/running-a-theory-of-change-workshop-a-quick-reference-for-workshop-facilitators"},{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 3: Theory of Change"}],"wann_passt":["Projektteam (5–15 Personen) zu Beginn einer Programmplanung, wenn unklar ist, ob die geplanten Aktivitäten wirklich zur angestrebten Veränderung führen — die Methode zwingt zur Klärung der Kausallogik: Wenn wir X tun, dann Y, weil Z.","Strategieprozess einer Organisation, die zwischen transformativen Zielen (Bedingungen müssen sich ändern) und interventionalen Zielen (was wir konkret tun) unterscheiden muss — die ToC macht diesen Unterschied explizit und verhandelbar.","Evaluations-Vorbereitung, wenn Geldgeber:innen oder Auftraggeber:innen wissen wollen, wie das Programm wirken soll — eine ausformulierte ToC (max. 3 Sätze im if-then-because-Format) ist die Grundlage für messbare Outcomes.","Teamklärung nach Konflikten über Prioritäten: Die Frage 'Was muss sich eigentlich ändern, damit unser Ziel erreicht wird?' trennt Aktivismus von strategischer Intervention."],"wann_nicht":["Als Einzel-Workshop in einer einzigen Sitzung: Eine ToC braucht Iteration — ein erster Entwurf, Feldtest, Überarbeitung. Wer sie in 90 Minuten 'fertig' macht, hat meist eine Wunschliste, keine Kausallogik.","In frühen Kontaktphasen mit Partnerorganisationen, die noch kein gemeinsames Problembild haben — dann zuerst Konfliktanalyse/Connectors-Dividers, danach ToC.","Als Kontrollwerkzeug von oben: Wenn die ToC vom Geldgeber vorgegeben wird und das Team sie nur 'ausfüllt', entsteht kein Orientierungswissen."],"fokusfragen":["„Wenn wir in drei Jahren auf dieses Programm zurückblicken und es war erfolgreich — was hat sich bei wem konkret verändert?“ (öffnet den Outcome-Raum)","„Warum glauben wir, dass unsere Aktivitäten genau diese Veränderung auslösen — welche Annahme steckt dahinter?“ (testet die Kausallogik)","„Welche Veränderungen müssen in der Gesellschaft/im System passieren, die wir selbst nicht direkt herbeiführen können, aber auf die wir angewiesen sind?“ (unterscheidet transformative von interventionalen Zielen)"],"mini_form":"If-then-because in 10 Minuten: Jede:r schreibt auf drei Post-its 'Wenn wir... (Aktivität)', 'dann... (Veränderung bei wem)', 'weil... (Annahme)'. Sammeln, clustern, die Annahmen mit einem Fragezeichen versehen — welche davon ist am unsichersten? Das ist der Risikopunkt der Theorie.","anlass_typen":["strategie","lernformat","retro"],"typ":"werkzeug","gruppen_sweetspot":"5–12 Personen ideal, bei größeren Gruppen in Untergruppen","stimmung_geeignet":["neugierig","frisch","skeptisch"],"beispiel":"Formulierung einer ToC im if-then-because-Format: 'Wenn wir lokale Friedenskomitees in der Konfliktanalyse ausbilden (Aktivität), dann werden sie Frühwarnsignale früher erkennen und Gesprächsräume öffnen (Outcome), weil Communities, die ihre eigene Konfliktdynamik verstehen, eher präventiv handeln als auf Eskalation zu warten (Annahme/Weil-Satz).' Der Weil-Satz ist der kritischste Teil — er macht die Theorie testbar und falsifizierbar."},{"id":"outcome-mapping","name":"Outcome Mapping","feld":"A","kurz":"Wirkung als beobachtbare Verhaltensänderung bei direkten Partner:innen (Boundary Partners) planen und verfolgen statt als abstrakten Impact.","schritte":["Vision und Mission des Programms formulieren.","Boundary Partners identifizieren: Akteure, mit denen das Programm direkt interagiert.","Pro Partner Outcome Challenges formulieren (erwünschte Verhaltensänderung).","Progress Markers staffeln: expect to see / like to see / love to see.","Strategien je Partner planen.","Monitoring über Outcome Journals vereinbaren."],"zweck":"Wirkung als beobachtbare Verhaltensänderung bei direkten Partner:innen planen und verfolgen.","hinweise":"Begrifflichkeit (Boundary Partner, Progress Marker) braucht Einführung; als Ergänzung zu LogFrame-Anforderungen von Geldgebern einsetzen.","phasen":["planen","reflektieren"],"ebenen":["organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":120,"dauer_max":240,"gruppe_min":4,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Outcome Mapping – BetterEvaluation","url":"https://www.betterevaluation.org/methods-approaches/approaches/outcome-mapping"},{"typ":"buch","titel":"Sarah Earl, Fred Carden, Terry Smutylo: Outcome Mapping. Building Learning and Reflection into Development Programs (IDRC)"},{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 4: Outcomes"}],"wann_passt":["Programmplanung für komplexe soziale Veränderungsprozesse (8–20 Personen), wo der direkte Kausalzusammenhang zwischen Aktivitäten und gesellschaftlichem Wandel zu lang ist — Outcome Mapping fokussiert auf Verhaltensänderungen bei 'Boundary Partners' (Schlüsselakteur:innen), nicht auf gesellschaftliche Endzustände.","Wenn ein Programm primär auf Verhaltensänderungen bei konkreten Personen oder Organisationen abzielt (z.B. Regierungsvertreter:innen, lokale Anführer:innen): Outcome Mapping benennt diese Boundary Partners explizit und definiert 'Outcome Challenges' — was sollen sie anders tun, denken, fühlen?","Reflexion mit Feldteams (6–15 Personen) über den Unterschied zwischen dem, was wir kontrollieren können (Outputs) und dem, worauf wir nur Einfluss haben (Outcomes) — schützt vor unrealistischen Wirkungsversprechen."],"wann_nicht":["Wenn das Team klare Indikatoren und messbare Zielgrößen für Geldgeber:innen braucht — Outcome Mapping ist wirkungsorientiert, aber nicht auf einfache Kennzahlen ausgerichtet.","Als Ersatz für Konfliktanalyse: Ohne Verständnis der Beziehungen zwischen Boundary Partners fehlt die Grundlage.","In Einzel-Workshops ohne Follow-up: Outcome Mapping lebt von regelmäßigem Monitoring der Verhaltensveränderungen."],"fokusfragen":["„Wer sind die drei bis fünf Akteur:innen, bei denen sich konkret etwas ändern muss, damit unser Ziel erreicht wird — und welche Beziehung haben wir zu ihnen?“ (Boundary Partners identifizieren)","„Was sollen diese Akteur:innen am Ende des Programms anders tun, mehr wissen oder anders denken? Formuliere das als beobachtbares Verhalten.“ (Outcome Challenge)","„Wie werden wir erkennen, dass sich bei diesen Akteur:innen etwas verändert — was können wir beobachten, auch ohne Fragebogen?“ (Progress Markers)"],"mini_form":"Boundary-Partners-Mapping in 15 Minuten: Auf einem Flipchart in der Mitte das eigene Programm, außen drum die Akteur:innen, die sich verändern müssen. Pfeile: wer beeinflusst wen? Dann: Für die zwei wichtigsten Boundary Partners je einen Satz: 'Am Ende wünschen wir uns, dass [Person/Organisation] ...' — das ist der Kern einer Outcome Challenge.","anlass_typen":["strategie","lernformat"],"typ":"werkzeug","gruppen_sweetspot":"6–15 Personen, Feldteam oder Programmleitung","stimmung_geeignet":["neugierig","frisch"]},{"id":"okr","name":"OKR","feld":"A","kurz":"Ein motivierendes Objective plus 3–5 messbare Key Results – Fokus und Ausrichtung in kurzen Zyklen.","schritte":["Ein qualitatives, motivierendes Objective formulieren: Wo wollen wir hin?","3–5 messbare Key Results definieren: Woran erkennen wir, dass wir da sind?","Auf Ambitionsniveau prüfen: Stretch-Ziel, 70 % Erreichung ist gut.","OKRs transparent für alle sichtbar machen.","Wöchentliche Check-ins und Quartals-Review/Retro vereinbaren."],"zweck":"Fokus und Ausrichtung in kurzen Zyklen schaffen, ohne in Detailplanung zu verfallen.","hinweise":"Häufigster Fehler: Key Results als To-do-Liste statt als Ergebnis-Messgrößen; OKRs nicht an Bonuszahlungen koppeln. In NGOs Begriff ggf. übersetzen, Logik bleibt gleich.","phasen":["planen","entscheiden"],"ebenen":["team","organisation"],"modi":["klaerung"],"formate":["meeting","workshop","klausur"],"dauer_min":60,"dauer_max":120,"gruppe_min":2,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"What is an OKR? Definition & Examples – What Matters","url":"https://www.whatmatters.com/faqs/okr-meaning-definition-example"},{"typ":"buch","titel":"John Doerr: Measure What Matters"},{"typ":"online","titel":"OKR für soziale Organisationen – IdeeQuadrat","url":"https://www.ideequadrat.org/objectives-and-key-results-in-sozialen-organisationen/"}],"wann_passt":["Organisation oder Team, das eine entwickelte Strategie und klare Mission hat und diese in 90-Tage-Zyklen operationalisieren will – OKR ohne strategische Basis ist Ziele-Roulette.","Teamklausur zur Quartalsplanung: gemeinsam ein Objective formulieren, das motiviert, und 3–5 Key Results bestimmen, an denen alle ihren Fortschritt erkennen.","Wenn das Team regelmäßig nach einem Quartal nicht weiß, was eigentlich wichtig war – OKR erzwingt Fokus durch Mengenbegrenzung (1 Objective, max. 5 KRs)."],"wann_nicht":["Ohne vorher klare Strategie, Vision oder Mission – OKR operationalisiert Richtung, kann sie aber nicht ersetzen.","Wenn Key Results an individuelle Bonuszahlungen gekoppelt werden – dann werden Ziele taktisch gesetzt (zu niedrig, damit sie erreichbar sind) statt ambitioniert.","In sehr kleinen Teams (2–3 Personen) – der Abstimmungsaufwand übersteigt den Nutzen; direkte Absprache ist effizienter.","Bei Vorhaben, die komplexe qualitative Wirkungen anstreben – Messbarkeit als Pflicht erzeugt dort Vereinfachungen, die das Wesentliche verfehlen. Besser: Theory of Change."],"fokusfragen":["„Wenn dieses Quartal großartig war – was haben wir dann erreicht? In einem Satz.\" (Objective-Formulierung)","„Woran werden wir in 3 Monaten erkennen, dass wir auf dem richtigen Weg sind – ganz konkret und messbar?\" (Key Results)","„Ist dieses Ziel ein Ergebnis – oder eine Aktivität?\" (KR-Qualitäts-Check)"],"beispiel":"OKR-Review, ein Team: Objective: „Wir sind für neue Partnerorganisationen als glaubwürdige Anlaufstelle bekannt.\" KR 1: 3 neue Partneranfragen im Quartal (aktuell: 1). KR 2: 2 co-erstellte Veranstaltungen (aktuell: 0). KR 3: Netzwerkseite mit 5 neuen Referenzen (aktuell: 2). Check-in nach 6 Wochen: KR 3 läuft, KR 1 und 2 stecken. Diskussion: Was blockiert KR 2? → fehlende Kapazität im Herbst. OKR anpassen oder Ressource umschichten.","mini_form":"OKR-Schnellentwurf in 20 Minuten: Jede:r schreibt ein Objective in einem Satz + 2–3 KR-Ideen. In 2er-Gruppen prüfen: Ist das ein Ergebnis oder eine Aktivität? Plenum: 1–2 Entwürfe als Ausgangspunkt wählen.","anlass_typen":["strategie","kickoff","retro"],"typ":"werkzeug","gruppen_sweetspot":"4–12, Quartalsplanung im Teamformat","stimmung_geeignet":["frisch","neugierig"]},{"id":"agiles-pm","name":"Agiles PM (Scrum/iterativ)","feld":"A","kurz":"Komplexe Vorhaben in kurzen Lern- und Lieferschleifen steuern statt per Vollplanung – mit Backlog, Sprints, Dailies und Retrospektiven.","schritte":["Product Backlog priorisieren: Was schafft als Nächstes Wert?","Sprint Planning: Team wählt realistisches Arbeitspaket für 1–4 Wochen.","Daily: 15 Min Abgleich (Was getan? Was als Nächstes? Was blockiert?).","Sprint Review: Ergebnis Stakeholdern zeigen, Feedback einholen.","Retrospektive: Zusammenarbeit verbessern.","Nächsten Zyklus starten."],"zweck":"Komplexe Vorhaben in kurzen Lern- und Lieferschleifen steuern statt per Vollplanung.","hinweise":"Funktioniert nur mit echtem Mandat für Selbstorganisation; Scrum-Theater (Rituale ohne Haltung) ist die häufigste Entgleisung. Für Nicht-Software-Kontexte Rollen und Artefakte pragmatisch anpassen.","phasen":["planen","verstetigen","reflektieren"],"ebenen":["team","organisation"],"modi":["klaerung","entscheidung"],"formate":["meeting","prozessbegleitung"],"dauer_min":15,"dauer_max":120,"gruppe_min":3,"gruppe_max":10,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The Scrum Guide – Schwaber & Sutherland","url":"https://scrumguides.org/"},{"typ":"buch","titel":"Ken Schwaber, Jeff Sutherland: The Scrum Guide (frei online)"}],"wann_passt":["Vorhaben mit komplexen, schwer vorhersehbaren Anforderungen, bei denen regelmäßige Kurskorrektur wichtiger ist als Vollplanung – Scrum-Sprints oder Kanban-Zyklen als Steuerungsrahmen.","Workshopmodul in einer Klausur zur Frage 'Wie arbeiten wir künftig?': Grundprinzipien (Backlog, Timebox, Retro) einführen und auf den eigenen Kontext übertragen.","Team mit hoher Eigenverantwortung und klarem Auftrag – dann liefert Agiles PM den Rhythmus, ohne Mikromanagement zu brauchen."],"wann_nicht":["Ohne echtes Mandat zur Selbstorganisation – Scrum-Theater (alle Rituale, keine Haltung) demoralisiert Teams schneller als klassische Führung.","Für klar planbare, stabile Vorhaben mit wenig Ungewissheit – lineares Projektmanagement ist dort effizienter.","Wenn 'agil' als Kostenspar-Argument eingesetzt wird (kein Projektmanager nötig) – ohne dedizierte Rollen kippt es in Chaos."],"fokusfragen":["„Was ist die kleinste lieferbare Einheit, die uns heute Feedback gibt?\" (Sprint-Auswahl)","„Was haben wir gelernt – und was ändern wir im nächsten Zyklus?\" (Retro-Einstieg)"],"mini_form":"Kanban-Einstieg in 20 Minuten: 3-Spalten-Board (To do / In Arbeit / Fertig) mit laufenden Aufgaben des Teams befüllen. Erste Frage: Was ist gerade in Arbeit – und warum ist davon so viel gleichzeitig aktiv?","anlass_typen":["kickoff","strategie"],"typ":"rahmenmodell","gruppen_sweetspot":"3–10 Personen (Scrum-Team-Größe)","stimmung_geeignet":["frisch","neugierig"]},{"id":"ecosystem-mapping","name":"Ecosystem Mapping","feld":"A","kurz":"Akteure, Beziehungen und Ressourcenflüsse eines Feldes auf einer gemeinsamen Karte sichtbar machen.","schritte":["Fokus festlegen: Um wen/was herum wird das Ökosystem kartiert?","Akteure und Entitäten sammeln (Personen, Organisationen, Plattformen, Orte) – auf Karten/Stickies.","Auf der Fläche anordnen, z. B. nach Nähe zum Zentrum.","Beziehungen einzeichnen: Informations-, Geld-, Ressourcen- und Unterstützungsflüsse.","Muster lesen: Lücken, Abhängigkeiten, ungenutzte Verbindungen.","Konsequenzen und nächste Schritte ableiten."],"zweck":"Akteure, Beziehungen und Flüsse eines Feldes auf einer gemeinsamen Karte sichtbar machen.","hinweise":"Karte wird schnell unübersichtlich – Fokusfrage eng halten und Linientypen begrenzen; online mit Miro/Mural gut machbar. Lebendes Artefakt, kein Endprodukt.","phasen":["verstehen","planen"],"ebenen":["netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Ecosystem Map – Service Design Tools","url":"https://servicedesigntools.org/tools/ecosystem-map"}],"wann_passt":["Strategieklausur einer Organisation in einem komplexen Umfeld: gemeinsames Bild des Ökosystems schärft das Verständnis dafür, wo man steht und welche Verbindungen fehlen oder gestärkt werden sollten.","Netzwerktreffen mehrerer Organisationen zu Beginn einer Kooperation: Karte macht sichtbar, wer was einbringt und welche Überschneidungen und Lücken es gibt.","Vorbereitung einer Ausschreibung oder eines Antrags: Akteure und Ressourcenflüsse verstehen, bevor die Interventionsstrategie geschrieben wird."],"wann_nicht":["Wenn die Fokusfrage zu breit ist – 'das gesamte Bildungsökosystem' passt nicht auf ein Board; Scope vorab eng fassen.","Als Einzelarbeit – die Karte lebt von multiplen Perspektiven; allein erstellt ist sie blind für Blinde Flecken."],"fokusfragen":["„Um wen oder was herum zeichnen wir diese Karte – was ist unser Zentrum?\" (Scope-Klärung)","„Welche Verbindungen überraschen euch – was habt ihr nicht erwartet zu sehen?\" (nach dem Zeichnen)"],"mini_form":"5-Min-Akteurs-Brainstorming: Alle schreiben Akteure auf Stickies (1 Akteur pro Sticky), dann grob anordnen: nah am Kern / weiter weg. Reicht als erstes gemeinsames Bild ohne vollständiges Mapping.","anlass_typen":["strategie","netzwerktreffen","kickoff"],"typ":"methode","gruppen_sweetspot":"4–12, mit Whiteboard oder Miro","stimmung_geeignet":["frisch","neugierig"]},{"id":"social-network-analysis","name":"Social Network Analysis","feld":"A","kurz":"Beziehungsstrukturen eines Netzwerks messen und visualisieren: Wer ist zentral, wer isoliert, wo sind Cluster und Brücken?","schritte":["Netzwerkfrage definieren: Wer arbeitet mit wem zusammen / tauscht Informationen aus?","Daten erheben: Befragung oder gemeinsames Kartieren der Beziehungen.","Netzwerk visualisieren (Knoten = Akteure, Kanten = Beziehungen; Tools: Kumu, Gephi oder Papier).","Auswerten: Wer ist zentral, wer isoliert, wo sind Cluster und Brücken?","Befunde mit der Gruppe interpretieren und Interventionen ableiten, z. B. gezielt Brücken bauen."],"zweck":"Beziehungsstrukturen eines Netzwerks messbar und sichtbar machen, um gezielt an Verbindungen zu arbeiten.","hinweise":"Datenerhebung ist sensibel (wer ist „isoliert\"?) – Ergebnisse wertschätzend rahmen und Datenschutz klären. In Sessions reicht oft eine partizipative Light-Variante auf Papier.","phasen":["verstehen"],"ebenen":["organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":5,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Social Network Analysis – BetterEvaluation","url":"https://www.betterevaluation.org/methods-approaches/methods/social-network-analysis"}],"wann_passt":["Organisationsentwicklung mit dem Ziel, Informationsflüsse oder Zusammenarbeitsmuster zu verstehen – SNA zeigt, wer de facto die Informationsdrehscheibe ist (oft nicht die formale Führung).","Netzwerk-Intervention, bei der gezielt Brücken zwischen isolierten Clustern gebaut werden sollen – SNA macht sichtbar, wo diese Brücken fehlen.","Evaluation eines Netzwerkprogramms: Hat das Programm tatsächlich neue Verbindungen geschaffen, die vorher nicht da waren?"],"wann_nicht":["Ohne explizite Datenschutzklärung – Netzwerkkarten zeigen, wer isoliert ist, was in vertrauenssensiblen Settings verletzend sein kann.","Als schnelle Workshop-Übung ohne Datenerhebung – ohne Befragung oder systematisches Kartieren sind die Ergebnisse Spekulation.","Wenn das Team die Erkenntnisse nicht aushalten kann (z.B. Führung ist isoliert) – dann braucht die SNA eine Verarbeitungskultur, nicht nur eine Visualisierung."],"fokusfragen":["„Mit wem tauscht du in einer typischen Woche Informationen zu X aus?\" (Erhebungsfrage)","„Was fällt euch auf – wer ist zentral, wen habt ihr überraschend nicht gefunden?\" (Interpretationsrunde)"],"mini_form":"Partizipatives Schnell-Mapping: Alle schreiben je 3 Namen auf Stickies ('Mit diesen Personen arbeite ich bei X eng zusammen') und verbinden sie auf einem Poster. In 15 Minuten entsteht ein erstes Bild – nicht statistisch valide, aber Gesprächsöffner.","anlass_typen":["strategie","teamtag"],"typ":"methode","gruppen_sweetspot":"8–30, mit Tool (Kumu, Gephi) oder Papier-Light-Version","stimmung_geeignet":["frisch","neugierig"]},{"id":"abcd","name":"Asset-Based Community Development (ABCD)","feld":"A","kurz":"Vorhandene Stärken einer Community kartieren statt Defizite – und Selbstorganisation von innen anstoßen.","schritte":["Perspektivwechsel einführen: von Defiziten zu Stärken.","Assets inventarisieren in fünf Kategorien: Individuen, Vereinigungen, Institutionen, Orte, Verbindungen.","Gaben einzelner sichtbar machen: Was kannst du beitragen?","Verbindungen stiften: Wer kann mit wem was bewegen?","Erste selbstorganisierte Vorhaben verabreden.","Erfolge sichtbar machen und Schwung halten."],"zweck":"Vorhandene Stärken einer Community kartieren und Selbstorganisation von innen anstoßen.","hinweise":"Keine schnelle Workshop-Methode, sondern Haltung und Langzeitprozess – in einer Session lässt sich gut das Asset-Mapping starten. Stolperstein: Externe übernehmen wieder die Führung.","phasen":["planen","oeffnen","verstetigen"],"ebenen":["netzwerk","feld"],"modi":["klaerung","verbindung"],"formate":["workshop","grossgruppe","prozessbegleitung"],"dauer_min":90,"dauer_max":240,"gruppe_min":8,"gruppe_max":50,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Asset Based Community Development – Nurture Development","url":"https://www.nurturedevelopment.org/asset-based-community-development/"},{"typ":"buch","titel":"John Kretzmann, John McKnight: Building Communities from the Inside Out"}],"wann_passt":["Kick-off einer Gemeinwesenarbeit oder Community-Initiative, bei der externe Akteure drohen, die Agenda zu setzen – ABCD dreht die Frage um: Was ist schon da? Was können wir selbst?","Organisations- oder Netzwerkentwicklung nach einer Krisenphase, in der das Defizit-Denken dominiert – das Asset-Mapping erzeugt Energie und Handlungsfähigkeit, bevor über Probleme gesprochen wird.","Workshop-Baustein in einem längeren Beteiligungsprozess: ein 90-Min-Asset-Mapping-Block, aus dem ein Bild der vorhandenen Stärken entsteht, das dann Basis für Planung wird."],"wann_nicht":["Als schnelles Workshop-Format mit Ergebniserwartung in 2 Stunden – ABCD ist eine Haltung und ein Langzeitprozess; in einer Session lässt sich nur das Asset-Mapping starten.","Wenn externe Facilitator:innen die Gruppe nach der Session verlassen und kein internes Commitment besteht weiterzumachen – dann erzeugt ABCD Energie ohne Nachhall.","In Kontexten mit starken Machtungleichgewichten, in denen bestimmte Stimmen systematisch nicht gehört werden – dann braucht ABCD vorher Arbeit an den Machtstrukturen, sonst kartiert man nur die Stärken der Privilegierten."],"fokusfragen":["„Was kannst du beitragen – nicht was brauchst du?\" (Paradigmen-Umkehr)","„Wer in dieser Gruppe könnte mit wem zusammenarbeiten – was würde dann möglich?\""],"mini_form":"Gaben-Runde in 20 Minuten: Alle nennen je eine Fähigkeit oder Ressource, die sie einbringen könnten. Moderation clustert sichtbar. Abschlussfrage: „Welche Kombination von Gaben überrascht euch?\"","anlass_typen":["beteiligung","kickoff","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"10–40, mit Raum für Bewegung; eingeschränkt online","stimmung_geeignet":["skeptisch","belastet","frisch"]},{"id":"stakeholder-mapping","name":"Stakeholder-/Akteurs-Mapping","feld":"A","kurz":"Interessen und Einfluss der Beteiligten auf einer Matrix offenlegen, um Beteiligung und Kommunikation gezielt zu planen.","schritte":["Fragestellung/Vorhaben benennen.","Alle relevanten Akteure brainstormen (intern/extern).","Auf Matrix einordnen: Einfluss/Macht (y) × Interesse (x).","Pro Quadrant Umgangsstrategie ableiten: eng einbinden, zufriedenstellen, informieren, beobachten.","Beziehungen und Koalitionen diskutieren.","Konkrete Engagement-Schritte vereinbaren und Review-Termin setzen."],"zweck":"Interessen und Einfluss der Beteiligten offenlegen, um Beteiligung und Kommunikation gezielt zu planen.","hinweise":"Einordnungen sind Hypothesen, keine Wahrheiten – regelmäßig aktualisieren; bei sensiblen Akteursbewertungen Vertraulichkeit des Raums klären. Varianten: Einfluss/Haltung-Matrix, Akteurszwiebel.","phasen":["verstehen","planen"],"ebenen":["team","organisation","netzwerk","feld"],"modi":["klaerung"],"formate":["meeting","workshop","prozessbegleitung"],"dauer_min":45,"dauer_max":120,"gruppe_min":2,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Power/Interest Grid – Improvement Service","url":"https://www.improvementservice.org.uk/business-analysis-framework/consider-perspectives/powerinterest-grid"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"}],"wann_passt":["Kick-off eines neuen Projekts oder einer Initiative mit mehreren Akteursgruppen – die Matrix macht sofort sichtbar, wen man einbinden, informieren, gewinnen oder beobachten muss.","Vorbereitung eines schwierigen Kommunikationsschritts: Welche Akteure haben hohes Interesse und könnten blockieren? Wo liegen Verbündete mit hohem Einfluss?","Kooperations-Design: Wer bringt was ein, wen brauchen wir unbedingt am Tisch, wen laden wir nicht ein – und warum?"],"wann_nicht":["Als statische Einmal-Übung – Akteurspositionen verschieben sich im Projektverlauf; die Karte muss regelmäßig aktualisiert werden.","Wenn die Einordnung einzelner Akteure sensibel ist und im Raum Vertreter:innen eben dieser Akteure sitzen – Vertraulichkeit des Prozesses vorab klären."],"fokusfragen":["„Wer hat das größte Interesse am Ergebnis – und wer den größten Einfluss, es zu verhindern?\" (Matrix-Einstieg)","„Welche Akteure haben wir vergessen? Wer fehlt, der betroffen wäre, aber nicht im Raum ist?\""],"mini_form":"5-Min-Brainstorm zu Akteuren, dann schnelle Einordnung: 4 Haftzettel-Quadranten (Einfluss hoch/niedrig × Interesse hoch/niedrig) auf dem Tisch. Karten draufkleben, 1-Min-Diskussion je Quadrant: Was brauchen diese Akteure von uns?","anlass_typen":["kickoff","strategie","entscheidungstreffen"],"typ":"werkzeug","gruppen_sweetspot":"2–12, als Teamarbeit am Whiteboard","stimmung_geeignet":["frisch","neugierig"]},{"id":"community-canvas","name":"Community Canvas","feld":"A","kurz":"Geteiltes Bild einer Community in drei Bereichen (Identity, Experience, Structure) mit 17 Themenfeldern entwickeln.","schritte":["Canvas einführen: drei Bereiche (Identity, Experience, Structure) mit 17 Themenfeldern.","Mit Identity starten: Purpose, Werte, Mitglieder-Definition gemeinsam beantworten.","Experience bearbeiten: Rituale, Erlebnisse, Rollen.","Structure bearbeiten: Governance, Finanzierung, Organisation.","Lücken und Spannungen markieren.","Prioritäten für die Community-Entwicklung ableiten."],"zweck":"Ein geteiltes, vollständiges Bild einer Community entwickeln und blinde Flecken im Community-Design finden.","hinweise":"17 Felder sind zu viel für eine Session – vorab 5–7 relevante Felder auswählen oder auf mehrere Termine verteilen. Gut als Diagnose für bestehende wie geplante Communities.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":90,"dauer_max":240,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The Community Canvas – community-canvas.org","url":"https://community-canvas.org/"}],"wann_passt":["Gründungsphase oder grundlegende Neuausrichtung einer Community: das Canvas deckt blinde Flecken im Community-Design auf – bei 17 Feldern findet fast jede Gruppe mindestens 5, über die sie noch nicht nachgedacht hat.","Diagnose einer bestehenden Community mit Energie-Verlust oder Mitglieder-Rückgang – systematisches Durchgehen der Felder zeigt, wo das Fundament fehlt.","Kooperationsklausur mehrerer Organisationen, die eine gemeinsame Community gestalten wollen – Canvas gibt eine gemeinsame Sprache."],"wann_nicht":["Alle 17 Felder in einer Session – das dauert einen ganzen Tag und überfordert; besser 5–7 Felder nach Diagnose-Priorität auswählen.","Als Schnell-Workshop-Tool für eine Community, die gerade akute Governance-Probleme lösen muss – dort ist direktes Klärungsgespräch schneller."],"fokusfragen":["„Was ist der Purpose dieser Community – warum existiert sie, und was würde fehlen, wenn sie nicht da wäre?\" (Identity-Einstieg)","„Welche Felder haben wir bisher noch nie gemeinsam besprochen? Was überrascht euch, wenn ihr draufschaut?\""],"mini_form":"Identity-Sprint in 30 Minuten: Nur die 3 Identity-Felder (Purpose, Werte, Mitgliederdefinition) bearbeiten. Diese drei allein erzeugen oft die wichtigsten Klärungen.","anlass_typen":["kickoff","strategie","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"4–12 (Kernteam oder Steuerungsgruppe der Community)","stimmung_geeignet":["frisch","neugierig"]},{"id":"platform-design-toolkit","name":"Platform Design Toolkit","feld":"A","kurz":"Ein Ökosystem als Plattform verstehen und gestalten: Wer produziert, wer konsumiert, welcher Wert wird getauscht?","schritte":["Ökosystem-Akteure kartieren (Ecosystem Canvas): Wer produziert, wer konsumiert, wer orchestriert?","Potenziale je Akteur erfassen (Entity Portrait): Ziele, Gaben, Druckpunkte.","Kern-Transaktionen designen: Welcher Wert wird zwischen wem getauscht?","Unterstützende Services der Plattform definieren (Enabling/Empowering Services).","Minimum Viable Platform skizzieren und Testschritte vereinbaren."],"zweck":"Ein Ökosystem als Plattform verstehen und gestalten, die Wertaustausch zwischen Akteuren ermöglicht.","hinweise":"Voraussetzungsreiches Vokabular – mit einem vertrauten Beispiel (z. B. Marktplatz) einführen; Toolkit ist frei verfügbar, vollständiger Durchlauf braucht mehrere Sessions.","phasen":["planen"],"ebenen":["netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":120,"dauer_max":300,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Platform Design Toolkit – Boundaryless","url":"https://www.platformdesigntoolkit.com/"}],"wann_passt":["Organisationen oder Netzwerke, die ein gemeinsames Ökosystem gestalten wollen, in dem Wert zwischen verschiedenen Akteuren ausgetauscht wird – das Toolkit gibt eine Sprache für Rollen und Transaktionen.","Design-Sprint für eine neue Initiative oder Plattform: das Entity Portrait erzwingt, jeden Akteurstyp aus dessen eigenem Interesse her zu denken, nicht aus dem eigenen.","Strategieklausur mit dem Ziel, das Geschäftsmodell eines Netzwerks zu überdenken – wer produziert Wert, wer konsumiert, wer orchestriert?"],"wann_nicht":["Ohne Einführung in die Terminologie – das Toolkit hat ein eigenes Vokabular (Ecosystem Canvas, Entity Portrait, Enabling Service), das vorab erklärt werden muss.","Als Werkzeug für einfache bilaterale Kooperationen ohne Plattform-Logik."],"fokusfragen":["„Wer produziert Wert in unserem Ökosystem – und wer konsumiert? Wo orchestriert jemand diesen Austausch?\" (Einstiegsfrage)","„Welche Transaktion ist der Kern unserer Plattform – was genau wird zwischen wem ausgetauscht?\""],"mini_form":"Ökosystem-Skizze in 20 Minuten: Drei Post-it-Farben: Produzenten (gelb), Konsumenten (blau), Orchestrator (grün). Auf eine Fläche legen, Pfeile zeichnen. Einstiegsfrage: Was fließt wo hin?","anlass_typen":["strategie","kickoff"],"typ":"methode","gruppen_sweetspot":"3–10, mit Facilitator der das Toolkit kennt","stimmung_geeignet":["frisch","neugierig"]},{"id":"strategic-doing","name":"Strategic Doing","feld":"A","kurz":"Lose Netzwerke ohne formale Autorität über kleine Commitments und 30/30-Rhythmus ins gemeinsame Handeln bringen.","schritte":["Rahmende Frage stellen („Was wäre, wenn …?\") und Gespräch in Regeln fassen: gleichberechtigt, zeitboxed.","Assets aller Beteiligten sichtbar machen: Was könnten wir beitragen?","Chancen verknüpfen: Wo ergeben kombinierte Assets neue Möglichkeiten?","„Big Easy\" wählen: wirkungsvollste, machbarste Chance.","Pathfinder-Projekt mit kleinen Commitments definieren: Wer tut was bis wann?","30/30-Rhythmus vereinbaren: in 30 Tagen wieder treffen, lernen, nachjustieren."],"zweck":"Lose Netzwerke ohne formale Autorität in schlanken Schleifen zu gemeinsamem Handeln bringen.","hinweise":"Lebt vom Rhythmus der Folgetreffen – ohne 30/30-Disziplin verpufft der Start; Commitments klein halten („klein genug, um es nebenbei zu tun\").","phasen":["planen","entscheiden","verstetigen"],"ebenen":["netzwerk"],"modi":["klaerung","verbindung","entscheidung"],"formate":["workshop","grossgruppe","prozessbegleitung"],"dauer_min":90,"dauer_max":180,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Strategic Doing – strategicdoing.net","url":"https://strategicdoing.net/"},{"typ":"buch","titel":"Edward Morrison u. a.: Strategic Doing. Ten Skills for Agile Leadership"},{"typ":"online","titel":"Strategic Doing – SSIR Artikel","url":"https://ssir.org/articles/entry/accelerating_civic_innovation_through_strategic_doing"}],"wann_passt":["Loses Netzwerk mehrerer Organisationen ohne gemeinsame Hierarchie, das ins gemeinsame Handeln kommen will – Strategic Doing ist gemacht für offene Netzwerke ohne formalen Entscheidungsrahmen.","Kick-off einer multi-organisationalen Kooperation: die 'Big Easy'-Logik (wirkungsvoll + machbar) verhindert, dass ambitionierte Ziele in lähmender Komplexität steckenbleiben.","Wenn eine Gruppe wiederholt gute Strategiegespräche führt, aber nichts passiert – das 30/30-Rhythmus-Prinzip erzwingt kleine, konkrete Commitments mit Folgetermin."],"wann_nicht":["Für etablierte Teams mit klarer Hierarchie und vorhandenen Entscheidungsstrukturen – die dezentrale Logik erzeugt dort Reibung.","Wenn die Gruppe keine Bereitschaft hat, tatsächlich kleine Commitments einzuhalten – ohne Follow-through ist der Einstiegsworkshop eine nette Übung ohne Wirkung.","Als Ersatz für Strategie-Entwicklung – Strategic Doing setzt Richtung als gegeben voraus und operationalisiert dann."],"fokusfragen":["„Was wäre, wenn …?\" (Rahmende Frage für den Strategic Doing-Einstieg)","„Was ist die machbarste und wirkungsvollste Sache, die wir gemeinsam tun könnten – mit dem, was wir heute schon haben?\""],"mini_form":"Asset-Runde + Big Easy in 30 Minuten: Jede:r nennt 2 Ressourcen/Fähigkeiten, die sie einbringen könnten. Dann Frage: „Was wäre die eine Sache, die wir mit diesen Assets gemeinsam tun könnten?\" Kleinste mögliche Version definieren, konkrete nächste Schritte benennen.","anlass_typen":["netzwerktreffen","kickoff","strategie"],"typ":"methode","gruppen_sweetspot":"6–20, lose Netzwerk-Konstellation","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"emergent-strategy","name":"Emergent Strategy (a.m. brown)","feld":"A","kurz":"Strategie als anpassungsfähige, beziehungsbasierte Praxis: fraktale Experimente verstärken, was schon entsteht.","schritte":["Prinzipien einführen, z. B. „small is all\", „move at the speed of trust\", „critical connections over critical mass\".","Gegenwart lesen: Welche kleinen Muster zeigen sich schon, die wir verstärken wollen?","Beziehungen statt Pläne priorisieren: Wo sind unsere kritischen Verbindungen?","Kleine, fraktale Experimente verabreden, die das Große im Kleinen abbilden.","Regelmäßig ernten: Was lernen wir, was passt sich an? („never a failure, always a lesson\")"],"zweck":"Strategie als anpassungsfähige, beziehungsbasierte Praxis gestalten statt als fixen Plan.","hinweise":"Eher Haltung und Prinzipienrahmen als Schritt-für-Schritt-Methode – funktioniert gut als Reflexionsfolie über bestehende Vorhaben; für planungsgewohnte Gruppen ungewohnt, braucht Übersetzung.","phasen":["planen","verstetigen","reflektieren"],"ebenen":["netzwerk","feld"],"modi":["reflexion","verbindung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Emergent Strategy – adrienne maree brown","url":"https://adriennemareebrown.net/book/emergent-strategy/"},{"typ":"buch","titel":"adrienne maree brown: Emergent Strategy. Shaping Change, Changing Worlds"},{"typ":"online","titel":"Emergent Strategy – Commons Library","url":"https://commonslibrary.org/emergent-strategy/"}],"wann_passt":["Soziale Bewegungen oder Netzwerke, die in komplexen, nicht-linearen Kontexten handeln und feststellen, dass klassische Strategiepläne in 6 Monaten veraltet sind – Emergent Strategy als Reflexionsfolie, um das Entstehende zu lesen und zu verstärken.","Retreat oder Klausur einer aktivistischen oder bürgergesellschaftlichen Organisation, die ihre Praxis reflektieren will: die Prinzipien (small is all, move at the speed of trust) als Bewertungsrahmen für bestehende Arbeit.","Strategieentwicklung mit Gruppen, die planungsgewohnte Frameworks als fremd oder entfremdend erleben – Emergent Strategy gibt eine alternative Sprache für Adaptivität."],"wann_nicht":["Als Schritt-für-Schritt-Methode mit klarem Output – Emergent Strategy liefert keine Pläne, sondern Prinzipien. Wer einen Strategieplan braucht, braucht ein anderes Werkzeug.","In planungsgewohnten, fördergebundenen Organisationen, die am Ende einer Session ein Resultat vorweisen müssen – das Format löst diesen Druck nicht.","Als einmalige Workshop-Erfahrung ohne Vertiefung – die Prinzipien sind einfach zu formulieren und schwer zu leben; ein Workshop schafft Interesse, keine Praxis."],"fokusfragen":["„Welche kleinen Muster zeigen sich in unserer Arbeit gerade, die wir verstärken wollen?\" (Muster lesen)","„Was würde 'move at the speed of trust' konkret bedeuten – in unserem nächsten Schritt?\""],"mini_form":"Prinzipien-Check in 20 Minuten: Drei Prinzipien von a.m. brown auf Karten. Kleingruppen: Welches trifft unsere Arbeit gerade am meisten – und was würden wir ändern, wenn wir ernst damit wären?","anlass_typen":["strategie","retro","dialograum"],"typ":"rahmenmodell","gruppen_sweetspot":"6–20 für Reflexionsformat, größere Gruppen möglich in Breakouts","stimmung_geeignet":["neugierig","belastet","skeptisch"]},{"id":"backcasting","name":"Backcasting","feld":"A","kurz":"Vom konkret beschriebenen Zukunftsbild rückwärts zu Meilensteinen und ersten Schritten planen – löst vom Status-quo-Denken.","schritte":["Zeithorizont festlegen (z. B. 10 Jahre) und wünschenswerte Zukunft konkret beschreiben: Präsens, sinnlich, gemeinsam.","Gegenwart ehrlich erfassen: Wo stehen wir heute?","Rückwärts gehen: Was muss unmittelbar vorher passiert sein, damit diese Zukunft möglich war? Meilensteine vom Zielbild zur Gegenwart.","Pfad wählen und auf Timeline anordnen.","Erste konkrete Schritte für die nächsten 6–12 Monate ableiten."],"zweck":"Vom Zukunftsbild her rückwärts planen, um sich vom Status-quo-Denken zu lösen.","hinweise":"Funktioniert nur, wenn das Zukunftsbild vorher reich ausgearbeitet ist (ggf. mit Visioning kombinieren); Stolperstein: Gruppe rutscht in Vorwärtsplanung zurück – konsequent rückwärts fragen.","phasen":["planen"],"ebenen":["person","team","organisation","netzwerk"],"modi":["klaerung","energie"],"formate":["workshop","klausur","grossgruppe"],"dauer_min":60,"dauer_max":180,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Backcasting – SessionLab","url":"https://www.sessionlab.com/methods/backcasting"},{"typ":"online","titel":"Backcasting from principles vs. Scenario planning – OERu","url":"https://course.oeru.org/csf103/learning-pathways/backcasting-from-sustainability-principles/backcasting-from-principles-vs-scenario-planning/"}],"wann_passt":["Strategieklausur, in der Status-quo-Denken die Planung blockiert – das Zukunftsbild im Präsens erlaubt es, von einem Wunschziel aus zu denken, ohne sofort mit 'das geht doch nicht' zu antworten.","Visionsentwicklung mit einer Gruppe, die kurzfristig orientiert ist und Schwierigkeiten hat, über 2 Jahre hinaus zu denken – Backcasting mit 10-Jahres-Zeithorizont dehnt den Horizont und erzeugt Handlungslogik.","Unterschied zu Szenario-Planung: Backcasting beginnt mit einem gewünschten Zukunftsbild und fragt rückwärts nach dem Pfad; Szenario-Planung entwickelt mehrere mögliche (auch unerwünschte) Zukünfte. Backcasting passt für Motivierung, Szenario-Planung für Risikorobustheit."],"wann_nicht":["Wenn das Zukunftsbild nicht ausreichend entwickelt ist – Backcasting ist nur so stark wie die Qualität der Vorstellungskraft der Gruppe. Oberflächliche Visionen erzeugen oberflächliche Pfade.","Bei sehr kurzem Zeithorizont (unter 2 Jahren) – dann ist normales Vorwärtsplanen effizienter.","Wenn die Gruppe in der Rückwärtsplanung immer wieder in Vorwärtsdenken rutscht – konsequente Moderation nötig, sonst wird es normales Planen mit umgekehrter Reihenfolge."],"fokusfragen":["„Wir schreiben das Jahr 2035 – beschreibe deinen Alltag in dieser Organisation/diesem Netzwerk so, als wärst du dabei.\" (Zukunftsbild-Einstieg)","„Was muss im Jahr 2033 bereits passiert sein, damit 2035 möglich ist? Und was davor?\" (Rückwärts-Schritt)","„Was ist der erste konkrete Schritt in den nächsten 6 Monaten, der auf diesem Pfad liegt?\""],"mini_form":"3-Horizonte-Skizze in 20 Minuten: Zeithorizont wählen (z.B. 5 Jahre). Gruppe beschreibt in 5 Min das gewünschte Bild. Dann: Was muss in 2,5 Jahren passiert sein? Was bis nächstes Jahr? Stickies auf Timeline. Kein vollständiges Backcasting, aber Richtungsgefühl.","anlass_typen":["strategie","kickoff"],"typ":"methode","gruppen_sweetspot":"6–25, mit Whiteboard oder Timeline auf dem Boden","stimmung_geeignet":["frisch","neugierig"]},{"id":"szenario-planung","name":"Szenario-Planung","feld":"A","kurz":"Mehrere plausible Zukünfte entlang zweier kritischer Unsicherheiten durchspielen, um Strategien robust gegen Ungewissheit zu machen.","schritte":["Schlüsselfrage und Zeithorizont klären.","Treibende Kräfte brainstormen: sozial, technologisch, ökonomisch, ökologisch, politisch.","Zwei kritische Unsicherheiten wählen (hohe Wirkung, hohe Ungewissheit) und als Achsen kreuzen.","Vier Szenarien ausarbeiten: in Kleingruppen als lebendige Zukunftserzählungen im Präsens.","Implikationen prüfen: Was bedeutet jedes Szenario für uns?","Robuste Strategien identifizieren, die in mehreren Szenarien tragen."],"zweck":"Mehrere plausible Zukünfte durchspielen, um Strategien gegen Ungewissheit robust zu machen.","hinweise":"Szenarien sind keine Prognosen – diese Erwartung früh ausräumen; Qualität hängt an der Wahl der zwei Unsicherheiten, dafür ausreichend Zeit nehmen.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","klausur","grossgruppe"],"dauer_min":120,"dauer_max":360,"gruppe_min":6,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"How to facilitate scenario planning workshops – SessionLab","url":"https://www.sessionlab.com/blog/scenario-planning/"},{"typ":"buch","titel":"Peter Schwartz: The Art of the Long View"}],"wann_passt":["Strategieprozess einer Organisation in einem hochunsicheren Umfeld: zwei kritische Unsicherheiten kreuzen und vier Szenarien durchspielen – macht die Strategie robust statt auf ein Bild zu wetten.","Wenn eine Organisation wissen will, ob ihre Strategie in unterschiedlichen Zukünften trägt oder nur bei einem bestimmten Umfeld-Verlauf funktioniert.","Unterschied zu Backcasting: Szenario-Planung entwickelt mehrere mögliche Zukünfte (inkl. unerwünschter) und leitet robuste Strategien ab; Backcasting beginnt mit einem gewünschten Bild und sucht den Pfad dorthin. Szenario-Planung passt besser für Risikobewusstsein, Backcasting für Motivation und Richtungsklarheit."],"wann_nicht":["Als Eintages-Workshop – vier ausgearbeitete Szenarien brauchen mindestens eineinhalb bis zwei Tage; sonst entstehen flache Karikaturen statt lebendiger Zukunftserzählungen.","Wenn die Gruppe die Szenarien als Prognosen versteht – Szenarien sind Denk-Werkzeuge, keine Vorhersagen. Diese Erwartung muss früh ausgeräumt werden.","Bei Gruppen mit sehr kurzem Zeithorizont (unter 3 Jahre) – dann überwiegt das Planungsdenken, und Szenarien fühlen sich konstruiert an."],"fokusfragen":["„Welche zwei Unsicherheiten haben die größte Wirkung auf uns – und sind gleichzeitig am wenigsten vorhersehbar?\" (Achsen-Auswahl)","„Stell dir vor, du lebst im Jahr 2030 im Szenario A – was macht ihr gerade, welche Nachrichten lest ihr?\" (Szenario-Ausarbeitung)","„Welche Strategie würde in mindestens 3 von 4 Szenarien funktionieren?\" (Robustheits-Test)"],"mini_form":"2-Szenario-Kurzversion in 45 Minuten: nur eine Achse (z.B. Ressourcen: viel vs. knapp) und zwei Szenarien ausarbeiten. Nicht vier Szenarien, aber schon eine andere Perspektive als Einzel-Zukunft.","anlass_typen":["strategie"],"typ":"methode","gruppen_sweetspot":"8–20, in Kleingruppen zu je einem Szenario","stimmung_geeignet":["frisch","neugierig"]},{"id":"systemische-organisationsberatung","name":"Systemische Organisationsberatung","feld":"B","kurz":"Organisationen als soziale Systeme verstehen und bei selbstgesteuerter Veränderung begleiten – über Hypothesen, Fragen und Settings.","schritte":["Kontakt und Kontrakt: Auftrag, Rollen und Erwartungen mit dem Klientensystem klären.","System beobachten: Kommunikationsmuster, Regeln, Wechselwirkungen statt Einzelpersonen in den Blick nehmen.","Hypothesen über die Funktionslogik des Systems bilden: Wozu ist das Problem gut?","Interventionen setzen, die Selbstreflexion und Musterwechsel ermöglichen: Fragen, Feedback, Settings.","Wirkung beobachten und Schleife neu durchlaufen.","Prozess gemeinsam auswerten und abschließen."],"zweck":"Organisationen als soziale Systeme verstehen und sie bei selbstgesteuerter Veränderung begleiten.","hinweise":"Beratungsansatz, kein einzelnes Tool – in einer Session arbeitet man mit seinen Elementen (Hypothesen, systemische Fragen, Schleife). Stolperstein: in Expertenberatung zurückfallen und Lösungen liefern.","phasen":["ankommen","verstehen","vertiefen"],"ebenen":["organisation"],"modi":["klaerung","reflexion"],"formate":["prozessbegleitung","coaching"],"dauer_min":60,"dauer_max":240,"gruppe_min":1,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Systemische Organisationsberatung – Wikipedia","url":"https://de.wikipedia.org/wiki/Systemische_Organisationsberatung"},{"typ":"buch","titel":"Roswita Königswieser, Martin Hillebrand: Einführung in die systemische Organisationsberatung"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["Ein Team oder eine Organisation hat ein wiederkehrendes Problem, das mit mehr Anstrengung oder neuen Techniken nicht besser wird – der systemische Rahmen lenkt den Blick weg von Einzelpersonen hin auf Muster und Wechselwirkungen.","Eine externe Begleitung wird beauftragt, die aber nicht als Expertin für Inhalte fungieren soll, sondern den Veränderungsprozess des Systems selbst gestaltet.","In einem Klausur- oder Klärungsgespräch wird als Einstieg ein Systemblick eingeführt: Wer gehört dazu, welche Muster sind erkennbar, wozu ist das Problem nützlich?"],"wann_nicht":["Wenn die Gruppe eine konkrete Expertenantwort erwartet und braucht (technisches Problem, rechtliche Frage) – hier führt Systemik zu Frustration.","In akuten Krisen mit Zeitdruck: das Modell braucht Beobachtungszeit und Reflexionsschleifen.","Wenn die Berater:in sich selbst nicht klar über die eigene Rolle ist – systemische Beratung ohne geklärten Kontrakt kippt schnell in unklare Erwartungen."],"fokusfragen":["„Wer ist alles Teil des Systems, das hier wirkt – auch die, die nicht im Raum sind??","„Wozu könnte dieses Problem für das System nützlich sein – was würde fehlen, wenn es weg wäre??","„Welche Muster sehen Sie immer wieder – unabhängig davon, wer gerade die Rollen besetzt??"],"beispiel":"In einem Begleitgespräch mit einer Führungskraft klagt sie über das mangelnde Engagement ihres Teams. Systemische Frage: ‚Was denken Sie, was Ihr Team über Ihr Engagement sagen würde?' (zirkulär – Perspektivwechsel erzwingen). Die Antwort zeigt, dass die Führungskraft selbst ambivalent wirkt. Anschlussfrage: ‚Woran merkt das Team, dass Sie hinter diesem Vorhaben stehen?' Damit wird das Muster sichtbar: Die Ambivalenz der Führung spiegelt sich im Team – das eigentliche Interventionsfeld liegt in der Führungshaltung, nicht im Team.","mini_form":"‚Wozu-ist-das-gut-Frage' in 5 Minuten: In einem laufenden Meeting eine einzige systemische Hypothesenfrage einwerfen – ‚Was wäre, wenn dieses Problem gerade eine wichtige Funktion für das System erfüllt?' – und die Reaktionen beobachten. Kein vollständiges Format, aber ein Schleifenstart.","anlass_typen":["coaching","konfliktklaerung","strategie"],"typ":"rahmenmodell","gruppen_sweetspot":"1–6 Personen ideal, bis 20 in strukturierten Workshop-Settings möglich","stimmung_geeignet":["neugierig","belastet","skeptisch"]},{"id":"prozessberatung-schein","name":"Prozessberatung (Schein)","feld":"B","kurz":"Den Arbeits- und Beziehungsprozess der Klient:innen gestalten statt Inhalt zu liefern – mit Humble Inquiry und helfender Beziehung.","schritte":["Helfende Beziehung aufbauen: Klient:in behält Eigentum an Problem und Lösung.","Aktuelle Realität gemeinsam erkunden („Never lose sight of current reality\").","Bescheiden fragen statt antworten (Humble Inquiry): Was passiert hier gerade im Prozess?","Beobachtungen zum Arbeitsprozess zurückspiegeln.","Klientensystem eigene Diagnose und nächste Schritte entwickeln lassen.","Vereinbaren, woran Fortschritt erkennbar sein wird."],"zweck":"Den Arbeits- und Beziehungsprozess der Klient:innen gestalten, sodass sie ihre Probleme selbst lösen.","hinweise":"Größte Falle: unter Druck doch Inhaltsexpertise liefern – das untergräbt die Selbstwirksamkeit des Systems; Scheins 10 Prinzipien eignen sich als Checkliste für die eigene Beratungshaltung.","phasen":["ankommen","verstehen","vertiefen"],"ebenen":["team","organisation"],"modi":["klaerung","reflexion"],"formate":["prozessbegleitung","coaching"],"dauer_min":30,"dauer_max":120,"gruppe_min":1,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Die 10 Prinzipien der Prozessberatung nach Edgar Schein – kantelbergs.de","url":"https://www.kantelbergs.de/prinzipien-prozessberatung-schein/"},{"typ":"buch","titel":"Edgar H. Schein: Prozessberatung für die Organisation der Zukunft"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["Eine Einzelperson oder ein Team will ein Problem lösen, hat aber die Antworten bereits in sich – die Beratung besteht darin, den Denkprozess zu begleiten, nicht Lösungen zu liefern.","Eine neue Beratungsbeziehung startet: Scheins ‚Humble Inquiry' gibt der ersten Sitzung eine klare Haltung – neugierig fragen, nicht beurteilen.","Der/die Berater:in gerät unter Druck, Ratschläge zu geben – dann dient die Prozessberatungshaltung als Korrektiv: aktuelle Realität beschreiben lassen statt Analyse liefern."],"wann_nicht":["Wenn echte Fachkompetenz gefragt ist (rechtlich, technisch, medizinisch) – reine Prozessberatung wäre dann Verweigerung.","In Gruppen, die Führungsimpulse und Struktur brauchen – zu viel Humble Inquiry kann als Führungsschwäche wahrgenommen werden.","Als starres Methodenkorsett: Schein beschreibt eine Haltung, die sich mit inhaltlichen Beiträgen mischen kann."],"fokusfragen":["„Was passiert gerade in diesem Prozess – nicht was Sie sich wünschen, sondern was tatsächlich passiert??","„Woran würden Sie merken, dass die Beratung erfolgreich war – konkret, beobachtbar??","„Was muss ich über Ihre Situation verstehen, das ich noch nicht gefragt habe??"],"beispiel":"Klient:in schildert einen Konflikt mit einer Kollegin. Statt Ratschläge: ‚Beschreiben Sie mir, was in einer typischen Begegnung zwischen Ihnen beiden passiert – von Anfang bis Ende.' (Humble Inquiry: Realität erkunden, nicht interpretieren). Klient:in schildert. Anschlussfrage: ‚Was machen Sie in dem Moment, in dem Sie merken, dass die Stimmung kippt?' Damit wird der eigene Anteil sichtbar – ohne dass die Beratung ihn benennt.","mini_form":"‚Beschreiben Sie mir…' als Einstiegstechnik: Statt einer Analysefrage die Klient:in die aktuelle Situation in eigenen Worten erzählen lassen (3–5 Min). Kein Kommentar, nur nachfragen: ‚Was noch?' Setzt die Prozessberatungshaltung für die restliche Sitzung.","anlass_typen":["coaching","konfliktklaerung","schwieriges_gespraech"],"typ":"haltung","gruppen_sweetspot":"1–3 Personen; in Teams bis 6 möglich bei explizit geklärter Rolle","stimmung_geeignet":["belastet","angespannt","skeptisch"]},{"id":"lewin","name":"Lewin (3 Phasen)","feld":"B","kurz":"Veränderung in drei Phasen strukturieren – Unfreeze, Change, Refreeze – mit der Kraftfeldanalyse als praktischem Baustein.","schritte":["Modell einführen: Unfreeze – Change – Refreeze.","Standort bestimmen: In welcher Phase steckt unser Veränderungsvorhaben?","Unfreeze bearbeiten: Kraftfeldanalyse – welche Kräfte treiben, welche bremsen die Veränderung?","Change planen: Welche neuen Verhaltensweisen/Prozesse werden erprobt, wer braucht welche Unterstützung?","Refreeze sichern: Wie verankern wir das Neue (Routinen, Strukturen, Anerkennung)?","Maßnahmen je Phase festhalten."],"zweck":"Veränderungsprozesse in drei Phasen strukturieren und passende Interventionen je Phase wählen.","hinweise":"„Refreeze\" wird in dynamischen Umfeldern oft als zu statisch kritisiert – eher als „stabilisieren\" rahmen; die Kraftfeldanalyse ist der praktischste Session-Baustein des Modells.","phasen":["verstehen","planen"],"ebenen":["organisation"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung","fortbildung"],"dauer_min":45,"dauer_max":120,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Das 3-Phasen-Modell nach Lewin – projekte-leicht-gemacht.de","url":"https://projekte-leicht-gemacht.de/blog/business-wissen/das-3-phasen-modell-lewin/"}],"wann_passt":["Eine Organisation startet ein Veränderungsprojekt und das Führungsteam ist sich nicht einig, warum bisherige Versuche gescheitert sind – Lewins Kraftfeldanalyse macht treibende und bremsende Kräfte sichtbar und schafft einen gemeinsamen Diagnoserahmen.","In einer Klausur soll ein Change-Vorhaben strukturiert werden: die drei Phasen dienen als Planungsraster (Was braucht Unfreeze? Was ist Change? Was verankert Refreeze?).","Ein Fortbildungsblock zu Veränderungsmanagement: das Modell ist eingängig, hat einen klaren Ablauf und liefert sofort anwendbare Werkzeuge."],"wann_nicht":["In sehr agilen, iterativen Umgebungen: das Refreeze-Konzept wirkt statisch und erzeugt Widerstand bei Menschen, die Veränderung als Dauerzustand leben.","Wenn das Veränderungsvorhaben bereits beschlossen und kommuniziert ist – dann hilft Unfreeze-Diagnose nicht mehr, es geht um Umsetzungsplanung.","Als Vollmodell bei kurzen Meetings – hier nur die Kraftfeldanalyse als Baustein nutzen."],"fokusfragen":["„In welcher der drei Phasen stecken wir gerade – und woran erkennen wir das konkret??","„Welche Kräfte treiben die Veränderung voran, welche bremsen – was ist die stärkste Bremse??","„Was müsste passieren, damit das Neue nicht in alte Muster zurückfällt (Refreeze)??"],"beispiel":"Kraftfeldanalyse in 20 Minuten: Zwei Spalten auf dem Flipchart – ‚Was treibt die Veränderung?' und ‚Was bremst sie?'. Gruppe sammelt in Stille (Post-its, 5 Min), dann clustern. Frage: ‚Welche Bremse hat das größte Gewicht?' Anschlussfrage: ‚Was bräuchte es, um genau diese Bremse um 20 % zu verringern?' – damit wird aus Diagnose ein Handlungsfeld.","mini_form":"Nur Kraftfeldanalyse als 20-Minuten-Baustein: ohne das gesamte Phasenmodell einzuführen direkt in die Analyse einsteigen – treibende und bremsende Kräfte sammeln, schwerste Bremse identifizieren, einen Maßnahmengedanken festhalten.","anlass_typen":["strategie","lernformat","retro"],"typ":"rahmenmodell","gruppen_sweetspot":"4–20 Personen; Kraftfeldanalyse auch zu zweit sinnvoll","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"glasl-org-phasen","name":"Glasl (Org-Phasen & Eskalation)","feld":"B","kurz":"Die Reifephase einer Organisation bestimmen (Pionier-, Differenzierungs-, Integrations-, Assoziationsphase) und Krisen als normale Entwicklungsschritte deuten.","schritte":["Die vier Entwicklungsphasen vorstellen: Pionier-, Differenzierungs-, Integrations-, Assoziationsphase.","Symptome sammeln: Woran erkennen wir unsere Organisation? (Führung, Strukturen, Kultur)","Gemeinsam verorten: In welcher Phase – oder Phasenkrise – stehen wir?","Typische Krisen der Phase benennen, z. B. Reife-Krise der Pionierphase, Bürokratisierung der Differenzierungsphase.","Entwicklungsrichtung ableiten: Was wäre der nächste gesunde Schritt?","Bei Konflikten ergänzend die Eskalationsstufen als Diagnosefolie nutzen."],"zweck":"Reifephase einer Organisation bestimmen, um Krisen als normale Entwicklungsschritte zu deuten.","hinweise":"Verortung löst oft Aha-Momente und Entlastung aus („unsere Krise ist typisch\") – Raum dafür lassen; Phasen nicht als Bewertung („weiter = besser\") kommunizieren.","phasen":["verstehen"],"ebenen":["organisation"],"modi":["klaerung","reflexion"],"formate":["workshop","klausur","prozessbegleitung","fortbildung"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Entwicklungsphasen einer Organisation nach Friedrich Glasl – fritz.tips","url":"https://www.fritz.tips/entwicklungsphasen-einer-organisation-nach-friedrich-glasl"},{"typ":"buch","titel":"Friedrich Glasl, Bernard Lievegoed: Dynamische Unternehmensentwicklung"}],"wann_passt":["Ein Leitungsteam merkt, dass die Organisation in Stress ist, aber nicht benennen kann warum – Glasls Phasenmodell liefert Entlastung durch Einordnung: ‚Unsere Pionierphase-Krise ist normal.'","Eine Organisation hat gerade eine größere Veränderung hinter sich (Fusionen, Wachstum, Führungswechsel) und fragt sich, wo sie steht – die Phasenverortung gibt Orientierung und Entwicklungsrichtung.","In einem Fortbildungsblock zu Organisationsentwicklung: das Modell macht OE-Prozesse greifbar, ohne zu abstrakt zu sein."],"wann_nicht":["Wenn die Gruppe die Phasen als Bewertungsleiter missversteht (‚weiter = besser') – dann lieber anderes OE-Modell oder Framing anpassen.","In einer akuten Krisensitzung: das Modell braucht Reflexionszeit, es ist kein Kriseninterventionswerkzeug.","Bei sehr kleinen Teams (unter 5): die Phasen sind auf Organisationsebene konzipiert, auf Teamebene greifen sie oft nicht."],"fokusfragen":["„Welche Symptome erkennen wir – was aus der Pionierphase ist noch lebendig, was hat sich differenziert??","„Was würde es für unsere Führungsstruktur bedeuten, wenn wir wirklich in Phase X sind??","„Was wäre der nächste gesunde Entwicklungsschritt – nicht der schnellste, sondern der stimmige??"],"beispiel":"In einer Klausur: Phasenmodell als Folie (4 Phasen + typische Krisen kurz vorstellen, 10 Min). Dann Kleingruppenarbeit: ‚Welche Symptome aus welcher Phase erkennt ihr bei uns?' (15 Min). Im Plenum: ‚Wo landen die meisten von euch?' – oft entsteht ein Gespräch über unterschiedliche Wahrnehmungen, das wertvoller ist als die Phasenverortung selbst. Anschlussfrage: ‚Was genau fehlt uns, um die aktuelle Krise als normalen Entwicklungsschritt zu nutzen?'","mini_form":"Verortungsfrage in 10 Minuten: ‚Wenn ihr unsere Organisation mit einem dieser vier Bilder beschreiben würdet – was passt am besten?' (Pionierbetrieb/Familienunternehmen, wachsende Bürokratie, integrierte Netzwerkorganisation, lernende Assoziation). Dann warum – ohne das vollständige Modell einzuführen.","anlass_typen":["strategie","lernformat","retro"],"typ":"rahmenmodell","gruppen_sweetspot":"4–20 Personen; am wirkungsvollsten mit Leitungsteam","stimmung_geeignet":["neugierig","belastet","muede"]},{"id":"kotter-8-stufen","name":"Kotter (8 Stufen)","feld":"B","kurz":"Großen organisationalen Wandel entlang von acht Stufen planen – von Dringlichkeit über Führungskoalition bis Verankerung.","schritte":["Die acht Stufen vorstellen: Dringlichkeit, Führungskoalition, Vision, Kommunikation, Hindernisse beseitigen, Quick Wins, nicht nachlassen, Verankerung.","Eigenes Veränderungsvorhaben auf den Stufen verorten: Was ist erledigt, was übersprungen?","Übersprungene Stufen als Risiko diskutieren (häufig: fehlende Dringlichkeit oder Koalition).","Für die aktuelle Stufe konkrete Maßnahmen erarbeiten.","Quick Wins identifizieren, die in 90 Tagen sichtbar sind.","Verantwortlichkeiten festlegen."],"zweck":"Großen organisationalen Wandel entlang einer bewährten Stufenfolge planen und Lücken im Change-Prozess finden.","hinweise":"Modell ist top-down geprägt – in partizipativen Kontexten Stufen als Checkliste statt als Reihenfolge nutzen; Kotter selbst empfiehlt inzwischen, die Stufen parallel und kontinuierlich zu denken.","phasen":["planen"],"ebenen":["organisation"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":150,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The 8 Steps for Leading Change – Kotter Inc.","url":"https://www.kotterinc.com/methodology/8-steps/"},{"typ":"buch","titel":"John P. Kotter: Leading Change"}],"wann_passt":["Ein größeres Change-Projekt steht an und das Leitungsteam fragt sich, was es bereits getan hat und was fehlt – die 8 Stufen dienen als Checkliste zur Lückendiagnose.","In einer Klausur zu Strategie und Wandel: das Modell strukturiert die Planung und macht konkrete Reihenfolge-Logiken besprechbar.","Nach einem gescheiterten Veränderungsversuch: rückwirkende Analyse, welche Stufen übersprungen wurden (häufig: Dringlichkeit nicht hergestellt, Koalition nicht gebildet)."],"wann_nicht":["In partizipativen, agilen Organisationen: das Modell ist top-down geprägt und wirkt in selbstorganisierten Kontexten fehl am Platz.","Als starre Reihenfolge: die Stufen überlappen sich und Kotter selbst betont dies in seiner aktualisierten Version.","Für kleine Teams oder kurze Projekte: der Overhead des Modells steht nicht im Verhältnis zum Nutzen."],"fokusfragen":["„Welche der 8 Stufen haben wir übersprungen oder nur oberflächlich bearbeitet??","„Wer ist in unserer Führungskoalition – und wer fehlt, dessen Fehlen uns gefährlich wird??","„Welchen Quick Win können wir in 90 Tagen sichtbar machen – konkret, nicht vage??"],"beispiel":"Leitungsklausur: Die 8 Stufen als Checkliste (Handout). Gruppe bewertet je Stufe auf einer Skala 1–5: ‚Wie gut haben wir das getan?' (10 Min Einzel, 10 Min Austausch). Auswertung: Wo gibt es die größten Lücken? Anschlussfrage zu Stufe 1 (Dringlichkeit): ‚Was wäre ein konkreter Moment, in dem wir Dringlichkeit nicht behaupten, sondern erlebbar machen?' – damit wird aus Modellarbeit ein Planungsimpuls.","mini_form":"Stufen-Diagnose in 15 Minuten: Nur die drei häufigsten Lücken fokussieren (Dringlichkeit, Koalition, Quick Wins) – Gruppe bewertet, wo sie stehen, und benennt je eine konkrete Maßnahme.","anlass_typen":["strategie","kickoff","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"4–20 Personen; besonders wirksam mit Leitungsteam","stimmung_geeignet":["neugierig","frisch"]},{"id":"theory-u-laloux","name":"Theory U / Laloux","feld":"B","kurz":"Tiefgreifenden Wandel aus dem entstehenden Zukunftspotenzial führen (Presencing) – ergänzt um Laloux' Bilder evolutionärer, selbstorganisierter Organisationen.","schritte":["U-Bewegung einführen: Downloading unterbrechen, mit offenem Denken, Fühlen und Willen wahrnehmen.","Co-Sensing: das System aus mehreren Perspektiven erkunden – Interviews, Empathie-Walks, Stakeholder-Stimmen.","Presencing: Stille/Reflexion am „Boden des U\" – was will hier entstehen?","Crystallizing: Vision und Intention verdichten.","Prototyping: kleine Experimente bauen, die das Neue erlebbar machen.","Lernen institutionalisieren; mit Laloux-Brille fragen: Welche Praktiken von Selbstorganisation, Ganzheit, evolutionärem Purpose passen zu uns?"],"zweck":"Tiefgreifenden Wandel aus dem entstehenden Zukunftspotenzial führen statt aus Mustern der Vergangenheit.","hinweise":"Hoher Abstraktionsgrad – ohne konkrete Praktiken (Interviews, Prototypen) bleibt es Esoterik-Verdacht ausgesetzt; Laloux liefert die Organisationsbilder (teal/evolutionär), Theory U den Prozessweg – sauber trennen.","phasen":["verstehen","oeffnen","vertiefen"],"ebenen":["organisation","feld"],"modi":["selbstzugang","reflexion","verbindung"],"formate":["workshop","klausur","prozessbegleitung","grossgruppe"],"dauer_min":90,"dauer_max":360,"gruppe_min":5,"gruppe_max":40,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah","beteiligend","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Theory U – Presencing Institute","url":"https://www.presencing.org/theoryu"},{"typ":"buch","titel":"C. Otto Scharmer: Theory U. Leading from the Future as It Emerges"}],"wann_passt":["Ein Transformationsprozess soll nicht nur Strukturen ändern, sondern Denk- und Wahrnehmungsmuster – Theory U gibt dem tieferen Wandel einen Rahmen und Sprache.","Eine Klausur oder ein mehrtägiges Retreat, in dem wirklich Neues entstehen soll (nicht nur Bestehendes optimiert) – das Presencing am Boden des U braucht Zeit und Raum.","Laloux' Organisationsbilder werden genutzt, um eine gemeinsame Zielvorstellung zu entwickeln: ‚Welche Praktiken von Ganzheit und evolutionärem Purpose wollen wir ausprobieren?'"],"wann_nicht":["In ergebnisgetriebenen Settings mit engem Zeitfenster: ohne echte Presencing-Phasen bleibt das Modell ein abstraktes Versprechen.","Wenn die Gruppe starken Esoterik-Vorbehalt hat: ohne konkrete Erdung in Praktiken (Interviews, Prototypen) kippt es schnell in Ablehnung.","Als Einzel-Methode in einem Meeting: es ist ein Prozessrahmen für Entwicklungsvorhaben über Wochen oder Monate."],"fokusfragen":["„Was laden wir gerade in unsere Wahrnehmung – was übersehen wir systematisch??","„Was will hier entstehen – nicht was wir planen, sondern was sich ankündigt??","„Welche Praktiken würden es uns konkret ermöglichen, Ganzheit in unserer Arbeit zu leben??"],"beispiel":"Co-Sensing-Runde in einem mehrtägigen Prozess: Teilnehmende machen Empathie-Interviews mit Stakeholdern (2 h), kommen zurück, sitzen in Stille (5 Min), dann: ‚Was hat Sie wirklich berührt – was haben Sie wahrgenommen, das Sie vorher nicht wussten?' (Presencing-Eingang). Anschlussfrage: ‚Was würde diese Person brauchen, die wir noch nicht bieten?' – damit wird aus Wahrnehmung eine Richtung.","mini_form":"‚Downloading unterbrechen' in 10 Minuten: Vor einem strategischen Gespräch die Gruppe fragen: ‚Was bringen wir gerade an fertigen Urteilen und Mustern mit – was würden wir lieber hören?' (Still notieren 3 Min, dann offen ansprechen). Öffnet den Unterschied zwischen Downloading und echtem Wahrnehmen.","anlass_typen":["strategie","dialograum","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"8–40 Personen; als Vollprozess mehrtägig; einzelne Elemente auch in kleineren Runden","stimmung_geeignet":["neugierig","frisch"]},{"id":"auftragsklaerung-kontrakt","name":"Auftragsklärung & Kontrakt","feld":"B","kurz":"Vor der Arbeit klären, wer was von wem will – Anlass, Anliegen und Auftrag ergeben den Kontrakt. Fundament jeder Beratung und Moderation.","schritte":["Anlass klären: Was führt zu diesem Gespräch, wer hat es initiiert?","Anliegen herausarbeiten: Was soll anders sein? Woran würden Sie merken, dass es sich gelohnt hat?","Beteiligte klären: Wer will hier was von wem? Bei mehreren Auftraggeber:innen: Dreieckskontrakt.","Auftrag formulieren: Was genau ist meine Rolle, was nicht?","Rahmen vereinbaren: Umfang, Vertraulichkeit, Grenzen.","Kontrakt explizit bestätigen lassen (Merkformel: Anlass + Anliegen + Auftrag = Kontrakt)."],"zweck":"Vor der Arbeit klären, wer was von wem will – als Fundament jeder Beratung und Moderation.","hinweise":"Häufigster Fehler: mit dem mitgebrachten „Problem\" arbeiten statt mit dem Auftrag; verdeckte Aufträge Dritter aktiv erfragen. Auftragsklärung ist wiederkehrend, nicht einmalig.","phasen":["ankommen"],"ebenen":["person","team","organisation"],"modi":["klaerung"],"formate":["meeting","coaching","prozessbegleitung","teamentwicklung"],"dauer_min":20,"dauer_max":60,"gruppe_min":1,"gruppe_max":10,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"Systemischer Spickzettel – Auftragsklärung – istob-Zentrum","url":"https://istob-zentrum.de/systemischer-spickzettel-auftragsklaerung/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["Zu Beginn jeder Beratungs- oder Moderationsbeziehung: ohne geklärten Kontrakt arbeitet man am falschen Auftrag – besonders wenn mehrere Auftraggeber:innen mit unterschiedlichen Erwartungen im Spiel sind.","Wenn eine Person oder Gruppe mit einem ‚Problem' kommt, das sich nach kurzem Nachfragen als anderes Anliegen entpuppt – Auftragsklärungs-Fragen helfen, das eigentliche Thema zu finden.","Nach dem Einstieg in einen längeren Prozess: Kontrakt-Revisionen sind normal und sollten explizit erfolgen, nicht implizit."],"wann_nicht":["Als starres Ritual, das die Gruppe langweilt – die Klärung muss fließend in den ersten Gesprächsteil integriert sein.","Wenn bereits mehrfach geklärt wurde und das Setting klar ist – dann reicht ein kurzes ‚Bin ich noch richtig aufgestellt für heute?'","Ohne echte Bereitschaft, den Auftrag auch zu verweigern oder umzuformulieren – wenn die Klärung nur pro forma ist, verliert sie ihre Schutzfunktion."],"fokusfragen":["„Was hat dazu geführt, dass wir heute zusammensitzen – wer hat dieses Gespräch initiiert und warum jetzt??","„Woran würden Sie in einem halben Jahr merken, dass dieses Gespräch / dieser Prozess sich gelohnt hat??","„Was wollen Sie von mir – was soll meine Rolle sein, und was explizit nicht??"],"beispiel":"Erstkontakt mit einem Team: ‚Wer hat dieses Treffen initiiert?' (Anlass). ‚Was soll am Ende anders sein als heute?' (Anliegen). ‚Was erwarten Sie konkret von mir – Moderation, Beratung, Entscheidung?' (Auftrag). Wenn sich zeigt, dass Leitungsperson und Teammitglieder verschiedene Aufträge im Kopf haben: ‚Ich höre zwei verschiedene Erwartungen – das ist wichtig zu klären, bevor wir inhaltlich starten. Wäre es okay, wenn wir das als erstes gemeinsam anschauen?' – Dreieckskontrakt explizit machen.","mini_form":"Drei-Fragen-Klärung in 10 Minuten: Anlass / Anliegen / Auftrag je als eine direkte Frage, Antworten kurz festhalten. Reicht für einen Jour fixe oder eine 1:1-Begleitung.","anlass_typen":["coaching","kickoff","schwieriges_gespraech"],"typ":"werkzeug","gruppen_sweetspot":"1–8 Personen ideal; bei größeren Gruppen Kontrakt mit Leitungsebene vorab klären","stimmung_geeignet":["neugierig","skeptisch","angespannt"]},{"id":"kundentypen-de-shazer","name":"Kundentypen (de Shazer)","feld":"B","kurz":"Die Beziehungsform der Klient:innen erkennen – Besucher:in, Klagende:r oder Kund:in – und Interventionen passend dosieren.","schritte":["Im Erstkontakt heraushören: Sieht die Person ein Problem? Sieht sie sich selbst als Teil der Lösung?","Typ einordnen: Besucher:in (geschickt, kein eigenes Anliegen), Klagende:r (Problem ja, Veränderung sollen andere leisten), Kund:in (eigenes Anliegen + Veränderungsbereitschaft).","Passung wählen: Besucher:innen wertschätzen ohne Arbeitsauftrag; Klagenden Beobachtungsaufgaben geben; mit Kund:innen an Lösungen arbeiten.","Im Prozess beobachten, wie sich der Typ verändert, und Arbeitsweise anpassen."],"zweck":"Die Beziehungsform der Klient:innen erkennen und Interventionen passend dosieren.","hinweise":"Typen sind Beziehungsmuster, keine Persönlichkeitsdiagnosen – sie können sich innerhalb einer Sitzung ändern; Falle: Klagende mit Veränderungsaufgaben überfordern und Widerstand erzeugen.","phasen":["ankommen","verstehen"],"ebenen":["person"],"modi":["klaerung"],"formate":["coaching","prozessbegleitung"],"dauer_min":10,"dauer_max":30,"gruppe_min":1,"gruppe_max":5,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Die drei Kliententypen in der Beratung nach Steve de Shazer – Consiglio","url":"https://consiglio.at/die-drei-kliententypen-in-der-beratung-nach-steve-de-shazer/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["In der Anfangsphase einer Beratung oder eines Coachings, wenn unklar ist, ob die Person wirklich etwas verändern will oder geschickt wurde – die Einordnung verhindert, dass man mit Klagenden an Lösungen arbeitet.","Wenn eine Intervention verpufft: die Frage ‚In welchem Kundentyp ist die Person gerade?' erklärt oft, warum Hausaufgaben nicht gemacht werden oder Widerstand entsteht.","In der Supervision eigener Beratungsprozesse: ‚Habe ich mit dieser Person als Kund:in oder als Klagend:em gearbeitet – und was hätte gepasst?'"],"wann_nicht":["Als Diagnose-Etikett, das man der Person zuschreibt – Typen sind Beziehungsmuster, keine Charakterzüge.","Wenn man die eigene Ungeduld mit dem Typ rationalisiert (‚Die ist halt Klagende, da kann man nichts machen') – dann ist es eine Abwehr, kein Werkzeug.","In Gruppenberatungen mit gemischten Typen ohne Differenzierung – die Interventionen müssen typ-sensibel dosiert werden."],"fokusfragen":["„Sieht die Person ein eigenes Anliegen – oder ist das Problem ausschließlich bei anderen??","„Was bräuchte ich von dieser Person, damit wir gemeinsam an einer Lösung arbeiten können??","„Wie kann ich Besucher:innen wertschätzen, ohne einen Arbeitsauftrag zu simulieren, den es nicht gibt??"],"beispiel":"Eine Führungskraft wird vom Vorstand zum Coaching geschickt. Ersten Sitzung: Sie schildert ausführlich, was die Mitarbeitenden falsch machen. Diagnose: wahrscheinlich Klagende:r. Passende Intervention statt Lösungsarbeit: ‚Was beobachten Sie bei sich selbst in diesen Situationen – was machen Sie in dem Moment?' (Beobachtungsaufgabe, kein Lösungsauftrag). Anschlussfrage beim nächsten Termin: ‚Was haben Sie beobachtet – was überrascht Sie daran?' – damit entsteht eine Öffnung hin zum Kund:innen-Modus.","mini_form":"Typ-Check in 5 Minuten (intern, für Berater:in): Vor der nächsten Sitzung drei Fragen stellen: ‚Sieht die Person ein eigenes Anliegen? Hat sie Veränderungsbereitschaft signalisiert? Wer hat den Auftrag initiiert?' Daraus ergibt sich der Typ und die passende Interventionsdosierung.","anlass_typen":["coaching","schwieriges_gespraech"],"typ":"werkzeug","gruppen_sweetspot":"1–3 Personen; primär Einzelsetting","stimmung_geeignet":["angespannt","skeptisch","belastet"]},{"id":"systemische-fragetechniken","name":"Systemische Fragetechniken","feld":"B","kurz":"Durch zirkuläre, skalierende und hypothetische Fragen neue Perspektiven, Unterschiede und Lösungsbilder im System erzeugen.","schritte":["Zielrichtung klären: Was soll die Frage öffnen – Perspektivwechsel, Unterschiede, Zukunft?","Fragetyp wählen: zirkulär, skalierend, hypothetisch, Wunderfrage, paradox.","Frage stellen und Antwort wirken lassen – nicht sofort nachschieben.","Mit Folgefragen Unterschiede vertiefen: Was wäre bei 6 anders als bei 5?","Erkenntnisse zusammenfassen lassen."],"zweck":"Durch Fragen neue Perspektiven, Unterschiede und Lösungsbilder im System erzeugen.","hinweise":"Wirkung entsteht durch Langsamkeit und echtes Interesse – Fragenfeuerwerk vermeiden; zirkuläre Fragen brauchen etwas Übung bei den Befragten, ggf. kurz erklären.","phasen":["verstehen","vertiefen"],"ebenen":["person","team"],"modi":["klaerung","reflexion"],"formate":["coaching","prozessbegleitung","workshop","teamentwicklung"],"dauer_min":10,"dauer_max":60,"gruppe_min":1,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Systemische Fragen: 8 Fragearten + 100 Beispiel-Fragen – Karrierebibel","url":"https://karrierebibel.de/systemisches-fragen/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["In einer Teamklärung, in der Rechtfertigungsschleifen dominieren – zirkuläre Fragen unterbrechen das Muster, indem sie Perspektivwechsel erzwingen, ohne zu konfrontieren.","In einer Coaching-Sitzung, in der die Person im Problemfokus feststeckt – skalierende Fragen und Wunderfragen öffnen den Lösungsraum ohne direkte Ratschläge.","In einem Workshop, wenn eine Gruppe zu schnell zu Lösungen springt – hypothetische Fragen und zirkuläre Fragen verlangsamen und vertiefen."],"wann_nicht":["Als Technik-Feuerwerk in kurzer Zeit – systemische Fragen brauchen Langsamkeit und echtes Interesse, sonst wirken sie manipulativ.","In einer Gruppe, die Fragetechniken kennt und als Technik wahrnimmt – dann transparenter Einsatz oder direktere Arbeit.","Wenn schnelle Faktenklärung gebraucht wird – dann geschlossene, direkte Fragen."],"fokusfragen":["„[Zirkulär] Wenn ich Ihre Kollegin fragen würde, was sie an dieser Situation am meisten belastet – was würde sie sagen??","„[Skalierend] Auf einer Skala von 1–10: Wie zufrieden sind Sie mit der Zusammenarbeit? Was wäre bei einer 7 anders als bei einer 5??","„[Hypothetisch] Angenommen, das Problem wäre über Nacht gelöst – was wäre am nächsten Morgen das erste Zeichen, dass etwas anders ist??"],"beispiel":"Frageklassen und ihre Unterscheidung: **Zirkulär** – erzeugt Perspektivwechsel: ‚Frau A, wenn ich Ihren Kollegen B fragen würde, was ihn an der Zusammenarbeit am meisten Kraft kostet – was würde er sagen?' Zweck: A muss Bs Perspektive konstruieren, das unterbricht Rechtfertigungsschleifen. Weiter: B antworten lassen, Differenz fruchtbar machen: ‚Was überrascht Sie an dem, was B gesagt hat?' **Skalierend** – macht Unterschiede sichtbar: ‚Auf einer Skala 1–10, wie nah war As Vermutung Ihrer Wirklichkeit?' und ‚Was müsste sich ändern, damit es von 5 auf 6 geht?' Zweck: konkrete Schritte statt vage Wünsche. **Hypothetisch/Wunderfrage** – öffnet Lösungsraum: ‚Stellen Sie sich vor, Sie wachen morgen auf und das Problem ist weg – woran merken Sie das als Erstes, und wer merkt es als Zweites?' Zweck: Zielbilder ohne Schuldzuweisung. **Ausnahmefrage** – löst Problemfixierung: ‚Gab es schon mal eine Situation, in der es besser lief – was war damals anders?' Zweck: Ressourcen aus Ausnahmen destillieren. **Paradoxe Frage** – für festgefahrene Systeme: ‚Was müssten Sie tun, damit das Problem noch schlimmer wird?' Zweck: durch Umkehr den Handlungsraum sichtbar machen. Wichtig: nach jeder Frage schweigen – die Wirkung liegt in der Pause.","mini_form":"Eine zirkuläre Frage als Perspektivöffner: In einem beliebigen Klärungsgespräch eine einzige zirkuläre Frage einwerfen – ‚Was würde X in diesem Moment sagen, wenn sie/er hier wäre?' – und 30 Sekunden warten. Kein vollständiges Fragetechnik-Repertoire nötig.","anlass_typen":["coaching","konfliktklaerung","schwieriges_gespraech","teamtag"],"typ":"werkzeug","gruppen_sweetspot":"1–8 Personen ideal; in größeren Gruppen nur einzelne Fragetechniken gezielt einsetzen","stimmung_geeignet":["angespannt","belastet","neugierig"]},{"id":"systemische-schleife","name":"Systemische Schleife","feld":"B","kurz":"Innere Navigationshilfe für Berater:innen: beobachten, Hypothesen bilden, intervenieren, neu beobachten – im Kreislauf.","schritte":["Informationen sammeln/beobachten: alle Sinne, ohne vorschnelle Deutung.","Hypothesen bilden: vorläufige Denkangebote über Muster und Funktion des Beobachteten.","Intervention planen: Welcher Impuls könnte auf Basis der Hypothesen passen?","Intervenieren: den Impuls setzen.","Neu beobachten: Wie reagiert das System? Hypothesen bestätigen, verwerfen, verfeinern – Schleife erneut durchlaufen."],"zweck":"Das eigene Berater:innen-Denken strukturieren, sodass Interventionen aus Beobachtung statt aus Reflex entstehen.","hinweise":"Eher Haltung als Schema – auch mitten in einer Moderation als innere Navigationshilfe nutzbar; Stolperstein: an der Lieblings-Hypothese festhalten, statt sie an neuen Beobachtungen zu prüfen.","phasen":["verstehen","vertiefen","reflektieren"],"ebenen":["person","organisation"],"modi":["klaerung","reflexion"],"formate":["prozessbegleitung","coaching","reflexionsrunde"],"dauer_min":15,"dauer_max":60,"gruppe_min":1,"gruppe_max":10,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Die Systemische Schleife als Navigationshilfe – Systemisches Netzwerk","url":"https://systemischesnetzwerk.de/die-systemische-schleife-als-navigationshilfe/"},{"typ":"buch","titel":"Roswita Königswieser, Alexander Exner: Systemische Intervention"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["Als innere Navigationshilfe während einer Moderation oder Beratung: Wenn man merkt, dass man aus Reflex interveniert statt aus Beobachtung – die Schleife verlangsamt das eigene Handeln.","In der Supervision eigener Beratungsprozesse: ‚Was habe ich beobachtet, welche Hypothesen hatte ich, was habe ich interveniert – und was hat das System zurückgemeldet?'","In einer Fortbildung zu Beratungskompetenz: die Schleife macht die eigene Denkbewegung explizit und lehrbar."],"wann_nicht":["Als externes Schema, das man der Gruppe zeigt – die Schleife gehört in den Berater:innen-Kopf, nicht auf das Flipchart.","In sehr schnellen Krisenmomenten, wo keine Reflexionszeit bleibt – hier regiert Erfahrung und Instinkt.","Als Ersatz für Hypothesenbildung in der Gruppe – die Schleife ist ein Selbst-Tool, kein Gruppenformat."],"fokusfragen":["„Was beobachte ich gerade – ohne Interpretation??","„Welche Hypothese erklärt am besten, was ich sehe – und welche Gegenhypothese könnte auch stimmen??","„Welcher Impuls würde jetzt passen – und was will ich als Reaktion des Systems sehen, um zu prüfen, ob die Hypothese stimmt??"],"beispiel":"Mitten in einer Teammoderation wird die Atmosphäre schwerer, ohne dass jemand etwas sagt. Schleife: Beobachtung: ‚Körpersprache geschlossener, weniger Augenkontakt.' Hypothese: ‚Das Thema berührt etwas Unausgesprochenes – vielleicht Hierarchie.' Intervention: ‚Ich bemerke, dass der Raum etwas schwerer wird – darf ich fragen, was gerade im Weg steht?' Neu beobachten: Reagiert jemand erleichtert? Wird das Unausgesprochene benannt? Gegenhypothese prüfen: ‚Vielleicht ist es auch einfach Erschöpfung – dann wäre eine Pause die richtige Intervention.'","mini_form":"Interne Stopp-Frage in 1 Minute: Bevor eine Intervention gesetzt wird, einmal innerlich durchlaufen: ‚Was beobachte ich? Was ist meine Hypothese? Passt mein geplanter Schritt dazu?' – diese drei Sekunden verändern die Qualität der Intervention.","anlass_typen":["coaching","konfliktklaerung","lernformat"],"typ":"haltung","gruppen_sweetspot":"Kein Gruppenformat – inneres Werkzeug der begleitenden Person","stimmung_geeignet":["angespannt","belastet","neugierig"]},{"id":"hypothesenbildung","name":"Hypothesenbildung (Mailänder Schule)","feld":"B","kurz":"Vorläufige zirkuläre Erklärungsangebote über die Funktion von Verhalten entwickeln – Nützlichkeit zählt, nicht Wahrheit.","schritte":["Informationen über das Klientensystem sammeln: Genogramm, Anliegen, Interaktionen.","Im Team oder allein zirkuläre Hypothesen bilden: Welche Funktion könnte das Verhalten für das System haben? Wer profitiert wie vom Status quo?","Hypothesen als vorläufig markieren – Nützlichkeit zählt, nicht Wahrheit.","Hypothesengeleitet zirkulär fragen und Reaktionen beobachten.","Hypothesen revidieren oder verwerfen; Neutralität/Allparteilichkeit wahren."],"zweck":"Vorläufige Erklärungsangebote über die Funktion von Verhalten entwickeln, die Neugier und Neutralität sichern.","hinweise":"Hypothesen gehören in den Werkzeugkoffer, nicht ungefiltert ins Klientensystem; Gefahr der „Verliebtheit\" in die eigene Hypothese – bewusst Gegenhypothesen bilden.","phasen":["verstehen"],"ebenen":["person","organisation"],"modi":["klaerung","reflexion"],"formate":["prozessbegleitung","reflexionsrunde","coaching"],"dauer_min":15,"dauer_max":45,"gruppe_min":1,"gruppe_max":8,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Hypothetisieren – Lexikon des systemischen Arbeitens, Carl-Auer","url":"https://www.carl-auer.de/magazin/systemisches-lexikon/hypothetisieren"},{"typ":"buch","titel":"Mara Selvini Palazzoli u. a.: Paradoxon und Gegenparadoxon"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["Vor einer Beratungssitzung als Vorbereitung: aus den bisherigen Informationen über das System zirkuläre Hypothesen bilden, die Neugier und Neutralität sichern.","Im Team-Debrief nach einer schwierigen Intervention: ‚Was könnte die Funktion dieses Verhaltens für das System sein?' – mehrere Hypothesen verhindern Vorschnellurteile.","In einer Fortbildung zu systemischer Beratung: Hypothesenbildung als explizite Übung macht den Unterschied zwischen linearer Ursache-Wirkung und systemischer Funktionslogik erfahrbar."],"wann_nicht":["Wenn man Hypothesen ungefiltert ins Klientensystem einbringt – sie gehören in den Berater:innen-Kopf oder das Berater:innen-Team.","Wenn die Verliebtheit in eine Lieblings-Hypothese entsteht – dann aktiv Gegenhypothesen bilden.","Als Analyse-Tool, das Wahrheit sucht – Hypothesen sind Denkangebote, keine Diagnosen."],"fokusfragen":["„Wozu könnte dieses Verhalten für das System nützlich sein – was würde fehlen, wenn es wegfiele??","„Wer profitiert wie vom Status quo – wer hat ein Interesse daran, dass es so bleibt??","„Welche Hypothese ist die mutigste – was würden wir lieber nicht denken??"],"beispiel":"Berater:innen-Team vor einer Sitzung: ‚Das Team klagt über den Chef, aber der Chef beklagt das Team.' Erste Hypothese: ‚Die Führungsperson hält durch ihren Führungsstil unbewusst das Klagen aufrecht, weil es ihre zentrale Rolle sichert.' Gegenhypothese: ‚Das Team signalisiert durch Klagen, dass es mehr Eigenverantwortung übernehmen will, traut sich aber nicht.' Neutralitätsprüfung: ‚Welche Hypothese bevorzuge ich – und warum?' Dann hypothesengeleitet fragen: ‚Was passiert in Ihrem Team, wenn der Chef nicht da ist?' (zirkulär) – um zu prüfen, welche Hypothese mehr Erklärungskraft hat.","mini_form":"Drei-Hypothesen-Übung in 10 Minuten (im Berater:innen-Tandem): zu einem Klientenfall schnell drei Hypothesen bilden – erste: naheliegend, zweite: systemisch (Funktion), dritte: mutig (was wir lieber nicht denken). Dann je eine Frage dazu formulieren.","anlass_typen":["coaching","konfliktklaerung","lernformat"],"typ":"werkzeug","gruppen_sweetspot":"1–4 Personen (Berater:innen-Team); kein Gruppenformat mit Klient:innen","stimmung_geeignet":["neugierig","frisch"]},{"id":"neun-felder-puma","name":"9-Felder-Modell & PUMA","feld":"B","kurz":"Anliegen schärfen und den Standort eines Gesprächs zwischen Problem-, Ressourcen- und Lösungsraum über drei Zeitperspektiven steuern.","schritte":["Matrix aufspannen: drei Zeitperspektiven (Vergangenheit, Gegenwart, Zukunft) × drei Räume (Problem, Ressource, Lösung/Wunsch).","Mit dem Gegenwarts-Problemfeld starten: Anliegen konkret beschreiben lassen.","Felder systematisch befragen: „Wann war es schon mal besser?\" (Ressource/Vergangenheit), „Was soll stattdessen sein?\" (Lösung/Zukunft).","Standort markieren: In welchem Feld bewegt sich die Person gerade?","Bewegungsrichtung wählen: bewusst in Ressourcen- und Lösungsfelder wechseln.","Erkenntnisse und nächsten Schritt sichern."],"zweck":"Anliegen schärfen und den Standort eines Gesprächs zwischen Problem-, Ressourcen- und Lösungsraum steuern.","hinweise":"Wirkt schnell technisch, wenn man die Felder „abarbeitet\" – besser als innere Landkarte nutzen und Wechsel dosieren; gut kombinierbar mit skalierenden Fragen.","phasen":["ankommen","verstehen"],"ebenen":["person"],"modi":["klaerung"],"formate":["coaching","prozessbegleitung"],"dauer_min":30,"dauer_max":90,"gruppe_min":1,"gruppe_max":6,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Das 9-Felder-Modell nach Prof. Joseph Rieforth – mediator.sweti.de","url":"https://mediator.sweti.de/post/9-felder-modell/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"}],"wann_passt":["In einer Coaching-Sitzung, in der die Person im Problemfokus kreist – die Matrix macht sichtbar, in welchem Feld das Gespräch hängt, und ermöglicht einen bewussten Wechsel in Ressourcen- oder Lösungsfelder.","Bei Anliegen mit zeitlicher Dimension (‚Das war schon immer so') – Ressourcen aus der Vergangenheit (‚Wann lief es besser?') werden durch die Matrix direkt adressierbar.","Als Moderationskompass in einem Klärungsgespräch: die Moderation kann intern prüfen ‚In welchem Feld bewegen wir uns?' und bewusst steuern."],"wann_nicht":["Als Formular, das man sichtbar ausfüllt – das macht das Gespräch technisch und die Klient:in fühlt sich analysiert.","Bei Personen, die noch nicht genug Vertrauen haben: zu früher Wechsel in Lösungsfelder fühlt sich wie ‚Abwimmeln' an.","In Gruppenformaten ohne individuelle Begleitung – das Modell ist primär für 1:1-Klärungsgespräche."],"fokusfragen":["„[Gegenwart/Problem] Was genau ist das Problem – was passiert konkret, wenn es auftritt??","„[Vergangenheit/Ressource] Gab es schon mal eine Zeit, in der das besser war – was war damals anders??","„[Zukunft/Lösung] Was soll stattdessen sein – wie würde Ihr Alltag aussehen, wenn das Problem weg ist??"],"beispiel":"Coaching-Gespräch: Person beschreibt seit 10 Minuten das Problem (Gegenwart/Problem-Feld). Bewusster Feldwechsel: ‚Ich merke, wir sind tief im Problem. Darf ich kurz die Perspektive wechseln? – Gab es schon mal eine Phase, in der das, was Sie beschreiben, besser war?' (Vergangenheit/Ressource). Person nennt eine Ausnahme. Anschlussfrage: ‚Was haben Sie damals gemacht – was war anders an der Situation oder an Ihnen?' (Ressource aktivieren). Dann Zukunft: ‚Was würden Sie als erstes Zeichen wahrnehmen, dass es wieder in diese Richtung geht?' – skalierend kombinieren: ‚Und auf einer Skala 1–10, wo wären Sie dann?'","mini_form":"Feldwechsel-Frage in 3 Minuten: Eine einzige gezielte Frage, die aus dem Problemfeld in die Ressource oder Lösung wechselt – ohne das gesamte Modell einzuführen. Reicht in vielen Gesprächen.","anlass_typen":["coaching","schwieriges_gespraech"],"typ":"werkzeug","gruppen_sweetspot":"1–3 Personen; primär Einzelsetting","stimmung_geeignet":["belastet","angespannt","muede"]},{"id":"tuckman","name":"Tuckman (Teamphasen)","feld":"C","kurz":"Teamdynamik als normale Entwicklungsphasen deuten – Forming, Storming, Norming, Performing, Adjourning – und passende Unterstützung wählen.","schritte":["Modell vorstellen: Forming – Storming – Norming – Performing – Adjourning.","Team selbst verorten lassen, z. B. per Punktabfrage oder Aufstellung: Wo stehen wir?","Unterschiede in der Einschätzung besprechen – sie sind selbst Diagnosematerial.","Phasentypische Bedürfnisse ableiten: Forming braucht Orientierung, Storming Konfliktklärung, Norming Vereinbarungen, Performing Freiraum.","1–2 konkrete Maßnahmen für die aktuelle Phase vereinbaren."],"zweck":"Teamdynamik als normale Entwicklungsphasen deuten und passende Unterstützung je Phase wählen.","hinweise":"Phasen verlaufen real zyklisch und überlappend, nicht linear – das Modell als Landkarte, nicht als Fahrplan einführen; entlastend wirkt vor allem die Normalisierung des Stormings.","phasen":["verstehen","reflektieren"],"ebenen":["team"],"modi":["klaerung","reflexion"],"formate":["teamentwicklung","workshop","fortbildung"],"dauer_min":30,"dauer_max":90,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Teamentwicklung nach Tuckman – 5 Phasen im Überblick – mychange.solutions","url":"https://mychange.solutions/toolbox/teamwork/phasen-der-teamentwicklung"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Arbeit mit Teams und Gruppen"}],"wann_passt":["Neues Team nach 4–8 Wochen gemeinsamer Arbeit, wenn erste Reibungen entstehen und Mitglieder das als persönliches Versagen deuten – das Modell normalisiert Storming als unvermeidliche Phase.","Teamklausur nach einem Führungswechsel oder Reorg: Das Team muss sich neu verorten; Tuckman gibt Sprache für die kollektive Desorientierung (Forming-Rückfall).","Fortbildungskontext (OE, Führung, Teamcoaching), wenn Grundlagen zu Gruppenentwicklung vermittelt werden sollen – das Modell ist bekannt genug, um sofort Anschlussgespräche zu erzeugen."],"wann_nicht":["In einem akuten Konflikt als Beruhigungsmittel – 'ihr seid nur im Storming' wirkt herablassend, wenn die Gruppe gerade echten Klärungsbedarf hat.","Als alleinige Diagnose in etablierten Teams: reife Teams durchlaufen keine linearen Phasen mehr, das Modell passt dann nicht und entkräftet sich selbst.","Wenn Hierarchiegefälle im Raum eine ehrliche Selbstverortung verhindert – die Verortungs-Übung braucht psychologische Sicherheit."],"fokusfragen":["„Wenn ihr euch auf der Kurve von Forming bis Performing verortet – wo steht ihr als Team heute, und wo steht ihr als Einzelne?' (Differenz zwischen Einzel- und Gruppeneinschätzung ist oft ergiebiger als die Einschätzung selbst)","„Was braucht ihr als Team in dieser Phase von Führung, von Struktur, voneinander?' (phasenspezifisches Bedürfnis konkretisieren)","„Gab es in eurer Teamgeschichte schon einen Rückfall in eine frühere Phase – was hat ihn ausgelöst, und was hat geholfen?'"],"mini_form":"Aufstellung auf einer imaginären Forming-bis-Performing-Linie im Raum (5 Min): alle positionieren sich, 2–3 Personen sagen einen Satz dazu. Reicht als Gesprächseinstieg ohne Modell-Einführung.","anlass_typen":["teamtag","retro","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"5–15 Personen ideal; bei größeren Gruppen Selbstverortung in Kleingruppen auswerten","stimmung_geeignet":["skeptisch","muede","neugierig"]},{"id":"eisbergmodell","name":"Eisbergmodell","feld":"C","kurz":"Sichtbar machen, dass verdeckte Beziehungs- und Gefühlsdynamiken (~80 %) das sichtbare Verhalten auf der Sachebene steuern.","schritte":["Modell einführen: ~20 % sichtbare Sachebene, ~80 % verdeckte Beziehungs- und Gefühlsebene.","Aktuelle Situation/Konflikt auf der Sachebene beschreiben lassen.","Unter die Wasserlinie schauen: Welche Gefühle, Bedürfnisse, Beziehungserfahrungen wirken mit? (Einzelreflexion oder Paargespräch)","Erkenntnisse teilen, soweit die Gruppe es trägt.","Ableiten: Was braucht die Beziehungsebene, damit die Sachebene wieder arbeiten kann?"],"zweck":"Sichtbar machen, dass verdeckte Beziehungs- und Gefühlsdynamiken das sichtbare Verhalten steuern.","hinweise":"Das Modell lädt zur Selbstöffnung ein – Freiwilligkeit betonen und nicht in Tiefenpsychologie abgleiten; die 80/20-Zahlen sind Faustregel, kein Forschungsergebnis.","phasen":["verstehen","konflikt"],"ebenen":["team"],"modi":["klaerung","konflikt"],"formate":["teamentwicklung","workshop","fortbildung"],"dauer_min":30,"dauer_max":90,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Das Eisbergmodell: Beispiele für sichtbare + unsichtbare Kommunikation – projekte-leicht-gemacht.de","url":"https://projekte-leicht-gemacht.de/blog/softskills/kommunikation/das-eisbergmodell/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Arbeit mit Teams und Gruppen"}],"wann_passt":["Wenn ein Team immer wieder über dasselbe Sachproblem streitet, ohne es zu lösen – das Modell macht besprechbar, dass die Energie aus der Beziehungsebene kommt, nicht aus dem Sachinhalt.","Fortbildung zu Kommunikation oder Konflikt: Das Modell ist niedrigschwellig genug für methodenfremde Gruppen und erzeugt sofort Wiedererkennungseffekte aus dem eigenen Alltag.","Vor einem Klärungsgespräch in einer Dyade oder kleinen Gruppe: Als Rahmen eingeführt, gibt es den Beteiligten Sprache für das, was sie bisher nicht sagen konnten."],"wann_nicht":["Wenn die Gruppe noch kein Grundvertrauen aufgebaut hat – das Modell lädt zur Selbstöffnung ein, die unter Fremden oder in hierarchischer Konstellation nicht sicher ist.","Als therapeutisches Tieftauchgerät: Das Modell zeigt die Wasseroberfläche, es ist kein Auftrag, in die Psychodynamik abzugleiten.","In zeitkritischen Sitzungen mit konkretem Entscheidungsbedarf – es verlangsamt und öffnet, was manchmal kontraproduktiv ist."],"fokusfragen":["„Was sehen alle im Raum – und was vermutest du, dass unter der Oberfläche mitschwingt, ohne ausgesprochen zu werden?' (Sachebene benennen, dann Beziehungsebene öffnen)","„Wenn du das Eisbergmodell auf unsere aktuelle Situation anwendest: Was liegt unter der Wasserlinie, das die Sachebene blockiert?' (Übertragung auf den konkreten Kontext)","„Was bräuchte die Beziehungsebene, damit die Sachebene wieder fließend werden kann?'"],"mini_form":"Stille Einzelreflexion (3 Min): Jede:r notiert für eine aktuelle Spannung das Sichtbare oben und das Vermutete darunter – danach Austausch zu zweit. Kein Plenumssprechen nötig.","anlass_typen":["konfliktklaerung","teamtag","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"2–15 Personen; ab 16 nur als Lehrmodell, nicht zur Gruppendiagnose","stimmung_geeignet":["angespannt","belastet","neugierig"]},{"id":"rangdynamik-schindler","name":"Rangdynamik (Schindler)","feld":"C","kurz":"Informelle Führungs- und Widerstandsrollen in Gruppen (Alpha, Beta, Gamma, Omega) sichtbar und besprechbar machen.","schritte":["Die vier Positionen einführen: Alpha (führt), Beta (Expertise, seitlich), Gamma (trägt mit), Omega (Gegenposition, Kritik).","Betonen: Positionen sind situativ, nicht Persönlichkeit.","Gruppe reflektieren lassen: Wer nimmt in welchen Situationen welche Position ein? (Einzelreflexion, dann Austausch)","Omega würdigen: Welche wichtige Information steckt im Widerstand?","Beweglichkeit fördern: Was bräuchte es, damit Positionen wechseln können?","Vereinbarungen für den Umgang mit den Rollen treffen."],"zweck":"Informelle Führungs- und Widerstandsrollen in Gruppen sichtbar und besprechbar machen.","hinweise":"Heikel, wenn Personen öffentlich als „Omega\" etikettiert werden – mit anonymisierten oder situationsbezogenen Beispielen arbeiten; Omega-Position als Funktion für die Gruppe rahmen, nicht als Problemfall.","phasen":["verstehen"],"ebenen":["team"],"modi":["klaerung","reflexion"],"formate":["teamentwicklung","workshop","fortbildung"],"dauer_min":45,"dauer_max":90,"gruppe_min":4,"gruppe_max":16,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Rangdynamik (Schindler) – wirtrainieren.de","url":"https://wirtrainieren.de/werkzeugkoffer/rangdynamik-schindler/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Arbeit mit Teams und Gruppen"}],"wann_passt":["Teamklausur, in der immer dieselbe Person alle Entscheidungen dominiert oder ein stiller Widerstand die Arbeit lähmt – Rangdynamik gibt Sprache für diese Muster, ohne Personen zu pathologisieren.","Fortbildung für Führungskräfte oder OE-Praktiker:innen: Das Modell ist in diesen Kreisen bekannt und erzeugt sofort Transferdiskussionen zur eigenen Organisation.","Supervision einer Gruppe, die gerade eine Omega-Person erlebt hat (jemand der gegangen ist oder marginalisiert wurde) – das Modell hilft, die Funktion dieser Position zu würdigen statt sie zu verwerfen."],"wann_nicht":["In der Gruppe selbst, wenn Personen öffentlich als 'die Omega' identifiziert werden könnten – das erzeugt Stigmatisierung statt Reflexion.","Als Erklärungsmodell für persönliche Konflikte: Rangdynamik erklärt strukturelle Muster, keine individuellen Motivationen.","Vor einem Plenum ohne Vorkenntnisse in Gruppendynamik – der Begriff 'Omega' wird leicht missverstanden."],"fokusfragen":["„Welche Positionen nehmt ihr in dieser Gruppe ein – und welche würdet ihr gern einnehmen, wenn die Gruppe es zuließe?' (Selbstreflexion ohne öffentliche Etikettierung)","„Was signalisiert uns der Widerstand in unserer Gruppe – welche wichtige Information steckt im Omega?' (Umdeuten der Omega-Funktion)","„Wann haben sich eure Positionen in der Gruppe verschoben – was hat das ausgelöst?'"],"mini_form":"Einzelschreiben (5 Min): 'Welche Position nehme ich situativ ein, welche am liebsten?' Dann Austausch zu zweit – kein Plenumssprechen. Reicht für erste Bewusstheit ohne Gruppenexposition.","anlass_typen":["teamtag","lernformat","retro"],"typ":"rahmenmodell","gruppen_sweetspot":"6–14 Personen ideal; unter 4 kollabiert die Rollenvielfalt","stimmung_geeignet":["neugierig","skeptisch"]},{"id":"teamrollen-belbin","name":"Teamrollen (Belbin)","feld":"C","kurz":"Funktionale Rollenvielfalt im Team sichtbar machen – neun Rollen in den Clustern Denken, Handeln, Beziehung – und Lücken ausgleichen.","schritte":["Die neun Belbin-Rollen vorstellen (z. B. Plant, Coordinator, Shaper, Teamworker, Completer Finisher) in den Clustern Denken/Handeln/Beziehung.","Selbsteinschätzung: Welche 2–3 Rollen fülle ich bevorzugt aus? (Fragebogen oder Kartenwahl)","Fremdbild ergänzen: kurzes Feedback aus dem Team.","Teamprofil legen: Welche Rollen sind über-, welche unterbesetzt?","Konsequenzen ableiten: Aufgabenverteilung, bewusste Rollenübernahme, Toleranz für „erlaubte Schwächen\".","Vereinbarungen festhalten."],"zweck":"Funktionale Rollenvielfalt im Team sichtbar machen und Lücken oder Doppelungen ausgleichen.","hinweise":"Rollen sind Verhaltenspräferenzen, keine Typologie-Schubladen – Sprache („bevorzugt\", „situativ\") sorgfältig wählen; der offizielle Belbin-Test ist kostenpflichtig, für Workshops genügt oft die Kartenwahl-Variante.","phasen":["verstehen","verstetigen"],"ebenen":["team"],"modi":["klaerung","reflexion"],"formate":["teamentwicklung","workshop","fortbildung"],"dauer_min":60,"dauer_max":150,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The Nine Belbin Team Roles – belbin.com","url":"https://www.belbin.com/about/belbin-team-roles"},{"typ":"buch","titel":"R. Meredith Belbin: Management Teams. Why They Succeed or Fail"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Arbeit mit Teams und Gruppen"}],"wann_passt":["Neues Projektteam zu Beginn einer längeren Zusammenarbeit (Kickoff oder erster Teamtag): Rollen sichtbar machen, bevor Lücken zum Problem werden.","Team mit wiederkehrenden Reibungen über Arbeitsteilung – Belbin macht besprechbar, dass alle Rollen gebraucht werden und 'erlaubte Schwächen' dazugehören.","Führungskräfte-Fortbildung mit Bezug zu Teamzusammensetzung: Das Modell ist im deutschsprachigen Raum gut bekannt, Transfergespräche entstehen leicht."],"wann_nicht":["Als Rechtfertigung für starre Aufgabenverteilung – Rollen sind Präferenzen, keine Schubladen; das Modell wird schädlich, wenn es Flexibilität einschränkt.","Wenn kein offizieller Belbin-Test vorliegt und die Selbsteinschätzung zu Identitätsaussagen wird: 'Ich bin ein Plant' ist anders als 'ich agiere gerade wie ein Plant'.","In Teams mit starkem Leistungsdruck und wenig Zeit für Reflexion – der Prozess braucht Muße und Bereitschaft zum Selbstfeedback."],"fokusfragen":["„Welche Rollen sind in unserem Team überbesetzt – und welche fehlen oder werden von niemandem wirklich gern gefüllt?' (Teamprofil lesen)","„Wo hast du in letzter Zeit eine Rolle ausgefüllt, die nicht deiner Präferenz entspricht – was hat das gekostet, was hat es gebracht?' (erlaubte Schwächen besprechen)","„Welche Rolle würdest du gern stärker einbringen, wenn der Kontext es erlauben würde?'"],"mini_form":"Kartenwahl (10 Min): Alle wählen ohne Fragebogen ihre Top-2-Rollen aus Karten, legen sie vor sich, kurzes Partnerinterview – 'stimmt das mit dem überein, was du an mir wahrnimmst?' Schnelldiagnose ohne Test-Aufwand.","anlass_typen":["kickoff","teamtag","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"4–12 Personen; über 15 wird die Auswertung unübersichtlich","stimmung_geeignet":["neugierig","frisch"]},{"id":"prozesskurven","name":"Prozesskurven","feld":"C","kurz":"Den energetischen Verlauf eines Gruppenprozesses als Kurve sichtbar machen und Einbrüche als normale Arbeitsphasen entdramatisieren.","schritte":["Konzept einführen: Gruppen- und Seminarenergie verläuft in Kurven – Hochs, Tiefs und Einbrüche gehören dazu.","Gemeinsame Kurve zeichnen lassen: Verlauf der Energie/Stimmung über den bisherigen Prozess (Wand oder Whiteboard).","Einzelne ihre persönliche Kurve einzeichnen lassen.","Auffälligkeiten besprechen: Wo waren Einbrüche, was ging ihnen voraus?","Normalisieren: Tiefs als notwendige Arbeitsphasen deuten, nicht als Scheitern.","Ableiten, was die Gruppe für die nächste Phase braucht."],"zweck":"Den energetischen Verlauf eines Gruppenprozesses sichtbar machen und Einbrüche als normale Phase entdramatisieren.","hinweise":"Wirkt am stärksten mitten in einem Tief – genau dann einsetzen; kein kanonisches Einzelmodell, sondern Praxiswerkzeug der Gruppendynamik (verwandt: Phasenmodelle der Gruppenentwicklung).","phasen":["vertiefen","reflektieren"],"ebenen":["team"],"modi":["reflexion","energie"],"formate":["teamentwicklung","workshop","klausur","fortbildung","reflexionsrunde"],"dauer_min":20,"dauer_max":60,"gruppe_min":4,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["schriftlich","beteiligend"],"blocktyp":["reflexion","uebergang"],"quellen":[{"typ":"online","titel":"Wissensbaustein Gruppendynamik – Deutsches Institut für Erwachsenenbildung (DIE)","url":"https://www.die-bonn.de/wb/2015-gruppendynamik-01.pdf"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Arbeitsblatt Prozesskurven"}],"wann_passt":["Mitten in einem Energie-Tief eines mehrtägigen Formats oder einer Fortbildungsreihe: Das Modell normalisiert das Tief und macht es gemeinsam besprechbar, statt es zu ignorieren.","Nach einer schwierigen Sitzungsphase (intensiver Konflikt, zähe Entscheidung): Gemeinsam die Kurve zeichnen gibt der Erschöpfung einen Platz und eröffnet, was die Gruppe jetzt braucht.","Als Reflexionsinstrument in Supervisions- oder Intervisionsgruppen, die einen längeren gemeinsamen Prozess haben."],"wann_nicht":["Als Einstieg in einen neuen Prozess – die Kurve braucht gemeinsame Geschichte, sonst bleibt sie abstrakt.","Wenn die Stimmung so gut ist, dass kein Einbruch vorliegt – dann wirkt das Modell konstruiert.","Wenn die Gruppe unter starkem Zeitdruck steht und keine Reflexionszeit hat."],"fokusfragen":["„Zeichnet eure persönliche Energiekurve über den heutigen Tag – und schreibt dazu: Was war der Tiefpunkt, was hat ihn ausgelöst?' (Diagnose des Musters)","„Wenn wir die Kurven vergleichen: Wo sind sie ähnlich, wo verschieden – was sagt das über unseren gemeinsamen Prozess?' (kollektives Muster lesen)","„Was braucht ihr – als Einzelne und als Gruppe – um aus dem aktuellen Tief wieder Energie zu ziehen?'"],"mini_form":"Blitzversion (5 Min): Jede:r zeichnet nur die Kurve (ohne Beschriftung), zeigt sie kurz, sagt ein Wort dazu. Kein Plenumsgespräch – nur sichtbar machen, dass alle es kennen.","anlass_typen":["retro","teamtag","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"4–20 Personen; über 25 nur mit Kleingruppen-Auswertung","stimmung_geeignet":["muede","belastet","angespannt"]},{"id":"faktoren-teamarbeit","name":"Faktoren erfolgreicher Teamarbeit","feld":"C","kurz":"Teamqualität anhand der fünf Faktoren aus Googles Project Aristotle diagnostizieren – psychologische Sicherheit, Verlässlichkeit, Struktur & Klarheit, Sinn, Wirkung.","schritte":["Die fünf Faktoren aus Googles Project Aristotle vorstellen: psychologische Sicherheit, Verlässlichkeit, Struktur & Klarheit, Sinn, Wirkung.","Team-Selbsteinschätzung: jeden Faktor auf Skala 1–10 bewerten (anonym oder offen).","Ergebnisse visualisieren und Unterschiede besprechen.","Den schwächsten Faktor vertiefen: Woran machen wir das fest? Konkrete Situationen sammeln.","2–3 Verbesserungs-Experimente vereinbaren.","Follow-up-Termin zur Überprüfung setzen."],"zweck":"Teamqualität anhand evidenzbasierter Faktoren diagnostizieren und gezielt verbessern.","hinweise":"Psychologische Sicherheit ist laut Studie der wichtigste Faktor – die Bewertung selbst erfordert schon Sicherheit, daher ggf. anonym starten; Faktoren betreffen das „Wie\" der Zusammenarbeit, nicht die Zusammensetzung.","phasen":["verstehen","verstetigen","reflektieren"],"ebenen":["team"],"modi":["klaerung","reflexion"],"formate":["teamentwicklung","workshop","klausur"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Guide: Understand team effectiveness – Google re:Work","url":"https://rework.withgoogle.com/intl/en/guides/understand-team-effectiveness"},{"typ":"buch","titel":"Amy C. Edmondson: The Fearless Organization"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Arbeit mit Teams und Gruppen"}],"wann_passt":["Team mit unterschwelliger Unzufriedenheit, aber ohne konkreten benennbaren Konflikt: Die fünf Faktoren geben der Diagnose Struktur und machen das Diffuse messbar.","Teamtag nach einem anstrengenden Jahr – als Selbstdiagnose mit anschließenden konkreten Verabredungen; die evidenzbasierte Quelle (Google Project Aristotle) gibt der Diagnose Gewicht.","Neue Führungskraft, die das Team verstehen will: Die Faktoren-Bewertung gibt schnell ein ehrliches Bild, wenn anonym erhoben."],"wann_nicht":["Wenn das Team der Führungskraft nicht vertraut – anonyme Bewertung ist dann nötig, aber das Ergebnis wird trotzdem nicht ehrlich geteilt werden.","Als Einmalaktion ohne Follow-up: Die Wirkung liegt in den Verbesserungs-Experimenten und dem Folge-Check, nicht in der Messung selbst.","In einer Krisensituation, die sofortiges Handeln erfordert – das Modell ist Diagnose, keine Intervention."],"fokusfragen":["„Welcher der fünf Faktoren fühlt sich in eurem Team am schwächsten an – und woran macht ihr das konkret fest?' (vom Abstrakten zum Konkreten)","„Was würde sich verändern, wenn psychologische Sicherheit bei euch um einen Punkt stiege – was könntet ihr dann sagen, was ihr jetzt nicht sagt?' (Wirkung greifbar machen)","„Was ist ein kleines Experiment, das ihr in den nächsten zwei Wochen ausprobieren könntet, um den schwächsten Faktor zu stärken?'"],"mini_form":"Schnelldiagnose (10 Min): Jede:r bewertet die fünf Faktoren auf Zetteln 1–5, Zettel werden eingesammelt, Moderator:in liest Durchschnitte vor. Gemeinsam nur den schwächsten Faktor vertiefen.","anlass_typen":["teamtag","retro","kickoff"],"typ":"rahmenmodell","gruppen_sweetspot":"4–15 Personen ideal; größere Teams brauchen anonyme Erhebung","stimmung_geeignet":["skeptisch","neugierig","muede"]},{"id":"open-space","name":"Open Space","feld":"C","kurz":"Großgruppenformat, in dem die Teilnehmenden ihre Agenda selbst bestimmen – mit Marktplatz, Gesetz der zwei Füße und selbstorganisierten Sessions.","schritte":["Einladende Leitfrage formulieren und Kreis-Setting aufbauen.","Eröffnung: Prinzipien und „Gesetz der zwei Füße\" erklären; Marktplatz öffnen.","Teilnehmende geben Sessions aus: Wer ein Anliegen hat, schreibt es an und wählt Zeit/Raum.","Sessionrunden laufen selbstorganisiert; Gastgeber:innen dokumentieren Ergebnisse.","Nachrichtenwand/Harvest: Ergebnisse für alle sichtbar sammeln.","Abschlusskreis: Resonanzen und nächste Schritte."],"zweck":"Großen Gruppen ermöglichen, ihre Agenda selbst zu bestimmen und an dem zu arbeiten, was ihnen wichtig ist.","hinweise":"Steht und fällt mit einer echten, offenen Leitfrage und dem Verzicht der Leitung auf Steuerung; mindestens ein halber Tag, sonst bleibt es ein Themen-Speeddating. Online mit Breakouts machbar, Marktplatz braucht gutes Tooling.","phasen":["oeffnen","vertiefen"],"ebenen":["team","organisation","netzwerk","feld"],"modi":["klaerung","verbindung","energie"],"formate":["grossgruppe","klausur"],"dauer_min":180,"dauer_max":480,"gruppe_min":15,"gruppe_max":500,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"What is Open Space Technology? – OpenSpaceWorld","url":"https://openspaceworld.org/wp2/what-is/"},{"typ":"buch","titel":"Harrison Owen: Open Space Technology. A User's Guide"}],"wann_passt":["Organisation mit 30–200 Personen, bei der viele verschiedene Themen gleichzeitig brennen und keine Führungsebene weiß, was wirklich wichtig ist – Open Space lässt die Themen emergieren, die wirklich Energie haben.","Strategietag oder Jahreskongress, bei dem die übliche Plenumspräsentation die Energie tötet: Open Space aktiviert alle und produziert in einem halben Tag mehr echte Gespräche als drei Konferenztage mit Agendas.","Netzwerk-Treffen ohne gemeinsamen Auftrag, aber mit einem gemeinsamen Anliegen – das Gesetz der zwei Füße stellt sicher, dass nur die Gespräche geführt werden, die wirklich relevant sind."],"wann_nicht":["Wenn Führung die Themen bereits gesetzt hat und nur Zustimmung sucht – eine echte offene Leitfrage ist Grundbedingung; ohne sie wird Open Space zum Alibiprozess und erzeugt Zynismus.","Unter 15 Personen: Der Mechanismus der parallel laufenden Sessions kollabiert, direktes Gespräch ist ehrlicher.","Wenn das Ergebnis protokollierbar und verbindlich sein muss – Open Space produziert Gespräche und Impulse, aber keine verbindlichen Beschlüsse ohne explizite Harvest-Struktur.","Online als vollwertiger Ersatz: Die physische Gleichzeitigkeit und das Gesetz der zwei Füße lassen sich digital nur bedingt nachbauen; Qualität sinkt merklich."],"fokusfragen":["„Was ist das dringlichste Thema, das du einbringen willst – und das du sonst nirgendwo besprechen kannst?' (Marktplatz-Einstieg)","„Was nimmst du aus deinen Sessions mit – und was willst du als konkreten nächsten Schritt festhalten?' (Harvest nach den Sessions)"],"mini_form":"Themen-Marktplatz ohne Sessions (20 Min): Alle schreiben ihre brennenden Fragen auf Karten, clustern sie gemeinsam, stimmen per Punkte ab – ohne anschließende Sessionrunden. Zeigt, was die Gruppe bewegt, ohne den vollen Zeitaufwand.","anlass_typen":["beteiligung","strategie","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"30–150 ideal; unter 20 nicht sinnvoll, über 200 braucht sehr viel Raumlogistik","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"world-cafe","name":"World Café","feld":"C","kurz":"Perspektiven vieler Menschen in rotierenden Tischgesprächen vernetzen und kollektive Muster sichtbar machen.","schritte":["Café-Atmosphäre schaffen: Tische à 4–5 Personen, Papiertischdecken, Stifte.","Kontext und Etikette einführen: zuhören, Ideen verbinden, kritzeln erwünscht.","Runde 1: Gespräch zur ersten Frage (~20 Min).","Wechsel: Gastgeber:in bleibt, alle anderen verteilen sich neu; 2–3 weitere Runden mit aufeinander aufbauenden Fragen.","Gastgeber:innen verknüpfen die Gesprächsstränge.","Ernte im Plenum: Muster und Einsichten sammeln."],"zweck":"Perspektiven vieler Menschen in rotierenden Tischgesprächen vernetzen und kollektive Muster sichtbar machen.","hinweise":"Qualität hängt fast vollständig an der Kraft der Fragen – Zeit in „questions that matter\" investieren; Ernte einplanen, sonst verdampfen die Erkenntnisse. Online per Breakouts + geteiltem Board gut möglich.","phasen":["oeffnen"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung","verbindung"],"formate":["workshop","klausur","grossgruppe"],"dauer_min":90,"dauer_max":180,"gruppe_min":12,"gruppe_max":200,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"World Café Method – The World Café","url":"https://theworldcafe.com/key-concepts-resources/world-cafe-method/"},{"typ":"buch","titel":"Juanita Brown, David Isaacs: The World Café. Shaping Our Futures Through Conversations That Matter"}],"wann_passt":["Strategie- oder Entwicklungsprozess, bei dem 3–4 unterschiedliche Fragen gleichzeitig bearbeitet werden sollen und Querbefruchtung zwischen Perspektiven erwünscht ist – die rotierenden Tische sorgen dafür, dass Ideen über Gesprächsgruppen hinweg wachsen.","Großgruppe (20–100), bei der nicht alle gleichzeitig sprechen können, aber alle Stimmen in die Ergebnisse einfließen sollen – World Café ist das Format, wenn Fishbowl zu selektiv und Open Space zu wenig strukturiert wäre.","Netzwerk-Kick-off mit Teilnehmenden aus unterschiedlichen Organisationen, die sich kaum kennen: Die lockere Café-Atmosphäre und der erzwungene Wechsel mischen besser als jeder Icebreaker."],"wann_nicht":["Wenn eine einzige, tiefe Frage bearbeitet werden soll – World Café braucht mehrere Fragen; für eine Frage ist Fishbowl oder 1-2-4-All besser.","Unter 12 Personen: Die Rotation macht keinen Sinn, wenn nur 2–3 Tische entstehen.","Wenn keine echten 'Questions that Matter' vorhanden sind – oberflächliche Fragen produzieren oberflächliche Gespräche, die Methode macht das nicht besser.","Als reines Netzwerk-Format ohne Ernte-Schritt: Ohne strukturierten Harvest verdampfen die Erkenntnisse."],"fokusfragen":["„Was ist die eine Erkenntnis aus diesem Tischgespräch, die ihr unbedingt in den nächsten Tisch mitnehmen sollt?' (Gastgeber:in-Briefing)","„Welche Muster tauchen immer wieder auf, egal an welchem Tisch ihr wart?' (Harvest-Eröffnung im Plenum)"],"mini_form":"Eintisch-Variante mit einer Frage und zwei Runden (30 Min, ab 8 Personen): Runde 1 (12 Min) alle am Tisch, dann Hälfte wechselt zu neuem Tisch, Gastgeber:in fasst zusammen. Reicht für eine intensive Frage ohne Tisch-Infrastruktur.","anlass_typen":["beteiligung","strategie","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"16–80 ideal; unter 12 nicht sinnvoll","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"appreciative-inquiry","name":"Appreciative Inquiry","feld":"C","kurz":"Veränderung aus den Stärken und besten Erfahrungen eines Systems entwickeln – im 4-D-Zyklus Discovery, Dream, Design, Destiny.","schritte":["Affirmatives Thema wählen: das, wovon die Organisation mehr will.","Discovery: Paarinterviews zu Höhepunkt-Erfahrungen – „Erzähl von einem Moment, als es richtig gut lief.\"","Dream: aus den Stärken ein lebendiges Zukunftsbild entwickeln.","Design: Aussagen formulieren, wie die Organisation sein soll (Provocative Propositions).","Destiny: Initiativen und Selbstverpflichtungen zur Umsetzung verabreden."],"zweck":"Veränderung aus den Stärken und besten Erfahrungen eines Systems entwickeln statt aus Problemanalysen.","hinweise":"Stärkenfokus heißt Probleme würdigen und umdeuten – sonst wirkt es wie verordneter Optimismus; das Discovery-Interview ist das Herzstück und trägt auch als Einzelbaustein.","phasen":["oeffnen","vertiefen","planen"],"ebenen":["team","organisation"],"modi":["verbindung","energie","klaerung"],"formate":["workshop","klausur","grossgruppe","teamentwicklung"],"dauer_min":90,"dauer_max":480,"gruppe_min":6,"gruppe_max":300,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"4D Appreciative Inquiry Model – AI Commons","url":"https://aicommons.champlain.edu/educational-material/4d-appreciative-inquiry-model/"},{"typ":"buch","titel":"David Cooperrider, Diana Whitney: Appreciative Inquiry. A Positive Revolution in Change"}],"wann_passt":["Organisation, die nach einem schwierigen Jahr (Krise, Umstrukturierung, Verluste) einen Neustart braucht und nicht mehr Problemanalyse, sondern Energie und Richtung sucht – AI startet bei dem, was schon funktioniert.","Strategie-Workshop, bei dem die Gruppe in Defizit-Denken feststeckt und der Moderator den Fokuswechsel braucht: Das Discovery-Interview allein als Einstieg verändert den Ton des gesamten Tages.","Großgruppe (50–300) mit heterogenen Stakeholdern, die ein gemeinsames Zukunftsbild entwickeln sollen – der 4-D-Zyklus funktioniert in allen Größen und lässt sich in einem Tag oder über Wochen laufen."],"wann_nicht":["Wenn reale strukturelle Probleme (fehlende Ressourcen, Fehlverhalten in Führung, systematische Diskriminierung) durch Stärken-Fokus unsichtbar gemacht werden – AI kann als verordneter Optimismus wirken und Vertrauen zerstören.","Als Ersatz für notwendige Konfliktklärung – AI arbeitet neben Konflikten, nicht durch sie hindurch.","Wenn die Gruppe schon mehrfach mit AI-Ansätzen gearbeitet hat und die Muster kennt – dann braucht es Variation."],"fokusfragen":["„Erzähl von einem Moment, in dem unsere Zusammenarbeit oder unser Projekt wirklich gut lief – was war anders als sonst, wer war beteiligt, was hast du getan?' (Discovery-Interview-Einstieg)","„Wenn dieses Format – also das, was in eurem besten Moment da war – zur Normalität würde: Wie würde sich eure Arbeit dann anfühlen?' (Dream-Übergang)","„Was ist der kleinste erste Schritt, den ihr jetzt gehen könntet, um dieses Zukunftsbild ein Stück realer zu machen?' (Destiny-Abschluss)"],"beispiel":"Discovery-Interview in einer Teamklausur: 'Erzähl von einem Moment in unserer Zusammenarbeit, in dem du gedacht hast: Genau so sollte Teamarbeit sein. Was war passiert, wer war wie involviert, was hast du konkret getan?' – Zweck: Die Erinnerung aktiviert vorhandene Ressourcen und schafft ein Vokabular für Gelingensbedingungen. Weiter: Interviewpartner:in erinnert Geschichte in Vierergruppe nach, Gruppe notiert wiederkehrende Themen. Anschlussfrage: 'Was von dem, was ihr in den Geschichten gehört habt, wäre sofort übertragbar?'","mini_form":"Discovery-Interview zu zweit (10 Min): Eine Frage, je 5 Min pro Richtung. Allein wirkt als Energie-Booster und Vertrauensgeste – ohne Dream/Design/Destiny. Funktioniert als Einstieg in jede Sitzung.","anlass_typen":["kickoff","strategie","teamtag","beteiligung"],"typ":"methode","gruppen_sweetspot":"8–150 ideal; skalierbar über Kleingruppen","stimmung_geeignet":["muede","belastet","skeptisch"]},{"id":"future-search","name":"Future Search","feld":"C","kurz":"Alle Stakeholder eines Systems zu einem geteilten Zukunftsbild und gemeinsamem Handeln auf Common Ground bringen – Großformat über mehrere Tage.","schritte":["Das „ganze System\" einladen: Menschen mit Autorität, Ressourcen, Expertise, Information, Betroffenheit.","Past: gemeinsame Timeline der Vergangenheit erstellen und auswerten.","Present: externe Trends als Mind Map kartieren, Stolz/Bedauern reflektieren.","Future: Stakeholder-Gruppen entwerfen ideale Zukunftsszenarien.","Common Ground: gemeinsame Grundlagen identifizieren – nur, was wirklich alle tragen.","Action: Maßnahmen und Selbstverpflichtungen auf dem Common Ground planen."],"zweck":"Alle Stakeholder eines Systems zu geteiltem Zukunftsbild und gemeinsamem Handeln auf Common Ground bringen.","hinweise":"Konflikte werden als Information behandelt, nicht bearbeitet – das vorab transparent machen; Original-Format braucht ~20 Stunden über 3 Tage, gekürzte Varianten verlieren deutlich an Tiefe.","phasen":["oeffnen","planen","entscheiden"],"ebenen":["organisation","netzwerk","feld"],"modi":["verbindung","klaerung","entscheidung"],"formate":["grossgruppe","klausur"],"dauer_min":480,"dauer_max":1200,"gruppe_min":40,"gruppe_max":80,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Methodology – Future Search Network","url":"https://futuresearch.net/about/methodology/"},{"typ":"buch","titel":"Marvin Weisbord, Sandra Janoff: Future Search. An Action Guide to Finding Common Ground"}],"wann_passt":["Systemische Weichenstellung: Eine Organisation oder ein Netzwerk muss eine Grundsatzfrage klären, bei der alle relevanten Stakeholder (Betroffene, Entscheidende, Expertise, Ressourcen) an einem Tisch sein müssen – Future Search ist das einzige Format, das das ‚ganze System' wirklich einlädt.","Wenn ein Thema seit Jahren in Sackgassen diskutiert wird und neue Perspektiven eingeflossen sein müssen, bevor Entscheidungen fallen – die Timeline-Arbeit schafft gemeinsames historisches Gedächtnis als Grundlage.","Stadtentwicklung, Bildungsreform, Netzwerkstrategie: Kontexte, in denen 40–80 Menschen drei Tage investieren können und dürfen – und Führung bereit ist, Common Ground tatsächlich umzusetzen."],"wann_nicht":["Wenn die eigentliche Entscheidung bereits gefallen ist und das Format nur Legitimation liefern soll – Future Search erkennt das, und die Frustration ist massiv.","Ohne verbindliche Umsetzungs-Commitments der Führungsebene: Das Format weckt Hoffnung; wenn danach nichts passiert, ist der Vertrauensschaden größer als vorher.","Wenn weniger als 2,5 Tage zur Verfügung stehen: Die Timeline-Arbeit und die Stakeholder-Gruppen-Phase brauchen ihre Zeit, Abkürzungen untergraben die Wirkung.","Für interne Team-Themen: Der Aufwand ist unverhältnismäßig; World Café oder Open Space reichen."],"fokusfragen":["„Was sind die wichtigsten Momente in unserer gemeinsamen Geschichte – Stolz und Bedauern – die uns hierher gebracht haben?' (Timeline-Eröffnung)","„Was ist der Common Ground – das, was wirklich alle tragen können, ohne Kompromiss, der niemanden befriedigt?' (Common-Ground-Suche, unterscheidet Future Search von Konsens-Formaten)"],"mini_form":"Stakeholder-Perspektiven-Runde (20 Min): Verschiedene Stakeholder-Positionen benennen lassen, je eine Person spricht aus der Perspektive – ohne Voting und ohne Future-Search-Vollformat. Zeigt Systemkomplexität ohne 3-Tage-Aufwand.","anlass_typen":["strategie","beteiligung","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"40–80 ideal; unter 30 ist der Stakeholder-Mix nicht glaubwürdig","stimmung_geeignet":["neugierig","skeptisch"]},{"id":"liberating-structures","name":"Liberating Structures","feld":"C","kurz":"33 präzise Mikro-Strukturen (z. B. 1-2-4-All, TRIZ, Troika Consulting), die alle Stimmen einbeziehen und konventionelle Meeting-Muster ablösen.","schritte":["Ziel der Sequenz klären: Was soll die Gruppe erreichen – öffnen, analysieren, entscheiden?","Passende Mikro-Strukturen aus den 33 auswählen, z. B. 1-2-4-All, TRIZ, Troika Consulting, 25/10 Crowd Sourcing.","Struktur exakt anleiten: Einladung, Raumaufbau, Beteiligungsverteilung, Zeitboxen.","Durchführen – die Struktur trägt, die Moderation hält sich zurück.","Strukturen verketten („Strings\") für längere Sessions.","Kurz debriefen: Was haben wir gesehen?"],"zweck":"Mit präzisen Mikro-Strukturen alle Stimmen einbeziehen und konventionelle Meeting-Muster ablösen.","hinweise":"Stärke liegt in der genauen Einhaltung der Mikro-Regeln – „ungefähr so\" verwässert die Wirkung; Einstieg am leichtesten über 1-2-4-All oder Impromptu Networking.","phasen":["oeffnen","vertiefen","entscheiden"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung","verbindung","energie"],"formate":["meeting","workshop","grossgruppe","fortbildung"],"dauer_min":10,"dauer_max":60,"gruppe_min":4,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["kern","einstieg"],"quellen":[{"typ":"online","titel":"Liberating Structures – Including and Unleashing Everyone","url":"https://www.liberatingstructures.com/"},{"typ":"buch","titel":"Henri Lipmanowicz, Keith McCandless: The Surprising Power of Liberating Structures"}],"wann_passt":["Moderator:in, die repetitive Meeting-Strukturen aufbrechen will, ohne viel Erklärung – einzelne LS wie Impromptu Networking oder 1-2-4-All lassen sich in 5 Minuten anleiten und sofort einsetzen.","Fortbildungskontext (OE, Facilitation, Leadership), in dem das Repertoire an Beteiligungsformaten erweitert werden soll – LS als Sammlung mit 33 klar codierten Mikro-Strukturen ist das bekannteste open-source Methodensystem.","Längere Workshop-Sequenz, in der mehrere Phasen (öffnen, vertiefen, entscheiden) modelliert werden sollen – LS 'Strings' ermöglichen kuratierte Abfolgen statt Zufallsprogrammen."],"wann_nicht":["Wenn nur eine einzelne Struktur halbherzig eingesetzt wird – die Stärke liegt in der genauen Einhaltung der Mikro-Regeln und im Sequenzieren; 'ungefähr so wie 1-2-4-All' verwässert die Wirkung.","Bei Gruppen mit sehr hoher Methodenmüdigkeit, die 'schon wieder ein Workshop-Spiel' erwarten – dann lieber die Struktur einsetzen, ohne sie zu labeln.","Als Ersatz für inhaltliche Vorbereitung: LS strukturieren Beteiligung, lösen aber keine inhaltlichen Probleme."],"fokusfragen":["„Welche der 33 Strukturen passt für diesen Moment – öffnen, klären oder entscheiden?' (Meta-Frage für Moderator:innen-Team)","„Was ist die eine Einladungsfrage für diese Struktur – präzise genug, dass alle wissen, worüber sie reden sollen?'"],"mini_form":"Impromptu Networking als LS-Einstieg (15 Min): Drei 4-Minuten-Gespräche zu einer Doppelfrage – bringt das Netz der ganzen Gruppe in Kontakt und macht sofort spürbar, wie LS wirken. Bester Einstieg in LS überhaupt.","anlass_typen":["beteiligung","lernformat","regeltermin"],"typ":"methode","gruppen_sweetspot":"8–200; je nach gewählter Einzelstruktur sehr unterschiedlich","stimmung_geeignet":["skeptisch","neugierig","muede","frisch"]},{"id":"fishbowl","name":"Fishbowl","feld":"C","kurz":"Innen- und Außenkreis: eine fokussierte, vertiefte Diskussion in großen Gruppen, an der sich über den freien Stuhl alle beteiligen können.","schritte":["Innenkreis (4–6 Stühle) und Außenkreis aufbauen; einen Stuhl im Innenkreis frei lassen.","Thema und Regeln einführen: Nur der Innenkreis spricht, der Außenkreis hört aktiv zu.","Startbesetzung diskutiert; wer aus dem Außenkreis beitragen will, setzt sich auf den freien Stuhl.","Bei Besetzung des freien Stuhls verlässt eine Person freiwillig den Innenkreis.","Moderation achtet auf Redeanteile und Themenfokus.","Abschluss: Beobachtungen aus dem Außenkreis und Essenzen sichern."],"zweck":"In großen Gruppen eine fokussierte, vertiefte Diskussion führen, an der sich grundsätzlich alle beteiligen können.","hinweise":"Der freie Stuhl ist der Wirkmechanismus – ohne ihn wird es ein Podium; stille Gruppen brauchen ggf. eine angewärmte Startbesetzung. Online nur als nachgebaute Variante bedingt wirksam.","phasen":["oeffnen","vertiefen"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","grossgruppe","fortbildung"],"dauer_min":30,"dauer_max":90,"gruppe_min":12,"gruppe_max":100,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Fishbowl Diskussion – Methodenkartei Uni Oldenburg","url":"https://www.methodenkartei.uni-oldenburg.de/methode/fishbowl-diskussion/"}],"wann_passt":["Großgruppe (20–100), in der ein kontroverses Thema mit verschiedenen Perspektiven vertieft besprochen werden soll, ohne dass alle gleichzeitig reden – der Innenkreis fokussiert das Gespräch, der Außenkreis hört wirklich zu.","Wenn eine Gruppe aus Vielredner:innen besteht, die im Plenum Redezeiten dominieren – der freie Stuhl zwingt zur Selektion und schafft echten Zugang für zurückhaltende Stimmen.","Lernformat, in dem ein Thema aus verschiedenen Rollen beleuchtet werden soll (z.B. Leitende vs. Mitarbeitende, verschiedene Fachdisziplinen) – die Besetzung des Innenkreises macht die Perspektiven sichtbar."],"wann_nicht":["Wenn die Gruppe zu wenig Vertrauen hat, um freiwillig in den Innenkreis zu gehen – ohne ausreichend 'Freiwillige' für den freien Stuhl kippt Fishbowl in ein Podium mit unbeteiligtem Außenkreis.","Online: Die räumliche Dynamik (freier Stuhl, Sitzen im Kreis, Außenkreis-Beobachtung) lässt sich digital kaum reproduzieren; digitale Varianten verlieren den zentralen Wirkmechanismus.","Für operationale Entscheidungen – Fishbowl vertieft und klärt, trifft aber keine Entscheidungen."],"fokusfragen":["„Was ist das Wichtigste, das ihr aus dem Innenkreis-Gespräch mitnehmt – und was wollt ihr als Außenkreis noch einbringen?' (Übergang zum Abschluss)","„Welche Perspektive fehlt noch im Innenkreis?' (Freier-Stuhl-Einladung, wenn der Außenkreis zögerlich ist)"],"mini_form":"Fishbowl mit festem Innenkreis (ohne freien Stuhl, 20 Min): 4 Personen mit verschiedenen Perspektiven diskutieren, Außenkreis beobachtet mit Beobachtungsaufgabe. Einfacher zu moderieren, aber weniger partizipativ.","anlass_typen":["dialograum","beteiligung","lernformat"],"typ":"methode","gruppen_sweetspot":"12–60 ideal; unter 12 direkte Diskussion besser","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"barcamp","name":"Barcamp/Unconference","feld":"C","kurz":"Teilnehmende gestalten das Tagungsprogramm am Morgen selbst und teilen Wissen auf Augenhöhe – mit Sessionboard und Gesetz der zwei Füße.","schritte":["Rahmen und Regeln eröffnen: jede:r kann Sessions anbieten, Gesetz der zwei Füße.","Kurze Vorstellungsrunde, z. B. drei Hashtags pro Person.","Sessionplanung: Teilnehmende pitchen Themen, Interesse wird per Handzeichen geprüft, Sessionboard mit Zeiten und Räumen entsteht.","Sessionrunden à ~45 Min laufen selbstorganisiert: Vortrag, Diskussion, Workshop.","Dokumentation je Session (Pad/Etherpad/Fotos).","Abschlussrunde mit Feedback."],"zweck":"Teilnehmende gestalten das Tagungsprogramm selbst und teilen Wissen auf Augenhöhe.","hinweise":"Erstteilnehmende brauchen Ermutigung zum Session-Anbieten – „eine Frage reicht als Session\" betonen; Sessionplanung straff moderieren, sie ist der kritische Moment. Digital gut erprobt.","phasen":["oeffnen"],"ebenen":["organisation","netzwerk","feld"],"modi":["verbindung","klaerung","energie"],"formate":["grossgruppe","fortbildung"],"dauer_min":240,"dauer_max":480,"gruppe_min":20,"gruppe_max":300,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Barcamp planen und durchführen – wb-web","url":"https://wb-web.de/material/interaktion/barcamp-planen-und-durchfuehren.html"}],"wann_passt":["Fachcommunity oder Netzwerk mit geteiltem Wissenshorizont, das Wissen auf Augenhöhe teilen will – Barcamp funktioniert nur, wenn Teilnehmende tatsächlich Themen haben, die sie einbringen wollen.","Verband, NGO oder Community of Practice mit Jahrestreffen: Barcamp ist das überzeugendste Argument gegen Frontal-Konferenzen, weil die Teilnehmenden selbst wählen, worüber sie sprechen.","Fortbildungsformat mit lernenden Praktiker:innen, die eigene Erfahrungen als gleichwertig mit Expert:innenwissen betrachten – das Format macht die implizite Demokratisierung von Wissen explizit."],"wann_nicht":["Wenn Teilnehmende keine eigenen Themen haben – Barcamp mit erzwungenen Sessions ist eine schlechtere Konferenz.","Mit Gruppen, die keine Erfahrung mit Selbstorganisation haben und klare Führung erwarten – die Sessionplanung am Morgen braucht Ermutigung und ein sicheres Moderations-Setting.","Wenn verbindliche Beschlüsse gebraucht werden – Barcamp produziert Wissen und Verbindungen, aber keine Entscheidungen."],"fokusfragen":["„Was ist die Frage oder das Thema, über das du heute unbedingt sprechen willst – egal ob du Expert:in bist oder nur Fragen hast?' (Sessionplanung-Einladung)","„Was nimmst du aus dieser Session mit – und wen willst du damit noch verbinden?' (Session-Abschluss)"],"mini_form":"Mini-Barcamp (90 Min, 20–40 Personen): Nur 2 Sessionrunden mit 3–4 parallelen Räumen. Reicht für erste Barcamp-Erfahrung, wenn kein voller Tag möglich ist.","anlass_typen":["netzwerktreffen","lernformat","beteiligung"],"typ":"methode","gruppen_sweetspot":"25–150 ideal; unter 20 ist Parallelisierung kaum sinnvoll","stimmung_geeignet":["neugierig","frisch"]},{"id":"buergerrat-planungszelle","name":"Bürgerrat/Planungszelle","feld":"C","kurz":"Zufällig ausgewählte Bürger:innen beraten informiert über eine politische Frage und geben Empfehlungen als Bürgergutachten.","schritte":["Auftrag und Fragestellung mit Auftraggeber (Kommune, Land) klären, Umsetzungszusage einholen.","Teilnehmende per Zufallsauswahl (Losverfahren) gewinnen, auf Vielfalt achten.","Informationsphase: Expert:innen und Interessengruppen geben ausgewogenen Input.","Beratungsphase: moderierte Kleingruppen (à ~5 Personen) wägen Optionen ab, Plenum bündelt.","Empfehlungen formulieren und priorisieren.","Bürgergutachten übergeben; Auftraggeber gibt öffentlich Rückmeldung zur Umsetzung."],"zweck":"Zufällig ausgewählte Bürger:innen beraten informiert über eine politische Frage und geben Empfehlungen.","hinweise":"Glaubwürdigkeit hängt an Zufallsauswahl, ausgewogenem Input und verbindlicher Antwort der Politik – ohne Letzteres droht Frustration; Originalformat dauert 2–4 Tage, in einer Session nur simulierbar.","phasen":["oeffnen","entscheiden"],"ebenen":["feld"],"modi":["klaerung","entscheidung"],"formate":["grossgruppe"],"dauer_min":480,"dauer_max":2400,"gruppe_min":25,"gruppe_max":160,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Planungszelle/Bürgergutachten – Methodenbeschreibung – Wegweiser Bürgergesellschaft","url":"https://www.buergergesellschaft.de/mitentscheiden/methoden-verfahren/methoden-und-verfahren-der-buergerbeteiligung-von-a-bis-z/planungszelle-buergergutachten/methodenbeschreibung"},{"typ":"buch","titel":"Peter C. Dienel: Die Planungszelle"}],"wann_passt":["Kommunale oder regionale Entscheidungsfrage mit hohem Konfliktpotenzial zwischen organisierten Interessen – die Zufallsauswahl bricht Lobbying-Dynamiken auf und legitimiert das Ergebnis als 'was normale Bürger:innen nach guter Information wollen'.","Wenn Fachwissen und Bürgerperspektive zusammengebracht werden müssen, ohne dass Expert:innen das Ergebnis dominieren – das Format garantiert, dass Lai:innen-Urteil zählt.","Bildungsformat (Politikwissenschaft, Demokratiebildung): Simulation der Methode als Lernformat macht deliberative Demokratie erlebbar."],"wann_nicht":["Ohne echten politischen Auftrag und Umsetzungsversprechen: Ein Bürgerrat ohne Konsequenz erzeugt mehr Zynismus als kein Bürgerrat.","Wenn das Ergebnis schon feststeht – die Methode braucht echte Offenheit der Entscheidungsebene.","Als Eintagsformat: Mindestens 2 Tage braucht es für Informationsphase und Beratung; komprimierte Varianten verlieren die deliberative Qualität."],"fokusfragen":["„Welche Empfehlung würdet ihr der Stadt/dem Land/der Organisation geben – und was war das entscheidende Argument, das euch überzeugt hat?' (Abschluss-Beratungsphase)","„Welche Information hat euch am meisten überrascht – und was habt ihr vorher geglaubt, das jetzt anders erscheint?'"],"mini_form":"Deliberatives Mini-Panel (45 Min): 6–8 zufällig ausgewählte Personen hören je 2 Min Expert:innen-Input zu einer Frage, beraten 15 Min, geben Empfehlung. Keine echte Planungszelle, aber erlebbar.","anlass_typen":["beteiligung","entscheidungstreffen","lernformat"],"typ":"methode","gruppen_sweetspot":"25–100 Teilnehmende; Kerngruppe 15–30 Ratsmitglieder","stimmung_geeignet":["skeptisch","neugierig"]},{"id":"palodium","name":"Palodium (IPG)","feld":"C","kurz":"Podiumsdiskussion und Kleingruppen-Palaver („griechisches Kaffeehaus\") verschränken, damit Großgruppen aktiv statt nur zuhörend beteiligt sind.","schritte":["Kurzes Podium: 2–4 Impulsgeber:innen äußern sich knapp zur Leitfrage (kein langer Vortrag).","Wechsel ins „griechische Kaffeehaus\": Teilnehmende diskutieren die Impulse an Kleingruppentischen.","Fragen und Thesen der Tische einsammeln (Karten oder Zuruf).","Zweite Podiumsrunde: Impulsgeber:innen antworten auf die Tischfragen.","Ggf. weitere Wechsel zwischen Podium und Tischen.","Abschluss: zentrale Erkenntnisse und offene Fragen sichern."],"zweck":"Podiumsdiskussion und Kleingruppen-Palaver verschränken, damit Großgruppen aktiv statt nur zuhörend beteiligt sind.","hinweise":"Lebt vom Takt der Wechsel – Podiumsrunden kurz halten (10–15 Min); Impulsgeber:innen vorab auf Dialogformat einstimmen, sonst kippt es in klassische Podiumsmonologe.","phasen":["oeffnen","vertiefen"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung","verbindung"],"formate":["grossgruppe","fortbildung"],"dauer_min":60,"dauer_max":180,"gruppe_min":20,"gruppe_max":200,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["gespraechsnah","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Arbeitsanweisung Palodium (Handbuch-Material) – Gemeinsam Digital Berlin","url":"https://gemeinsamdigital.berlin.de/documents/48/GDB_Materialien_fur_das_Handbuch_-_Arbeitsanweisung_A3___Palodium.pdf"},{"typ":"buch","titel":"IPG Methodenbücherei: Palodium (MTB 0022)"}],"wann_passt":["Großgruppen-Tagung (40–200), bei der ein Podium unvermeidbar ist – z.B. wegen externen Expert:innen, Entscheidungsträger:innen oder Prestige-Logik – und trotzdem echte Beteiligung entstehen soll: Palodium ist die strukturierte Antwort auf das klassische Podiums-Dilemma.","Wenn ein Thema kontrovers ist und verschiedene Positionen gegenüberstehen – die Wechsel zwischen Podium und Kleingruppenpalaver verhindern, dass eine Seite das Plenum dominiert.","Netzwerk-Jahrestreffen mit Keynote-Logik: Palodium macht aus einer Keynote einen Dialog."],"wann_nicht":["Wenn Impulsgeber:innen nicht bereit sind, sich auf Dialog einzulassen – Palodium braucht Podiumsgäste, die kurze Antworten geben und echte Fragen wollen.","Online als vollwertiger Ersatz: Die Raumlogistik (Tische, Wechsel) ist digital schwer abbildbar; funktioniert nur mit sehr gutem Tooling.","Wenn das Thema keine echte Kontroverse hat – dann ist ein normales Q&A effizienter."],"fokusfragen":["„Was ist die eine Frage, die ihr dem Podium stellen wollt – schreibt sie auf, bevor wir wechseln?' (Tisch-zu-Podium-Übergang)","„Was hat euch die Antwort des Podiums gegeben – und was ist offen geblieben?' (nach Podiums-Runde 2)"],"mini_form":"Podium-Palaver-Wechsel (40 Min): Kurzer Impuls (10 Min), Tischgespräch zu einer Frage (10 Min), Fragen ans Podium (10 Min), Abschluss-Palaver (10 Min). Reicht für eine fokussierte Frage.","anlass_typen":["beteiligung","lernformat","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"25–150; unter 20 direkte Diskussion besser","stimmung_geeignet":["skeptisch","neugierig","frisch"]},{"id":"new-games","name":"New Games","feld":"C","kurz":"Bewegungsspiele ohne Gewinner:innen und Verlierer:innen – „play hard, play fair, nobody hurt\" – bauen Kontakt und Gemeinschaftsgefühl auf.","schritte":["Spielidee und Grundsatz einführen: „Play hard, play fair, nobody hurt\" – ohne Gewinner:innen und Verlierer:innen.","Mit niedrigschwelligem Bewegungsspiel starten, z. B. alle gemeinsam einen Ballon in der Luft halten.","Intensität steigern: Spiele mit mehr Kontakt oder Koordination, Freiwilligkeit wahren.","Zwischendurch Regeln gemeinsam variieren lassen.","Kurz auswerten: Wie hat sich gemeinsames statt kompetitives Spielen angefühlt?"],"zweck":"Durch Bewegungsspiele ohne Verlierer:innen Kontakt, Vertrauen und Gemeinschaftsgefühl aufbauen.","hinweise":"Körperkontakt immer optional machen und kulturelle/körperliche Grenzen respektieren; wirkt am besten dosiert als Einstieg oder Energiewechsel, nicht als Dauerprogramm.","phasen":["ankommen","vertiefen"],"ebenen":["team"],"modi":["vertrauen","verbindung","energie"],"formate":["teamentwicklung","workshop","klausur","fortbildung"],"dauer_min":10,"dauer_max":45,"gruppe_min":6,"gruppe_max":100,"online":"nein","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["koerperlich","spielerisch"],"blocktyp":["einstieg","energizer"],"quellen":[{"typ":"online","titel":"New Games – Kooperative Spiele ohne Gewinner und Verlierer – wirkstatt.com","url":"https://wirkstatt.com/newgames"},{"typ":"buch","titel":"Andrew Fluegelman (Hrsg.): The New Games Book"}],"wann_passt":["Neues Team, das sich noch nicht gut kennt, am Anfang eines Teamtages oder einer Fortbildungsreihe – New Games bauen in 15–20 Minuten mehr körperlich-emotionalen Kontakt auf als zwei Stunden Kennenlerngespräch.","Gruppe, die nach intensiver Kopfarbeit physisch aktiviert werden muss – ein einfaches Bewegungsspiel wechselt den Modus vollständig.","Kinder- und Jugendseminare oder gemischte Altersgruppen: New Games funktionieren unabhängig von Fitness-Level, weil Kooperation statt Wettkampf zählt."],"wann_nicht":["Online – New Games sind körperlich und nicht digital übertragbar.","Bei Gruppen mit körperlichen Einschränkungen oder traumasensiblem Hintergrund ohne explizite Vorbereitung – Körperkontakt ist Pflicht-Opt-out.","Als Einziges in einem langen Prozess – dosiert als Energizer stark, als Hauptformat zu wenig Reflexionstiefe."],"fokusfragen":["„Wie hat sich gemeinsames Spielen ohne Gewinner:innen angefühlt – was ist anders als im Alltag?","„Welche Momente im Spiel erinnern euch an gute Zusammenarbeit?'"],"mini_form":"Ballon in der Luft (5 Min): Ein Ballon, alle müssen ihn gemeinsam oben halten – keine Hände zweimal hintereinander. Gelingt fast immer, erzeugt Erfolgserlebnis ohne Körperkontakt-Druck.","anlass_typen":["kickoff","teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"8–30 ideal; über 40 nur in Untergruppen","stimmung_geeignet":["muede","frisch","neugierig"]},{"id":"initiativaufgaben","name":"Initiativaufgaben","feld":"C","kurz":"Aufgaben wie Spinnennetz, Säureteich oder Turmbau, die nur durch Kooperation aller lösbar sind – Teamprozesse werden erlebbar.","schritte":["Aufgabe und Regeln klar anleiten, z. B. Spinnennetz: jede Öffnung nur einmal, keine Netzberührung; Säureteich: Gegenstand bergen, ohne den Boden zu berühren.","Sicherheitsregeln explizit machen (Heben, Spotten).","Planungsphase: Gruppe entwickelt eigenständig eine Strategie – Leitung hält sich raus.","Durchführung; bei Regelverstoß definierte Konsequenz, z. B. Neustart.","Ausführliches Debriefing: Wie haben wir entschieden, wer wurde gehört, was übertragen wir in den Alltag?"],"zweck":"Eine Aufgabe stellen, die nur durch Kooperation aller lösbar ist, und daran Teamprozesse erlebbar machen.","hinweise":"Der Lerngewinn liegt im Debriefing, nicht im Lösen – mindestens ein Drittel der Zeit dafür reservieren; körperliche Voraussetzungen der Gruppe beachten und Rollen für Nicht-Kletternde anbieten.","phasen":["vertiefen","reflektieren"],"ebenen":["team"],"modi":["vertrauen","verbindung","reflexion"],"formate":["teamentwicklung","workshop","klausur","fortbildung"],"dauer_min":45,"dauer_max":120,"gruppe_min":6,"gruppe_max":16,"online":"nein","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["koerperlich","spielerisch","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Probleme lösen, Initiative ergreifen – erlebnispädagogische Übungen (PDF) – Uni Wuppertal","url":"https://itps.uni-wuppertal.de/fileadmin/itps/Wastl/EP-Aktiv-04.pdf"}],"wann_passt":["Team, das über Zusammenarbeit reden will, aber nicht will – die Aufgabe schafft eine sichere Beobachtungsebene: Man spricht über das Spinnennetz, nicht übereinander.","Fortbildung mit Teamarbeit als Lerngegenstand: Die Entscheidungsprozesse und Kommunikationsmuster werden live sichtbar und sind dann im Debriefing analysierbar.","Teamklausur mitten in einer Phase der Lähmung – die körperliche Herausforderung mit klarer Aufgabe und Ende schafft Handlungsfähigkeit als Erfahrung."],"wann_nicht":["Ohne ausreichend Zeit für das Debriefing – die Aufgabe selbst ist nichts wert; der Lerngewinn liegt vollständig im anschließenden Gespräch.","Bei körperlichen Einschränkungen ohne angepasste Varianten – Klettern und Heben müssen für alle machbar oder durch Beobachter:innen-Rollen ersetzbar sein.","Online – nicht übertragbar."],"fokusfragen":["„Wie wurde in eurer Gruppe entschieden – wer hat Ideen eingebracht, wer hat zugehört, wer hat gezweifelt?' (Debriefing-Einstieg)","„Was übertragt ihr aus diesem Prozess in eure reale Zusammenarbeit – was wollt ihr beibehalten, was verändern?'"],"mini_form":"Turm aus Papier (15 Min, indoor): Jede Gruppe baut aus 10 Blatt Papier und Klebeband den höchsten freistehenden Turm. Kein Körperkontakt, wenig Aufwand, gleiche Dynamik. Gut als Debriefing-Aufgabe ohne Sicherheitsanforderungen.","anlass_typen":["teamtag","kickoff","lernformat"],"typ":"methode","gruppen_sweetspot":"8–16 ideal; über 20 in Untergruppen mit gemeinsamer Auswertung","stimmung_geeignet":["skeptisch","muede","neugierig"]},{"id":"trust-uebungen","name":"Trust-/Vertrauensübungen","feld":"C","kurz":"Kontrolle abgeben und Vertrauen körperlich erfahrbar machen – von der Blindführung bis zum Pendel im engen Kreis.","schritte":["Freiwilligkeit und Sicherheitsregeln etablieren: Körperspannung, Spotten, Stopp-Signal.","Mit niedriger Intensität starten: paarweise Blindführung durch den Raum.","Steigern: Pendel im engen Kreis – Person lässt sich fallen, Gruppe fängt sanft auf.","Rollen tauschen, damit alle führen und sich anvertrauen.","Auswerten: Wie war es, Kontrolle abzugeben? Was hat Vertrauen ermöglicht?"],"zweck":"Kontrolle abgeben und Vertrauen körperlich erfahrbar machen.","hinweise":"Niemals früh in einem Gruppenprozess oder unter sozialem Druck einsetzen – misslungene Vertrauensübungen beschädigen mehr, als sie aufbauen; Aufsicht und Matten je nach Übung.","phasen":["vertiefen"],"ebenen":["team"],"modi":["vertrauen","verbindung","selbstzugang"],"formate":["teamentwicklung","workshop","klausur","fortbildung"],"dauer_min":15,"dauer_max":60,"gruppe_min":2,"gruppe_max":30,"online":"nein","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Vertrauensspiele – praxis-jugendarbeit.de","url":"https://www.praxis-jugendarbeit.de/spielesammlung/spiele-vertrauen.html"}],"wann_passt":["Gruppe mit gewachsenem Vertrauen nach mehreren gemeinsamen Tagen, die einen nächsten Vertiefungsschritt machen will – Trust-Übungen sind dann ein kraftvoller Ausdruck dessen, was schon da ist.","Fortbildung mit Körper/Vertrauen/Führung als Lernthema – die Auswertung nach der Übung ist dann das eigentliche Lernformat.","Erlebnispädagogisches Programm, das gezielt Vertrauen als Ziel hat – hier gehören Trust-Übungen ins Repertoire."],"wann_nicht":["Früh in einem Prozess oder bei unbekannten Gruppen – misslungene Vertrauensübungen erzeugen mehr Misstrauen als vorher da war.","Wenn Hierarchiegefälle stark ist: Führungskraft, die sich von Mitarbeitenden fangen lässt, erzeugt keine Vertrauensübung, sondern eine Machtdemonstration.","Online – nicht durchführbar.","Bei traumasensiblen Kontexten ohne explizite Clearing-Phase und therapeutisch ausgebildete Begleitung."],"fokusfragen":["„Wie war es, Kontrolle abzugeben – was hat das ermöglicht, was hat es gekostet?' (Auswertung nach Blindführung)","„Was ist zwischen euch passiert, das Vertrauen möglich oder unmöglich gemacht hat?'"],"mini_form":"Rücken-an-Rücken-Sitzen (5 Min): Zwei Personen setzen sich Rücken an Rücken, spüren den Kontakt, kommen so zur Ruhe. Kein Fallen, kein Kontrollverlust – sanfteste Form von Körperkontakt und Gegenseitigkeit.","anlass_typen":["teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"4–20; zu zweit oder in kleinen Gruppen","stimmung_geeignet":["frisch","neugierig"]},{"id":"betzavta-dilemmata","name":"Betzavta-Dilemmata","feld":"C","kurz":"Demokratische Prinzipien über erlebte Dilemmata erfahrbar machen statt über Belehrung – beide Ansprüche, meine Freiheit und die der anderen, existieren auch in mir.","schritte":["Übung mit eingebautem Dilemma anleiten (z. B. begrenzte Ressourcen, Mehrheitsentscheid mit Folgen für die Minderheit), ohne das Lernziel vorwegzunehmen.","Gruppe handeln lassen – der Konflikt entsteht aus der Aufgabe selbst.","Prozess stoppen und reflektieren: Wie wurde entschieden? Wessen Freiheit wurde eingeschränkt?","Kernfrage bearbeiten: Beide Ansprüche – meine Freiheit und die der anderen – existieren auch in mir.","Übertragung: Wo erleben wir solche Aushandlungen im Alltag/der Organisation?","Demokratische Handlungsoptionen sammeln."],"zweck":"Demokratische Prinzipien über erlebte Dilemmata erfahrbar machen statt über Belehrung.","hinweise":"Braucht ausgebildete Anleitung – die Reflexionsphase ist anspruchsvoll und kann Frustration auslösen, die ausgehalten werden muss; Übungen nie auflösen, bevor die Gruppe das Dilemma wirklich gespürt hat.","phasen":["vertiefen","konflikt","reflektieren"],"ebenen":["team","feld"],"modi":["konflikt","reflexion"],"formate":["fortbildung","workshop","klausur"],"dauer_min":60,"dauer_max":180,"gruppe_min":8,"gruppe_max":25,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["spielerisch","beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Betzavta / Mehr als eine Demokratie – Akademie Führung & Kompetenz, C·A·P München","url":"https://www.cap-lmu.de/akademie/schwerpunkte/betzavta-miteinander/"},{"typ":"buch","titel":"Uki Maroshek-Klarman: Miteinander – Erfahrungen mit Betzavta"}],"wann_passt":["Demokratiebildungs-Fortbildung, in der Prinzipien wie Mehrheitsentscheid und Minderheitenschutz nicht erklärt, sondern erlebt werden sollen – die Übungen machen die Spannung spürbar, bevor sie konzeptualisiert wird.","Gruppe, die mit Machtdynamiken und Ausgrenzungserfahrungen arbeitet (NGO, politische Bildung, Schule) – Betzavta bietet dafür eine erprobte und geschützte Form.","Ausgebildete Moderation vorausgesetzt: Als Baustein in mehrtägigen Fortbildungen, wo die anspruchsvolle Reflexionsphase in einem sicheren Gesamtrahmen sitzt."],"wann_nicht":["Ohne ausgebildete Anleitung: Die Reflexionsphase kann intensive Emotionen und Frustrationen auslösen, die gehalten werden müssen.","In Gruppen mit akuten Konflikten oder traumatischen Erfahrungen im Zusammenhang mit Ausgrenzung – das Format kann triggern.","Als Einzelübung ohne Einbettung in einen Bildungsprozess – die Übungen brauchen konzeptionelle Rahmung."],"fokusfragen":["„Was habt ihr in der Übung für euch entschieden – und was hat das für andere bedeutet?' (Ergebnissicherung nach der Handlungsphase)","„Wo erlebt ihr diese Spannung zwischen eurer Freiheit und der Freiheit anderer in eurem Alltag – und wie geht ihr damit um?'"],"mini_form":"Ressourcen-Dilemma (20 Min): Gruppe bekommt zu wenige Materialien für alle (Stühle, Karten o.ä.). Keine Lösung vorgeben – beobachten lassen, wie entschieden wird. Kurze Auswertung: 'Wie wurde entschieden, wer hat verloren?' Reicht für einen ersten Dilemma-Moment.","anlass_typen":["lernformat","dialograum","teamtag"],"typ":"methode","gruppen_sweetspot":"10–20 ideal; über 25 braucht es Kleingruppen-Struktur","stimmung_geeignet":["neugierig","frisch"]},{"id":"gefangenendilemma","name":"(Iteriertes) Gefangenendilemma","feld":"C","kurz":"Die Spannung zwischen Eigeninteresse und Kooperation spieltheoretisch erlebbar machen und Bedingungen für Vertrauen ableiten.","schritte":["Spielmatrix erklären: kooperieren oder defektieren, Auszahlung hängt von beiden Entscheidungen ab.","Paare oder Teams spielen mehrere Runden (iteriert), Entscheidungen verdeckt, Punkte notieren.","Zwischenstand zeigen und weiterspielen – Strategien dürfen sich anpassen.","Auswerten: Welche Strategien entstanden? (Tit for Tat, Vergeltung, Vergebung)","Übertragen: Wo stehen Eigeninteresse und Vertrauen in unserem Kontext in Spannung? Was begünstigt Kooperation?"],"zweck":"Die Spannung zwischen Eigeninteresse und Kooperation spieltheoretisch erlebbar machen und Bedingungen für Vertrauen ableiten.","hinweise":"Bei Team-gegen-Team-Varianten kann echte Verärgerung entstehen – Zeit zum Auflösen einplanen; der Lerneffekt steckt in der Iteration (Zukunftsschatten), Einzelrunden greifen zu kurz.","phasen":["verstehen","vertiefen"],"ebenen":["team"],"modi":["reflexion","vertrauen"],"formate":["fortbildung","workshop","teamentwicklung"],"dauer_min":30,"dauer_max":90,"gruppe_min":4,"gruppe_max":40,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["spielerisch","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Prisoner's Dilemma – Stanford Encyclopedia of Philosophy","url":"https://plato.stanford.edu/entries/prisoner-dilemma/"},{"typ":"buch","titel":"Robert Axelrod: The Evolution of Cooperation"}],"wann_passt":["Fortbildung zu Kooperation, Vertrauen oder Spieltheorie: Das iterierte Dilemma macht abstrakte Konzepte wie 'Zukunftsschatten', 'Tit for Tat' und 'Vergebung' erlebbar und anschlussfähig.","Team, das implizit oder explizit mit Konkurrenz zwischen Einheiten kämpft (Abteilungen, Teams, Standorte) – das Spiel externalisiert die Dynamik und macht sie analysierbar.","Workshop zu Verhandlungsstrategien oder Organisationsentwicklung: Das Debriefing zur Kooperations-vs.-Defektierungs-Entscheidung ist direkt übertragbar."],"wann_nicht":["Einzelrunden ohne Iteration – der entscheidende Lerneffekt (Kooperation entsteht durch Erwartung an Zukunft) geht verloren.","Wenn echte Verärgerung zwischen Gruppen entstehen und nicht aufgelöst werden kann – ausreichend Auflösungszeit einplanen.","Mit Gruppen, die sehr rational-skeptisch auf Spiele reagieren – dann erst das Konzept erklären, dann spielen."],"fokusfragen":["„Wann habt ihr entschieden zu kooperieren – und was hat euch bewogen? Wann habt ihr defektiert?' (Strategieanalyse im Debriefing)","„Was bräuchte es in eurer realen Zusammenarbeit, damit die 'Tit for Tat'-Logik entsteht – also: Kooperation als erste Wahl, Reaktion auf Verrat, aber auch Vergebung?'"],"beispiel":"Iteriertes Spiel (5 Runden, je 2 Min): Team A und B wählen verdeckt 'K' oder 'D'. Ergebnis: KK = je 3 Punkte; KD = A 0, B 5; DD = je 1. Nach Runde 3 kurzes Strategie-Murmeln erlaubt. Debriefing: 'Welche Strategie war langfristig klüger?' – Pointe: Tit for Tat (Start mit K, dann Spiegel der Gegenseite) ist in Studien langfristig überlegen. Anschlussfrage: 'Was ist der erste Schritt, der Kooperation auch nach einem Verrat wieder ermöglicht?'","mini_form":"Einzel-Entscheidung ohne Team (10 Min): Jede:r wählt anonym K oder D zu einem konkreten Dilemma aus der eigenen Arbeit. Auswertung der Verteilung im Plenum. Kein Spiel, aber direkter Transfer.","anlass_typen":["lernformat","teamtag","dialograum"],"typ":"methode","gruppen_sweetspot":"8–24 ideal; größere Gruppen in parallele Paarungen aufteilen","stimmung_geeignet":["neugierig","skeptisch","frisch"]},{"id":"wetterbericht-check-in","name":"Wetterbericht (Check-in)","feld":"C","kurz":"Innere Verfassung als Wetterlage beschreiben – schneller Check-in ohne Erklärungsdruck, die Metapher schützt.","schritte":["Einladung aussprechen: „Beschreibe deine innere Verfassung als Wetterlage.\"","Kurz Beispiele geben: sonnig, bewölkt mit Aufhellungen, Gewitterfront.","Reihum oder freiwillig in Popcorn-Reihenfolge teilen, ohne Kommentierung.","Optional kurz würdigen („Danke\") und in die Agenda überleiten."],"zweck":"Zu Sessionbeginn schnell die innere Verfassung aller sichtbar machen, ohne Erklärungsdruck.","hinweise":"Die Wettermetapher schützt – niemand muss Gründe nennen; bei großen Gruppen Chat- oder Bildkarten-Variante nutzen. Nicht kommentieren oder therapeutisieren.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["verbindung","selbstzugang"],"formate":["meeting","workshop","klausur","teamentwicklung","reflexionsrunde","fortbildung"],"dauer_min":5,"dauer_max":15,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah","spielerisch"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"Weather Check-in – SessionLab","url":"https://www.sessionlab.com/methods/weather-check-in-obyout"}],"wann_passt":["Regelmäßiges Teammeeting, bei dem die Stimmung stark variiert und nicht angesprochen wird – der Wetterbericht gibt allen die Chance, mit einem Wort zu signalisieren, ohne erklären zu müssen.","Gruppe, die Check-ins als 'zu persönlich' abgelehnt hat – die Wettermetapher schützt und fühlt sich spielerischer an als 'Wie geht es dir?'","Zu Beginn eines schwierigen Gesprächs: Kurz sichtbar machen, mit welcher inneren Verfassung alle in den Raum kommen, bevor der Inhalt startet."],"wann_nicht":["In sehr großen Gruppen (>25) ohne Anpassung – reihum wird es lang; Chat-Variante oder Bildkarten dann besser.","Wenn direkte Sachlichkeit gefragt ist und die Gruppe Check-ins grundsätzlich ablehnt – dann lieber Stimmungsskala 1–10.","Als Dauerlösung ohne Variation – nutzt sich nach einigen Wochen ab."],"fokusfragen":["„Beschreib deine innere Verfassung als Wetterlage – ein Satz reicht.' (Einladungsformel)","„Was brauchst du, damit es in den nächsten Stunden besser werden kann?' (optionale Vertiefung für belastete Gruppen)"],"mini_form":"Wetterbalken im Chat (2 Min): Alle schreiben gleichzeitig ihre Wetterlage in den Chat, keine Reaktion. Gibt Bild der Gruppe in 2 Minuten ohne Reihum-Logik.","anlass_typen":["regeltermin","teamtag","coaching"],"typ":"werkzeug","gruppen_sweetspot":"3–20 ideal; über 25 Chat- oder Bildkartenvariante","stimmung_geeignet":["angespannt","muede","belastet","neugierig","frisch"]},{"id":"ein-wort-check-in","name":"Ein-Wort-Check-in","feld":"C","kurz":"Mit einem einzigen Wort ankommen – in kürzester Zeit alle Stimmen hörbar machen und ein Stimmungsbild gewinnen.","schritte":["Frage stellen: „Mit welchem einen Wort kommst du heute an?\"","Kurz Bedenkzeit geben.","Reihum jede:r ein Wort, unkommentiert.","Optional: auffällige Worte am Ende kurz aufgreifen oder stehen lassen."],"zweck":"In kürzester Zeit alle Stimmen hörbar machen und ein Stimmungsbild gewinnen.","hinweise":"Konsequent bei einem Wort bleiben – die Beschränkung erzeugt die Prägnanz; eignet sich genauso als Ein-Wort-Check-out.","phasen":["ankommen","reflektieren"],"ebenen":["person","team"],"modi":["verbindung"],"formate":["meeting","workshop","klausur","teamentwicklung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":3,"dauer_max":10,"gruppe_min":3,"gruppe_max":40,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["einstieg","abschluss"],"quellen":[{"typ":"online","titel":"One Word Method – SessionLab","url":"https://www.sessionlab.com/methods/one-word-method"}],"wann_passt":["Zeitknapper Kontext (Jour fixe, kurze Arbeitssitzung), bei dem kein langer Check-in möglich ist – ein Wort pro Person dauert 30 Sekunden und gibt trotzdem ein Stimmungsbild.","Großgruppe (20–40): Reihum ein Wort ist in 5 Minuten durch, ohne dass jemand abschweifen kann.","Als Check-out am Ende: 'Mit welchem Wort gehst du?' – kompakter Abschluss, der Essenz verdichtet."],"wann_nicht":["Wenn die Gruppe Klärungsbedarf hat und ein Wort zu wenig Raum gibt – dann Wetterbericht oder Blitzlicht.","In einer angespannten Gruppe, in der Einworte wie 'erschöpft' oder 'frustriert' unkommentiert stehen bleiben würden – das braucht Nachfrage-Raum."],"fokusfragen":["„Mit welchem einen Wort kommst du heute hier an?' (Ankommen-Variante)","„Mit welchem Wort verlässt du diesen Raum?' (Abschluss-Variante)"],"mini_form":"Ist selbst schon Minimalform – keine weitere Reduktion möglich.","anlass_typen":["regeltermin","teamtag","retro"],"typ":"werkzeug","gruppen_sweetspot":"3–40; über 40 schriftlich","stimmung_geeignet":["muede","skeptisch","neugierig","frisch","angespannt","belastet"]},{"id":"stimmungsskala","name":"Stimmungsskala 1–10","feld":"C","kurz":"Energie oder Zustimmung der Gruppe schnell quantifizieren – per Handzeichen, Karte, Aufstellung oder Chat – und steuerbar machen.","schritte":["Frage definieren: „Wie ist deine Energie/Klarheit zum Thema – 1 bis 10?\"","Abfragen: Handzeichen, Karte hochhalten, Aufstellung an imaginärer Linie oder Zahl in den Chat.","Bild kurz lesen: Wo liegt die Gruppe, wo sind Ausreißer?","Optional 1–2 Stimmen hören: „Was bräuchtest du für einen Punkt mehr?\"","Konsequenz ziehen: Pause, Tempowechsel, Themenwechsel."],"zweck":"Energie oder Zustimmung der Gruppe schnell quantifizieren und steuerbar machen.","hinweise":"Zahlen nicht bewerten („nur eine 4?\") – sie sind Information, kein Urteil; die Frage nach „+1 Punkt\" macht aus der Messung eine Intervention.","phasen":["ankommen","reflektieren"],"ebenen":["person","team"],"modi":["klaerung","energie"],"formate":["meeting","workshop","klausur","teamentwicklung","fortbildung","grossgruppe"],"dauer_min":3,"dauer_max":10,"gruppe_min":3,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["einstieg","uebergang","abschluss"],"quellen":[{"typ":"online","titel":"Soziometrische Aufstellung und Skalenabfrage beim Online-Lernen – selbstlernen.net","url":"https://www.selbstlernen.net/aufstellung-und-skalenabfrage/"}],"wann_passt":["Übergang zwischen Programmpunkten, wenn die Moderation nicht weiß, wie die Energie steht – die Skala gibt in 2 Minuten ein objektives Bild und legitimiert Kursanpassungen.","Entscheidungs-Vorbereitung: Bevor eine Gruppe abstimmt, kurz Klarheits-Skala ('Wie klar bist du zu diesem Thema auf einer Skala 1–10?') – zeigt, ob Informationsbedarf da ist.","Online-Meetings, in denen Kamera-Abwesenheit das Stimmungsbild unsichtbar macht – Zahlen im Chat geben sofort Orientierung."],"wann_nicht":["Wenn Zahlen als Leistungsbewertung missverstanden werden können – in hierarchischen Kontexten fühlen sich niedrige Zahlen wie öffentliche Schwäche an.","Als Ersatz für echtes Gespräch: Die Skala misst, löst aber nichts – 'Was bräuchtest du für +1 Punkt?' ist die entscheidende Anschlussfrage.","Wenn die Gruppe schon mehrmals in derselben Sitzung befragt wurde – Messmüdigkeit entsteht schnell."],"fokusfragen":["„Auf einer Skala von 1–10: Wie klar/energievoll/zufrieden bist du gerade – 1 im Chat bitte.' (Einladungsformel)","„Was bräuchtest du, um einen Punkt höher zu kommen?' (entscheidende Anschlussfrage, macht aus Messung Intervention)"],"beispiel":"Vor einer Abstimmung über eine Strategie-Option: 'Auf einer Skala von 1–10: Wie gut verstehst du die Implikationen dieser Option?' – Moderator:in liest vor: 'Ich sehe viele 4–6. Bevor wir abstimmen: Was fehlt euch noch?' Zwei Personen nennen konkrete Informationslücken. Zweite Frage nach 5 Min Klärung: Skala steigt auf 7–8. Abstimmung findet jetzt auf echtem Informationsstand statt.","mini_form":"Handzeichen-Variante (2 Min): Alle zeigen gleichzeitig Finger 1–5 – kein Chat nötig, kein Tool. Im Raum sofort sichtbar.","anlass_typen":["regeltermin","entscheidungstreffen","teamtag","krisensitzung"],"typ":"werkzeug","gruppen_sweetspot":"3–100; ab 30 Chat oder Handzeichen statt Einzelabfrage","stimmung_geeignet":["muede","angespannt","neugierig","frisch"]},{"id":"1-2-4-all","name":"1-2-4-All","feld":"C","kurz":"Alle gleichzeitig aktivieren: still allein, dann zu zweit, dann zu viert denken – und nur die besten Ideen ins Plenum tragen (Liberating Structures).","schritte":["Klare Einladung/Frage stellen.","1 Min stille Einzelreflexion.","2 Min Austausch zu zweit, Ideen weiterentwickeln.","4 Min Abgleich in Vierergruppen: Gemeinsamkeiten und beste Ideen markieren.","5 Min „All\": jede Vierergruppe teilt eine wichtige Idee im Plenum; ggf. Zyklus wiederholen."],"zweck":"Alle gleichzeitig aktivieren und Ideen von Einzelnen über Paare zu Gruppen-Essenzen verdichten.","hinweise":"Zeitboxen strikt halten – die Kürze erzeugt Fokus; im Plenum nicht alles einsammeln, sondern nur die wichtigste Idee pro Gruppe (sonst stirbt die Energie).","phasen":["oeffnen","vertiefen"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung","energie"],"formate":["meeting","workshop","grossgruppe","fortbildung","klausur"],"dauer_min":12,"dauer_max":25,"gruppe_min":4,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["kern","einstieg"],"quellen":[{"typ":"online","titel":"1-2-4-All – Liberating Structures","url":"https://www.liberatingstructures.com/1-1-2-4-all/"},{"typ":"buch","titel":"Henri Lipmanowicz, Keith McCandless: The Surprising Power of Liberating Structures"}],"wann_passt":["Workshop ab ~8 Personen, in dem 2–3 Vielredner:innen sonst den Raum füllen und stillere Stimmen verloren gehen – die Stillarbeit zu Beginn gibt allen einen eigenen Gedanken, bevor die Lauten sprechen.","Skeptische oder methodenmüde Gruppe: fühlt sich kaum wie eine 'Methode' an, weil es nur strukturiertes Gespräch ist – guter Einstieg, wenn 'Workshop-Spiele' verbrannt sind.","Wenn zu einer offenen Frage echte Meinungsvielfalt vermutet wird, die in der Großrunde nicht sichtbar würde (Hierarchie im Raum, Chef:in anwesend)."],"wann_nicht":["Unter 6 Personen: die Stufen kollabieren, direktes moderiertes Gespräch ist ehrlicher.","Wenn die Frage in Wahrheit schon entschieden ist – dann erzeugt die Beteiligung Zynismus.","Als Dauerlösung in jedem Meeting: nutzt sich schnell ab und wirkt dann mechanisch."],"fokusfragen":["„Was ist aus deiner Sicht der wichtigste Hebel, um X zu erreichen?' (eine Frage, nicht drei – die Qualität von 1-2-4-All steht und fällt mit einer präzisen Eingangsfrage)","„Was würde Y aus Sicht der Menschen verändern, für die wir arbeiten?'"],"mini_form":"Nur '1-2-All' in 10 Minuten: 1 Minute still notieren, 4 Minuten zu zweit, dann Blitzlicht – reicht in kleinen Runden (6–10) völlig.","anlass_typen":["beteiligung","strategie","retro"],"typ":"methode","gruppen_sweetspot":"12–40 ideal, ab 8 sinnvoll, unter 6 nicht","stimmung_geeignet":["skeptisch","neugierig","frisch"]},{"id":"think-pair-share","name":"Think-Pair-Share","feld":"C","kurz":"Einzeldenken, Paar-Austausch, Plenum: Beteiligung aller sichern und Beitragsqualität durch Vordenken erhöhen.","schritte":["Frage oder Aufgabe stellen.","Think: 1–3 Min stilles Einzeldenken, ggf. Notizen.","Pair: Austausch zu zweit, Gedanken vergleichen und schärfen.","Share: Ergebnisse ins Plenum tragen – per Zufall oder freiwillig.","Moderation bündelt Muster."],"zweck":"Beteiligung aller sichern und Qualität der Beiträge durch Vordenken und Paar-Check erhöhen.","hinweise":"Die Think-Phase wirklich still halten – sie schützt introvertierte und langsamer Denkende; Unterschied zu 1-2-4-All: bleibt bei der Paar-Ebene, dadurch noch niedrigschwelliger.","phasen":["oeffnen","vertiefen"],"ebenen":["team","organisation"],"modi":["klaerung"],"formate":["meeting","workshop","fortbildung","grossgruppe"],"dauer_min":5,"dauer_max":20,"gruppe_min":4,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Think-Pair-Share – Methodenkartei Uni Oldenburg","url":"https://www.methodenkartei.uni-oldenburg.de/methode/think-pair-share/"}],"wann_passt":["Lernformat oder Workshop mit einer einzelnen inhaltsschweren Frage, bei der Vordenken die Qualität der Antworten deutlich hebt – Think-Pair-Share ist die einfachste Struktur dafür.","Gruppe mit stark unterschiedlichem Vorwissen: Das Paar-Gespräch gleicht aus, bevor alles ins Plenum kommt – Ergebnisse sind konsistenter.","Als leichterer Einstieg als 1-2-4-All: Wenn keine Vierergruppe gebildet werden soll oder die Frage zu nah ist für 4 Personen."],"wann_nicht":["Bei Fragen, die Einzelmeinung erfordern und nicht von Paardiskussion profitieren (z.B. persönliche Reflexion, Selbsteinschätzung).","Wenn die Think-Phase nicht wirklich still gehalten wird – dann ist es nur ein leicht verzögertes Plenumsgespräch.","Für komplexe Themen, die mehr als 2 Perspektiven brauchen – dann besser 1-2-4-All."],"fokusfragen":["„Was ist deine persönliche Antwort auf diese Frage – noch bevor du mit jemandem sprichst?' (Think-Phase-Einladung)","„Was hat dein Paar-Gespräch verändert oder geschärft an deiner ersten Antwort?' (Share-Phase-Einleitung)"],"mini_form":"Ist selbst schon Kurzformat (5–10 Min). Kürzeste Version: 1 Min still – 2 Min zu zweit – eine Aussage pro Paar ins Plenum.","anlass_typen":["lernformat","regeltermin","retro"],"typ":"methode","gruppen_sweetspot":"4–100; bei Großgruppen Sharing in Untergruppen statt Plenum","stimmung_geeignet":["neugierig","skeptisch","frisch"]},{"id":"blitzlicht","name":"Blitzlicht","feld":"C","kurz":"Reihum ein Satz pro Person, unkommentiert – schnelles, unzensiertes Stimmungs- oder Meinungsbild der ganzen Gruppe.","schritte":["Fokusfrage stellen: „Wie geht es dir mit dem Zwischenstand?\" / „Was nimmst du mit?\"","Regel erklären: reihum ein Satz pro Person, keine Kommentare, keine Diskussion.","Runde durchführen; Passen ist erlaubt.","Moderation dankt und fasst allenfalls Muster zusammen – ohne einzelne Beiträge zu bewerten."],"zweck":"Schnell ein unzensiertes Stimmungs- oder Meinungsbild der ganzen Gruppe einholen.","hinweise":"Die Nicht-Kommentierung ist die Schutzregel – auch die Moderation hält sich daran; ab ~15 Personen wird es lang, dann Ein-Wort-Variante wählen.","phasen":["reflektieren"],"ebenen":["person","team"],"modi":["reflexion"],"formate":["meeting","workshop","klausur","teamentwicklung","reflexionsrunde","fortbildung"],"dauer_min":5,"dauer_max":15,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["abschluss","reflexion"],"quellen":[{"typ":"online","titel":"Blitzlicht – Methodenkartei Uni Oldenburg","url":"https://www.methodenkartei.uni-oldenburg.de/methode/blitzlicht/"}],"wann_passt":["Abschluss einer Sitzungsphase oder des ganzen Tages: Ein Satz pro Person gibt der Moderation eine schnelle Diagnose, ob die Gruppe bereit für den nächsten Schritt ist oder Klärungsbedarf hat.","Gruppe unter 12 Personen, bei der eine Skalabfrage zu wenig differenziert wäre – Blitzlicht gibt sprachliche Nuancen ohne großen Zeitaufwand.","Wenn nach einem anstrengenden Block die Stimmung sichtbar werden soll, ohne sie therapeutisch zu bearbeiten."],"wann_nicht":["Ab ~16 Personen: Blitzlicht wird dann zu lang; Ein-Wort-Check-in oder Stimmungsskala ist effizienter.","Wenn Diskussion oder Kommentierung der Beiträge erwartet wird – das Nicht-Kommentieren ist Schutzregel, aber auch Einschränkung.","Als einziges Feedbackformat für einen ganzen Tag – es gibt zu wenig Tiefe für wichtige Auswertungen."],"fokusfragen":["„In einem Satz: Wie geht es dir gerade mit dem, was wir erarbeitet haben?' (Zwischenstand)","„Was nimmst du aus dieser Sitzung mit – ein Satz, keine Diskussion.' (Abschluss)"],"mini_form":"Ist selbst Minimalform. Noch kürzer: Wort-Blitzlicht (1 Wort statt 1 Satz) für Gruppen > 12.","anlass_typen":["regeltermin","retro","teamtag","krisensitzung"],"typ":"werkzeug","gruppen_sweetspot":"4–14 ideal; über 15 zu lang","stimmung_geeignet":["muede","angespannt","neugierig","belastet"]},{"id":"paarinterview","name":"Paarinterview (Icebreaker)","feld":"C","kurz":"Sich gegenseitig interviewen und die Partner:in im Plenum vorstellen – Kontakt über Geschichten statt Selbstdarstellung.","schritte":["Paare bilden, möglichst Personen, die sich wenig kennen.","Leitfragen geben: Name, Bezug zum Thema, eine überraschende Sache.","Gegenseitig interviewen, je 3–5 Min pro Richtung.","Im Plenum stellt jede:r die Partner:in vor – nicht sich selbst.","Optional: Gemeinsamkeiten im Raum sammeln."],"zweck":"Kontakt stiften und Kennenlernen über Geschichten statt über Selbstdarstellung.","hinweise":"Vorstellung der anderen Person senkt Lampenfieber und erhöht Zuhörqualität; bei großen Gruppen Vorstellung in Vierergruppen statt im Plenum.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["verbindung","vertrauen"],"formate":["workshop","klausur","teamentwicklung","fortbildung","grossgruppe"],"dauer_min":15,"dauer_max":40,"gruppe_min":6,"gruppe_max":40,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","beteiligend"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"Partnerinterview – Methodenkartei Uni Oldenburg","url":"https://www.methodenkartei.uni-oldenburg.de/methode/partnerinterview/"}],"wann_passt":["Neues Team oder Fortbildungsgruppe am ersten Tag: Vorstellen durch die andere Person senkt Lampenfieber massiv und erzeugt sofort echte Zuhör-Qualität.","Netzwerk-Treffen, bei dem sich die Menschen noch nicht kennen und die klassische Vorstellungsrunde im Plenum alle langweilt – Paarinterviews schaffen in 15 Minuten mehr echten Kontakt.","Als Warm-up vor einem intensiven Prozess: Das Interview-Setting baut bilateral Vertrauen auf, das dann dem Gesamtprozess zugute kommt."],"wann_nicht":["Wenn keine Zeit für die Vorstellung im Plenum ist – dann fehlt die Würdigung des Zuhörens.","In sehr großen Gruppen (>40) ohne Anpassung: Plenumsvorstellung wird zu lang; besser in Vierergruppen vorstellen.","Wenn die Gruppe sich schon gut kennt – das Format wirkt dann aufgesetzt."],"fokusfragen":["„Interviewt euer Gegenüber – drei Fragen: Name und Bezug zum Thema, ein Projekt das euch gerade bewegt, eine Sache die man euch nicht ansieht.' (Leitfragen für Interview)","„Was hat euch an eurer Interview-Partner:in am meisten überrascht?' (Plenum-Einstieg nach Vorstellung)"],"mini_form":"Interview-Blitz (10 Min): Je 3 Min pro Richtung, eine Frage ('Was bringt dich her?'), Plenum-Vorstellung in einem Satz. Reicht für erstes Kontaktnetz.","anlass_typen":["kickoff","netzwerktreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"6–30 ideal; ab 40 in Gruppen vorstellen statt Plenum","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"warp-speed","name":"Warp Speed (Energizer)","feld":"C","kurz":"Ball-Reihenfolge im Kreis immer schneller schaffen – aktiviert in Minuten und macht kreatives Problemlösen jenseits gewohnter Annahmen erlebbar.","schritte":["Kreis bilden; Ball wird so geworfen, dass jede Person ihn genau einmal bekommt und er zur ersten zurückkehrt – Reihenfolge merken.","Reihenfolge wiederholen und Zeit stoppen.","Challenge stellen: „Schafft ihr es schneller?\" – Gruppe darf Aufstellung und Methode frei verändern.","Mehrere Versuche mit kurzer Strategieabsprache.","Kurz debriefen: Welche Annahmen haben uns anfangs gebremst?"],"zweck":"Gruppe in Minuten aktivieren und nebenbei kreatives Problemlösen jenseits gewohnter Annahmen erlebbar machen.","hinweise":"Der Aha-Moment kommt, wenn die Gruppe das Kreis-Schema aufgibt (unter 1 Sekunde ist möglich) – nicht vorsagen; weiche Bälle nutzen.","phasen":["ankommen"],"ebenen":["team"],"modi":["energie"],"formate":["workshop","klausur","teamentwicklung","fortbildung"],"dauer_min":5,"dauer_max":15,"gruppe_min":6,"gruppe_max":25,"online":"nein","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich","spielerisch"],"blocktyp":["energizer"],"quellen":[{"typ":"online","titel":"Warp Speed – SessionLab","url":"https://www.sessionlab.com/methods/warp-speed"}],"wann_passt":["Nach einem langen Vortrags- oder Arbeitsblock, wenn die Energie spürbar abgesunken ist – Warp Speed aktiviert in 10 Minuten vollständig, ohne Inhaltsbezug zu brauchen.","Workshop zu kreativem Denken oder Innovation: Das Debriefing ('Welche Annahmen haben uns gebremst?') ist direkt auf den Inhalt des Tages übertragbar.","Gruppe, die skeptisch gegenüber Warming-up-Spielen ist, aber einen gemeinsamen Erfolg braucht – der Aha-Moment beim Aufgeben des Kreisschemas erzeugt echte Energie."],"wann_nicht":["Online – körperliche Präsenz und Ball sind Voraussetzung.","Wenn kein Debriefing folgt – dann ist es nur ein Spiel; der Transfer entsteht im Gespräch danach.","Mit Gruppen, die sich nicht bewegen wollen oder können."],"fokusfragen":["„Welche Annahme habt ihr am Anfang gemacht, die euch ausgebremst hat – und wann habt ihr sie aufgegeben?' (Debriefing-Kern)","„Welche Denkblockade kennt ihr aus eurer Arbeit, die ähnlich funktioniert?'"],"mini_form":"Ist selbst Kurzformat (5–15 Min) – keine weitere Reduktion nötig.","anlass_typen":["teamtag","lernformat","kickoff"],"typ":"methode","gruppen_sweetspot":"8–25; über 25 zwei parallele Kreise","stimmung_geeignet":["muede","skeptisch","frisch"]},{"id":"zaehlkreis","name":"Zählkreis (Energizer)","feld":"C","kurz":"Gemeinsam bis 20 zählen ohne Absprache und Reihenfolge – schärft Aufmerksamkeit, Zuhören und gemeinsames Timing.","schritte":["Kreis bilden, Augen schließen oder Blick zu Boden.","Aufgabe erklären: Gemeinsam bis 20 zählen, eine Person pro Zahl, ohne Absprache und Reihenfolge.","Bei Doppelung beginnt die Gruppe bei 1.","So lange spielen, bis 20 erreicht ist oder die Zeit endet.","Kurz reflektieren: Was hat geholfen – Tempo, Pausen, Zuhören?"],"zweck":"Aufmerksamkeit, Zuhören und gemeinsames Timing schärfen und konzentrierte Stille erzeugen.","hinweise":"Misserfolg gehört zum Spiel – locker rahmen, sonst entsteht Frust; Varianten: rückwärts zählen, Alphabet, mit geöffneten Augen nach außen gewandt.","phasen":["ankommen"],"ebenen":["team"],"modi":["energie"],"formate":["workshop","klausur","teamentwicklung","fortbildung"],"dauer_min":5,"dauer_max":10,"gruppe_min":5,"gruppe_max":25,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["koerperlich","spielerisch"],"blocktyp":["energizer","uebergang"],"quellen":[{"typ":"online","titel":"Count To 20 – Drama Resource","url":"https://dramaresource.com/count-to-20/"}],"wann_passt":["Gruppe, die nach intensiver Diskussion oder Konflikt wieder in einen gemeinsamen Rhythmus finden soll – der Zählkreis erzeugt konzentrierte Stille ohne Inhalts-Exposition.","Als Übergangsritual in wiederkehrenden Gruppen (Supervisionsgruppe, Fortbildungsreihe): Das Scheitern gehört dazu und wird entspannt – entlastet.","Kurz nach der Mittagspause oder am frühen Nachmittag, wenn Energie tief ist – erzeugt Aufmerksamkeit ohne körperliche Anstrengung."],"wann_nicht":["Bei sehr großen Gruppen (>25) – die Wahrscheinlichkeit des Doppelnennens steigt, was frustriert statt entspannt.","Wenn Zeitdruck herrscht und 5–10 Min nicht vorhanden sind – lieber nichts als ein abgebrochenes Spiel.","Online synchron: das gemeinsame Timing ist ohne physische Präsenz kaum erlebbar."],"fokusfragen":["„Was hat geholfen – Tempo, Pausen, auf andere hören?' (Kurzauswertung nach dem Spiel)","„Was davon brauchen wir in unserem gemeinsamen Arbeiten?'"],"mini_form":"Ist selbst Minimalformat. Variante ohne Scheitern: Alphabet statt Zahlen, gleichmäßig der Reihe nach – weniger Risiko, weniger Dynamik.","anlass_typen":["teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"5–20; über 20 zu unzuverlässig","stimmung_geeignet":["muede","angespannt","neugierig"]},{"id":"gefuehls-beduerfnis-karten","name":"Gefühls- & Bedürfnis-Karten (GFK-Mini)","feld":"C","kurz":"Karten mit Gefühls- und Bedürfnisbegriffen senken die Schwelle, über die eigene Lage zu sprechen – benennen ohne begründen zu müssen.","schritte":["Karten mit Gefühls- und Bedürfnisbegriffen auslegen oder Listen austeilen.","Einladung: „Wähle 1–2 Karten, die deine aktuelle Lage treffen.\"","Stille Wahlzeit.","Teilen in Paaren oder Runde – nur benennen, nicht begründen müssen.","Optional vertiefen: „Welches Bedürfnis steht hinter dem Gefühl?\""],"zweck":"Emotionale Sprache öffnen und Gefühle/Bedürfnisse benennbar machen, ohne Gesprächsdruck.","hinweise":"Karten senken die Schwelle deutlich gegenüber freiem Sprechen über Gefühle; Listen des CNVC (Feelings/Needs Inventory) sind frei verfügbar und auch digital teilbar.","phasen":["ankommen","vertiefen","konflikt"],"ebenen":["person","team"],"modi":["selbstzugang","verbindung"],"formate":["workshop","teamentwicklung","coaching","reflexionsrunde","fortbildung"],"dauer_min":10,"dauer_max":30,"gruppe_min":2,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["schriftlich","gespraechsnah"],"blocktyp":["einstieg","kern"],"quellen":[{"typ":"online","titel":"Feelings and Needs Inventory – Center for Nonviolent Communication","url":"https://www.cnvc.org/store/feelings-and-needs-inventory"},{"typ":"buch","titel":"Marshall B. Rosenberg: Gewaltfreie Kommunikation"}],"wann_passt":["Team nach einem schwierigen Ereignis (Kündigung, Kritik, Scheitern), das über die Lage sprechen soll, aber direkte Aufforderung zur Selbstöffnung zu viel wäre – Karten geben Sprache und senken die Scham-Schwelle.","Konfliktklärung als Einstieg: Bevor Positionen ausgetauscht werden, klären alle für sich, was sie fühlen und brauchen – GFK-Karten strukturieren das, ohne GFK als Methode einzuführen.","Coaching oder Einzelbegleitung: Als Einstieg in ein schwieriges Gespräch, wenn die Person schwer in Kontakt mit der eigenen Lage kommt."],"wann_nicht":["In sehr sachorientierten Gruppen ohne vorherige Hinführung – 'Gefühlskarten' ohne Kontext wirken befremdlich.","Wenn keine Zeit ist, das, was gezeigt wird, auch aufzufangen – keine Gefühls-Öffnung ohne Schließraum.","Online ohne gutes digitales Kartenmaterial – die Wahl aus physischen Karten hat eine andere Qualität als Wortlisten am Bildschirm."],"fokusfragen":["„Wähle 1–2 Karten, die deine aktuelle Lage am besten beschreiben – du musst nichts erklären, nur benennen.' (Einladungsformel)","„Welches Bedürfnis steht hinter dem Gefühl, das du gewählt hast – und ist es gerade erfüllt oder nicht?' (Vertiefung, freiwillig)"],"beispiel":"In einer Teamklärung nach einem gescheiterten Projekt: Karten werden ausgelegt, alle wählen still. Person A wählt 'erschöpft' und 'frustriert' – sagt nur das. Person B wählt 'enttäuscht' und 'traurig'. Moderation: 'Ich höre, dass hier Erschöpfung und Traurigkeit im Raum sind – was bräuchtet ihr jetzt?' Schritt zu Bedürfnissen: Anerkennung, Klarheit, Pause. Das öffnet das Gespräch ohne Vorwürfe.","mini_form":"Wort-Auswahl ohne Karten (5 Min): Moderator:in liest 10 Gefühlswörter vor, jede:r sagt oder schreibt die zwei, die am meisten treffen. Kein Material nötig.","anlass_typen":["konfliktklaerung","teamtag","coaching"],"typ":"werkzeug","gruppen_sweetspot":"2–20; über 25 in Kleingruppen","stimmung_geeignet":["angespannt","belastet","muede"]},{"id":"selbstempathie-pause","name":"Selbstempathie-Pause (GFK-Mini)","feld":"C","kurz":"In 2–3 Minuten innerlich klären, was ich fühle und brauche – Selbstregulation mitten in einer hitzigen Session.","schritte":["Kurz unterbrechen und still werden – auch mitten in einer hitzigen Session möglich.","Beobachtung klären: Was ist konkret passiert – ohne Bewertung?","Innerlich fragen: „Was fühle ich gerade?\"","Weiterfragen: „Welches Bedürfnis ist (nicht) erfüllt?\"","Optional eine Bitte an sich selbst oder andere formulieren; danach bewusst zurück ins Gespräch."],"zweck":"Sich in 2–3 Minuten selbst regulieren, indem Gefühle und Bedürfnisse innerlich geklärt werden.","hinweise":"Als Moderationsangebot einführen, bevor es gebraucht wird – im Affekt ist die Anleitung schwer aufzunehmen; auch als stille Schreibminute durchführbar.","phasen":["konflikt","vertiefen"],"ebenen":["person"],"modi":["selbstzugang","reflexion"],"formate":["meeting","workshop","coaching","teamentwicklung","reflexionsrunde"],"dauer_min":2,"dauer_max":10,"gruppe_min":1,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["strukturiert","schriftlich"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Der Prozess der Selbstempathie – Fachverband Gewaltfreie Kommunikation","url":"https://www.fachverband-gfk.org/der-prozess-der-selbstempathie"}],"wann_passt":["Mitten in einer hitzigen Diskussion, wenn eine Person spürbar aus der Regulierung geraten ist – die Pause gibt ihr Raum, ohne dass das Gespräch abgebrochen wird.","Als Moderationswerkzeug, bevor eskalative Äußerungen fallen: 'Lasst uns eine kurze Selbstempathie-Pause machen – 2 Minuten still, jede:r fragt sich: Was fühle ich, was brauche ich?'","In Coaching oder Einzelbegleitung als Eigenpraxis: Selbstempathie bevor eine schwierige Intervention oder ein schwieriges Gespräch."],"wann_nicht":["Als Dauerlösung für wiederkehrende Eskalationen – dann liegt ein strukturelles Problem vor, das keine Pause löst.","Wenn die Gruppe das Tool nicht kennt und der Moment zu aufgeladen ist, um Anleitung aufzunehmen – dann besser einfache Pausenanweisung.","Als Alibi-Pause, ohne dass tatsächlich innere Klärung passiert."],"fokusfragen":["„Was beobachte ich gerade – ohne Bewertung?' (GFK-Selbstempathie-Schritt 1)","„Was fühle ich gerade – und welches Bedürfnis ist (nicht) erfüllt?' (GFK-Schritte 2 und 3)"],"beispiel":"In einer Team-Klärung wird die Auseinandersetzung laut. Moderator:in: 'Kurze Pause – 2 Minuten für uns alle. Frage euch innerlich: Was passiert gerade in mir? Was fühle ich, was brauche ich jetzt?' – Stille. Danach: 'Wer möchte, sagt einen Satz dazu – ohne sich zu rechtfertigen.' Person A: 'Ich merke, ich bin gereizt – ich brauche das Gefühl, dass mein Beitrag gehört wird.' Das öffnet den nächsten Gesprächsschritt auf Bedürfnis-Ebene statt Positions-Ebene.","mini_form":"Ist selbst Minimalformat (2–5 Min). Noch kürzer: 30-Sekunden-Atempause ohne Anleitung als Moderations-Signal.","anlass_typen":["konfliktklaerung","schwieriges_gespraech","coaching"],"typ":"werkzeug","gruppen_sweetspot":"1–30; als Gruppen-Intervention bis 20 sinnvoll","stimmung_geeignet":["angespannt","belastet"]},{"id":"erdung-bodyscan","name":"Erdung / kurzer Bodyscan (Embodiment)","feld":"C","kurz":"Die Gruppe aus dem Kopf in die Körperwahrnehmung holen: Aufmerksamkeit wandert durch den Körper, Kontaktflächen spüren, ankommen.","schritte":["Einladen, eine bequeme Haltung zu finden (sitzend, Füße am Boden); Augen schließen optional.","Aufmerksamkeit zum Atem führen, 2–3 bewusste Atemzüge.","Aufmerksamkeit langsam durch den Körper wandern lassen: Füße – Beine – Becken – Rücken – Schultern – Kopf; wahrnehmen ohne verändern.","Kontaktflächen spüren: Boden, Stuhl.","Mit einem tiefen Atemzug zurückkommen, Augen öffnen; kurz nachspüren lassen."],"zweck":"Die Gruppe aus dem Kopf in die Körperwahrnehmung und ins Hier und Jetzt holen.","hinweise":"Sprache einladend und säkular halten („Wahrnehmungsübung\", nicht „Meditation\"), Teilnahme freiwillig; bei traumasensiblen Kontexten Augen offen lassen und kurze Dauer wählen.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["selbstzugang","energie"],"formate":["meeting","workshop","klausur","teamentwicklung","coaching","reflexionsrunde","fortbildung"],"dauer_min":3,"dauer_max":15,"gruppe_min":1,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["einstieg","uebergang"],"quellen":[{"typ":"online","titel":"A Beginner's Body Scan Meditation – Mindful.org","url":"https://www.mindful.org/beginners-body-scan-meditation/"}],"wann_passt":["Sessionbeginn nach intensiver Anreise, Stress oder einem schwierigen Vortag – Erdung holt die Gruppe aus dem Kopf und schafft Präsenz als Grundlage für alles Folgende.","Übergang zwischen einem inhaltsschweren Block und einem neuen Thema – der Bodyscan signalisiert: wir kommen jetzt woanders an.","Online-Meetings, in denen alle gerade von anderen Calls kommen und kognitiv noch woanders sind – 3 Minuten Erdung erhöht tatsächlich die Gesprächsqualität."],"wann_nicht":["In Gruppen, die Körperübungen oder 'Meditation' kategorisch ablehnen – dann lieber Ein-Wort-Check-in oder kurze Stille.","Traumasensibel ohne Vorbereitung: Augen schließen und Körper spüren kann triggern – bei vulnerablen Gruppen Augen offen lassen, kurz halten (2 Min) und ankündigen.","Wenn Zeitdruck herrscht und die Gruppe keine Bereitschaft für Innehalten hat."],"fokusfragen":["„Spür, wo du gerade Kontakt hast – mit dem Boden, dem Stuhl. Du musst nichts verändern, nur wahrnehmen.' (Anleitungsformel)","„Was nimmst du mit in die nächste Stunde – ein Wort für deine Verfassung jetzt?' (optionaler Abschluss)"],"mini_form":"30-Sekunden-Atempause: 'Drei bewusste Atemzüge – Einatmen zählen bis 4, ausatmen bis 6. Los.' Kein Bodyscan, kein Augen schließen nötig. Funktioniert in jeder Gruppe, auch in skeptischen.","anlass_typen":["teamtag","lernformat","coaching"],"typ":"werkzeug","gruppen_sweetspot":"1–100; skaliert beliebig","stimmung_geeignet":["muede","angespannt","belastet"]},{"id":"systems-mapping-causal-loops","name":"Systems Mapping / Causal Loops","feld":"D","kurz":"Rückkopplungen und Systemdynamiken visualisieren, die lineares Ursache-Wirkung-Denken übersieht.","schritte":["Fokusfrage definieren: Warum bleibt X trotz aller Anstrengung stabil?","Schlüsselvariablen sammeln – Dinge, die zu- oder abnehmen können","Wirkungspfeile ziehen (gleichgerichtet/gegenläufig)","Schleifen identifizieren: verstärkend (R) oder ausgleichend (B)","Schleifen benennen und als Geschichte erzählen lassen","Ansatzpunkte für Intervention markieren"],"zweck":"Rückkopplungen und Systemdynamiken sichtbar machen, die lineares Ursache-Wirkung-Denken übersieht.","hinweise":"Karte klein halten (max. 10–15 Variablen), sonst Spaghetti-Map. Variablen neutral formulieren (Niveau, nicht Ereignis). Die Diskussion beim Bauen ist wertvoller als das fertige Diagramm.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The Systems Thinker – Causal Loop Construction: The Basics","url":"https://thesystemsthinker.com/causal-loop-construction-the-basics/"},{"typ":"buch","titel":"Donella Meadows: Thinking in Systems (2008)"},{"typ":"online","titel":"Omidyar Group – Systems Practice Workbook (free PDF)","url":"https://www.omidyar.com/sites/default/files/file_archive/Systems%20Practice%20Workbook.pdf"},{"typ":"online","titel":"Academy for Systems Change – Tools & Resources","url":"https://academyforchange.org/resources/"}],"wann_passt":["Eine Gruppe von 4–12 Personen arbeitet an einem Problem, das trotz wiederholter Interventionen stabil bleibt (z.B. chronische Unterfinanzierung, wiederkehrende Konflikte, stagnierende Lernkultur) – Causal Loops machen sichtbar, welche Rückkopplungen das Problem stabilisieren, und wo Eingriffe an Schleifen ansetzen könnten statt an Symptomen.","Kick-off einer Systems-Change-Initiative: Stakeholder:innen aus verschiedenen Bereichen bringen Teilwissen mit – das gemeinsame Bauen der Map macht Systemwissen kollektiv zugänglich und schafft geteiltes Verständnis, das Einzelgespräche nicht erzeugen können.","In einer Strategie-Klausur, in der die Gruppe bisher linear plant (Ursache → Maßnahme → Wirkung): die Mapping-Session unterbricht diesen Reflex und öffnet die Diskussion für Wechselwirkungen und unbeabsichtigte Effekte.","Als Evaluations-Element am Ende einer Phase: 'Was hat sich verändert – welche Schleifen sind schwächer geworden, welche haben wir übersehen?'"],"wann_nicht":["Gruppe hat akuten Handlungsdruck und braucht in 30 Minuten eine Entscheidung – Mapping kostet Zeit und Offenheit, die unter Druck nicht entstehen.","Mehr als 15 Personen ohne Untergruppen-Struktur: die Map wird zur Spaghetti-Katastrophe, niemand versteht das Ergebnis.","Thema ist tatsächlich linear und gut verstanden – dann ist Causal Loops Overengineering und irritiert die Gruppe."],"fokusfragen":["'Warum bleibt [konkrete Situation] trotz allem stabil – was hält sie in Position?' (Einstiegsfrage; zwingt zur Schleifensuche statt zur Maßnahmenplanung)","'Welche Variable müsste sich verändern, damit die verstärkende Schleife R1 langsamer dreht?' (Ansatzpunkt-Frage nach der Analyse)","'Was verstärkt sich hier selbst – und wer profitiert davon, dass es so bleibt?' (Macht- und Interessenfrage; öffnet die politische Dimension des Systems)","'Wenn wir an Hebel X eingreifen – was passiert in der Schleife B2 als Reaktion?' (Interventions-Test vor der Entscheidung)'"],"beispiel":"Thema: Warum kommen marginalisierte Gruppen in unserem Netzwerk nie wirklich an Entscheidungsmacht? Einstiegsfrage: 'Welche Variablen nehmen zu oder ab, wenn Macht konzentriert bleibt?' Antworten der Gruppe: Sichtbarkeit, Zugangshürden, informelle Netzwerke, Vertrauen. Wirkungspfeil: mehr Vertrauen → mehr Sichtbarkeit → mehr Einladungen → mehr Vertrauen (verstärkende Schleife R1). Gegenpfeil: mehr Zugangshürden → weniger Sichtbarkeit (ausgleichend B1). Anschlussfrage: 'Wo in B1 könnten wir die Hürde am günstigsten senken?' – so entsteht eine begründete Intervention statt einer Maßnahme aus dem Bauch.","mini_form":"15-Minuten-Schnellmap: Eine einzige Frage ('Was hält X in Position?'), 3 Minuten still Variablen auf Post-its, dann 10 Minuten gemeinsam Pfeile ziehen – kein vollständiges Modell, aber ein erster Schleifenblick, der das Gespräch in Tiefe kippt.","anlass_typen":["strategie","lernformat","netzwerktreffen","retro"],"typ":"methode","gruppen_sweetspot":"5–12 ideal, ab 3 möglich, über 15 nur mit parallelen Untergruppen","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"leverage-points","name":"Leverage Points (Meadows)","feld":"D","kurz":"Interventionen nach ihrer Wirktiefe sortieren – von Stellschrauben bis zum Paradigma.","schritte":["Vorhandene Systemanalyse auslegen","Die 12 Hebel in 4 Clustern einführen: Parameter â†’ Strukturen â†’ Regeln/Information â†’ Ziele/Paradigmen","Bestehende und mögliche Interventionen sammeln","Interventionen den Hebelebenen zuordnen","Diskutieren: Wo arbeiten wir nur an flachen Hebeln?","1–2 tiefere Interventionen konkretisieren"],"zweck":"Interventionen nach ihrer Wirktiefe sortieren – von Stellschrauben bis zum Paradigma.","hinweise":"Tiefe Hebel (Paradigmen) sind wirksam, aber am schwersten zugänglich – Frustration einplanen. Hierarchie nicht dogmatisch lesen, Meadows selbst nennt sie vorläufig.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung","entscheidung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":45,"dauer_max":120,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Donella Meadows – Leverage Points: Places to Intervene in a System","url":"https://donellameadows.org/archives/leverage-points-places-to-intervene-in-a-system/"},{"typ":"buch","titel":"Donella Meadows: Thinking in Systems (2008)"},{"typ":"online","titel":"FSG / Kania, Kramer, Senge – The Water of Systems Change","url":"https://www.fsg.org/resource/water_of_systems_change/"}],"wann_passt":["Eine Strategie-Gruppe hat eine Liste von Interventionen und streitet, was wirklich priorisiert werden soll – Leverage Points gibt eine gemeinsame Sprache für Wirktiefe (Parameter vs. Paradigma) und macht sichtbar, dass viele Maßnahmen an flachen Hebeln arbeiten.","Programm-Review einer Organisation, die viele Aktivitäten betreibt, aber wenig systemische Wirkung sieht: Interventionen auf die 12 Hebelebenen mappen zeigt das Strukturproblem, ohne jemanden persönlich zu beschuldigen.","Fortbildungskontext (Systems Change Literacy): als Lernformat, um Teilnehmende intuitiv an der Frage 'Flacher oder tiefer Hebel?' zu trainieren – Meadows' Framework ist gut erzählbar und hängen bleibt das Paradigma-Argument.","In einer Koalition, in der verschiedene Akteure an verschiedenen Stellen des Systems arbeiten: Leverage Points macht sichtbar, wer an welchem Hebel zieht und ob sich die Ansätze ergänzen oder neutralisieren."],"wann_nicht":["Als Entscheidungstool für konkrete operative Maßnahmen – die 12 Hebel sind Denkstruktur, keine Entscheidungsmatrix.","Wenn die Gruppe die Systemanalyse (Causal Loops, Iceberg) noch nicht gemacht hat: ohne Grundverständnis des Systems bleibt die Hebel-Einordnung spekulativ.","In einer Gruppe, die Vertiefung als Prokrastination nutzt – Leverage Points kann 'Wir müssen noch mehr verstehen' endlos verlängern."],"fokusfragen":["'Welche unserer aktuellen Interventionen arbeiten auf der Ebene der Parameter (Flussgrößen, Kennzahlen) – und was wäre das Äquivalent eine Ebene tiefer?' (Upgrade-Frage)","'Wer profitiert davon, dass die jetzigen mentalen Modelle in unserem Feld bestehen bleiben – und wie werden sie aufrechterhalten?' (Paradigmen-Frage, politisch)","'Wenn wir unbegrenzte Ressourcen hätten: An welchem Hebel würden wir wirklich eingreifen wollen?' (hypothetischer Ernstfall, öffnet strategische Fantasie)"],"beispiel":"Eine NGO-Koalition prüft ihre Advocacy-Strategie. Interventionen auf Karten: 'Öffentlichkeitskampagne', 'Gesetz ändern', 'Finanzierungsregeln', 'Netzwerk von Changemaker:innen aufbauen', 'Narrativ in Medien verändern'. Einordnung auf Hebelebenen: Kampagne = Hebel 3 (Information flows), Gesetz = Hebel 5 (Rules), Finanzierungsregel = Hebel 6 (Structure), Changemaker-Netzwerk = Hebel 2 (Goals/Paradigms tangiert). Anschlussfrage: 'Wir investieren 80% unserer Zeit in Hebel 3–6 – wer kümmert sich um die mentalen Modelle hinter der Politik?' Das reframt die Ressourcen-Diskussion.","mini_form":"Schnell-Kartierung in 15 Minuten: Jede Person schreibt ihre zwei wichtigsten aktuellen Interventionen auf. Gemeinsam nur in drei Cluster sortieren: 'Stellschrauben', 'Spielregeln', 'Paradigmen'. Dann eine Frage: 'Was fehlt in der Paradigmen-Spalte?'","anlass_typen":["strategie","lernformat","retro"],"typ":"methode","gruppen_sweetspot":"6–15 ideal, ab 3 möglich, über 20 nur mit Untergruppen","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"six-conditions","name":"Six Conditions of Systems Change (FSG)","feld":"D","kurz":"Prüfen, ob eine Initiative nur Sichtbares verändert oder auch Beziehungen, Macht und mentale Modelle.","schritte":["Modell einführen: drei Ebenen (strukturell/relational/transformativ) mit sechs Bedingungen","Das eigene System auf alle sechs Bedingungen kartieren","Markieren, welche Bedingungen die Initiative bisher adressiert","Mental Models und Power Dynamics gezielt vertiefen","Interventionen pro Bedingung ableiten und priorisieren"],"zweck":"Eine Initiative daraufhin prüfen, ob sie nur Sichtbares verändert oder auch Beziehungen, Macht und mentale Modelle.","hinweise":"Gefahr, das Raster nur als Checkliste abzuhaken – pro Bedingung konkrete Beispiele verlangen. Power Dynamics ehrlich zu besprechen braucht Vertrauen im Raum.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung","reflexion"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"FSG – The Water of Systems Change (PDF)","url":"https://www.fsg.org/resource/water_of_systems_change/"},{"typ":"online","titel":"Omidyar Group – Systems Practice Workbook","url":"https://www.omidyar.com/sites/default/files/file_archive/Systems%20Practice%20Workbook.pdf"}],"wann_passt":["Eine Initiative will wissen, ob sie wirklich Systems Change betreibt oder nur Symptome behandelt – die 6 Bedingungen (Policies, Practices, Resource Flows, Relationships, Power Dynamics, Mental Models) als Diagnose-Raster zeigt, auf welchen Ebenen gearbeitet wird und welche fehlen.","Strategieentwicklung in einer Koalition: Verschiedene Organisationen mit verschiedenen Ansätzen kartieren, welche Bedingungen sie jeweils adressieren – das macht Lücken und Synergiepotenziale sichtbar, ohne Hierarchie.","Programm-Evaluation nach 2–3 Jahren: Welche der 6 Bedingungen haben sich verändert, welche nicht? Das Rahmenmodell gibt der Evaluation eine systems-informierte Sprache.","Fortbildung zu Systems Change: als Lernformat, um die Unterscheidung strukturell/relational/transformativ intuitiv erfahrbar zu machen."],"wann_nicht":["Als alleinige Grundlage für eine Budgetentscheidung – die 6 Bedingungen sind Diagnose, keine Priorisierungsmatrix.","Wenn im Raum keine psychologische Sicherheit für die Diskussion von Power Dynamics vorhanden ist: die transformative Ebene (mentale Modelle, Machtverhältnisse) bleibt dann auf der Oberfläche.","In frühen Phasen einer Koalition, die sich noch nicht kennt – die ehrliche Kartierung von Machtdynamiken braucht Vertrauen, das zuerst aufgebaut werden muss."],"fokusfragen":["'Auf welchen der sechs Bedingungen arbeiten wir gerade – und welche lassen wir systematisch aus?' (Diagnose-Frage)","'Wessen mentale Modelle im Feld müssten sich verändern, damit unsere Intervention langfristig hält – und wer hält diese Modelle gerade aufrecht?' (Transformationsebene)","'Welche Machtdynamik im System macht es schwer, an Bedingung X zu arbeiten – und wer hat Interesse daran, dass das so bleibt?' (Power-Dynamics-Frage)"],"beispiel":"Eine Bildungsinitiative kartiert ihre Arbeit: Policies (Lehrplan-Änderung ✓), Practices (neue Unterrichtsmethoden ✓), Resource Flows (neue Fördermittel ✓), Relationships (Schul-Community-Partnerschaften ✓), Power Dynamics (wer entscheidet über Curriculum? – leer), Mental Models (was Lehrende über 'gutes Lernen' glauben – leer). Erkenntnis: Die Initiative arbeitet ausschließlich auf den drei strukturellen Bedingungen. Anschlussfrage: 'Was würde es brauchen, um auch die mentalen Modelle der Schulleitung anzusprechen?'","mini_form":"10-Minuten-Scan: Gruppe benennt still je eine Aktivität pro Bedingung (oder 'leer'). Ergebnis zeigen. Nur eine Frage stellen: 'Welche Ebene haben wir noch nie explizit bearbeitet?'","anlass_typen":["strategie","lernformat","retro"],"typ":"rahmenmodell","gruppen_sweetspot":"6–20 ideal, ab 4 möglich","stimmung_geeignet":["neugierig","frisch"]},{"id":"iceberg-systeme","name":"Iceberg (Systeme)","feld":"D","kurz":"Von Ereignisreaktion zu Strukturverständnis in einer geführten Abwärtsbewegung.","schritte":["Ein konkretes Ereignis wählen: Was ist passiert?","Muster/Trends darunter sammeln: Was passiert wiederholt?","Strukturen identifizieren: Was erzeugt diese Muster – Regeln, Anreize, Beziehungen?","Mentale Modelle freilegen: Welche Annahmen halten die Strukturen am Leben?","Hebel auf jeder Ebene diskutieren – je tiefer, desto wirksamer"],"zweck":"Von Ereignisreaktion zu Strukturverständnis kommen, in einer einzigen geführten Abwärtsbewegung.","hinweise":"Funktioniert am besten mit einem realen, emotional besetzten Ereignis der Gruppe. Bei den mentalen Modellen wertschätzend bleiben – dort wird es persönlich.","phasen":["verstehen"],"ebenen":["team","organisation","netzwerk","feld"],"modi":["klaerung","reflexion"],"formate":["workshop","teamentwicklung","prozessbegleitung"],"dauer_min":30,"dauer_max":90,"gruppe_min":3,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Ecochallenge.org – A Systems Thinking Model: The Iceberg","url":"https://ecochallenge.org/iceberg-model/"}],"wann_passt":["Ein Team reagiert immer wieder auf dasselbe Ereignis (Krise, Konflikt, Fehler) ohne zu verstehen, was es erzeugt – das Iceberg-Modell führt die Gruppe in 30–45 Minuten von der Ereignisreaktion zur Strukturanalyse, ohne Systemtheorie erklären zu müssen.","Workshop-Einstieg in ein belastendes Thema: Statt direkt in Lösungen zu gehen, hilft das Modell, die Tiefe des Problems zu spüren – besonders wenn die Gruppe bisher nur auf Symptomebene diskutiert hat.","Lernformat für Führungskräfte, die Systemdenken noch nicht kennen: Das Bild des Eisbergs ist intuitiv zugänglich und funktioniert auch ohne Vorkenntnisse.","Konflikt-Vorbereitung: Bevor eine Mediation beginnt, hilft das Iceberg-Modell, mentale Modelle und Strukturen hinter dem Konflikt zu verstehen – nicht als Gruppenübung mit Konfliktparteien, sondern als Analyse-Tool für die Facilitatorin."],"wann_nicht":["Wenn ein konkretes, unstrittiges operatives Problem vorliegt, das bekannt und lösbar ist – das Modell vertieft, wo manchmal nur gehandelt werden muss.","Als Ersatz für eine echte Systemanalyse: Das Iceberg-Modell öffnet die Tiefenebene, bildet aber keine Rückkopplungen ab – als Standalone reicht es für komplexe Systeme nicht.","Mit einer Gruppe, die zu erschöpft oder zu angespannt ist, um in Abstraktionen zu gehen – dann zuerst den Raum stabilisieren."],"fokusfragen":["'Was ist in den letzten Monaten immer wieder passiert – welches Muster erkennt ihr?' (Schritt von Ereignis zu Muster)","'Welche Strukturen – Regeln, Rollen, Anreize, Ressourcenflüsse – erzeugen diese Muster?' (Schritt von Muster zu Struktur)","'Welches Bild von der Welt, welche Überzeugung, welcher Glaube hält diese Strukturen in Position – und wer teilt ihn?' (Schritt zu mentalen Modellen; hier wird es persönlich, wertschätzend moderieren)"],"beispiel":"Ereignis: Das Team schlägt in Krisensitzungen immer wieder kurzfristige Notfall-Lösungen vor, ohne nachhaltig zu wirken. Muster: Seit 3 Jahren taucht alle 6 Monate dieselbe Krise auf. Strukturen: Finanzierungszyklen belohnen Aktivität, nicht Wirkung; kein Budget für strukturelle Prävention; Führung wechselt alle 2 Jahre. Mentales Modell: 'Wir müssen zeigen, dass wir handeln – sonst verlieren wir Vertrauen.' Anschlussfrage: 'Was würde es brauchen, um dieses Bild im Feld zu verändern – und wer müsste das hören?'","mini_form":"Schnell-Iceberg in 15 Minuten: Nur zwei Ebenen – Ereignis (Was ist passiert?) und Muster (Was passiert immer wieder?). Drei Post-its pro Person, dann clustern. Einstieg in die Strukturfrage als Hausaufgabe.","anlass_typen":["strategie","lernformat","retro","krisensitzung"],"typ":"methode","gruppen_sweetspot":"5–15 ideal, bis 25 mit Untergruppen möglich","stimmung_geeignet":["neugierig","belastet","skeptisch"]},{"id":"conflict-map-onion-tree-wheel","name":"Conflict Map/Onion/Tree/Wheel","feld":"D","kurz":"Einen Konflikt strukturiert zerlegen – Akteure, Ursachen und Bedürfnisse hinter Positionen sichtbar machen.","schritte":["Konflikt und Analyseziel benennen","EIN Tool pro Session wählen: Map (Akteure/Beziehungen/Allianzen), Onion (Positionenâ†’Interessenâ†’Bedürfnisse), Tree (Wurzeln/Stamm/Äste), Wheel (sechs Konfliktdimensionen)","Gemeinsam auf Großformat befüllen","Perspektivunterschiede in der Gruppe sichtbar machen und stehen lassen","Ansatzpunkte für Bearbeitung ableiten"],"zweck":"Einen Konflikt strukturiert zerlegen – Akteure, Ursachen und Bedürfnisse hinter Positionen sichtbar machen.","hinweise":"Die Analyse ist immer perspektivisch – mehrere Karten verschiedener Subgruppen vergleichen statt eine wahre Karte erzwingen. Wann NICHT: gemeinsam mit hocheskalierten Konfliktparteien ohne erfahrene Moderation – die Analyse selbst wird dann zum Kampfplatz.","phasen":["verstehen","konflikt"],"ebenen":["team","organisation","netzwerk","feld"],"modi":["klaerung","konflikt"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Mason/Rychard (CSS ETH Zürich) – Conflict Analysis Tools (PDF)","url":"https://css.ethz.ch/content/dam/ethz/special-interest/gess/cis/center-for-securities-studies/pdfs/Conflict-Analysis-Tools.pdf"},{"typ":"buch","titel":"SCA Training Manual (Cambodia)"},{"typ":"buch","titel":"Simon Fisher et al.: Working with Conflict (Zed Books, 2000)"},{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 1: Conflict Analysis"}],"wann_passt":["Konfliktklärungs- oder Strategieprozess (6–20 Personen), wenn ein komplexer Konflikt visualisiert werden soll: Onion-Modell trennt Positionen (was wir fordern) von Interessen (was wir wirklich brauchen) von Bedürfnissen (was wir nicht verhandeln) — entscheidend für Durchbrüche in verfahrenen Situationen.","Ausbildungskontext (Lernformat): Die Unterscheidung zwischen Ursachen, treibenden Faktoren und Akteur:innen eines Konflikts (Konfliktbaum/Radmodell) macht Komplexität handhabbar und erzeugt gemeinsames Verständnis im Team.","Vor Verhandlungsprozessen: Konfliktlandkarte als Vorbereitung — wer sind die Akteur:innen, was sind ihre Positionen und Interessen, wo gibt es Überschneidungen?"],"wann_nicht":["In akuter Eskalation ohne Deeskalationsschritt davor: Visualisierung funktioniert nur, wenn die Beteiligten bereit sind, analytisch auf den Konflikt zu schauen, statt emotional darin zu stecken.","Als Endprodukt statt als Arbeitsmittel: Die Karte ist nie 'fertig' — sie muss aktualisiert werden, wenn sich der Kontext verändert."],"fokusfragen":["„Wenn wir die Zwiebel schälen: Was ist die offizielle Position jeder Partei — und was steckt darunter, welches echte Interesse?“ (Onion-Logik)","„Was sind die treibenden Faktoren, die den Konflikt am Leben erhalten — und welche davon können wir beeinflussen?“ (Konfliktbaum: Ursachen vs. Symptome)","„Wer profitiert davon, dass dieser Konflikt weitergeht — und wer leidet am meisten?“ (Akteur:innen-Analyse)"],"beispiel":"Onion in einer Team-Klärungs-Session: Zwei Abteilungen streiten um Budget. Position A: 'Wir brauchen 30% mehr.' Position B: 'Das ist nicht gerechtfertigt.' Onion-Frage an Abteilung A: 'Was braucht ihr wirklich hinter dem Mehr-Budget?' Interesse: Planungssicherheit für das nächste Jahr. Bedürfnis: Anerkennung der strategischen Bedeutung der Arbeit. Anschlussfrage: 'Wie könnte Planungssicherheit auch ohne 30% mehr entstehen?' – das öffnet Optionen jenseits der ursprünglichen Position.","mini_form":"Schnell-Akteursmap in 15 Minuten: Einen Kreis in die Mitte des Flipcharts (= der Konflikt/das Thema). Dann alle Akteur:innen drumherum eintragen, Pfeile je nach Beziehung. Drei Farben: unterstützt / blockiert / neutral. Reicht als Orientierung für die nächste Verhandlungsphase.","anlass_typen":["konfliktklaerung","strategie","lernformat"],"typ":"werkzeug","gruppen_sweetspot":"5–20 Personen","stimmung_geeignet":["neugierig","angespannt","skeptisch"]},{"id":"cynefin","name":"Cynefin","feld":"D","kurz":"Erkennen, welche Art Problem vorliegt – und welche Handlungslogik dazu passt.","schritte":["Die Domänen einführen: clear, kompliziert, komplex, chaotisch plus Verwirrung","Aktuelle Herausforderungen der Gruppe auf Karten sammeln","Karten gemeinsam den Domänen zuordnen – Streitfälle diskutieren","Pro Domäne die passende Handlungslogik ableiten","Konsequenz prüfen: Wo behandeln wir Komplexes wie Kompliziertes?"],"zweck":"Erkennen, welche Art Problem vorliegt – und welche Handlungslogik dazu passt.","hinweise":"Domänen sind kontextabhängig, keine festen Etiketten. Häufigster Fehler: Verwechslung von komplex und kompliziert (Expertenplan statt Experiment). Kein Persönlichkeitsraster.","phasen":["verstehen","planen"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung","entscheidung"],"formate":["workshop","teamentwicklung","prozessbegleitung"],"dauer_min":45,"dauer_max":90,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The Cynefin Co – About the Cynefin Framework","url":"https://thecynefin.co/about-us/about-cynefin-framework/"}],"wann_passt":["Ein Führungsteam behandelt unterschiedliche Herausforderungen mit derselben Handlungslogik (Best Practice auf alles) – Cynefin als Diagnose-Brille macht sichtbar, dass komplex nicht gleich kompliziert ist und welche Konsequenzen das für Steuerung hat.","Strategischer Planungsprozess in einer Organisation mit vielen Themen unterschiedlicher Art: Cynefin als Sortier-Heuristik hilft, Ressourcen auf die richtige Handlungslogik (Planung, Experiment, Triage) zu verteilen.","Teamday oder Klausur nach einer Krise: 'Was war das eigentlich – chaotisch, komplex, oder kompliziert?' als Reflexionsfrage im Rückblick.","Fortbildung für Führungskräfte oder Facilitator:innen, die im Komplexen arbeiten wollen: Das Framework ist gut lernbar und bleibt als mentale Heuristik hängen."],"wann_nicht":["Als Persönlichkeitstypologie oder zur Kategorisierung von Personen – Cynefin beschreibt Situationen, nicht Menschen.","Wenn die Entscheidung faktisch schon gefallen ist und das Framework nur zur Rationalisierung dienen würde.","Als alleinige Grundlage für eine strategische Entscheidung ohne Systemanalyse – Cynefin ordnet ein, aber analysiert nicht."],"fokusfragen":["'In welcher Domäne liegt dieses Problem wirklich – und wie begründen wir diese Einordnung?' (Kern-Frage; Einordnung soll begründet werden, nicht nur gefühlt)","'Wo behandeln wir gerade Komplexes wie Kompliziertes – also suchen wir nach Best Practice, wo Experimente nötig wären?' (Fehler-Diagnose)","'Was wäre die zur Domäne passende nächste Handlung – Sense-Categorize-Respond, Probe-Sense-Respond, oder Act-Sense-Respond?' (Konsequenz-Frage)"],"beispiel":"Strategie-Klausur einer NGO. Themen-Karten auf dem Tisch: 'IT-Migration', 'Neue Zielgruppe erschließen', 'Akuter Kommunikationskonflikt mit Förderer'. Einordnung: IT-Migration = kompliziert (Expert:innen können es lösen), Neue Zielgruppe = komplex (unbekannt, Experimente nötig), Konflikt = chaotisch (akuter Handlungsbedarf, stabilisieren zuerst). Anschlussfrage: 'Wir haben nur einen Modus bisher – welcher der drei braucht eine andere Handlungslogik?'","mini_form":"10-Minuten-Cynefin-Check: Jede Person ordnet ihre aktuell wichtigste Herausforderung einer Domäne zu und begründet mit einem Satz. Diskussion nur bei Streitfällen – diese sind besonders wertvoll.","anlass_typen":["strategie","lernformat","entscheidungstreffen","krisensitzung"],"typ":"rahmenmodell","gruppen_sweetspot":"4–15 ideal, bis 20 möglich","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"fuenf-cs","name":"Die 5 Cs","feld":"D","kurz":"Ein Impact Network auf seine fünf Kernaktivitäten hin auditieren und weiterentwickeln.","schritte":["Die fünf Aktivitäten einführen: Clarify · Convene · Cultivate trust · Coordinate · Collaborate","Das eigene Netzwerk pro C einschätzen (Skala + Beispiele)","Lücken identifizieren: Welches C ist unterversorgt?","Pro Lücke 1–2 konkrete nächste Aktivitäten entwickeln","Verantwortlichkeiten und Rhythmus vereinbaren"],"zweck":"Ein Impact Network systematisch auf seine fünf Kernaktivitäten hin auditieren und weiterentwickeln.","hinweise":"Die 5 Cs sind zyklisch, kein Stufenmodell – Netzwerke fallen auf Clarify und Cultivate immer wieder zurück. Nicht als Projektplan missverstehen.","phasen":["planen","verstetigen"],"ebenen":["netzwerk","feld"],"modi":["klaerung","reflexion"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"SSIR – Five Steps to Building an Effective Impact Network","url":"https://ssir.org/articles/entry/five_steps_to_building_an_effective_impact_network"},{"typ":"buch","titel":"David Ehrlichman: Impact Networks (Berrett-Koehler, 2021)"}],"wann_passt":["Netzwerk-Review nach dem ersten oder zweiten Jahr: Das 5-Cs-Raster (Clarify, Convene, Cultivate Trust, Coordinate, Collaborate) gibt dem Netzwerk eine gemeinsame Sprache, um einzuschätzen, wo es stark ist und wo es hakt – ohne externe Bewertung von außen.","Kick-off einer neuen Netzwerk-Initiative: Die 5 Cs als Planungsrahmen einführen und von Beginn an für jedes C eine Mindest-Aktivität benennen – das verhindert, dass das Netzwerk in reinem Convening stecken bleibt.","Klausur einer Steuerungsgruppe, die merkt, dass das Netzwerk an Kraft verliert: Welches C ist unterversorgt? Häufig: Clarify (gemeinsame Ausrichtung verwässert) oder Cultivate Trust (nach Wachstum nicht mitgewachsen).","Fortbildung zu Impact Networks als Lernformat – die 5 Cs sind intuitiv zugänglich und sofort auf reale Netzwerke der Teilnehmenden anwendbar."],"wann_nicht":["Als Projektplan-Ersatz – die 5 Cs sind zyklisch, nicht sequenziell; wer sie als Stufen liest, plant einen Prozess, der so nicht funktioniert.","In einer Organisation, die kein Netzwerk ist – das Raster ist auf lose gekoppelte Multi-Akteur-Konstellationen zugeschnitten, nicht auf Teams oder Hierarchien.","Als alleinige Planungsgrundlage ohne Bezug zur spezifischen Geschichte und Dynamik des Netzwerks – die 5 Cs sind Heuristik, kein Fahrplan."],"fokusfragen":["'Wenn wir auf einer Skala von 1–10 einschätzen: Wo sind wir bei jedem C – und was fehlt beim schwächsten?' (Diagnose-Einstieg)","'Bei Cultivate Trust: Wann haben wir zuletzt bewusst Zeit für Vertrauen investiert – und was hat das ausgelöst?' (Konkretisierung des oft vernachlässigten C)","'Bei Clarify: Würden alle Netzwerkmitglieder unseren gemeinsamen Zweck identisch formulieren – oder divergiert er still?' (Überprüfungs-Frage)"],"beispiel":"Netzwerk-Review: Gruppe bewertet die 5 Cs auf Karten (1–5 Sterne). Ergebnis: Convene ★★★★, Coordinate ★★★, Collaborate ★★, Clarify ★★, Cultivate Trust ★. Diskussion: 'Wir treffen uns viel, aber ohne klaren gemeinsamen Zweck – und Vertrauen haben wir nie explizit bearbeitet.' Nächster Schritt: ein Termin nur für Clarify (gemeinsamer Zweck-Workshop) und ein Netzwerk-Treffen mit persönlichem Storytelling-Format für Trust.","mini_form":"5-C-Schnellcheck in 10 Minuten: Jedes C auf einem Flipchart, alle geben Punkte (Klebepunkte oder Zählen). Ergebnis zeigen, eine Lücke benennen, eine konkrete nächste Aktivität vereinbaren.","anlass_typen":["netzwerktreffen","strategie","retro"],"typ":"methode","gruppen_sweetspot":"6–20 ideal, ab 3 möglich","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"network-weaving","name":"Network Weaving (Holley)","feld":"D","kurz":"Verbindungen über Silos hinweg gezielt stiften, statt auf zufällige Vernetzung zu hoffen.","schritte":["Eigenes Beziehungsnetz skizzieren: Wen kenne ich, wer kennt wen?","Muster lesen: Cluster, Brücken, isolierte Knoten","Closing triangles: konkrete Paare identifizieren, die sich kennen sollten","Verbindungs-Verabredungen treffen (wer stellt wen wem bis wann vor)","Follow-up-Termin für die Ernte der neuen Verbindungen setzen"],"zweck":"Verbindungen über Silos hinweg gezielt stiften, statt auf zufällige Vernetzung zu hoffen.","hinweise":"Weaving ist eine Daueraufgabe, keine Einzelaktion – Rolle der Weaver:innen explizit benennen. Qualität vor Quantität: wenige gut vorbereitete Vorstellungen wirken mehr als Adressenlisten.","phasen":["verstetigen","oeffnen"],"ebenen":["netzwerk","feld"],"modi":["verbindung","vertrauen"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Krebs/Holley – Building Smart Communities through Network Weaving (PDF)","url":"http://www.orgnet.com/BuildingNetworks.pdf"},{"typ":"buch","titel":"June Holley: Network Weaver Handbook (2012)"}],"wann_passt":["Netzwerktreffen mit Teilnehmenden, die sich kaum kennen oder in getrennten Clustern operieren – Network Weaving als explizite Übung: Wer sollte hier wen kennen, und warum? Konkrete Vorstellungsverabredungen mit Follow-up.","Einzelbegleitung einer Netzwerk-Koordinatorin, die ihre Weaving-Praxis reflektieren will: Eigenes Beziehungsnetz skizzieren, Cluster und Brücken lesen, nächste 'closing triangles' benennen.","Strategische Phase eines Netzwerks, in der neue Akteure ins Feld geholt werden sollen – Network Weaving als strukturierter Erweiterungs-Prozess statt zufälliger Begegnung.","Netzwerk-Klausur nach Wachstum: 'Wir haben mehr Mitglieder, aber die alten Silos sind geblieben' – Weaving-Übung zur gezielten Verbindung zwischen Clustern."],"wann_nicht":["In Gruppen, wo das Vertrauen so niedrig ist, dass eine Vorstellung zu einer anderen Person als Zumutung wirkt – zuerst Common-Ground herstellen.","Als Einzel-Event ohne Follow-up: Weaving-Effekt zeigt sich erst nach der zweiten und dritten Verbindung – ohne Nachhalten verpufft die Übung.","Wenn die Gruppe zu groß ist und keine klare Weaving-Rolle oder -Koordination existiert: Network Weaving ohne Weaver:in wird zur losen Vernetzung ohne Richtung."],"fokusfragen":["'Wen kenne ich gut – und wen sollten diese Personen sich gegenseitig kennen, aber kennen sich noch nicht?' (Closing-Triangles-Einstieg)","'Welche Verbindung zwischen zwei Personen oder Organisationen in diesem Netzwerk hätte den größten Multiplikatoreffekt?' (strategische Weaving-Frage)","'Wer ist im Netzwerk isoliert oder am Rand – und warum? Was hält ihn/sie dort?' (Randknoten-Diagnose)"],"beispiel":"Netzwerktreffen, 15 Personen aus verschiedenen Organisationen. Übung: Jede Person skizziert auf einer Karte ihre zwei wichtigsten Verbindungen im Raum. Dann Frage: 'Wen im Raum kennst du kaum, obwohl eure Arbeit Berührungspunkte hat?' Paare bilden, 5 Minuten kennenlernen. Anschließend: Wer übernimmt die Weaving-Verantwortung für diese neue Verbindung bis zum nächsten Treffen?","mini_form":"Closing-Triangles in 10 Minuten: Jede Person schreibt zwei Namen auf – 'Diese Person und jene Person kenne ich beide gut, aber sie kennen sich nicht.' Kurzvorstellung im Plenum, Kontakt-Versprechen.","anlass_typen":["netzwerktreffen","kickoff","strategie"],"typ":"methode","gruppen_sweetspot":"8–20 ideal; auch als Coaching-Tool für Einzelpersonen","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"trust-building","name":"Trust Building","feld":"D","kurz":"Vertrauen als Arbeitsinfrastruktur eines Netzwerks gezielt und beschleunigt aufbauen.","schritte":["Format wählen, das gemeinsame Erfahrung mit persönlichem Teilen verbindet","Paar-Interviews zu Werdegang und Motivation: Warum bist du bei diesem Thema?","Gemeinsamkeiten ernten – das geteilte Stück Boden benennen","Eine kleine echte Aufgabe gemeinsam bearbeiten","Kurz reflektieren: Wie war die Zusammenarbeit, was hat Vertrauen auf-/abgebaut?"],"zweck":"Vertrauen als Arbeitsinfrastruktur eines Netzwerks gezielt und beschleunigt aufbauen.","hinweise":"Vertrauen entsteht aus wiederholter Erfahrung, nicht aus einer Übung – Rhythmus wichtiger als Intensität. Persönliches Teilen dosieren, Überforderung erzeugt Rückzug.","phasen":["ankommen","verstetigen"],"ebenen":["team","netzwerk"],"modi":["vertrauen","verbindung"],"formate":["workshop","teamentwicklung","prozessbegleitung"],"dauer_min":30,"dauer_max":90,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","beteiligend"],"blocktyp":["kern","einstieg"],"quellen":[{"typ":"online","titel":"SSIR – The Tactics of Trust (Ehrlichman/Sawyer)","url":"https://ssir.org/articles/entry/the_tactics_of_trust"}],"wann_passt":["Auftakt einer neuen Koalition oder eines neuen Netzwerks: Bevor inhaltliche Arbeit beginnt, eine halbe Stunde für Paar-Interviews (Werdegang, Motivation) – das beschleunigt Vertrauen mehr als jede Teamübung, weil echte Geschichten entstehen.","Nach einem Rückschlag oder Vertrauensverlust im Team: Eine gemeinsame kleine echte Aufgabe (nicht Übung!) kombiniert mit anschließender Reflexion über die Zusammenarbeit – das Vertrauen wird durch Handeln wieder aufgebaut, nicht durch Reden.","Netzwerktreffen mit wechselnden Teilnehmenden: Vertrauen nicht voraussetzen, sondern eine kurze Begegnungssequenz einplanen (Paar-Gespräch, gemeinsame Gemeinsamkeiten finden), die Fremde zu Bekannten macht.","Teamentwicklung für ein verteiltes, digitales Team: explizite Trust-Building-Struktur in Onsites einbauen – informelle Zeit strukturiert gestalten statt dem Zufall überlassen."],"wann_nicht":["Als Ersatz für das Gespräch über konkrete Vertrauensverletzungen – Trust Building baut Infrastruktur auf, repariert aber keinen Bruch, der adressiert werden muss.","Wenn Beteiligung nicht freiwillig ist oder Asymmetrien zu groß sind (Vorgesetzte:r im Raum mit echter Weisungsmacht) – dosiertes persönliches Teilen erzeugt dann Druck statt Sicherheit.","Als einmalige Aktion: Vertrauen entsteht aus Wiederholung, eine einzelne Trust-Building-Session ohne Folge-Rhythmus verpufft."],"fokusfragen":["'Was hat dich zu diesem Thema gebracht – was steckt dahinter für dich persönlich?' (Motivationsfrage; öffnet echte Begegnung)","'Was hast du an der gerade gemeinsam gemachten Aufgabe als leicht erlebt, was als schwierig – und was sagt das über unsere Zusammenarbeit?' (Reflexion nach gemeinsamer Aufgabe)","'Was bräuchtest du von dieser Gruppe, damit du dich wirklich einbringen kannst?' (Bedarfs-Frage; macht unausgesprochene Erwartungen explizit)"],"beispiel":"Netzwerk-Auftakt, 12 Personen aus 8 Organisationen. Paar-Interview (8 Minuten): 'Erzähl mir von einem Moment, in dem du gemerkt hast, dass dir dieses Thema wirklich wichtig ist.' Anschließend jede Person stellt ihre Gesprächspartnerin/ihren Gesprächspartner vor. Dann gemeinsame Mini-Aufgabe (10 Minuten): 'Einigt euch auf drei Worte, die beschreiben, wie wir miteinander arbeiten wollen.' Abschluss: Kurze Reflexion, was Vertrauen aufgebaut hat.","mini_form":"Paar-Interview in 8 Minuten als Einstieg: Eine Frage, beide sprechen, dann kurze Vorstellung. Kein weiteres Format nötig – allein das Zuhören schafft Vertrauen.","anlass_typen":["kickoff","netzwerktreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"6–20 ideal, bis 30 mit parallelen Paaren/Kleingruppen","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"convening","name":"Convening","feld":"D","kurz":"Begegnungsräume so gestalten, dass Beziehungen entstehen – nicht nur Programm abläuft.","schritte":["Zweck der Zusammenkunft präzise klären: Was soll zwischen den Menschen entstehen?","Teilnehmenden-Mix designen: Wer muss im Raum sein, welche Stimmen fehlen?","Format und Raum als Beziehungsarchitektur planen (Sitzordnung, Kleingruppen, informelle Zeit)","Begegnungsdichte maximieren: lange Pausen, Mahlzeiten, wechselnde Konstellationen","Nachhalten planen: Wie bleiben entstandene Verbindungen lebendig?"],"zweck":"Begegnungsräume so gestalten, dass Beziehungen entstehen – nicht nur Programm abläuft.","hinweise":"Häufigster Fehler: Programm zu voll, Begegnung verkümmert. Convening-Macht ist Macht – wer einlädt, prägt das Feld, Auswahl transparent machen.","phasen":["planen","ankommen"],"ebenen":["netzwerk","feld"],"modi":["verbindung","vertrauen"],"formate":["workshop","grossgruppe","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":2,"gruppe_max":10,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Rockefeller Foundation – Gather: The Art and Science of Effective Convening (PDF)","url":"https://www.rockefellerfoundation.org/wp-content/uploads/Gather-The-Art-and-Science-of-Effective-Convening.pdf"}],"wann_passt":["Planung eines Netzwerktreffens oder einer Fachtagung: Convening als explizite Design-Aufgabe – Wer muss im Raum sein? Wie viel Programm, wie viel Begegnungszeit? Welche Raumgestaltung fördert Gespräch über Silos hinweg?","Eine Organisation will erstmals Akteure aus verschiedenen Lagern zusammenbringen, die sich sonst meiden – Convening als sorgfältig vorbereitete Einladungsarchitektur, in der Status-Differenz abgepuffert und gemeinsamer Boden markiert wird.","Netzwerk-Koordination: Regelmäßige Gastgeber-Rolle als Wirkstrategie – wer convened, prägt Felder. Dieses Meta-Bewusstsein in der Strategie verankern.","Evaluations-Frage nach einem Treffen: 'Haben Beziehungen entstanden oder nur Information fließen gelassen?' – Convening als Qualitätskriterium für Events."],"wann_nicht":["Wenn das Treffen primär Informationsvermittlung ist, nicht Beziehungsaufbau – dann reicht ein anderes Format.","Wenn die Einladungsmacht intransparent bleibt: Wer einlädt und wen, prägt das Feld machtpolitisch. Ohne Transparenz darüber entsteht Misstrauen.","Als kurzfristig zusammengewürfeltes Format ohne Vorbereitung der Frage und des Teilnehmenden-Mix – das Ergebnis ist ein beliebiges Treffen, kein Convening."],"fokusfragen":["'Welche Beziehungen sollen nach diesem Treffen existieren, die vorher nicht existiert haben – und wie designen wir dafür den Raum?' (Ergebnis-Frage für Convening-Design)","'Wessen Stimme fehlt im Raum – und was würde sie einbringen, das wir ohne sie nicht haben?' (Teilnehmenden-Mix-Frage)","'Wie viel informelle Zeit ist eingeplant – und ist das genug für echte Begegnung?' (Zeitarchitektur-Frage)'"],"beispiel":"Vorbereitung einer zweitägigen Fachtagung. Convening-Design-Frage: 'Welche zwei Personen in diesem Feld sollten unbedingt miteinander sprechen?' Liste von 5 strategischen Paaren. Design-Konsequenz: Tischplan für Abendessen gezielt nach diesen Paaren, Kaffeepausen mit wechselnden Kleingruppen-Formaten, ein Open-Space-Block, damit Energie folgen kann. Evaluationsfrage am Ende: 'Wer hat heute jemanden getroffen, den ihr dringend wieder treffen wollt?'","mini_form":"Convening-Review in 10 Minuten nach einem Treffen: 'Welche Begegnung war für dich am wertvollsten – und was hat sie ermöglicht?' Daraus für das nächste Mal lernen.","anlass_typen":["netzwerktreffen","kickoff","strategie"],"typ":"methode","gruppen_sweetspot":"Kein fixes Sweetspot – Convening ist Planungs-Methode, keine Gruppen-Größen-gebundene Übung; relevant ab 2 einzuladenden Parteien","stimmung_geeignet":["frisch","neugierig"]},{"id":"self-organization","name":"Self-Organization","feld":"D","kurz":"Gerade genug Struktur schaffen, damit Ordnung aus dem System selbst entsteht statt von oben.","schritte":["Minimal Specs definieren: Purpose, wenige Prinzipien, klare Grenzen – nicht mehr","Verantwortung an selbstgewählte Kreise/Initiativen geben (wer Energie hat, handelt)","Transparenz-Infrastruktur aufsetzen (sichtbare Vorhaben, offene Kommunikation)","Regelmäßige Sense-making-Runden: Was entsteht, was braucht das Ganze?","Struktur nur dort nachlegen, wo Reibung wiederholt auftritt"],"zweck":"Gerade genug Struktur schaffen, damit Ordnung aus dem System selbst entsteht statt von oben.","hinweise":"Selbstorganisation heißt nicht strukturlos – ohne klaren Purpose und Grenzen kippt sie in informelle Machtstrukturen (Tyranny of Structurelessness). Führungsrolle wandelt sich, verschwindet nicht.","phasen":["planen","verstetigen"],"ebenen":["organisation","netzwerk"],"modi":["klaerung","entscheidung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Margaret Wheatley – Self-Organization: The Irresistible Future of Organizing","url":"https://margaretwheatley.com/articles/irresistiblefuture.html"}],"wann_passt":["Eine Organisation überlegt, ob und wie sie Hierarchie abbauen und dezentrale Steuerung einführen will – Self-Organization als Rahmenmodell hilft, die Konsequenzen zu durchdenken: Was müssen Minimal Specs leisten? Wie verändert sich Führung?","Diagnose-Moment nach Wachstum: 'Unsere alten Steuerungsmechanismen passen nicht mehr' – das Rahmenmodell hilft, die richtige Frage zu stellen: Welche Struktur reicht für das, was entstehen soll?","Fortbildung oder Strategie-Input für Führungskräfte, die Selbstorganisation einführen wollen: Die Unterscheidung strukturlos vs. minimal strukturiert ist die zentrale Lernerkenntnis.","Netzwerk-Governance-Design: Wie viel Koordination braucht ein loses Netzwerk, ohne seine Energie zu töten? Self-Organization als Brille für die Design-Entscheidung."],"wann_nicht":["Als Begründung, auf Struktur ganz zu verzichten – 'Wir sind selbstorganisiert' kann zur Ausrede werden; das Rahmenmodell zeigt gerade, dass klare Purpose und Grenzen notwendig sind.","In Krisen, die sofortige Entscheidungen brauchen – Selbstorganisation ist langsamerer, verteilter Prozess; in der Krise braucht es klare Führung.","Wenn die Gruppe keine gemeinsame Basis für Entscheidungen hat – Selbstorganisation setzt gemeinsamen Purpose voraus, der explizit entwickelt werden muss."],"fokusfragen":["'Was sind die Minimal Specs für unser System – welche drei bis fünf Prinzipien würden ausreichen, damit die richtigen Entscheidungen entstehen?' (Governance-Design-Frage)","'Wer hat in unserem System gerade informelle Macht, die wir nicht explizit gemacht haben – und wie wirkt das?' (Tyranny-of-Structurelessness-Prüfung)","'Welche Stelle im System braucht gerade mehr Struktur, weil Reibung wiederholt auftritt – und warum ist sie noch nicht da?' (Nachjustierungs-Frage)'"],"beispiel":"Workshop mit dem Leitungsteam einer wachsenden sozialen Organisation. Frage: 'Welche Entscheidungen sollen dezentral getroffen werden – und welche Minimal Specs müssen dafür gelten?' Ergebnis: Drei Prinzipien (Transparenz über Ressourcen, Rückbindung an Purpose, Information des Gesamtsystems bei Entscheidungen über X€). Anschlussfrage: 'Was passiert, wenn jemand dagegen verstößt – und wer bemerkt das?' – das öffnet die Governance-Diskussion konkret.","mini_form":"Minimal-Specs-Brainstorm in 15 Minuten: 'Welche drei Prinzipien müssten gelten, damit dieses System ohne uns gute Entscheidungen trifft?' Still notieren, dann zusammenführen.","anlass_typen":["strategie","lernformat","entscheidungstreffen"],"typ":"rahmenmodell","gruppen_sweetspot":"5–20 als Planungsrahmen; keine Gruppenübung per se","stimmung_geeignet":["neugierig","frisch"]},{"id":"netzwerk-vs-hierarchie","name":"Netzwerk vs. Hierarchie","feld":"D","kurz":"Klarheit gewinnen, wann Netzwerklogik die passende Organisationsform ist.","schritte":["Die zwei Logiken gegenüberstellen: Hierarchie (Steuerung, Effizienz) vs. Netzwerk (Emergenz, Anpassung)","Das eigene Vorhaben einordnen: kompliziert-planbar oder komplex-verteilt?","Prüfen: Wo behandeln wir ein Netzwerkproblem mit Hierarchie-Werkzeugen?","Konsequenzen für Governance, Rollen und Entscheidungswege ableiten"],"zweck":"Klarheit gewinnen, wann Netzwerklogik die passende Organisationsform ist – für Probleme, die niemand allein lösen kann.","hinweise":"Keine Entweder-oder-Debatte führen – die meisten Vorhaben brauchen beides in verschiedenen Zonen. Netzwerk-Romantik vermeiden: Netzwerke sind langsamer bei operativen Entscheidungen.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","prozessbegleitung"],"dauer_min":30,"dauer_max":60,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Converge – Resources on Impact Networks","url":"https://www.converge.net/"},{"typ":"buch","titel":"David Ehrlichman: Impact Networks (Berrett-Koehler, 2021)"}],"wann_passt":["Eine Organisation oder Koalition diskutiert Governance-Fragen und will wissen, welche Steuerungslogik zu welchem Teil ihrer Arbeit passt – das Rahmenmodell gibt eine strukturierte Gegenüberstellung ohne ideologische Wertung.","Kick-off eines neuen Kooperationsprojekts mit mehreren Organisationen: Frühzeitig klären, welche Entscheidungen hierarchisch (intern) und welche netzwerkartig (gemeinsam) getroffen werden.","Fortbildung für Führungskräfte, die in hybriden Strukturen arbeiten – das Modell hilft, die eigene Organisation zu verorten und bewusst mit beiden Logiken zu arbeiten.","Diagnose nach Frustration: 'Wir funktionieren nicht als Netzwerk, obwohl wir keines sind' – das Modell klärt den Kategorienfehler."],"wann_nicht":["Als normatives Argument für oder gegen Hierarchie – das Modell ist analytisch, keine Ideologie.","Als Ersatz für konkrete Governance-Entscheidungen: Das Modell zeigt Logiken, entscheidet nicht.","Wenn die Gruppe zu müde oder zu belastet ist für konzeptionelle Arbeit – dann zuerst den konkreten Anlass klären."],"fokusfragen":["'Welche unserer aktuellen Herausforderungen ist planbar-komplex – und welche ist emergent-verteilt?' (Einordnungs-Frage)","'Wo wenden wir gerade Hierarchie-Logik auf ein Netzwerkproblem an – oder umgekehrt?' (Kategorienfehler-Diagnose)","'Was wäre der konkrete Unterschied in Entscheidung, Kommunikation und Steuerung, wenn wir für diesen Teil Netzwerk-Logik anwenden würden?' (Konsequenz-Frage)'"],"beispiel":"Strategie-Klausur einer Koalition. Frage: 'Für welche Entscheidungen brauchen wir Hierarchie – und für welche Netzwerk?' Karten-Sortierung: 'Budget-Entscheidung' → Hierarchie (klare Accountability), 'Fachkonzept entwickeln' → Netzwerk (verteiltes Wissen), 'Öffentlichkeitsarbeit' → Hierarchie (Schnelligkeit), 'Neue Partnerorganisationen einladen' → Netzwerk (Emergenz). Erkenntnis: Wir haben bisher alles durch Hierarchie entschieden – das blockiert Emergenz bei Fachkonzepten.","mini_form":"10-Minuten-Sortierung: Aktuelle Entscheidungen auf Karten, zwei Spalten (Hierarchie/Netzwerk). Clustern, eine Überraschung benennen.","anlass_typen":["strategie","lernformat","entscheidungstreffen"],"typ":"rahmenmodell","gruppen_sweetspot":"4–15 ideal","stimmung_geeignet":["neugierig","frisch"]},{"id":"systems-oriented-design","name":"Systemic / Systems Oriented Design (Sevaldson)","feld":"D","kurz":"Komplexität eines Feldes gemeinsam externalisieren und daraus Design-Ansatzpunkte gewinnen.","schritte":["Thema und Systemgrenze festlegen","Gigamapping: alles Wissen auf eine sehr große Fläche bringen – Akteure, Prozesse, Materialflüsse, Geschichte","Beziehungen einzeichnen, zwischen Detailebene und Gesamtbild zoomen","ZIP-Analyse: Punkte markieren für Zoom (vertiefen), Innovation (Potenzial) und Pain (Problem)","Aus den markierten Punkten Designaufgaben ableiten"],"zweck":"Komplexität eines Feldes gemeinsam externalisieren und daraus Design-Ansatzpunkte gewinnen.","hinweise":"Die Map darf chaotisch sein – Vollständigkeit vor Schönheit. Physisch (Papier, mehrere Meter) deutlich stärker als digital. Zeitfresser, großzügig planen.","phasen":["verstehen","planen"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","klausur"],"dauer_min":90,"dauer_max":240,"gruppe_min":2,"gruppe_max":12,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Systems Oriented Design (Birger Sevaldson)","url":"https://systemsorienteddesign.net/"},{"typ":"online","titel":"Systems Oriented Design – Gigamapping Introduction (Sevaldson)","url":"https://systemsorienteddesign.net/index.php/giga-mapping/giga-mapping-descriptions/introduction-to-gigamapping"}],"wann_passt":["Ein Design- oder Innovationsteam will die Komplexität eines sozialen oder organisationalen Feldes visualisieren, bevor es Lösungen entwirft – Gigamapping als radikale Externalisierung aller beteiligten Faktoren auf eine sehr große Fläche.","Klausur eines interdisziplinären Teams (Design, Sozialwissenschaft, Praxis), das eine gemeinsame Systemsprache entwickeln will – der Mapping-Prozess selbst erzeugt kollektives Wissen.","Vorhaben mit vielen Akteuren, langen Zeitreihen und mehreren Systemebenen: SOD ist das einzige Format, das physisch groß genug ist, um alles auf einmal sichtbar zu halten.","Forschungs- oder Evaluations-Kontext, in dem qualitative Komplexität visualisiert werden soll – ZIP-Analyse markiert direkt aus der Karte Vertiefungsbereiche (Zoom), Potenziale (Innovation) und Schmerzpunkte (Pain)."],"wann_nicht":["Online-Kontext: SOD braucht sehr große Papier- oder Tafelfläche und physische Bewegung im Raum – digitale Boards sind ein schlechter Ersatz.","Wenn Zeit unter 3 Stunden: Gigamapping braucht 3–6 Stunden für ein brauchbares Ergebnis; in weniger Zeit entsteht eine oberflächliche Version, die frustriert.","Wenn eine klare Entscheidung in kurzem Zeitrahmen gebraucht wird – SOD ist Tiefenanalyse, kein Entscheidungsformat."],"fokusfragen":["'Was gehört alles zu diesem System – wer sind die Akteure, welche Ressourcen fließen, welche Geschichte steckt dahinter?' (Einstiegs-Expansionsfrage für Gigamap)","'Wo auf der Karte ziehen uns alle in die Tiefe – was braucht ein Zoom?' (ZIP-Analyse: Z)","'Welche Verbindungen auf der Karte überraschen uns – was haben wir nie zusammengedacht?' (Innovations-Frage, ZIP: I)","'Wo ist der Schmerz am größten – wo reibt es am meisten?' (ZIP: P)'"],"beispiel":"Klausur zu einem Stadtentwicklungs-Vorhaben. Gigamap auf 3×2 Meter Papier: Akteure (Stadtverwaltung, Bürger:innen, Investoren, NGOs), Prozesse (Planungsverfahren, Förderanträge), Materialflüsse (Flächen, Baumaterial, Geld), Geschichte (letzte 20 Jahre). Nach 3 Stunden: ZIP-Analyse. Zoom auf 'informelle Entscheidungswege in der Verwaltung'. Innovation: 'Bürger:innen kennen Investoren nicht – direkte Verbindung fehlt'. Pain: 'Förderanträge dauern 18 Monate – das tötet Initiative'. Designaufgabe: Wie beschleunigen wir Anträge ohne Qualitätsverlust?","mini_form":"Schnell-Systemkarte in 20 Minuten: Nur Akteure und die wichtigsten drei Verbindungen, auf A1. Dann eine ZIP-Frage stellen. Kein vollständiges Gigamapping – aber der Einstieg in die Systemsicht.","anlass_typen":["strategie","lernformat","kickoff"],"typ":"methode","gruppen_sweetspot":"3–10 ideal; über 12 wird die Map unkontrollierbar","stimmung_geeignet":["neugierig","frisch"]},{"id":"participatory-co-design","name":"Participatory / Co-Design","feld":"D","kurz":"Lösungen mit statt für Betroffene entwickeln – gelebte Expertise gleichwertig neben Fachexpertise stellen.","schritte":["Betroffene als gleichberechtigte Designpartner:innen gewinnen (nicht nur befragen)","Erfahrungen teilen: Geschichten, Journeys, gelebte Expertise sichtbar machen","Gemeinsam Lösungsideen entwickeln – alle gestalten, niemand liefert nur Input","Schnelle Prototypen bauen (Papier, Rollenspiel, Mock-up)","Mit weiteren Betroffenen testen und iterieren","Entscheidungsmacht über das Ergebnis explizit teilen"],"zweck":"Lösungen mit statt für Betroffene entwickeln – Expertise durch gelebte Erfahrung gleichwertig neben Fachexpertise stellen.","hinweise":"Größter Stolperstein ist Tokenismus: Beteiligung ohne echte Entscheidungsmacht beschädigt Vertrauen nachhaltig. Barrierefreiheit, Sprache und Bezahlung der Mitgestaltenden mitdenken.","phasen":["planen","oeffnen","vertiefen"],"ebenen":["organisation","netzwerk","feld"],"modi":["verbindung","klaerung"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":90,"dauer_max":240,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","spielerisch"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"KA McKercher (Beyond Sticky Notes) – What is Co-Design?","url":"https://www.beyondstickynotes.com/what-is-codesign"}],"wann_passt":["Produktentwicklung oder Policy-Design, bei dem die Lösung für Gruppen gedacht ist, die selten in Planungsprozessen sitzen – Co-Design holt gelebte Expertise in den Raum und verändert nicht nur das Produkt, sondern auch die Beziehung zwischen Entwicklerin und Nutzerin.","Wenn bisherige Lösungen nicht angenommen werden, obwohl sie gut durchdacht schienen – die Wahrscheinlichkeit liegt im fehlenden Einbezug der tatsächlichen Bedürfnisse und Kontexte der Betroffenen.","Community-Projekte im NGO-Kontext: Nicht 'Wir wissen, was ihr braucht', sondern gemeinsames Entwerfen – als Haltungs- und Strukturfrage für den gesamten Prozess.","Fortbildungskontext: Co-Design als Methodik lernen – iteratives Prototyping mit echten Nutzer:innen im Schnelldurchlauf zeigen."],"wann_nicht":["Wenn die Entscheidung faktisch schon gefallen ist und Co-Design nur Legitimation erzeugen soll – Tokenismus beschädigt das Vertrauen nachhaltig und ist schlechter als kein Co-Design.","Wenn keine Ressourcen für echte Feldphasen vorhanden sind: Ohne Kontakt zu Betroffenen bleibt Co-Design intern und verliert seinen Kern.","Ohne Klarheit über echte Entscheidungsmacht: Wenn Betroffene mitwirken, aber am Ende andere entscheiden, ohne Erklärung – das ist eine Verletzung des Ko-Design-Versprechens."],"fokusfragen":["'Wessen Erfahrungswissen steckt in dieser Frage – und wer ist noch nicht im Raum?' (Einladungs-Frage vor dem Start)","'Was erleben Menschen, die mit unserem Angebot in Kontakt kommen – was ist leicht, was ist schwer, was fehlt?' (Journey-Frage aus Betroffenen-Perspektive)","'Was würdet ihr anders bauen, wenn ihr die Entscheidungsmacht hättet – und was bräuchtet ihr dafür?' (Empowerment-Frage; testet, ob Co-Design ernst gemeint ist)'"],"beispiel":"NGO entwickelt ein Beratungsangebot für Geflüchtete. Co-Design-Session mit 6 betroffenen Personen und 3 Mitarbeitenden. Einstieg: 'Erzählt uns von dem Moment, in dem ihr Unterstützung gesucht habt – was hat geholfen, was nicht?' 15 Minuten Geschichten, dann gemeinsam Erkenntnisse clustern. 'How might we …'-Fragen ableiten. Papier-Prototypen für zwei Ideen bauen. Anschlussfrage: 'Was fehlt noch – was haben wir übersehen?' – die Lücken im Prototyp sind wertvollstes Feedback.","mini_form":"How-might-we in 15 Minuten: Drei Erkenntnisse aus Betroffenen-Gesprächen auswählen, in je eine HMW-Frage übersetzen, 5 Minuten Ideen generieren. Kein vollständiger Co-Design-Zyklus, aber der Kern der Haltung.","anlass_typen":["strategie","kickoff","lernformat","beteiligung"],"typ":"methode","gruppen_sweetspot":"6–16 ideal (ausgewogen zwischen Betroffenen und Gestaltenden)","stimmung_geeignet":["neugierig","frisch"]},{"id":"service-design","name":"Service Design","feld":"D","kurz":"Eine Dienstleistung konsequent aus Nutzendensicht durchleuchten und Brüche zwischen Erleben und Organisation finden.","schritte":["Eine Nutzer:innen-Persona wählen","Journey mappen: alle Schritte und Touchpoints der Dienstleistung aus Nutzersicht","Service Blueprint ergänzen: Frontstage (sichtbar) und Backstage (Prozesse, Systeme, Rollen) übereinanderlegen","Schmerzpunkte und Brüche markieren","Verbesserungen priorisieren und als Prototyp skizzieren"],"zweck":"Eine Dienstleistung konsequent aus Sicht der Nutzenden durchleuchten und Brüche zwischen Erleben und Organisation finden.","hinweise":"Journey auf echten Daten/Beobachtungen aufbauen, nicht auf Vermutungen des Teams. Backstage nicht weglassen – dort liegen meist die Ursachen der Frontstage-Probleme.","phasen":["verstehen","planen"],"ebenen":["organisation"],"modi":["klaerung"],"formate":["workshop","prozessbegleitung"],"dauer_min":90,"dauer_max":180,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Nielsen Norman Group – Service Design 101","url":"https://www.nngroup.com/articles/service-design-101/"}],"wann_passt":["Eine Organisation merkt, dass Nutzende abbrechen oder unzufrieden sind, aber nicht weiß wo – Customer/User Journey Mapping macht Brüche sichtbar, die intern unsichtbar sind, weil niemand das Ende-zu-Ende-Erlebnis im Blick hat.","Optimierungs-Workshop: Bestehendes Angebot durchleuchten, bevor neu entwickelt wird – Journey + Blueprint zeigen, was optimiert werden sollte statt ersetzt.","Interdisziplinäres Team aus Front- und Backstage-Rollen: Service Blueprint macht explizit, was Nutzer:innen sehen und was dahinter passiert – erzeugt Verständnis für die Arbeit der anderen Seite.","Social-Sector-Kontext: Welche Erfahrung macht eine antragstellende NGO mit einem Förder-Programm? Service Design bringt die Nutzendenperspektive in die Programm-Entwicklung."],"wann_nicht":["Wenn die Journey-Map aus Annahmen statt aus Beobachtungen und Interviews entsteht – dann ist es eine Wunsch-Map, kein Service Design.","Als rein visuelles Ergebnis ohne Konsequenz: Die Map hat Wert nur, wenn daraus priorisierte Verbesserungen folgen.","Für sehr frühe Konzeptphasen, wo noch kein Service existiert – dann ist Co-Design oder Human-Centered Design der richtigere Ansatz."],"fokusfragen":["'Welchen Schritt im Prozess erleben Nutzer:innen als besonders aufreibend – und warum passiert das?' (Schmerzpunkt-Frage aus Journey)","'Was passiert backstage in diesem Moment – und erklärt das den Frontstage-Schmerz?' (Blueprint-Verbindungsfrage)","'Welcher Touchpoint kostet uns am meisten Ressourcen, erzeugt aber den geringsten Nutzendenwert?' (Optimierungs-Priorität)'"],"beispiel":"Service-Design-Workshop für ein Beratungsangebot. Persona: 'Ayşe, 34, alleinerziehend, sucht Bildungsberatung.' Journey: Suche (unklar, wo anfangen), Anruf (Warteschleife), Ersttreffen (gut), Wartezeit auf Rückmeldung (2 Wochen, kein Status), Abschluss (kein Follow-up). Blueprint: Wartezeit backstage = Kapazitätsproblem in Buchungssystem. Priorität: Status-Update-System einrichten, kostet wenig, eliminiert größten Frust. Anschlussfrage: 'Was wäre der günstigste erste Schritt zur Verbesserung?'","mini_form":"Journey-Scan in 15 Minuten: Nur 5 Schritte (Erkenntnis, Erstkontakt, Nutzung, Problem, Ende). Pro Schritt: Was erleben Nutzende wirklich? Schmerzpunkte markieren. Kein Blueprint – aber der Blickwechsel passiert.","anlass_typen":["strategie","retro","lernformat"],"typ":"methode","gruppen_sweetspot":"4–12 ideal","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"human-centered-social-design","name":"Human-Centered / Social Design","feld":"D","kurz":"Gestaltung konsequent von menschlichen Bedürfnissen her denken – für Produkte wie für gesellschaftliche Wirkung.","schritte":["Inspiration: Interviews und Beobachtungen mit den Menschen, für die gestaltet wird","Synthese: Erkenntnisse clustern, Insights formulieren","How might we …?-Fragen ableiten","Ideation: breit Ideen generieren","Schnellen Prototyp bauen","Mit Nutzer:innen testen und lernen"],"zweck":"Gestaltung konsequent von menschlichen Bedürfnissen her denken – für Produkte wie für gesellschaftliche Wirkung.","hinweise":"In einer Session lässt sich der Zyklus nur im Schnelldurchlauf üben – für reale Projekte echte Feldphasen einplanen. Gefahr der Extraktion: Beforschte sollten vom Ergebnis profitieren.","phasen":["verstehen","planen"],"ebenen":["person","organisation","feld"],"modi":["klaerung"],"formate":["workshop","fortbildung"],"dauer_min":90,"dauer_max":240,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["beteiligend","spielerisch"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"IDEO.org – Design Kit: Methods","url":"https://www.designkit.org/methods"},{"typ":"online","titel":"IDEO.org – Design Kit: The Field Guide to Human-Centered Design","url":"https://www.designkit.org/resources/1"}],"wann_passt":["Workshop oder Fortbildung, in der Teilnehmende das Design-Denken-Prinzip ('vom Menschen her') erleben sollen – der Schnelldurchlauf (Empathize–Define–Ideate–Prototype–Test) in 2–3 Stunden macht die Haltung spürbar.","Frühe Phase eines sozialen Innovationsvorhabens, in der das Team noch nicht weiß, für wen und für welches Problem es eine Lösung entwickelt – HCD/Social Design als Explorations-Prozess vor der Lösung.","NGO-Kontext, in dem Angebote historisch von oben definiert wurden: HCD als kultureller Bruch, der den Entwicklungsprozess zur Gemeinschaft hin öffnet.","Fortbildung für Sozialarbeiter:innen oder Community-Entwickler:innen: Die Haltung 'zuerst verstehen, dann gestalten' als professionelles Prinzip einüben."],"wann_nicht":["Ohne echte Feld-/Empathie-Phase: Wenn keine Zeit für Interviews mit Betroffenen ist, bleibt HCD intern und verliert seinen Unterschied zu herkömmlichem Brainstorming.","Bei politisch aufgeladenem Thema ohne Reflexion der Forschungsbeziehung: Wer befragt wen, wem nützt das Ergebnis? Die Extraktions-Gefahr muss explizit besprochen werden.","Wenn schnelle operative Entscheidungen gebraucht werden – HCD ist erkundend und iterativ, kein Entscheidungsformat."],"fokusfragen":["'Was erleben Menschen, die mit diesem Problem konfrontiert sind – was sehen, fühlen, tun, sagen sie?' (Empathy-Map-Frage)","'Wie würden wir das Problem aus Sicht dieser Person formulieren – 'Wie könnten wir …'?' (How Might We – Fokussierungs-Frage)","'Was ist der einfachste Prototyp, mit dem wir heute lernen können, ob unsere Idee taugt?' (Prototyping-Frage – Bias towards action)'"],"beispiel":"Fortbildungs-Workshop für Mitarbeitende einer Jugendhilfe-Organisation. Aufgabe: In 2 Stunden den HCD-Zyklus einmal durchlaufen. Empathize: Paar-Interview innerhalb der Gruppe ('Erzähl mir von einem Moment, in dem du dich als Jugendliche:r unverstanden gefühlt hast'). Define: 'Die Person braucht …, weil …, aber …' – Insight-Satz formulieren. Ideate: 5 Ideen in 5 Minuten. Prototype: Rollenspiel als Prototyp für eine neue Gesprächsführung. Test: Feedback in der Gruppe. Erkenntnis: Der Zyklus funktioniert auch mini – die Haltung bleibt.","mini_form":"How-Might-We + 3 Ideen in 10 Minuten: Insight in eine HMW-Frage übersetzen, drei Ideen generieren, eine auswählen. Kein Interview nötig, wenn ein echter Insight vorhanden ist.","anlass_typen":["lernformat","kickoff","strategie"],"typ":"methode","gruppen_sweetspot":"4–12 ideal","stimmung_geeignet":["neugierig","frisch"]},{"id":"theory-u-presencing","name":"Theory U / Presencing","feld":"D","kurz":"Von der Wiederholung des Bekannten zu einem Handeln kommen, das sich an der entstehenden Zukunft orientiert.","schritte":["Thema benennen und Downloading erklären: gewohnte Denkmuster erkennen","Sensing-Übung: Empathie-Interview oder Perspektivwechsel mit einer betroffenen Person","Stille-Moment / geführtes Journaling: Was will hier entstehen? Was ist mein Anteil?","Crystallizing: Kernintention in einem Satz formulieren","Einen kleinen Prototyp-Schritt für die nächsten 72 Stunden festlegen"],"zweck":"Von der Wiederholung des Bekannten zu einem Handeln kommen, das sich an der entstehenden Zukunft orientiert.","hinweise":"Presencing-Phasen brauchen Vertrauen und Freiwilligkeit – Stille nicht erzwingen. Sprache nüchtern halten, sonst Esoterik-Abwehr in pragmatischen Gruppen. Das volle U ist ein Prozess über Wochen, nicht eine Session.","phasen":["vertiefen","oeffnen"],"ebenen":["person","team","organisation"],"modi":["selbstzugang","reflexion"],"formate":["workshop","klausur","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"u-school for Transformation – Theory U","url":"https://www.u-school.org/theory-u"},{"typ":"buch","titel":"C. Otto Scharmer: Theory U (2009)"},{"typ":"online","titel":"u.lab – Leading From the Emerging Future (MITx MOOC)","url":"https://www.edx.org/course/u-lab-leading-from-the-emerging-future"}],"wann_passt":["Klausur oder Retreat einer Führungsgruppe, die sich in Routinen festgefahren hat und einen echten Perspektivwechsel braucht – Theory U als Prozessrahmen für einen Tag (Sensing + Presencing + Crystallizing), nicht als mehrtägige Academy.","Einzelbegleitung oder Coaching, in der jemand aus alten Mustern herausfinden will: Die Journaling-Phase ('Was will hier entstehen?') als geführter Selbstzugang.","Netzwerk-Treffen mit Zukunftsfrage: Wenn eine Gruppe nicht mehr von der Vergangenheit her plant, sondern von der entstehenden Zukunft her – als Haltungs-Einstieg für strategische Arbeit.","Fortbildungskontext für Facilitator:innen, die lernen wollen, mit Tiefe zu arbeiten: Das U als Meta-Struktur verstehen, nicht als starres Format."],"wann_nicht":["In pragmatischen, operativen Gruppen ohne Vorwarnung – Stille, Presencing, Journaling wirken esoterisch wenn sie nicht erklärt und freiwillig sind.","Als Einzel-Session in 90 Minuten ohne Vorbereitung: Das U ist ein Prozess über Wochen; was in einer Session möglich ist, ist ein Ausschnitt, der das ernst nehmen muss.","Wenn die Gruppe gerade in akutem Krisenmodus ist – Presencing braucht innere Stille, die in der Krise nicht entsteht."],"fokusfragen":["'Was ist gerade das dringendste Thema, das du wegschiebst – und was würde passieren, wenn du dich ihm öffnest?' (Sensing-Frage; öffnet Downloading-Muster)","'Was will hier entstehen – nicht was soll, sondern was will?' (Presencing-Frage; Futur II statt Planung)","'Was ist dein Anteil daran, dass die Zukunft, die entstehen will, tatsächlich entsteht – eine Handlung in den nächsten 72 Stunden?' (Crystallizing-Frage; verankert Presencing im Alltag)'"],"beispiel":"Klausur-Abend mit einem Leitungsteam. Sensing: 30 Minuten Empathie-Interviews mit zwei Personen aus der Zielgruppe (mitgebracht oder per Video). Presencing: 10 Minuten geführtes Journaling, Frage: 'Was will hier entstehen, das noch nicht da ist?' Stille respektieren. Crystallizing: Jede Person formuliert einen Satz ihres persönlichen Beitrags zur entstehenden Zukunft. Anschlussfrage: 'Was ist der kleinste Schritt, den du morgen tun kannst?' – kein großer Aktionsplan, sondern ein konkreter Einstieg.","mini_form":"Presencing-Moment in 10 Minuten: Stille (2 Min), Journaling-Frage 'Was will hier entstehen?' (5 Min), Satz vorlesen (3 Min). Kann als Abschluss einer Strategie-Session stehen und gibt dem Tag einen anderen Ton.","anlass_typen":["strategie","dialograum","teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"6–20 ideal; als Coaching-Sequenz auch 1:1","stimmung_geeignet":["neugierig","belastet","muede"]},{"id":"art-of-hosting","name":"Art of Hosting","feld":"D","kurz":"Einen gehaltenen Raum schaffen, in dem kollektive Intelligenz an echten Fragen arbeiten kann.","schritte":["Einladung und calling question sorgfältig formulieren","Container öffnen: Check-in, Vereinbarungen, Präsenz der Gastgeber:innen","Passende Kernstruktur wählen und durchführen (Circle, World Café, Open Space, Pro Action Café)","Harvesting: Erkenntnisse sichtbar und mitnehmbar machen","Check-out und nächste Schritte"],"zweck":"Einen gehaltenen Raum schaffen, in dem kollektive Intelligenz an echten Fragen arbeiten kann.","hinweise":"Die Haltung (hosten statt steuern) trägt die Methode – Werkzeuge ohne Haltung wirken hohl. Vorbereitung der Frage ist die halbe Arbeit.","phasen":["oeffnen","vertiefen"],"ebenen":["team","organisation","netzwerk"],"modi":["verbindung","klaerung"],"formate":["grossgruppe","workshop","prozessbegleitung"],"dauer_min":90,"dauer_max":240,"gruppe_min":8,"gruppe_max":100,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Art of Hosting – What is the Art of Hosting?","url":"https://artofhosting.org/what-is-aoh/"},{"typ":"online","titel":"Peer Canvas – Art of Hosting overview","url":"https://www.peercanvas.com/methodology/art-of-hosting/"}],"wann_passt":["Netzwerk-Großgruppe (20–100 Personen) mit einer echten offenen Frage, zu der kollektive Intelligenz gebraucht wird – Art of Hosting als Meta-Rahmen, in den World Café, Open Space oder Circle eingebettet werden.","Gemeinschaftsprozesse mit verteilter Expertise und flacher Hierarchie: AoH-Haltung (Gastgeber:in statt Steuerer:in) passt zu diesen Kontexten besonders gut.","Mehrjährige Prozessbegleitung: AoH als Grundphilosophie für wiederkehrende Großformat-Treffen in einer Community of Practice oder einem Netzwerk.","Facilitator:innen-Fortbildung: AoH als Schule des Haltens ('hosting') – die Sprache und Haltung sind Gegenstand, nicht nur das Format."],"wann_nicht":["Online als Vollformat: Präsenz im Raum, Körper, informelle Begegnung, Raumgestaltung sind integraler Bestandteil – Online-AoH ist stark abgeschwächt.","Wenn feste Ergebnisse in festen Zeiten erwartet werden – AoH folgt der Energie, nicht der Agenda. Für Entscheidungs-Meetings ist es das falsche Format.","Als Einzel-Methode für ungeübte Facilitator:innen: AoH setzt Vertrautheit mit den eingebetteten Formaten (World Café, Circle, Open Space) voraus."],"fokusfragen":["'Was ist die Frage, für die diese Gruppe gerufen werden muss – eine Frage, die groß genug ist, damit das Kommen sich lohnt?' (Calling-Question-Entwicklungsfrage; zentral im AoH-Design)","'Wie baue ich einen Container, in dem Menschen sicher genug sind, die wirklich wichtigen Dinge zu sagen?' (Gastgeber:innen-Frage; Haltung, nicht Technik)","'Wie ernten wir, was entstanden ist – und wie machen wir es für die Gruppe sichtbar und nutzbar?' (Harvesting-Frage)'"],"beispiel":"Netzwerk-Jahrestreffen, 60 Personen. Design: Check-in im Kreis (25 Min), dann World Café zu drei Calling Questions (90 Min), dann Open-Space-Marktplatz für selbstorganisierte Vertiefungsgruppen (120 Min), Harvesting im Plenum (30 Min), Check-out. Die Gastgeber:innen-Gruppe von 4 Personen hat die Fragen 4 Wochen vorher entwickelt. Anschlussfrage im Harvesting: 'Was ist das Eine, das wir uns merken – und was nehmen wir mit nach Hause?' – Ernte aus der Energie des Tages, nicht vorab festgelegt.","mini_form":"Circle-Einstieg in 15 Minuten als AoH-Mini: Alle im Kreis, Check-in-Frage, ruhige Moderation, kein Kommentar. Reicht als Einstimmung in die Hosting-Haltung.","anlass_typen":["netzwerktreffen","dialograum","beteiligung","lernformat"],"typ":"methode","gruppen_sweetspot":"20–80 ideal; ab 8 mit einem Format wie Circle möglich","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"dynamic-facilitation","name":"Dynamic Facilitation","feld":"D","kurz":"Kreative Durchbrüche bei verfahrenen Themen ermöglichen, indem die Moderation der Energie folgt statt einer Agenda.","schritte":["Vier sichtbare Listen anlegen: Herausforderungen / Lösungsideen / Bedenken / Informationen","Der Energie der Gruppe folgen – sprechen lassen, was gerade drängt","Jeden Beitrag würdigen und auf der passenden Liste festhalten","Bedenken nicht wegmoderieren, sondern notieren – sie werden zu neuen Herausforderungen","Durchbrüche (shifts) abwarten und benennen, wenn die Gruppe konvergiert","Ergebnisse und offene Fäden sichern"],"zweck":"Kreative Durchbrüche bei verfahrenen Themen ermöglichen, indem die Moderation der Energie folgt statt einer Agenda.","hinweise":"Braucht geübte, schnelle Moderation (viel Mitschreiben). Keine Agenda erzwingen – wer feste Ergebnisse in fester Zeit braucht, wählt ein anderes Format.","phasen":["vertiefen","konflikt"],"ebenen":["team","organisation"],"modi":["klaerung","konflikt"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":5,"gruppe_max":20,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Co-Intelligence Institute – Dynamic Facilitation","url":"https://www.co-intelligence.org/P-dynamicfacilitation.html"},{"typ":"buch","titel":"IPG Methodenbücherei: Dynamic Facilitation (MTB 0043)"},{"typ":"buch","titel":"Rosa Zubizarreta: From Conflict to Creative Collaboration (2014)"},{"typ":"online","titel":"Rosa Zubizarreta – Dynamic Facilitation Associates","url":"http://www.dynamicfacilitation.com/"}],"wann_passt":["Eine Gruppe steckt seit Monaten in einem Thema fest, das mit herkömmlicher Moderation nicht weiterkommt – Dynamic Facilitation folgt der Energie statt einer Agenda und ermöglicht kreative Durchbrüche dort, wo strukturierte Methoden Widerstand erzeugen.","Spannungsgeladenes Team-Meeting, in dem verschiedene Positionen laut und ungehört nebeneinander stehen – die Vier-Listen-Struktur (Herausforderungen, Lösungen, Bedenken, Informationen) macht alle Beiträge gleichwertig sichtbar ohne Sieger:innen.","Klausur mit einem komplexen Thema und ausreichend Zeit (mindestens 3 Stunden): Wenn der Shift (Durchbruch) kommt, braucht er Raum – Dynamic Facilitation funktioniert nicht in 60 Minuten.","Facilitator:innen-Fortbildung: DF als Schule für das Moderieren ohne Agenda – die Übung, der Energie zu folgen statt zu steuern, verändert die Haltung grundlegend."],"wann_nicht":["Wenn ein festes Ergebnis in festem Zeitrahmen erwartet wird – Dynamic Facilitation kann im besten Fall Durchbrüche liefern, aber nicht planbar wann.","Für ungeübte Moderator:innen: Das simultane Mitschreiben auf vier Listen, Würdigen jedes Beitrags, und Folgen der Energie ist technisch anspruchsvoll – Erfahrung ist Voraussetzung.","Bei sehr großen Gruppen (über 20) ohne Kleingruppenstruktur: Die Energie verliert sich, die Moderation überfordert.","Wenn eine Partei im Raum aktiv Sabotage betreibt oder die Gruppe traumatisiert ist – DF braucht zumindest minimales gegenseitiges Grundvertrauen."],"fokusfragen":["'Was ist das, was dich an diesem Thema am meisten bewegt – das Dringlichste, das du jetzt sagen willst?' (Energie-Einstieg; offen für jede Liste)","'Was ist das Bedenken hinter deinem Bedenken – was befürchtest du wirklich?' (Vertiefungs-Frage bei Einwand; macht aus Blockade eine neue Herausforderung)","'Was müsste wahr sein, damit diese Lösung funktioniert – welche Bedingungen stecken dahinter?' (Lösungs-Vertiefung; öffnet Informations-Liste)'"],"beispiel":"Team-Klausur nach internem Konflikt. Vier Listen auf Flipcharts. Jemand sagt: 'Wir können so nicht weiterarbeiten.' Moderation notiert auf Liste Herausforderungen: 'Wir können so nicht weiterarbeiten.' Würdigung: 'Das höre ich – das ist wichtig.' Nächste Person sagt eine Lösung ('Wir brauchen klare Regeln'). Notiert auf Liste Lösungen. Jemand antwortet mit einem Bedenken ('Regeln helfen nicht, wenn wir uns nicht vertrauen'). Notiert auf Bedenken-Liste als neue Herausforderung: 'Vertrauen fehlt als Grundlage.' Kein Debattieren, kein Werten – alle vier Listen füllen sich. Nach 60 Minuten oft der erste Shift: Die Gruppe merkt, dass sie dasselbe Problem aus verschiedenen Winkeln beleuchtet hat.","mini_form":"Vier-Listen-Schnelleinstieg in 20 Minuten: Vier Flipcharts aufstellen, Thema benennen, 15 Minuten frei assoziieren (je nach Energie notieren). Nicht auf Durchbruch warten – aber die Energie sichtbar machen. Kann als Einstieg in eine längere Session dienen.","anlass_typen":["konfliktklaerung","dialograum","krisensitzung","strategie"],"typ":"methode","gruppen_sweetspot":"5–15 ideal; ab 5 sinnvoll, über 20 nur mit sehr erfahrener Moderation","stimmung_geeignet":["angespannt","belastet","skeptisch"]},{"id":"sociocracy-3","name":"Sociocracy 3.0","feld":"D","kurz":"Tragfähige Entscheidungen treffen, die gut genug für jetzt und sicher genug zum Ausprobieren sind.","schritte":["Proposal vorstellen (Treiber: Welches Bedürfnis der Organisation?)","Verständnisfragen-Runde","Reaktionsrunde: kurze Einschätzungen, keine Debatte","Einwände sammeln – nur begründete: Schadet es dem Zweck oder ist es nicht sicher genug zum Ausprobieren?","Einwände integrieren, Proposal anpassen","Konsent feststellen und Review-Termin setzen"],"zweck":"Tragfähige Entscheidungen treffen, die gut genug für jetzt und sicher genug zum Ausprobieren sind.","hinweise":"Konsent ist nicht Konsens – es geht um Abwesenheit begründeter Einwände, nicht um Begeisterung aller. Rundenformat strikt halten, sonst kippt es in offene Diskussion.","phasen":["entscheiden"],"ebenen":["team","organisation"],"modi":["entscheidung","klaerung"],"formate":["meeting","workshop","teamentwicklung"],"dauer_min":30,"dauer_max":90,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Sociocracy 3.0 – Patterns (frei zugänglich)","url":"https://patterns.sociocracy30.org/"},{"typ":"online","titel":"Sociocracy 3.0 – free handbook (CC license)","url":"https://patterns.sociocracy30.org/the-handbook.html"}],"wann_passt":["Ein Team oder eine Organisation trifft Entscheidungen entweder durch Abstimmungsmehrheit (Verlierer:innen entstehen) oder durch informellen Konsens (wenige bestimmen, andere schweigen) – Sociocracy 3.0 / Konsent-Runde als dritte Option: Einwände werden integriert statt überstimmt.","Governance-Design in einer selbstorganisierten oder Netzwerk-Organisation, die eine Entscheidungsstruktur braucht, die keine zentrale Autorität voraussetzt – S3 als vollständiges Governance-System oder einzelner Pattern wie Konsent-Entscheidung.","Klassisches Jour-fixe-Meeting, in dem Entscheidungspunkte im Protokoll hängen, weil keine Einigkeit hergestellt werden kann – Konsent als Methode für diese Agenda-Punkte.","Onboarding neuer Teammitglieder in eine selbstorganisierte Struktur: Konsent-Entscheidung als erstes S3-Pattern einüben, weil es intuitiv ist und sichtbare Wirkung zeigt."],"wann_nicht":["Bei operativen Alltagsentscheidungen, die keine Einwände produzieren würden – Overhead vermeiden, nicht jede Entscheidung braucht eine Konsent-Runde.","Wenn im Raum große Machtungleichgewichte existieren und schwächere Parteien Einwände nicht aussprechen werden – Konsent ist nur so gut wie die psychologische Sicherheit im Raum.","Ohne Erklärung des Unterschieds Konsent vs. Konsens: Wenn die Gruppe denkt, es geht um Begeisterung aller, verliert das Format seinen Sinn."],"fokusfragen":["'Gibt es einen begründeten Einwand – also: Schadet dieses Proposal dem Zweck unserer Organisation, oder ist es nicht sicher genug zum Ausprobieren?' (Kernfrage des Konsent; Unterschied zu 'ich mag das nicht' muss gelernt werden)","'Was müsste am Proposal geändert werden, damit dein Einwand ausgeräumt ist – welche Bedingung muss erfüllt sein?' (Einwand-Integration; Einwand wird zur Verbesserungs-Information)","'Ist dieses Proposal gut genug für jetzt – und sicher genug zum Ausprobieren?' (Abschluss-Frage; gibt Erlaubnis für Imperfektes)'"],"beispiel":"Konsent-Entscheidung in einer NGO-Sitzung. Proposal: 'Wir führen ab nächstem Monat wöchentliche Check-ins ein.' Verständnisfrage: 'Gilt das auch für Ehrenamtliche?' Antwort: 'Nein, nur für bezahlte Stellen.' Reaktionsrunde (je 30 Sekunden): 'Gut', 'Ich bin unsicher ob das reicht', 'Finde ich sinnvoll'. Einwand: 'Dienstag passt nicht für alle – das schließt manche aus.' Integration: 'Wir legen den Tag gemeinsam fest.' Konsent: 'Gibt es noch einen begründeten Einwand?' – Stille. 'Wir sind im Konsent.' Review-Termin in 6 Wochen gesetzt.","mini_form":"Blitz-Konsent in 10 Minuten: Proposal in einem Satz, eine Runde für Einwände (nur begründete, 30 Sekunden pro Person), Integration wenn nötig, Konsent feststellen. Ohne Verständnis- und Reaktionsrunde für einfache Entscheidungen.","anlass_typen":["entscheidungstreffen","regeltermin","strategie"],"typ":"methode","gruppen_sweetspot":"4–12 ideal; bis 20 mit geübter Moderation","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"schreibgespraech","name":"Schreibgespräch (IPG)","feld":"D","kurz":"Ein Gespräch ohne Reden führen – stille Stimmen gleichberechtigen und Gleichzeitigkeit ermöglichen.","schritte":["Plakate mit Fragen oder Thesen im Raum verteilen","Stilles Schreiben: alle notieren Gedanken direkt auf die Plakate","Auf Beiträge anderer schriftlich antworten – Pfeile, Kommentare, Fragen","Zwischen Plakaten rotieren","Gemeinsamer Rundgang und mündliche Auswertung der Diskussionsfäden"],"zweck":"Ein Gespräch ohne Reden führen – stille Stimmen gleichberechtigen und Gleichzeitigkeit ermöglichen.","hinweise":"Stille konsequent halten, sonst verliert die Methode ihren Kern. Gute Fragen entscheiden über die Tiefe. Online mit kollaborativem Dokument/Board gut machbar.","phasen":["vertiefen","oeffnen"],"ebenen":["team","organisation"],"modi":["klaerung","reflexion"],"formate":["workshop","fortbildung"],"dauer_min":20,"dauer_max":60,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["schriftlich","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Methodenkartei Uni Oldenburg – Schreibgespräch","url":"https://www.methodenkartei.uni-oldenburg.de/methode/schreibgespraech/"},{"typ":"buch","titel":"IPG Methodenbücherei: Schreibgespräch (MTB 0043)"}],"wann_passt":["Workshop mit einer Gruppe, in der typischerweise 2–3 Personen dominieren und der Rest schweigt – das Schreibgespräch zwingt zur Gleichzeitigkeit und macht stille Stimmen sichtbar, ohne die Lautstarken zu bremsen.","Hierarchisches Umfeld (Abteilung mit Leitung im Raum): Schriftlichkeit senkt die soziale Risikowahrnehmung – Kritisches, Widersprüchliches entsteht auf Plakaten, bevor es ausgesprochen werden muss.","Fortbildung oder Training, in dem viele Fragen gleichzeitig bearbeitet werden sollen: 4–6 Plakate, alle rotieren – in 30 Minuten mehr Oberfläche als in 60 Minuten Plenumsgespräch.","Online-Setting mit kollaborativem Board (Miro, Mural): Schreibgespräch funktioniert digital sehr gut, weil Gleichzeitigkeit und Stille auch im digitalen Raum erhalten bleiben."],"wann_nicht":["Wenn Stille nicht gehalten werden kann (moderierte Ausnahmen werden zur Regel) – dann verliert die Methode ihren Kern.","Bei einer Gruppe mit sehr niedriger Schreibbereitschaft oder Sprachbarrieren: Schriftlichkeit kann exkludieren.","Als Auftakt-Format für eine Gruppe, die sich noch gar nicht kennt und Orientierung braucht – zuerst kurze mündliche Begegnung, dann Schreibgespräch."],"fokusfragen":["'Was ist deine ehrlichste Einschätzung zu diesem Thema – was würdest du sagen, wenn du sicher bist, dass es keine Konsequenzen hat?' (Frage für Plakat; öffnet, was im Gespräch nicht gesagt würde)","'Was übersehen wir als Gruppe bei diesem Thema – welcher Aspekt taucht nie auf?' (Blinder-Fleck-Frage)","'Was würde ich meiner Kollegin/meinem Kollegen antworten, die/der gerade diesen Kommentar auf dem Plakat hinterlassen hat?' (Antwort-Impuls; erzeugt echten Dialog auf Papier)'"],"beispiel":"Workshop zu Verbesserungsideen in einem Team (12 Personen, Leitung im Raum). Vier Plakate mit Fragen: 'Was läuft gut?', 'Was stört uns?', 'Was trauen wir uns bisher nicht zu sagen?', 'Was würden wir ändern, wenn wir könnten?'. 10 Minuten stilles Schreiben, rotieren. Dann 5 Minuten: auf Beiträge anderer kommentieren (Pfeile, Ausrufezeichen, Ergänzungen). Auswertung: Gemeinsamer Rundgang, die Leitung liest zuerst, ohne zu kommentieren. Anschlussfrage: 'Was hat uns überrascht?' – die Überraschung ist meist das Aufrichtigste.","mini_form":"Ein-Plakat-Schreibgespräch in 10 Minuten: Ein Plakat, eine Frage, 5 Minuten schreiben, 3 Minuten auf Beiträge anderer reagieren. Miniversion reicht als Einstieg für ein Plenumsgespräch.","anlass_typen":["lernformat","retro","teamtag","strategie"],"typ":"methode","gruppen_sweetspot":"6–25 ideal; bis 30 mit genug Plakaten","stimmung_geeignet":["skeptisch","muede","angespannt","neugierig"]},{"id":"psychologische-sicherheit","name":"Psychologische Sicherheit (Edmondson)","feld":"D","kurz":"Die Bedingung schaffen, unter der Teams lernen, Fehler melden und Neues wagen.","schritte":["Konzept einführen: Sicherheit, zwischenmenschliche Risiken einzugehen (Fragen, Fehler, Widerspruch) ohne Bestrafung","Anonyme Kurzdiagnose mit den 7 Edmondson-Items","Ergebnisse gemeinsam besichtigen – ohne Schuldsuche","Situationen sammeln: Wann habe ich hier geschwiegen, obwohl ich etwas sagen wollte?","Team-Vereinbarungen für sicherere Praxis treffen","Führung geht voran: eigene Fehler/Unsicherheit zuerst teilen"],"zweck":"Die Bedingung schaffen, unter der Teams lernen, Fehler melden und Neues wagen.","hinweise":"Psychologische Sicherheit ist keine Kuschel-Norm – sie gehört mit hohen Leistungsstandards zusammen. Niemanden zur Offenheit zwingen, das Gegenteil entsteht.","phasen":["verstehen","verstetigen"],"ebenen":["team","organisation"],"modi":["vertrauen","reflexion"],"formate":["workshop","teamentwicklung"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"McKinsey Explainers – What is psychological safety?","url":"https://www.mckinsey.com/featured-insights/mckinsey-explainers/what-is-psychological-safety"},{"typ":"buch","titel":"Amy Edmondson: The Fearless Organization (2018)"}],"wann_passt":["Ein Team-Diagnose-Moment: Warum lernen wir nicht aus Fehlern, warum kommen Bedenken nie im Meeting – Edmondson's Rahmenmodell gibt der Diagnose eine Sprache und macht das unsichtbare Phänomen besprechbar.","Führungskräfte-Fortbildung: Psychologische Sicherheit als Konzept einführen und den Zusammenhang mit Lernkurve und Fehlerkultur durcharbeiten – besonders wirkungsvoll, weil es Führung als Einflussvariable sichtbar macht.","Teamentwicklung nach Rückschlag oder öffentlicher Kritik: Die Diagnose (Wie sicher fühlt sich das Team wirklich?) als strukturierter Einstieg in ein Gespräch über Teamklima.","Organisationsentwicklung: Als Diagnose-Brille in einer Kultur-Analyse – in welchen Teams und unter welchen Führungskräften ist PS hoch, in welchen nicht?"],"wann_nicht":["Als Anleitung für eine einmalige Übung: Psychologische Sicherheit ist kein Format, sondern eine Bedingung – sie entsteht durch Verhalten über Zeit, nicht durch eine Session.","Wenn die Führungskraft im Raum nicht bereit ist, eigene Unsicherheit zu teilen: Ohne dieses Vorangehen bleibt das Konzept akademisch und die Diagnose oberflächlich.","Als Entschuldigungs-Konzept für mangelnde Performance: Sicherheit ohne Herausforderung (Learning Zone nach Edmondson) produziert keine Lernkultur, sondern Comfort Zone."],"fokusfragen":["'Wann hast du in letzter Zeit etwas nicht gesagt, obwohl du es für wichtig hieltest – und was hat dich davon abgehalten?' (Verhaltens-Diagnose; konkret, nicht abstrakt)","'Als Führungskraft: Welchen Fehler habe ich gemacht, von dem ich glaube, dass er dem Team wichtig wäre zu hören?' (Vorangehen-Frage; Führung öffnet den Raum)","'Auf einer Skala von 1–10: Wie sicher fühlt es sich an, in diesem Team eine unfertige Idee zu teilen – und woran liegt das?' (Skalen-Frage; macht die Wahrnehmung explizit und gesprächsfähig)'"],"beispiel":"Teamentwicklung nach einer Krisensituation, in der ein Problem eskaliert war, das das Team schon lange gesehen hatte. Einstieg: Kurze Erklärung des Rahmenmodells (10 Min). Anonyme Blitzdiagnose mit drei Items: 'Ich kann Fehler zugeben', 'Ich kann die Leitung kritisieren', 'Ich kann eine Idee einbringen, die vielleicht dumm klingt'. Ergebnisse zeigen. Dann Frage: 'Was haben wir gerade in der Krise nicht gesagt – und warum?' Anschlussfrage: 'Was müsste die Leitung als Erstes anders machen, damit das nächste Mal gesagt wird?' – Führung notiert und reagiert konkret.","mini_form":"PS-Blitzcheck in 10 Minuten: Drei Items auf Klebepunkten (1–5), anonym auf Flipchart. Ergebnis zeigen, eine Beobachtung machen, eine Konsequenz benennen. Kein vollständiges Diagnose-Format nötig.","anlass_typen":["teamtag","retro","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"4–15 ideal als Diagnosekomplex; als Konzept-Input bis 30","stimmung_geeignet":["skeptisch","belastet","muede"]},{"id":"trust-equation","name":"Trust Equation (Maister)","feld":"D","kurz":"Vertrauen aus einer Gefühlsfrage in vier beeinflussbare Verhaltensdimensionen übersetzen.","schritte":["Formel einführen: Vertrauen = (Glaubwürdigkeit + Verlässlichkeit + Intimität) ÷ Selbstorientierung","Selbsteinschätzung: jede Person bewertet sich auf den vier Dimensionen","Austausch in Paaren mit Beispielen: Woran merkt man bei mir …?","Pro Person 1–2 konkrete Verhaltensänderungen ableiten (oft: Selbstorientierung senken, Intimität erhöhen)","Commitments festhalten"],"zweck":"Vertrauen aus einer Gefühlsfrage in vier beeinflussbare Verhaltensdimensionen übersetzen.","hinweise":"Der Nenner (Eigennutz) wirkt am stärksten und wird am ungernsten besprochen. Als Selbstreflexionstool nutzen, nicht zum Bewerten anderer.","phasen":["verstehen","verstetigen"],"ebenen":["person","team"],"modi":["vertrauen","selbstzugang"],"formate":["workshop","coaching","teamentwicklung"],"dauer_min":45,"dauer_max":90,"gruppe_min":2,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Trusted Advisor Associates – Understanding the Trust Equation","url":"https://trustedadvisor.com/why-trust-matters/understanding-trust/understanding-the-trust-equation"},{"typ":"buch","titel":"Maister/Green/Galford: The Trusted Advisor (2000)"}],"wann_passt":["Coaching oder Einzelreflexion: Jemand wird als 'nicht vertrauenswürdig' erlebt und versteht nicht warum – die vier Dimensionen (Glaubwürdigkeit, Verlässlichkeit, Intimität, Selbstorientierung) als diagnostisches Werkzeug, um den eigenen blinden Fleck zu finden.","Führungskräfteentwicklung: Vertrauen als beeinflussbare Verhaltensvariable statt als Persönlichkeitsmerkmal – das Werkzeug entmystifiziert Vertrauen und gibt konkrete Ansatzpunkte.","Paar-Reflexion in einer Team-Entwicklung: Zwei Personen, die in Spannung zueinander stehen, reflektieren je für sich ihre eigene Trust-Equation – nicht das Gegenüber bewerten, sondern sich selbst.","Fortbildung für Berater:innen und Coaches: Trust Equation als Orientierung für professionelle Beziehungen – besonders die Selbstorientierung (Nenner) als Haupthebel für professionelle Dienstleister:innen."],"wann_nicht":["Als Instrument, um andere zu bewerten – 'Ich analysiere deine Trust Equation' ist ein Beziehungsbruch, kein Vertrauens-Builder.","In hocheskalierten Konflikten als erste Intervention – die Reflexion ist ein ruhiges Werkzeug und braucht einen stabilen Rahmen.","Wenn die Gruppe noch kein Vertrauen zueinander hat, um über Selbstorientierung zu sprechen – der Nenner ist heikel und braucht psychologische Sicherheit."],"fokusfragen":["'Auf welcher der vier Dimensionen bist du bei dir selbst am schwächsten – und was wäre ein konkretes Verhalten, das du dort verändern könntest?' (Selbstreflexions-Frage nach der Selbsteinschätzung)","'Was bräuchte jemand von dir sehen, um deine Verlässlichkeit zu erleben – was ist ein Versprechen, das du in den nächsten zwei Wochen einhalten könntest?' (Verhaltens-Frage für Verlässlichkeit)","'Wenn du ehrlich bist: In welchen Situationen steht dein eigenes Interesse vor dem der anderen Person – und was treibt das an?' (Selbstorientierungs-Frage; der produktivste und unbequemste Punkt)'"],"beispiel":"Coaching-Session. Führungskraft X wird vom Team als unzuverlässig erlebt, obwohl X sich fachlich sehr kompetent fühlt. Trust Equation einführen. Selbsteinschätzung: Glaubwürdigkeit hoch (Kompetenz), Verlässlichkeit mittel (manchmal vergisst er Zusagen), Intimität niedrig (zeigt nie Unsicherheit), Selbstorientierung hoch (redet viel über eigene Projekte). Diagnose: Der Nenner ist groß. Anschlussfrage: 'Was würde passieren, wenn du in der nächsten Team-Sitzung etwas teilst, das dir wirklich schwerfällt – und um Rat bittest statt zu informieren?' Woche später: Rückmeldung, dass die Sitzung anders war.","mini_form":"Trust-Gleichung in 5 Minuten: Formel zeigen, Selbst-Score auf den vier Dimensionen (1–10), einen Satz zur Konsequenz formulieren. Als Impuls in ein Führungskräfte-Training eingebaut.","anlass_typen":["coaching","lernformat","teamtag"],"typ":"werkzeug","gruppen_sweetspot":"1:1 ideal; bis 8 als Gruppenreflexion möglich","stimmung_geeignet":["neugierig","frisch","belastet"]},{"id":"grit-reziprozitaet","name":"GRIT / schrittweise Reziprozität (Osgood)","feld":"D","kurz":"Eine Abwärtsspirale des Misstrauens durch kalkulierte einseitige Vorleistungen umkehren.","schritte":["Logik vorstellen: angekündigte, einseitige, verifizierbare De-Eskalationsschritte laden zur Erwiderung ein","Kleine, risikoarme erste Schritte brainstormen, die das eigene Sicherheitsinteresse nicht gefährden","Ersten Schritt plus öffentliche Ankündigung formulieren","Kriterien festlegen: Woran erkennen wir Erwiderung, wie verifizieren wir?","Fortsetzungs- und Abbruchplan vereinbaren"],"zweck":"Eine Abwärtsspirale des Misstrauens durch kalkulierte einseitige Vorleistungen umkehren.","hinweise":"Schritte müssen verifizierbar und kostspielig genug sein, um als ernsthaft zu gelten. Wann NICHT: bei akuter Gewalt oder wenn die Gegenseite Konzessionen systematisch ausnutzt ohne je zu erwidern.","phasen":["konflikt","verstetigen"],"ebenen":["team","organisation","netzwerk"],"modi":["vertrauen","konflikt"],"formate":["coaching","prozessbegleitung"],"dauer_min":45,"dauer_max":90,"gruppe_min":2,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"International Online Training Program on Intractable Conflict – Step-by-Step De-escalation (GRIT)","url":"https://www.intractableconflict.org/www_colorado_edu_conflict/peace/treatment/grit.htm"}],"wann_passt":["Eine Konflikt-Dyade in einer Organisation oder einem Netzwerk steckt in einer Misstrauens-Spirale, in der keine Seite den ersten Schritt machen will, weil sie glaubt, ausgenutzt zu werden – GRIT als strukturierte De-Eskalationslogik für genau diese Pattsituation.","Konfliktbegleitung nach langer Eskalation: Wenn Mediation noch nicht möglich ist, weil Vertrauen für Direktgespräche fehlt – GRIT als Vorstufe, die Handlungsfähigkeit ohne unmittelbaren Kontakt wiederherstellt.","Strategische Konflikt-Analyse in einer Koalition mit zerstrittenen Lagern: GRIT als Konzept-Input, um die Gruppe zu befähigen, mit kalkulierten kleinen Gesten Bewegung zu erzeugen.","Internationale Kontexte: GRIT entstammt der Rüstungskontrolle (Osgood, Kalter Krieg) und ist besonders robust bei institutionalisierten Konfliktparteien."],"wann_nicht":["Bei akuter Gewalt oder Bedrohung – GRIT setzt voraus, dass beide Seiten sicher genug sind, um Konzessionen zu machen.","Wenn eine Seite Konzessionen systematisch ausnutzt ohne je zu erwidern – dann stabilisiert GRIT das Misstrauens-System statt es aufzulösen.","Als Erstintervention in einem frisch eskalierenden Konflikt ohne Analyse – zuerst die Dynamik verstehen, dann kalkulierte Schritte planen."],"fokusfragen":["'Was wäre ein kleiner, kostspieliger aber risikoarmer Schritt, den wir einseitig machen könnten – verifiziertbar, öffentlich ankündbar, ohne unsere Kerninteressen zu gefährden?' (GRIT-Kern-Frage; Schritt muss alle drei Bedingungen erfüllen)","'Woran würden wir erkennen, dass die Gegenseite unseren Schritt erwidert – und was ist der Zeitrahmen, den wir akzeptieren?' (Verifikations- und Gedulds-Frage)","'Was ist unser Plan B, wenn nach drei Schritten keine Erwiderung kommt?' (Abbruch-Kriterium; ohne das ist GRIT Einseitigkeit ohne Strategie)'"],"beispiel":"Zwei Fachbereiche in einer Organisation streiten seit einem Jahr um Zuständigkeit. Keine direkten Gespräche mehr. GRIT-Strategie: Bereich A kündigt öffentlich an (im All-Hands), eine umstrittene Ressource für 3 Monate dem anderen Bereich zu überlassen, ohne Gegenleistung zu fordern. Ankündigung: 'Wir glauben, dass Vertrauen auch von uns kommen muss.' Verifizierung: sichtbar im nächsten Quartalsbericht. Erwartung: Bereich B reagiert mit einer eigenen kleinen Geste. Wenn nicht: nach drei Monaten Gespräch anbieten, nicht eskalieren.","mini_form":"GRIT-Planung in 20 Minuten: Schritt 1 – Was ist ein erster Schritt? Schritt 2 – Ist er verifizierbar und öffentlich? Schritt 3 – Wann und wie ankündigen? Drei Fragen als Checkliste, kein vollständiger Prozess.","anlass_typen":["konfliktklaerung","strategie"],"typ":"methode","gruppen_sweetspot":"Konflikt-Coaching für 1–2 Parteien; bis 12 als Analyse-Session","stimmung_geeignet":["angespannt","belastet","skeptisch"]},{"id":"confidence-building-measures","name":"Confidence Building Measures","feld":"D","kurz":"Durch institutionalisierte Transparenz und Verlässlichkeit ein Mindestmaß an Sicherheit zwischen misstrauischen Parteien schaffen.","schritte":["Quellen des Misstrauens zwischen Parteien sammeln (Intransparenz, Fehldeutungen, Vorfälle)","Maßnahmen-Typen vorstellen: Kommunikation, Transparenz, Verifikation, Verhaltensregeln","Konkrete Maßnahmen für den eigenen Kontext brainstormen","Niedrigschwellige zuerst sequenzieren – eine Serie planen, nicht eine Einzelmaßnahme","Monitoring und Überprüfungsrhythmus vereinbaren"],"zweck":"Durch institutionalisierte Transparenz und Verlässlichkeit ein Mindestmaß an Sicherheit zwischen misstrauischen Parteien schaffen.","hinweise":"Eine einzelne CBM bewirkt wenig – die Wirkung liegt in der Serie. CBMs ersetzen die Bearbeitung des Kernkonflikts nicht, sie machen sie möglich.","phasen":["konflikt","verstetigen"],"ebenen":["organisation","netzwerk","feld"],"modi":["vertrauen","konflikt"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":2,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Beyond Intractability – Confidence-Building Measures","url":"https://www.beyondintractability.org/essay/confidence_building_measures"}],"wann_passt":["Kooperationsbeginn zwischen Akteuren, die sich misstrauen und eine formale Zusammenarbeit aufnehmen müssen (Fusionsprozesse, neue Koalitionen, Post-Konflikt-Strukturen) – CBMs als strukturierter Aufbau von Mindest-Sicherheit vor der inhaltlichen Arbeit.","Netzwerk-Governance-Design in einem Feld mit historisch misstrauischen Organisationen: Welche Transparenz- und Kommunikationsmaßnahmen braucht es, damit Zusammenarbeit möglich wird?","Organisationsentwicklung nach einem Vertrauensbruch (z.B. Restrukturierung, Entlassungen): CBMs als formaler Plan, der zeigt, was die Führung tut, um Verlässlichkeit zurückzugewinnen.","Internationale oder interorganisationale Projektzusammenarbeit mit ungleichen Partnern: CBMs als explizite Vereinbarung über Informationsfluss, Entscheidungstransparenz und Berichtspflichten."],"wann_nicht":["Als Ersatz für die Bearbeitung des Kernkonflikts – CBMs schaffen Bedingungen, lösen aber keine Ursachen.","Wenn eine Seite nicht bereit ist, Transparenz zu zeigen – dann ist die Maßnahme einseitig und stabilisiert Misstrauen statt es zu reduzieren.","Als einmalige Aktion: CBMs wirken als Serie aufbauender Schritte, nicht als einzelne Geste."],"fokusfragen":["'Welches sind die drei Quellen des Misstrauens zwischen uns – Intransparenz, vergangene Verletzungen, Fehldeutungen? Welche ist am stärksten?' (Diagnose-Einstieg)","'Welche Information, wenn sie regelmäßig und verlässlich geteilt würde, würde das Misstrauen am stärksten senken?' (Kern-CBM-Frage; zielt auf Kommunikations-Maßnahmen)","'Wie bauen wir eine Sequenz auf – was kommt zuerst, weil es am wenigsten kostet und am meisten zeigt?' (Sequenzierungs-Frage; Reihenfolge ist wichtig)'"],"beispiel":"Zwei Organisationen in einer Koalition misstrauen einander nach einem Ressourcenkonflikt. CBM-Planung: Maßnahme 1 (sofort): Wöchentliches 30-Minuten-Update-Gespräch der Koordinator:innen. Maßnahme 2 (Monat 2): Offenes Budget-Reporting für Koalitions-Mittel. Maßnahme 3 (Monat 4): Gemeinsames Treffen mit Partnern aus dem Feld, das Rolle beider zeigt. Review nach 6 Monaten: Hat Misstrauen abgenommen? Anschlussfrage: 'Was hat sich verändert – und was braucht noch mehr Transparenz?'","mini_form":"CBM-Brainstorm in 15 Minuten: Pro Quelle des Misstrauens eine Maßnahme nennen. Nur die erste – günstigste und sichtbarste – als Commitment vereinbaren. Review in 4 Wochen.","anlass_typen":["konfliktklaerung","kickoff","strategie"],"typ":"methode","gruppen_sweetspot":"2–15 (Vertreter:innen misstrauender Parteien)","stimmung_geeignet":["angespannt","skeptisch","belastet"]},{"id":"contact-hypothesis","name":"Contact Hypothesis (Allport)","feld":"D","kurz":"Vorurteile zwischen Gruppen durch gut gestalteten, gleichberechtigten Kontakt abbauen.","schritte":["Allports vier Bedingungen prüfen: gleicher Status in der Situation, gemeinsames Ziel, Kooperation statt Wettbewerb, institutionelle Unterstützung","Eine echte Kooperationsaufgabe wählen (etwas gemeinsam herstellen, nicht debattieren)","Gleichen Status in der Situation herstellen (Rollen, Redezeit, Setting)","Persönliche Begegnung ermöglichen (Paare/Kleingruppen statt Blöcke)","Nachbereiten: Erfahrung reflektieren und Folgekontakte anlegen"],"zweck":"Vorurteile zwischen Gruppen durch gut gestalteten, gleichberechtigten Kontakt abbauen.","hinweise":"Schlecht designter Kontakt kann Vorurteile verstärken – die vier Bedingungen sind Wirkbedingung, nicht Deko. Wann NICHT: bei großem unausgeglichenem Machtgefälle oder akuter Bedrohungslage ohne Schutzrahmen.","phasen":["oeffnen","konflikt"],"ebenen":["netzwerk","feld"],"modi":["vertrauen","verbindung"],"formate":["workshop","grossgruppe","prozessbegleitung"],"dauer_min":60,"dauer_max":240,"gruppe_min":6,"gruppe_max":40,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Simply Psychology – Contact Hypothesis (Intergroup Contact Theory)","url":"https://www.simplypsychology.org/contact-hypothesis.html"},{"typ":"buch","titel":"Gordon Allport: The Nature of Prejudice (1954)"}],"wann_passt":["Design von Begegnungsformaten zwischen polarisierten Gruppen (interreligiös, interethnisch, pro/kontra): Die vier Allport-Bedingungen als Qualitätscheckliste für jede Begegnungsarchitektur – nicht was geplant ist, sondern ob die Bedingungen wirklich erfüllt werden.","Evaluations-Brille für bestehende Formate: 'Unser Austauschprogramm erzeugt kaum Wirkung' – Contact Hypothesis erklärt warum, wenn Status nicht gleich oder kein gemeinsames Ziel gesetzt war.","Fortbildung für Konflikt-Facilitator:innen und Community-Entwickler:innen: Das Rahmenmodell ist die theoretische Grundlage für Encounter-Design und unverzichtbar für alle, die zwischen Gruppen arbeiten.","Policy-Beratung für Integrations- oder Austauschprogramme: Die vier Bedingungen als analytischer Rahmen, um bestehende Programme zu bewerten und zu verbessern."],"wann_nicht":["Schlecht designter Kontakt (ohne Allport-Bedingungen) kann Vorurteile verstärken statt reduzieren – das ist die zentrale Warnung des Rahmenmodells. Jedes Encounter-Format ohne Bedingungsprüfung ist potenziell kontraproduktiv.","Bei großem strukturellen Machtgefälle ohne Schutzrahmen: Wenn die eine Gruppe die andere historisch dominiert hat, reicht Begegnung nicht – Strukturfragen müssen adressiert sein.","Als Sofort-Lösung bei akutem Konflikt: Contact funktioniert als mittel- und langfristiger Ansatz, nicht als Krisenintervention."],"fokusfragen":["'Haben alle Beteiligten in dieser Situation gleichen Status – und was konkret ist geplant, um Status-Ungleichheit in der Begegnung zu neutralisieren?' (Bedingung 1-Check)","'Was ist das gemeinsame Ziel, das alle Gruppen teilen und das Kooperation erfordert – und ist es wirklich gemeinsam oder bloß zugewiesen?' (Bedingung 2-Check)","'Welche institutionelle Unterstützung signalisiert, dass diese Begegnung legitim und erwünscht ist – und fehlt sie, was wäre die Konsequenz?' (Bedingung 4-Check)'"],"beispiel":"Evaluierung eines interkulturellen Jugenddialogs. Contact Hypothesis als Analyse-Raster: Gleicher Status? Teilweise – Gastgebende Gruppe hatte mehr Ressourcen und Sprachkompetenz in der Lingua Franca. Gemeinsames Ziel? Unklar formuliert ('Austausch erleben' ist kein kooperatives Ziel). Kooperation statt Wettbewerb? Eine gemeinsame Aufgabe war enthalten, aber zu wenig Zeit. Institutionelle Unterstützung? Vorhanden. Diagnose: Die Bedingungen 1 und 2 waren nicht ausreichend erfüllt – Kontakteffekt war deshalb schwach. Konsequenz für nächstes Jahr: Klare gemeinsame Aufgabe, Sprachanpassung, Rollenmix.","mini_form":"Allport-Checkliste in 10 Minuten: Für ein geplantes Format vier Fragen durchgehen (eine pro Bedingung). Jede Bedingung bewerten: erfüllt / teilweise / nicht. Lücken als Design-Aufgabe formulieren.","anlass_typen":["lernformat","konfliktklaerung","netzwerktreffen"],"typ":"rahmenmodell","gruppen_sweetspot":"Keine Gruppenübung – Diagnose-Werkzeug für Designer:innen und Facilitator:innen; als Lernformat bis 20","stimmung_geeignet":["neugierig","frisch"]},{"id":"vulnerabilitaet","name":"Vulnerabilität (Brown/Lencioni)","feld":"D","kurz":"Durch dosiertes Zeigen von Schwäche die Risikowahrnehmung im Team senken und vertrauensbasierte Zusammenarbeit ermöglichen.","schritte":["Führung/Moderation geht voran: eigene echte Lernerfahrung oder Schwäche teilen","Personal-Histories-Übung: jede Person teilt Herkunft, eine prägende Herausforderung, einen Stolz","Zuhören ohne Kommentar, anschließend kurzes Würdigen","Bezug zur Zusammenarbeit herstellen: Was davon hilft uns, einander besser zu verstehen?","Vereinbaren, wie das Team mit Geteiltem umgeht (Vertraulichkeit)"],"zweck":"Durch dosiertes Zeigen von Schwäche die Risikowahrnehmung im Team senken und vertrauensbasierte Zusammenarbeit ermöglichen.","hinweise":"Strikt freiwillig – erzwungene Intimität zerstört Vertrauen. Tiefe der Fragen an Reifegrad der Gruppe anpassen; kein Therapie-Ersatz. Wann NICHT: in frisch zerstrittenen oder stark politisierten Gruppen als Einstieg.","phasen":["ankommen","verstetigen"],"ebenen":["person","team"],"modi":["vertrauen","selbstzugang"],"formate":["workshop","teamentwicklung","coaching"],"dauer_min":30,"dauer_max":90,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Brené Brown – The Power of Vulnerability (TED Talk)","url":"https://www.ted.com/talks/brene_brown_the_power_of_vulnerability"},{"typ":"buch","titel":"Patrick Lencioni: The Five Dysfunctions of a Team (2002); Brené Brown: Daring Greatly (2012)"}],"wann_passt":["Teamtag oder Klausur, in der explizit Beziehungstiefe aufgebaut werden soll – Vulnerabilität als Haltungs-Impuls einführen: Führung oder Moderation geht voran, teilt etwas Echtes. Das ist die Mini-Form, die am meisten bewegt.","Onboarding oder Teamentwicklung in einer neuen Gruppe: Personal-Histories-Übung (Lencioni) als strukturierter Rahmen, in dem Vulnerabilität dosiert eingeübt wird – Fragen nach Herkunft, Herausforderungen, Stolz.","Fortbildung für Führungskräfte: Vulnerabilität als professionelle Stärke verstehen – das Gegenteil von Schwäche, sondern Bedingung für Vertrauen. Brown's Forschung als Lern-Impuls.","Coaching: Welche Momente im Arbeitsalltag könnten für Selbstoffenbarung genutzt werden – ohne Therapie zu werden?"],"wann_nicht":["In frisch zerstrittenen oder politisierten Gruppen als Einstieg – erzwungene oder unfreiwillige Intimität erzeugt Misstrauen, nicht Vertrauen.","Als Pflicht-Übung ohne Freiwilligkeit – wer sich nicht öffnen will, darf das. Druck ist das Gegenteil der Haltung.","Wenn die Tiefe der Fragen nicht zum Reifegrad der Gruppe passt – lieber niedrigschwellig beginnen und steigern als zu früh zu tief gehen."],"fokusfragen":["'Als Führungskraft oder Moderation: Was ist etwas, das mir wirklich schwerfällt – und das ich bereit bin, heute zu teilen?' (Vorangehen-Frage; nur für die Person, die den Raum öffnet)","'Was ist eine Situation, in der es für dich schwer war – und was hast du daraus gelernt?' (Niedrigschwellige Einladung; nicht zu persönlich, aber echt)","'Was würde es für dich bedeuten, in dieser Gruppe verletzlicher zu sein – was müsste dafür da sein?' (Bedingungen-Frage; respektiert, dass Vulnerabilität Sicherheit braucht)'"],"beispiel":"Teamtag, neue Führungskraft im Team. Statt einer Kennenlernen-Runde teilt die Führungskraft zuerst etwas Echtes: 'Als ich in diese Rolle kam, war mein größter Zweifel, ob ich das Vertrauen des Teams gewinnen kann – und ich bin da noch nicht sicher.' Pause. Dann Einladung: 'Wer möchte, kann auch etwas teilen, was ihn oder sie gerade bewegt.' Freiwillig. Was passiert: Fast alle teilen etwas. Der Raum hat sich verändert – in 5 Minuten. Der Rest des Tages hat eine andere Qualität.","mini_form":"Vorangehen in 3 Minuten: Führung oder Moderation teilt eine echte Unsicherheit. Keine Einladung an die Gruppe nötig – allein dieser Akt öffnet den Raum.","anlass_typen":["teamtag","kickoff","coaching"],"typ":"haltung","gruppen_sweetspot":"3–12 ideal; über 15 wird die Intimität zu dünn","stimmung_geeignet":["frisch","neugierig","belastet"]},{"id":"check-in-rituale","name":"Check-in-Rituale","feld":"D","kurz":"Präsenz und Sichtbarkeit aller herstellen und einen verlässlichen Container öffnen und schließen.","schritte":["Feste Eingangsfrage wählen (von leicht: Wie kommst du an? bis tiefer: Was beschäftigt dich gerade wirklich?)","Reihum kurz antworten – jede Stimme klingt einmal im Raum","Keine Kommentierung, kein Dialog","Am Ende der Session Check-out als Spiegel (Erkenntnis, Gefühl, nächster Schritt)","Als wiederkehrendes Ritual etablieren – die Wiederholung erzeugt die Wirkung"],"zweck":"Präsenz und Sichtbarkeit aller herstellen und einen verlässlichen Container für die Zusammenarbeit öffnen und schließen.","hinweise":"Tiefe der Frage an Kontext und Zeitbudget anpassen. Bei großen Gruppen in Kleingruppen oder als Ein-Wort-Runde. Vielredner:innen freundlich begrenzen (Timebox).","phasen":["ankommen","reflektieren"],"ebenen":["team","organisation"],"modi":["vertrauen","energie"],"formate":["meeting","workshop","teamentwicklung"],"dauer_min":5,"dauer_max":20,"gruppe_min":2,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["einstieg","abschluss"],"quellen":[{"typ":"online","titel":"Hyper Island Toolbox – Check-in / Check-out","url":"https://toolbox.hyperisland.com/check-in-check-out"}],"wann_passt":["Beginn jedes Meetings oder Workshops, das mehr als 20 Minuten dauert: Check-in stellt Präsenz her und gibt allen eine erste Stimme im Raum – verhindert, dass die ersten 10 Minuten nur 2–3 Personen sprechen.","Müde oder erschöpfte Gruppe am Nachmittag: Ein kurzer Check-in ('Was bringst du gerade mit?') holt Menschen aus dem Autopilot und macht Energie sichtbar – besser als Kaffeepause ohne Kontakt.","Online-Meetings: Check-in ist im digitalen Raum noch wichtiger, weil nonverbale Präsenz fehlt – eine kurze Runde gibt dem Raum Körper.","Regelmäßige Team-Meetings als Ritual: Check-in + Check-out als verlässliche Klammer, die Orientierung gibt – über Wochen entsteht Vertrauen durch Wiederholung, nicht durch eine Übung."],"wann_nicht":["In sehr großen Gruppen (30+) ohne Untergruppen-Format: Eine vollständige Runde dauert dann zu lang und zieht Energie, statt zu öffnen.","Wenn die Frage zu tief oder zu persönlich ist für den Kontext – eine einstündige Projektbesprechung mit 'Was bewegt dich heute wirklich?' überfordert und wirkt unecht.","Als Pflicht-Ritual, das als solches erlebt wird – dann lieber weglassen oder die Frage vereinfachen."],"fokusfragen":["'Was bringst du gerade mit in diesen Raum – in einem Wort oder einem Satz?' (Standard-Check-in; niedrigschwellig, für jeden Kontext)","'Was ist eine Sache, die dich heute beschäftigt – außerhalb dieser Sitzung?' (Tieferer Check-in; macht den Menschen sichtbar, nicht nur die Rolle)","'Was brauchst du von dieser Sitzung, damit sie sich für dich lohnt?' (Ergebnisoffener Check-in; macht Erwartungen explizit und ermöglicht Anpassung)'"],"beispiel":"Online-Jour-fixe, 8 Personen, 45 Minuten. Check-in-Frage: 'In einem Wort: Wie bist du gerade?' Runde geht durch, 30 Sekunden pro Person, keine Kommentare. Ergebnis: 3 Personen sagen 'müde', 2 'gestresst'. Moderations-Entscheidung: Agenda kürzen, wichtigstes Thema zuerst. Check-out am Ende: 'Was nimmst du mit?' – in einem Satz. Ergebnis: Die Sitzung hat eine Qualität, die sonst fehlt, weil Menschen kurz sichtbar wurden.","mini_form":"Ein-Wort-Check-in in 3 Minuten: Frage stellen ('Ein Wort, wie du ankommst'), reihum, kein Kommentar, weiter. Kürzer geht nicht – und es wirkt trotzdem.","anlass_typen":["regeltermin","teamtag","kickoff","lernformat"],"typ":"werkzeug","gruppen_sweetspot":"2–25 ideal; bei größeren Gruppen nur als Untergruppen oder als Ein-Wort-Variante","stimmung_geeignet":["muede","angespannt","frisch","neugierig"]},{"id":"cultivate-trust","name":"Cultivate Trust (Ehrlichman)","feld":"D","kurz":"Vertrauen als dauerhafte Kernaktivität eines Netzwerks pflegen – als das dritte C der 5 Cs.","schritte":["Regelmäßige persönliche Begegnungen in den Netzwerk-Rhythmus einbauen (nicht nur Arbeitssitzungen)","Räume für Geschichten und Motivationen schaffen – warum ist jede:r hier?","Verlässlichkeit praktizieren: kleine Zusagen machen und sichtbar einhalten","Spannungen früh und direkt ansprechen statt sie gären zu lassen","Vertrauensstand regelmäßig gemeinsam reflektieren"],"zweck":"Vertrauen als dauerhafte Kernaktivität eines Netzwerks pflegen – als das dritte C der 5 Cs.","hinweise":"Vertrauen in Netzwerken ist Infrastruktur, kein Nebenprodukt – Zeit dafür explizit budgetieren. In verteilten Netzwerken Präsenztreffen priorisieren, sie tragen monatelang.","phasen":["verstetigen","ankommen"],"ebenen":["netzwerk","feld"],"modi":["vertrauen","verbindung"],"formate":["workshop","prozessbegleitung"],"dauer_min":30,"dauer_max":90,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Chief Executive – How To Cultivate An Impact Network: 5 Core Activities","url":"https://chiefexecutive.net/how-to-cultivate-an-impact-network-5-core-activities/"},{"typ":"buch","titel":"David Ehrlichman: Impact Networks (Berrett-Koehler, 2021)"}],"wann_passt":["Netzwerk-Design: Als Planungs-Haltung, die daran erinnert, dass Vertrauen explizit Zeit braucht – bei jedem Netzwerk-Treffen-Design wird gefragt: 'Wo ist der Raum für Begegnung, nicht nur für Programm?'","Netzwerk-Review: Als Diagnose-Frage – 'Wie viel unserer gemeinsamen Zeit geht für Vertrauen auf? Reicht das?' Das dritte C der 5 Cs als Prüfpunkt.","Fortbildung für Netzwerk-Koordinator:innen: Cultivate Trust als dauerhafte Kernaufgabe einführen, nicht als einmalige Aktion – der Rhythmus ist die Methode.","Als Vorab-Check vor einer inhaltlich intensiven Netzwerk-Phase: 'Ist das Vertrauen stark genug für das, was wir jetzt vorhaben – oder müssen wir zuerst in Trust investieren?'"],"wann_nicht":["Als eigenständiges Format neben den 5 Cs: Cultivate Trust ist das dritte C und hat als Haltung seinen Platz im Kontext der 5 Cs-Systematik – als isoliertes Standalone-Format verliert es seine Unterscheidungskraft gegenüber trust-building.","Als Legitimation für endloses Beziehungsmanagement ohne inhaltlichen Fortschritt – Vertrauen ist Infrastruktur, nicht Selbstzweck.","In einer Gruppe, die bereits hohes Vertrauen hat und jetzt liefern will – dann ist Priorisierung von Trust-Aktivitäten ein Energiedieb."],"fokusfragen":["'Wie viel Zeit in unseren letzten drei Netzwerk-Treffen war explizit für Vertrauen und Beziehung – und was war das Ergebnis?' (Audit-Frage für bestehendes Netzwerk)","'Welche einfache wiederkehrende Struktur würde Vertrauen in unserem Netzwerk am meisten stärken – und kostet wenig?' (Rhythmus-Frage; auf Nachhaltigkeit ausgerichtet)","'Was ist das Vertrauen-Problem in unserem Netzwerk – zu wenig Zeit füreinander, zu wenig Verlässlichkeit, oder zu wenig Direktheit bei Spannungen?' (Differenzierungsfrage; nicht alle Trust-Probleme sind gleich)'"],"beispiel":"Netzwerk-Jahresrückblick. Frage: 'Wie haben wir Cultivate Trust als drittes C in diesem Jahr gelebt?' Ergebnis: Wir haben 4 gemeinsame Inhaltstreffen gehabt, aber kein einziges Treffen mit Fokus auf Beziehung. Konsequenz: Im nächsten Jahresplan ein Präsenztreffen mit explizitem Trust-Design einbauen (Abendessen, persönliche Geschichten, kein Programm nach 18 Uhr). Anschlussfrage: 'Wer übernimmt dafür die Verantwortung?'","mini_form":"Trust-Audit in 10 Minuten: Letzte drei Treffen ansehen – wie viel Zeit war für Vertrauen? Genug, zu wenig, oder gar nicht? Eine Konsequenz für das nächste Treffen formulieren.","anlass_typen":["netzwerktreffen","retro","strategie"],"typ":"haltung","gruppen_sweetspot":"Als Haltung: keine Gruppe nötig; als Audit: 3–15 Personen aus dem Netzwerk","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"conflict-transformation","name":"Conflict Transformation (Lederach)","feld":"E","kurz":"Konflikt als Chance für dauerhaften Wandel von Beziehungen und Strukturen begreifen statt nur als Problem zum Abstellen.","schritte":["Aktuelle Konfliktsituation schildern – Linse 1: die unmittelbare Episode","Linse 2: das Epizentrum – welche Beziehungsmuster und Strukturen erzeugen solche Episoden immer wieder?","Linse 3: das Zukunftsbild – welche Beziehungen und Strukturen wollen wir stattdessen?","Antworten verbinden: kurzfristige Lösung der Episode + langfristige Arbeit am Epizentrum","Erste Schritte auf beiden Zeithorizonten festlegen"],"zweck":"Konflikt als Chance für dauerhaften Wandel von Beziehungen und Strukturen begreifen statt nur als Problem zum Abstellen.","hinweise":"Nicht als schnelle Problemlösung framen – Transformation denkt in Jahren. Die Episode trotzdem ernst nehmen, sonst fühlt sich die akute Not übergangen. Wann NICHT: wenn akuter Schutz vor Gewalt Vorrang hat.","phasen":["verstehen","konflikt"],"ebenen":["team","organisation","netzwerk","feld"],"modi":["konflikt","klaerung"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Beyond Intractability – Conflict Transformation (Lederach)","url":"https://www.beyondintractability.org/essay/transformation"},{"typ":"buch","titel":"John Paul Lederach: The Little Book of Conflict Transformation (2003)"},{"typ":"buch","titel":"Peacebuilding Practice (Woman PeaceMaker Program, 2023) – Chapter 2: Conflict Transformation"},{"typ":"buch","titel":"John Paul Lederach: The Moral Imagination – The Art and Soul of Building Peace – Kapitel 5: On Peace Accords"}],"wann_passt":["Einführungs- oder Orientierungsformat (Lernformat, 10–30 Personen), wenn eine Gruppe den Unterschied zwischen Konfliktlösung (kurzfristig, symptomfokussiert) und Konflikttransformation (langfristig, beziehungsfokussiert) verstehen und auf ihre Arbeit anwenden soll.","Reflexionsrunde nach einer Verhandlung oder Mediation, die formal 'erfolgreich' war, aber kein Vertrauen aufgebaut hat — Konflikttransformation fragt nach dem relationalen Unterbau, nicht nur dem Ergebnis.","Strategiegespräch in Organisationen, die in komplexen Konfliktkontexten arbeiten: Wann lohnt es sich, tiefer in Beziehungsarbeit zu investieren, statt schnelle Lösungen anzustreben?"],"wann_nicht":["In akuten Krisensituationen, wo Handlungsfähigkeit gefragt ist — Konflikttransformation ist ein langfristiger Rahmen, kein Krisenprotokoll.","Als Ersatz für konkretes Methoden-Know-how: Das Konzept allein ersetzt nicht die Kompetenz in Mediation, Dialogue oder Community-Prozessen.","Wenn die Gruppe ausschließlich nach schnellen Lösungen sucht und keine Bereitschaft mitbringt, über systemische Ursachen nachzudenken."],"fokusfragen":["„Was würde sich ändern, wenn dieser Konflikt wirklich transformiert wäre — nicht nur gelöst, sondern so verarbeitet, dass er die Beziehungen gestärkt hat?“ (Transformationshorizont)","„Wo in diesem Konflikt steckt die eigentliche Verletzung — und wer trägt sie?“ (Beziehungsebene freilegen)","„Was wäre ein erstes konkretes Zeichen, dass eine Transformation beginnt — welches Verhalten, welche Geste?“ (Einstieg in die Praxis)"],"mini_form":"Kurz-Reflexion 'Lösung vs. Transformation' in 10 Minuten: Zwei Spalten. Team nennt Unterschiede: Was ist eine 'Lösung' dieses Konflikts? Was wäre eine 'Transformation'? Der Kontrast allein erzeugt Orientierung.","anlass_typen":["lernformat","dialograum","konfliktklaerung"],"typ":"rahmenmodell","gruppen_sweetspot":"6–25 Personen","stimmung_geeignet":["neugierig","belastet","skeptisch"]},{"id":"glasl-eskalation","name":"Glasl Eskalationsstufen","feld":"E","kurz":"Den Eskalationsgrad eines Konflikts diagnostizieren und die Interventionsform daran ausrichten.","schritte":["Die neun Stufen in drei Ebenen vorstellen: win-win (1–3), win-lose (4–6), lose-lose (7–9)","Den eigenen Konflikt anhand konkreter Verhaltensbeobachtungen einstufen","Einschätzen, auf welcher Stufe die andere Seite den Konflikt erlebt (oft höher)","Passende Interventionsform ableiten: Moderation (1–3), Prozessbegleitung/Mediation (4–6), Machteingriff (7–9)","Nächste Schritte und ggf. externe Unterstützung festlegen"],"zweck":"Den Eskalationsgrad eines Konflikts diagnostizieren und die Interventionsform daran ausrichten.","hinweise":"Diagnose-Tool, kein Bearbeitungsprozess. Selbsteinstufung verzerrt systematisch (eigene Seite milder). Wann NICHT: hocheskalierte Parteien gemeinsam einstufen lassen – das wird sofort zur gegenseitigen Schuldzuweisung; ab Stufe 6–7 keine Selbsthilfe mehr.","phasen":["verstehen","konflikt"],"ebenen":["team","organisation"],"modi":["konflikt","klaerung"],"formate":["coaching","prozessbegleitung"],"dauer_min":45,"dauer_max":90,"gruppe_min":2,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Thomas Jordan (Mediate.com) – Glasl's Nine-Stage Model Of Conflict Escalation","url":"https://mediate.com/glasls-nine-stage-model-of-conflict-escalation/"},{"typ":"buch","titel":"Friedrich Glasl: Konfliktmanagement (1980, laufend aktualisiert)"}],"wann_passt":["Coaching mit einer Führungskraft vor einer geplanten Konflikt-Intervention: Das Modell gibt ihr ein realistisches Bild der Eskalationsstufe und verhindert, dass sie mit Moderationsangeboten in eine Situation geht, die externe Machteingriffe braucht (Stufe 7+).","Fortbildung für Personalverantwortliche oder Mediator:innen: Die neun Stufen als Lehreinheit - mit Fallvignetten, die die Gruppe einstuft. Sehr lernwirksam, weil alle eine Meinung haben und die Abweichungen das Gespräch tragen.","Beratungsgespräch mit einem Team, das einen laufenden Konflikt hat und wissen will, welche Unterstützung es braucht: Glasl gibt eine gemeinsame Sprache für den Schweregrad."],"wann_nicht":["Beide Konfliktparteien gemeinsam das Modell anwenden lassen - ab Stufe 4 wird die gemeinsame Einstufung sofort zur nächsten Eskalationsrunde (gegenseitige Schuldzuweisung, wer höher einstuft).","Ab Stufe 6-7 als Selbsthilfeinstrument einsetzen - dort braucht es externen Machteingriff oder Eskalationsstopp-Massnahmen, keine Reflexion.","Als alleinige Grundlage für Interventionsentscheidungen: Das Modell diagnostiziert, ersetzt aber keine Kontextanalyse der spezifischen Konstellation."],"fokusfragen":["Auf welcher Stufe würden Sie den Konflikt einordnen - und auf welcher Stufe sehen Sie die andere Partei? (Selbst- vs. Fremdwahrnehmung offenlegen)","Was passiert in dieser Konstellation, das Sie auf Stufe X einordnen lässt - welches Verhalten, welche Eskalationsdynamik? (konkrete Beobachtungen sammeln)","Welche Form von Unterstützung brauchte es auf dieser Stufe realistischerweise? (Intervention ableiten)"],"beispiel":"Coaching-Einstieg: Stellen Sie sich die neun Stufen als Treppe vor - Stufe 1 ist eine Meinungsverschiedenheit, Stufe 9 ist der Punkt, an dem beide Seiten eigene Vernichtung in Kauf nehmen, um die andere Seite zu schädigen. Wo auf dieser Treppe stehen Sie? Person antwortet: Vielleicht Stufe 4 oder 5. Coach: Was beobachten Sie konkret, das Sie dorthin einordnet? Person beschreibt Koalitionsbildung und Kommunikationsabbruch. Coach: Was glauben Sie, wo die andere Seite sich selbst einordnen würde? - Oft liegt die andere Seite höher. Dann: Auf Stufe 4-5 wird Moderation allein nicht mehr ausreichen - haben Sie überlegt, ob professionelle Prozessbegleitung sinnvoll wäre? Zweck: Das Modell schafft gemeinsame Sprache und zeigt realistisch, welche Interventionsform nötig ist.","mini_form":"Stufen-Selbsteinschätzung: Jede Person tippt anonym (z.B. via Mentimeter) ihre Einschätzung der Eskalationsstufe. Verteilung zeigen und Abweichungen besprechen - 10 Minuten, sehr aufschlussreich in Gruppen.","anlass_typen":["konfliktklaerung","coaching","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"Einzelcoaching oder Kleingruppe (3-8) für Diagnose; Fortbildungsgruppen bis 20 für Lernzweck","stimmung_geeignet":["angespannt","skeptisch","neugierig"]},{"id":"do-no-harm","name":"Do No Harm","feld":"E","kurz":"Sicherstellen, dass eine Intervention Konfliktlinien abschwächt statt sie unbeabsichtigt zu verschärfen.","schritte":["Konfliktkontext analysieren: Teiler (Dividers) und Verbinder (Connectors) sammeln","Das eigene Vorhaben daneben legen: Ressourcentransfers und implizite ethische Botschaften","Wirkung prüfen: Stärkt das Vorhaben Teiler oder Verbinder?","Programmoptionen anpassen, wo es Teiler verstärkt","Monitoring vereinbaren – Kontext und Wirkung verändern sich laufend"],"zweck":"Sicherstellen, dass eine Intervention Konfliktlinien abschwächt statt sie unbeabsichtigt zu verschärfen.","hinweise":"Keine Einmal-Übung, sondern wiederkehrender Reflexionszyklus. Ehrlich werden bei den eigenen Ressourcenwirkungen – dort liegt der häufigste Schaden.","phasen":["verstehen","planen","reflektieren"],"ebenen":["organisation","netzwerk","feld"],"modi":["klaerung","reflexion"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Conflict Sensitivity Community Hub – Ressourcen zu Do No Harm / Conflict Sensitivity","url":"https://www.conflictsensitivityhub.net/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up (PME Guidelines GIZ Civil Peace Service)"},{"typ":"buch","titel":"Mary B. Anderson: Do No Harm – How Aid Can Support Peace or War (1999)"},{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 1: Conflict Analysis / Do No Harm"},{"typ":"buch","titel":"Peacebuilding Practice (Woman PeaceMaker Program, 2023) – Chapter 4: Conflict Sensitivity & DNH"}],"wann_passt":["Programmplanung in konfliktsensitiven Kontexten (5–20 Personen): bevor Aktivitäten festgelegt werden, Analyse welche Connectors (verbindende Faktoren) und Dividers (trennende Faktoren) im Kontext existieren — damit Programmdesign nicht unabsichtlich Trennlinien verstärkt.","Review laufender Programme in Kontexten, wo die Konfliktsituation sich verändert hat: Die vier DNH-Analysekomponenten (Kontext, Verhalten der Akteur:innen, Programm, Optionen) zeigen systematisch, wo das Programm ungewollte Wirkungen entfaltet.","Ausbildung und Sensibilisierung von Feldteams (8–20 Personen), die in fragilen Kontexten arbeiten: Die sechs impliziten ethischen Botschaften (z.B. 'wessen Sicherheit zählt') machen unsichtbare Annahmen sichtbar.","Strategische Entscheidungssituationen mit mehreren Optionen: DNH-Analyse filtert, welche Option am wenigsten Dividers aktiviert."],"wann_nicht":["Als reines Compliance-Formular: DNH verpufft, wenn es nur zum Abhaken ausgefüllt wird — es braucht ehrliche Auseinandersetzung mit dem was das Programm möglicherweise anrichtet.","In akuten Krisensituationen unter extremem Zeitdruck: dann zuerst Handlungsfähigkeit sichern, DNH-Reflexion nachgelagert.","Ohne Kontextwissen: Connectors und Dividers lassen sich nicht im Büro identifizieren — sie erfordern lokale Perspektiven aus der Zielgemeinschaft."],"fokusfragen":["„Welche Faktoren verbinden die Menschen in diesem Kontext trotz des Konflikts — und berühren unsere Aktivitäten diese Connectors?“ (Connector-Analyse)","„Was könnte daran, wie wir arbeiten — nicht nur was wir tun — Spannungen zwischen Gruppen verstärken?“ (implizite ethische Botschaften)","„Wenn wir unser Programm so verändern würden, dass es Dividers schwächt, was müssten wir konkret anders machen?“ (Optionsanalyse)"],"mini_form":"Connectors-Dividers in 15 Minuten: Je zwei Spalten auf einem Blatt, Team identifiziert 3–5 Connectors und 3–5 Dividers des Kontexts. Dann eine einzige Frage: 'Welcher Divider wird durch unser aktuelles Vorgehen möglicherweise verstärkt?' — genügt als Frühwarnsignal.","anlass_typen":["strategie","lernformat","retro"],"typ":"werkzeug","gruppen_sweetspot":"6–15 Personen, mit lokalem Kontextwissen im Raum","stimmung_geeignet":["neugierig","belastet","skeptisch"],"beispiel":"Connectors-Dividers-Scan in einer Teamreflexion: Zwei Flipcharts — 'Verbindendes' und 'Trennendes'. Das Team sammelt für ihren Kontext: gemeinsame Märkte, geteilte religiöse Feste, gemeinsame Geschichte (Connectors) vs. unterschiedliche Zugang zu Land, Erinnerungskonflikte, ethnische Identifikation (Dividers). Dann: 'Welche unserer Aktivitäten stärken Connectors? Welche könnten unabsichtlich Dividers aktivieren?' Beispiel: Ein Trainingsformat, das nur eine Gruppe erreicht, kann als Bevorzugung gelesen werden — selbst wenn die Auswahl rein kapazitätsbasiert war. Anschlussfrage: 'Was müssten wir ändern, damit beide Gruppen das Programm als für sie gemacht erleben?'"},{"id":"transitional-justice","name":"Transitional Justice / Reconciliation","feld":"E","kurz":"Verstehen, wie Gesellschaften nach Massengewalt Aufarbeitung, Gerechtigkeit und Versöhnung organisieren.","schritte":["Die vier Säulen vorstellen: Wahrheitsfindung, Strafverfolgung, Reparationen, Garantien der Nichtwiederholung","Einen konkreten Fallkontext auf die Säulen kartieren: Was geschieht, was fehlt?","Spannungsfelder diskutieren: Frieden vs. Gerechtigkeit, Amnestie vs. Strafverfolgung","Opferzentrierung prüfen: Wer definiert, was Gerechtigkeit ist?","Implikationen für das eigene Vorhaben ableiten"],"zweck":"Verstehen, wie Gesellschaften nach Massengewalt Aufarbeitung, Gerechtigkeit und Versöhnung organisieren.","hinweise":"Hochsensibel, sobald Betroffene im Raum sind – dann Trauma-sensible Moderation und Freiwilligkeit sichern. Wann NICHT: als abstrakte Schreibtischübung durchziehen, wenn Teilnehmende selbst Gewalt erlebt haben und darauf nicht vorbereitet wurde.","phasen":["verstehen","konflikt"],"ebenen":["feld"],"modi":["klaerung","reflexion"],"formate":["workshop","fortbildung"],"dauer_min":90,"dauer_max":180,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"International Center for Transitional Justice – What is Transitional Justice?","url":"https://www.ictj.org/what-transitional-justice"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"}],"wann_passt":["Fortbildung für Fachkräfte in Post-Konflikt-Kontexten: Die vier Säulen (Wahrheit, Strafverfolgung, Reparation, Garantien der Nichtwiederholung) als Analyserahmen für konkrete Länderfälle - Ruanda, Südafrika, Kolumbien.","Policy-Workshop mit Akteur:innen, die an Versöhnung sprogrammen arbeiten: Welche Säule ist in unserem Kontext besonders schwach? Wo liegen die Spannungsfelder (Amnestie vs. Strafverfolgung)?","Reflexionsrunde in Programmen, die mit Überlebenden von Massengewalt arbeiten: Transitional Justice als konzeptueller Rahmen, der erklärt, warum Einzelgespräche und gesellschaftliche Ebene zusammenhängen."],"wann_nicht":["Als abstrakte Schreibtischübung, wenn Betroffene im Raum sind und keine trauma-sensible Begleitstruktur vorhanden ist.","Wenn Teilnehmende selbst Überlebende sind und die Sitzung nicht explizit als Verarbeitungsraum konzipiert wurde - dann braucht es spezialisierte psychosoziale Begleitung.","In Kontexten, wo der Konflikt noch aktiv ist - Transitional Justice setzt mindestens einen formalen Übergang (Waffenstillstand, Regierungswechsel) voraus."],"fokusfragen":["Welche der vier Säulen ist in diesem Kontext am stärksten vertreten - welche fehlt fast völlig? (Analyse-Einstieg)","Wer definiert in diesem Prozess, was Gerechtigkeit bedeutet - und wessen Stimme fehlt? (Opferzentrierung prüfen)","Wo liegt die größte Spannung: zwischen Frieden und Gerechtigkeit, Amnestie und Strafverfolgung? (Dilemmadiskussion)"],"mini_form":"Vier-Säulen-Kartierung: 15 Minuten, vier Flipcharts (Wahrheit / Strafverfolgung / Reparation / Nichtwiederholung), Gruppe klebt Punkte bei vorhandenen Elementen, Lücken werden sichtbar.","anlass_typen":["lernformat","strategie","dialograum"],"typ":"rahmenmodell","gruppen_sweetspot":"4-20 Personen; kleiner (8-12) wenn Betroffene anwesend","stimmung_geeignet":["neugierig","belastet"]},{"id":"multi-track-diplomacy","name":"Multi-Track Diplomacy","feld":"E","kurz":"Friedensarbeit als Zusammenspiel vieler gesellschaftlicher Ebenen sehen und das eigene Handeln darin verorten.","schritte":["Die neun Tracks vorstellen (Regierung, professionelle Konfliktbearbeitung, Wirtschaft, Bürger:innen, Bildung/Forschung, Aktivismus, Religion, Förderung, Medien)","Akteure des eigenen Konfliktkontexts je Track sammeln","Aktivitäten und Lücken markieren: Welche Tracks sind aktiv, welche brach?","Andockpunkte für das eigene Vorhaben identifizieren","Track-übergreifende Verbindungen planen"],"zweck":"Friedensarbeit als Zusammenspiel vieler gesellschaftlicher Ebenen sehen und das eigene Handeln darin verorten.","hinweise":"Kein Track wirkt allein – Karte auf Verbindungen hin lesen, nicht auf Zuständigkeiten. Gefahr der Beliebigkeit, wenn keine Priorisierung folgt.","phasen":["verstehen","planen"],"ebenen":["netzwerk","feld"],"modi":["klaerung"],"formate":["workshop","fortbildung"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Institute for Multi-Track Diplomacy – What Is Multi-Track Diplomacy?","url":"https://imtdsite.wordpress.com/about/what-is-multi-track-diplomacy/"},{"typ":"buch","titel":"Louise Diamond / John McDonald: Multi-Track Diplomacy – A Systems Approach to Peace (1996)"}],"wann_passt":["Strategieworkshop einer Friedensorganisation, die ihren Platz im größeren Ökosystem finden will: Die neun Tracks als Karte, um zu sehen, welche Ebenen schon aktiv sind und wo Lücken oder Andockpunkte liegen.","Fortbildung für Multiplikator:innen in Konfliktkontexten: Das Modell vermittelt, dass Regierungsebene und Zivilgesellschaft nicht getrennt agieren, sondern zusammen ein Friedenssystem bilden.","Netzwerkplanung bei multi-sektoriellen Konstellationen (z.B. NGO + Wirtschaft + Religion): Welche Tracks sind vertreten, welche nicht - und wie können wir diese Lücke schliessen?"],"wann_nicht":["Wenn die Gruppe keinen Bezug zum Friedenskontext hat - das Modell wirkt dann zu abstrakt und akademisch.","Als Einzeltool ohne Priorisierung: Die neun Tracks zu kennen hilft nichts, wenn keine konkreten Andockpunkte und nächsten Schritte abgeleitet werden.","Als Ersatz für Kontextanalyse: Das Modell strukturiert, gibt aber kein Bild der Machtverhältnisse und Dynamiken zwischen den Tracks."],"fokusfragen":["Welche der neun Tracks sind in unserem Kontext aktiv - und welche liegen brach? (Lückenanalyse)","Wo auf der Track-Karte sitzt unsere Organisation - und mit welchen anderen Tracks haben wir Verbindungen? (Verortung)","Wo läge der größte Hebel, um Track-übergreifende Verbindungen herzustellen? (strategische Priorisierung)"],"mini_form":"Track-Mapping: Jede:r klebt einen Punkt bei dem Track, in dem die eigene Organisation primär arbeitet - Verteilung sichtbar machen, Verbindungen einzeichnen (5-10 Minuten).","anlass_typen":["strategie","netzwerktreffen","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"3-20 Personen; ideal für multi-sektorielle Netzwerke","stimmung_geeignet":["neugierig","frisch"]},{"id":"bohm-dialogue","name":"Bohm Dialogue","feld":"E","kurz":"Gemeinsames Denken und geteilte Bedeutung entstehen lassen, jenseits von Debatte und Positionsverteidigung.","schritte":["Kreis ohne Agenda und ohne Entscheidungsziel eröffnen","Prinzipien vereinbaren: eigene Urteile suspendieren, in die Mitte sprechen statt zu Personen, radikal zuhören","Lange Öffnungsphase mit Stille aushalten – das Thema findet die Gruppe","Eigene Reaktionen beobachten und ggf. als Beobachtung teilen","Ohne Zusammenfassung oder Ergebniszwang schließen"],"zweck":"Gemeinsames Denken und geteilte Bedeutung entstehen lassen, jenseits von Debatte und Positionsverteidigung.","hinweise":"Ergebnisorientierte Gruppen frustriert das Format – Erwartung vorab klären. Mindestens 60 Minuten ansetzen. Wann NICHT: wenn eine Entscheidung gebraucht wird.","phasen":["vertiefen","oeffnen"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung","verbindung"],"formate":["workshop","reflexionsrunde"],"dauer_min":60,"dauer_max":120,"gruppe_min":8,"gruppe_max":40,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"David Bohm / Donald Factor / Peter Garrett – Dialogue: A Proposal","url":"http://www.david-bohm.net/dialogue/dialogue_proposal.html"},{"typ":"buch","titel":"David Bohm: On Dialogue (1996)"}],"wann_passt":["Gruppe von 10-20 Menschen, die regelmäßig zusammenarbeiten und merken, dass ihre Meetings immer auf denselben Positionen steckenbleiben: Bohm Dialogue schafft einen Raum jenseits von Agenda und Entscheidungszwang, in dem kollektives Denken entstehen kann.","Lerngemeinschaft (Community of Practice, Fortbildungsgruppe), die mindestens monatlich zusammenkommt: Das Format braucht Kontinuität - dieselben Menschen über mehrere Sitzungen. Mit der Zeit löst sich die formale Moderation auf.","Abschluss eines intensiven Strategieprozesses: Bohm Dialogue als Raum, bevor eine Gruppe in den Umsetzungsmodus geht - nicht zur Entscheidung, sondern um gemeinsam innezuhalten und zu vertiefen."],"wann_nicht":["Wenn eine Entscheidung gebraucht wird oder ein Ergebnis erwartet wird - Bohm Dialogue hat per Design kein Produkt und frustriert ergebnisorientierte Gruppen erheblich.","Als Einzelformat ohne Kontinuität: Ein einziger Bohm Dialogue ist kaum mehr als eine ungewohnte Gesprächsform; die Wirkung entfaltet sich über viele Sitzungen.","Bei stark hierarchischen Gruppen, in denen das freie Suspendieren von Urteilen durch Anwesenheit von Vorgesetzten strukturell verhindert wird.","Online: Das Format verliert wesentliche Qualitäten (Stille, Körperpräsenz im Kreis, nonverbale Signale)."],"fokusfragen":["Welche Annahme trägst du in dieses Gespräch mit, die du bereit wärst, zu suspendieren - nicht aufzugeben, sondern anzuhalten und anzuschauen? (Einstieg in Suspension of Judgement)","Was hat dich in dem, was jemand gerade gesagt hat, bewegt - nicht als Meinung, sondern als innere Reaktion? (Eigene Reaktion als Beobachtung teilen)"],"mini_form":"20-Minuten-Bohm-Ausschnitt: Kreis, kein Tisch, kein Thema ausser 'Was beschäftigt uns gerade?', eine Person spricht, alle hören, Mindeststille von 30 Sekunden zwischen Wortmeldungen. Kein Abschluss-Plakat, kein Ergebnis. Danach Kurzreflexion: 'Was war anders als sonst?'","anlass_typen":["dialograum","teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"8-20 ideal; unter 6 fehlt die Vielfalt, über 30 nur mit sehr erfahrener Begleitung","stimmung_geeignet":["neugierig","müde","belastet"]},{"id":"sustained-dialogue","name":"Sustained Dialogue (Saunders)","feld":"E","kurz":"Zerrüttete Beziehungen zwischen Gruppen über wiederholte, moderierte Gespräche schrittweise verwandeln.","schritte":["Rahmen klären: Es geht um die Veränderung der Beziehung, nicht um Verhandlung","Erfahrungen zum Thema austauschen – jede Person erzählt, alle hören","Gemeinsam Muster der Beziehung zwischen den Gruppen benennen","Szenarien entwickeln: Was würde die Beziehung vertiefen oder verändern?","Nächste Runde vereinbaren – Kontinuität derselben Gruppe ist der Wirkstoff"],"zweck":"Zerrüttete Beziehungen zwischen Gruppen über wiederholte, moderierte Gespräche schrittweise verwandeln.","hinweise":"Eine Einzelsession ist nur der Auftakt – die Methode wirkt über Monate in fünf Phasen. Teilnehmende müssen sich auf Wiederkommen verpflichten, sonst bleibt es ein Strohfeuer.","phasen":["konflikt","verstetigen"],"ebenen":["netzwerk","feld"],"modi":["konflikt","verbindung"],"formate":["prozessbegleitung"],"dauer_min":90,"dauer_max":180,"gruppe_min":8,"gruppe_max":15,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Sustained Dialogue Institute – Our Approach","url":"https://sustaineddialogue.org/"},{"typ":"buch","titel":"Harold Saunders: A Public Peace Process (1999)"}],"wann_passt":["Zwei Gemeinschaftsgruppen (z.B. verschiedene ethnische, religiöse oder politische Gruppen in einer Stadt), die kaum miteinander sprechen, aber dauerhaft zusammenleben müssen: Sustained Dialogue baut über 5 Phasen und viele Monate gemeinsames Beziehungskapital auf, das politische Verhandlungen erst möglich macht.","Universitätsprogramm oder Jugendaustausch, wo eine einmalige Begegnung nicht ausreicht: Dieselben jungen Menschen treffen sich alle 2-3 Wochen über ein Semester - die Kontinuität ist der Wirkstoff.","Zerrüttete Kooperationsbeziehung zwischen zwei Organisationen, die strukturell aufeinander angewiesen sind: Wenn nicht verhandelt, sondern die Beziehung selbst verändert werden soll."],"wann_nicht":["Wenn Teilnehmende sich nicht auf Wiederkommen verpflichten können oder wollen - eine Einzelsitzung ist dann ehrlicher.","Wenn eine schnelle, sichtbare Lösung gebraucht wird: Sustained Dialogue ist auf 6-18 Monate angelegt; als Kurzformat wäre es ein Etikettenschwindel.","Bei akutem Gewaltgeschehen: Erst Sicherheit, dann Dialog."],"fokusfragen":["Warum sitzen wir heute hier - was ist der Zustand unserer Beziehung, den wir verändern wollen? (Phase 1: Rahmung)","Was haben Sie erlebt - konkret, aus Ihrer Perspektive - was zu dieser Beziehung geführt hat? (Phase 2: Erfahrungen austauschen)","Welche Muster sehen Sie in unserer Beziehung als Gruppen - nicht zwischen uns als Personen, sondern strukturell? (Phase 3: Muster benennen)"],"mini_form":"Phase-1-Einstieg (30 Minuten): Jede Person beschreibt in 3 Minuten, warum sie heute im Raum ist und was sie sich von dieser Serie erhofft - ohne Diskussion. Schafft das Bewusstsein, dass es um die Beziehung geht, nicht um eine Einzelsitzung.","anlass_typen":["dialograum","konfliktklaerung","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"8-15 ideal; zu klein fehlt Diversität, zu gross geht Tiefe verloren","stimmung_geeignet":["angespannt","skeptisch","belastet"]},{"id":"deep-democracy","name":"Deep Democracy (Lewis)","feld":"E","kurz":"Minderheitsstimmen hörbar machen und in Entscheidungen integrieren, bevor sie als Sabotage in den Untergrund gehen.","schritte":["Alle Sichtweisen zum Thema sammeln – auch die leisen","Aktiv nach dem Nein fischen: Wer sieht das anders? Was sagt niemand laut?","Abstimmen","Die überstimmte Minderheit fragen: Was brauchst du, um mitzugehen?","Diese Bedingung in den Mehrheitsbeschluss aufnehmen","Erneut abstimmen – die Entscheidung trägt jetzt die Weisheit der Minderheit in sich"],"zweck":"Minderheitsstimmen hörbar machen und in Entscheidungen integrieren, bevor sie als Sabotage in den Untergrund gehen.","hinweise":"Moderation muss neutral bleiben und die Minderheit aktiv schützen; das Nein ist Information, kein Störfall. Wann NICHT: bei massiver Machtasymmetrie ohne Schutzrahmen.","phasen":["entscheiden","konflikt"],"ebenen":["team","organisation"],"modi":["entscheidung","konflikt"],"formate":["workshop","meeting"],"dauer_min":30,"dauer_max":90,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Lewis Deep Democracy","url":"https://www.lewisdeepdemocracy.com/"}],"wann_passt":["Teamentscheidung, bei der eine Minderheit gegen den Konsens ist und das Nein nicht gehört wird: Deep Democracy macht die Energie des Neins zum Informationsträger - es fragt, was die Minderheit weiss, das die Mehrheit nicht sieht.","Gruppe, die eine scheinbar beschlossene Sache immer wieder sabotiert: Das Tool zeigt, dass der Widerstand Information trägt, keine Blockade ist - und holt das Unterground-Wissen an die Oberfläche.","Konfliktbearbeitung, wo eine Seite strukturell schwächer ist und in normalen Formaten nicht gehört wird: Deep Democracy schützt aktiv die Minderheitsstimme."],"wann_nicht":["Bei massiver Machtasymmetrie ohne geschützten Rahmen: Wenn die Führungskraft im Raum ist und das Nein reale Konsequenzen hat, funktioniert das Format nicht - es gibt nur gespieltes Nein.","Wenn die Moderation nicht neutral bleiben kann (z.B. hat eine persönliche Meinung zum Thema oder gehört einer Partei an).","Ohne ausreichende Facilitator-Ausbildung: Das Lewis-Modell braucht trainierte Meta-Skills (Neutralität, Umgang mit starken Emotionen, Schutz der Minderheit).","Bei rein informatorischen Meetings ohne echte Entscheidungsoffenheit - das Nein ernst zu nehmen muss real möglich sein."],"fokusfragen":["Was weiss der Teil von uns, der Nein sagt - welche Information trägt dieser Widerstand? (Nein als Informationsträger einführen)","Was braucht die Minderheit, damit sie dem Mehrheitsbeschluss nicht entgegenarbeiten muss? (Integrationsweg suchen)","Wenn die Minderheitsstimme recht hätte - was müssten wir dann wissen oder anders machen? (Perspektive ernst nehmen)"],"mini_form":"Nein-Runde (10 Minuten): Nachdem eine Entscheidung ansteht, explizit Raum für das Nein öffnen: Wer hat noch Bedenken oder Widerstand? Bitte ausformulieren. Alle hören zu. Dann: Was müsste sich ändern, damit ihr Nein kleiner würde? - kein Abstimmen, nur Zuhören und Weiterentwickeln.","anlass_typen":["entscheidungstreffen","konfliktklaerung","teamtag"],"typ":"methode","gruppen_sweetspot":"6-20 ideal; über 25 Personen mit Untergruppen arbeiten","stimmung_geeignet":["angespannt","skeptisch","müde"]},{"id":"circle-council","name":"Circle / Council","feld":"E","kurz":"Gleichwürdiges Sprechen und tiefes Zuhören strukturell sichern – jede Stimme bekommt denselben Raum.","schritte":["Mitte gestalten und Absicht der Runde benennen","Vereinbarungen treffen: zuhören ohne Urteil, von Herzen sprechen, Wesentliches sagen, Vertraulichkeit","Check-in-Runde mit Redeobjekt – nur wer es hält, spricht","Themenrunden (reihum oder Popcorn), Hüter:in darf jederzeit eine Pause einläuten","Check-out: jede Stimme schließt die Runde"],"zweck":"Gleichwürdiges Sprechen und tiefes Zuhören strukturell sichern – jede Stimme bekommt denselben Raum.","hinweise":"Das Redeobjekt entschleunigt bewusst – genau das ist die Funktion. Runden brauchen Zeit, Gruppengröße begrenzen. Wann NICHT: für schnelle operative Meetings – dort wirkt es künstlich.","phasen":["ankommen","vertiefen","reflektieren"],"ebenen":["team","organisation"],"modi":["verbindung","klaerung"],"formate":["workshop","reflexionsrunde","prozessbegleitung"],"dauer_min":45,"dauer_max":120,"gruppe_min":5,"gruppe_max":20,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"The Circle Way – Basic Guidelines","url":"https://www.thecircleway.net/circle-way-guidelines"},{"typ":"buch","titel":"Christina Baldwin / Ann Linnea: The Circle Way (2010)"}],"wann_passt":["Klärungsrunde in einem Team nach einem verletzenden Vorfall: Der Circle schafft einen Rahmen, in dem jede Person weiss, dass sie sprechen wird und gehört wird - das allein senkt Defensivität.","Auftakt einer sensiblen oder bedeutsamen Sitzung (Strategieprozess, Abschluss, Konfliktklärung): Der Circle als bewusster Raumhalter setzt einen anderen Ton als ein normales Meeting.","Regelmäßige Team-Check-ins, wo echte Stimmen gehört werden sollen statt performativer Rückmeldungen - besonders wenn Hierarchie im Raum ist, weil das Redeobjekt strukturell alle gleichstellt."],"wann_nicht":["Fuer operative Entscheidungs-Meetings mit knapper Agenda: Das Format entschleunigt bewusst - in einem Jour-fixe mit 12 Punkten wirkt es künstlich und erzeugt Frust.","Wenn die Gruppe das Redeobjekt als infantil empfindet (manche Unternehmenskulturen): Dann vorher erklären oder auf ein kulturell stimmiges Objekt wechseln.","Über mehr als 20 Personen ohne Untergruppen: Der Circle wird dann zu lang und die Konzentration bricht."],"fokusfragen":["Was trägst du in diesen Kreis mit - was liegt dir auf dem Herzen zu diesem Thema? (Öffnungsrunde)","Was nimmst du aus dem, was du gehört hast, mit - was hat dich bewegt oder überrascht? (Schlussrunde)","Wenn du dem Kreis eine Frage hinterlassen könntest, die uns alle beschäftigt - welche wäre das? (Vertiefungsrunde)"],"mini_form":"Blitz-Circle (8-12 Minuten): Redeobjekt in die Mitte, eine Frage, jede Person 1 Minute, kein Kommentar, kein Applaus. Reicht als Einstieg in schwierige Sitzungen, um die Stimmung im Raum zu holen.","anlass_typen":["konfliktklaerung","teamtag","dialograum","schwieriges_gespraech"],"typ":"methode","gruppen_sweetspot":"6-18 ideal; ab 4 möglich, über 20 nur mit Untergruppen","stimmung_geeignet":["angespannt","belastet","müde","skeptisch"]},{"id":"reflecting-team","name":"Reflecting Team (Andersen)","feld":"E","kurz":"Durch die Position des Zuhörens auf Gespräche über sich selbst neue Perspektiven auf das eigene Anliegen gewinnen.","schritte":["Fallgeber:in schildert Anliegen, Moderation interviewt – das Team hört nur zu","Wechsel: Das Team spricht untereinander wertschätzend und hypothetisch über das Gehörte – Fallgeber:in hört zu ohne zu reagieren","Rückwechsel: Fallgeber:in greift auf, was Resonanz erzeugt hat","Ggf. zweite Reflexionsschleife","Abschluss: Fallgeber:in benennt Mitnahme"],"zweck":"Durch die Position des Zuhörens auf Gespräche über sich selbst neue Perspektiven auf das eigene Anliegen gewinnen.","hinweise":"Sprache des Teams muss wertschätzend, fragend und möglichkeitsorientiert sein – Bewertungen oder Ratschläge zerstören den Mechanismus. Trennung der Gesprächsräume strikt halten.","phasen":["vertiefen","reflektieren"],"ebenen":["person","team"],"modi":["reflexion","klaerung"],"formate":["coaching","teamentwicklung","fortbildung"],"dauer_min":30,"dauer_max":60,"gruppe_min":4,"gruppe_max":10,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"socialnet Lexikon – Reflecting Team","url":"https://www.socialnet.de/lexikon/Reflecting-Team"},{"typ":"buch","titel":"Tom Andersen: Das Reflektierende Team (1990)"}],"wann_passt":["Supervision oder kollegiale Fallberatung: Eine Person schildert einen Fall, ein kleines Team reflektiert laut darüber, die erzählende Person hört zu und kann danach antworten - sie erhält Aussenperspektiven ohne direkte Ratschläge.","Ausbildungskontext (Coaching, Therapie, Mediation): Trainee führt ein Gespräch, beobachtendes Team reflektiert offen - das ist lernwirksamer als nachträgliches Feedback, weil der Kontext noch präsent ist.","Klärungsprozess in einer Gruppe, wo eine Subgruppe eine Entscheidung getroffen hat und die Gesamtgruppe Rückmeldung geben soll: Das Reflecting Team verhindert, dass Rückmeldung zur Verteidigung oder Rechtfertigung wird."],"wann_nicht":["Wenn das Team in bewertende oder ratgebende Sprache verfällt - dann bricht der Mechanismus zusammen (Beobachtende müssen ausschliesslich möglichkeitsorientiert sprechen, im Konjunktiv).","Wenn die erzählende Person das Zuhören als demütigend erlebt (z.B. statusniedrigere Mitarbeiterin hört dem Team zu, wie es über sie reflektiert) - dann vorab Schutz klären.","In hocheskalierten Konflikten ohne neutrale Moderation: Das Format setzt grundlegende Sicherheit voraus."],"fokusfragen":["Was hat uns in dem, was wir gehört haben, bewegt - nicht als Bewertung, sondern als innere Reaktion? (Team-Einstieg in Reflecting-Runde)","Welche Möglichkeiten sehen wir, die die Person vielleicht noch nicht gesehen hat - als Einladung, nicht als Ratschlag? (Möglichkeitsraum öffnen)","Was nimmst du mit - was von dem, was du gehört hast, trifft etwas in dir? (Rückkehr zur erzählenden Person)"],"mini_form":"Mini-Reflecting (10 Minuten): Jemand schildert ein Dilemma (3 Min.), zwei Personen reflektieren laut, ohne die Person anzusprechen (5 Min.), Person antwortet, was sie gehört hat (2 Min.). Kein ausführlicheres Format nötig.","anlass_typen":["coaching","lernformat","konfliktklaerung"],"typ":"methode","gruppen_sweetspot":"1 erzählende Person + 2-5 im Reflecting Team; max. 20 Personen gesamt","stimmung_geeignet":["neugierig","belastet","müde"]},{"id":"betzavta","name":"Betzavta","feld":"E","kurz":"Demokratische Prinzipien nicht lehren, sondern am eigenen Verhalten im Dilemma erfahrbar machen.","schritte":["Eine Betzavta-Übung mit eingebautem Dilemma wählen","Übung durchführen – die Entscheidung ist echt, der Konflikt entsteht von selbst","Prozess unterbrechen, wenn das Dilemma sichtbar ist","Reflexion: Wie sind wir mit Freiheit, Mehrheit, Minderheit umgegangen?","Transfer: Was heißt das für demokratisches Miteinander im Alltag?"],"zweck":"Demokratische Prinzipien nicht lehren, sondern am eigenen Verhalten im Dilemma erfahrbar machen.","hinweise":"Die Wirkung liegt fast vollständig in der Auswertung – ohne gründliche Reflexion bleibt nur Frust. Braucht ausgebildete Anleitung. Wann NICHT: ohne ausreichend Zeit für die Auswertung oder als Energizer missverstanden.","phasen":["vertiefen","reflektieren"],"ebenen":["team","organisation"],"modi":["konflikt","reflexion"],"formate":["fortbildung","workshop"],"dauer_min":90,"dauer_max":180,"gruppe_min":8,"gruppe_max":25,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["beteiligend","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Akademie Führung & Kompetenz – Betzavta / Mehr als eine Demokratie","url":"https://www.cap-lmu.de/akademie/schwerpunkte/betzavta-miteinander/"},{"typ":"buch","titel":"Uki Maroshek-Klarman: Mehr als eine Demokratie (Bertelsmann Stiftung)"},{"typ":"online","titel":"Adam Institute - Betzavta Method","url":"https://www.adaminstitute.org.il/language/en/betzavta_method-2/"}],"wann_passt":["Politische Bildung oder Demokratiebildung mit Erwachsenen oder Jugendlichen: Betzavta macht erfahrbar, was es kostet, Rechte zu teilen - durch ein Dilemma-Spiel, das echte Emotionen auslöst, die dann analysiert werden.","Fortbildung für Multiplikator:innen (Lehrer:innen, Jugendbetreuer:innen, Sozialarbeiter:innen), die demokratisches Miteinander vermitteln wollen: Das Format gibt ihnen ein konkretes Werkzeug, das sie weiterverwenden können.","Gruppen, die mit Polarisierung zu tun haben: Betzavta zeigt, dass Konflikte zwischen Rechten und Interessen nicht durch Überzeugung, sondern durch gemeinsame Verfahren bearbeitet werden."],"wann_nicht":["Ohne ausreichend Auswertungszeit: Die Wirkung liegt fast vollständig in der Reflexion nach dem Dilemma-Spiel - ohne diese wird das Erlebnis zur Frustration.","Als Energizer oder Aufwaermübung missverstanden: Das Format ist kein Spielchen, sondern eine ernsthafte Lernerfahrung, die Zeit für die Verarbeitung braucht.","Mit unausgebildeten Moderator:innen in hochkonfliktuösen Gruppen: Betzavta braucht ausgebildete Facilitation, weil das Spiel echte Emotionen erzeugt."],"fokusfragen":["Was haben Sie in dem Dilemma gespürt - welche Impulse, welche Konflikte? (Auswertungseinstieg)","Wo haben Sie zwischen Ihrem Interesse und dem Recht anderer abgewogen - und wie haben Sie entschieden? (Verbindung zu demokratischen Prinzipien)","Was bedeutet das für Situationen in Ihrem Alltag, in denen Rechte kollidieren? (Transfer)"],"mini_form":"Kein sinnvolles Mini-Format: Betzavta braucht das vollständige Dilemma-Erlebnis und die Auswertung - Teilformen würden den Mechanismus zerstören.","anlass_typen":["lernformat","dialograum","teamtag"],"typ":"methode","gruppen_sweetspot":"12-24 ideal; unter 8 fehlt die Dynamik","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"nvc-4-schritte","name":"NVC – 4 Schritte","feld":"E","kurz":"Konfliktträchtige Kommunikation in eine Sprache übersetzen, die Verbindung statt Verteidigung auslöst.","schritte":["Beobachtung formulieren – konkret, ohne Bewertung","Gefühl benennen","Bedürfnis dahinter aussprechen","Bitte formulieren – konkret, positiv, verhandelbar","An realen Beispielen in Paaren üben","Feedback: Wo rutschten Bewertungen hinein?"],"zweck":"Konfliktträchtige Kommunikation in eine Sprache übersetzen, die Verbindung statt Verteidigung auslöst.","hinweise":"Größte Gefahr ist mechanischer GFK-Sprech – Haltung (Empathie) vor Technik. Beobachtung ohne Bewertung ist der schwerste Schritt, dort viel Übungszeit einplanen.","phasen":["vertiefen","konflikt"],"ebenen":["person","team"],"modi":["klaerung","konflikt"],"formate":["workshop","coaching","fortbildung"],"dauer_min":45,"dauer_max":120,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"PuddleDancer Press – 4-Part Nonviolent Communication (NVC)","url":"https://nonviolentcommunication.com/learn-nonviolent-communication/4-part-nvc/"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001)"},{"typ":"buch","titel":"Peacebuilding Practice (Woman PeaceMaker Program, 2023) – Chapter 11: Nonviolent Communication"}],"wann_passt":["Schwieriges 1:1-Gespräch, in dem eine Person eine Beschwerde oder Kritik ausdrücken muss, ohne die Beziehung zu beschädigen — die vier Schritte (Beobachtung, Gefühl, Bedürfnis, Bitte) geben Struktur für präzises, nicht-angreifendes Sprechen.","Team, das in destruktiven Kommunikationsmustern feststeckt (gegenseitige Vorwürfe, Schuldzuweisungen): NVC-Training von 60–90 Min. mit konkreten Beispielen aus dem Teamalltag bricht den Kreislauf auf.","Kontext mit Machtgefälle, wo die schwächere Partei lernt, Grenzen zu setzen (Protection-Modus nach Rosenberg): 'Wenn du X tust, werde ich Y tun, um mein Bedürfnis nach Z zu schützen.'"],"wann_nicht":["In stark asymmetrischen Konflikten mit physischer Gewalt oder echter Machtlosigkeit: NVC setzt voraus, dass die andere Person in der Lage und bereit ist, empathisch zu hören — das ist in Missbrauchsbeziehungen nicht gegeben.","Als Schnell-Technik ohne Einüben: Der Unterschied zwischen Beobachtung und Interpretation ('Du bist arrogant' vs. 'Ich sehe, dass du in drei Meetings nacheinander das Wort genommen hast ohne zu fragen') muss geübt werden — sonst klingt NVC künstlich.","Wenn die Gruppe keinen emotionalen Zugang hat oder emotionale Selbstoffenbarung kulturell unüblich ist — dann eher systemische Fragetechniken oder Mediation."],"fokusfragen":["„Was habe ich konkret gesehen/gehört — ohne Wertung? (Beobachtung, nicht Bewertung: 'Ich habe bemerkt, dass...' statt 'Du machst immer...')","„Welches Gefühl löst das in mir aus — und ist es wirklich ein Gefühl oder ein Gedanke über die andere Person?“ (Gefühl vs. Pseudo-Gefühl wie 'Ich fühle mich manipuliert')","„Welches Bedürfnis steckt hinter diesem Gefühl — was brauche ich, das gerade nicht erfüllt ist?“ (Bedürfnis als Brücke zur anderen Person)"],"beispiel":"NVC-Formulierung in einer Teamspannung: Statt 'Du hörst nie zu wenn ich spreche' (Vorwurf) → 'In unserem letzten Meeting habe ich bemerkt, dass du dreimal auf dein Handy geschaut hast, während ich gesprochen habe [Beobachtung]. Das hat mich frustriert [Gefühl], weil mir Gehörtwerden wichtig ist [Bedürfnis]. Ich möchte dich bitten, beim nächsten Meeting das Handy wegzulegen, wenn ich spreche [Bitte].' Anschlussfrage der Moderator:in: 'Was löst das in dir aus — was brauchst du gerade?' — öffnet den Dialog statt Rechtfertigungsschleife.","mini_form":"NVC-Satzrahmen in 5 Minuten: Jede:r schreibt für eine aktuelle Spannung die vier Sätze: 'Ich beobachte... / Ich fühle... / Weil ich brauche... / Ich bitte dich...' Allein aufschreiben, nicht zwingend aussprechen — schon das Formulieren bringt Klarheit.","anlass_typen":["schwieriges_gespraech","konfliktklaerung","lernformat","coaching"],"typ":"werkzeug","gruppen_sweetspot":"ideal 1:1 bis 8, Gruppen bis 15 mit Rollenspielen","stimmung_geeignet":["angespannt","belastet","neugierig"]},{"id":"selbstempathie","name":"Selbstempathie","feld":"E","kurz":"Die eigene innere Lage klären, bevor man spricht oder handelt – Voraussetzung für jeden empathischen Kontakt.","schritte":["Eine Situation wählen, die innerlich aufwühlt","Innere Urteile ungefiltert notieren","Hinter jedem Urteil das Gefühl benennen","Hinter jedem Gefühl das Bedürfnis finden","Beim Bedürfnis verweilen und spüren, was sich verschiebt","Ggf. eine Bitte an sich selbst formulieren"],"zweck":"Die eigene innere Lage klären, bevor man spricht oder handelt – Voraussetzung für jeden empathischen Kontakt.","hinweise":"Funktioniert auch still mitten in einer Sitzung (2–3 Minuten). Urteile nicht überspringen – sie sind das Rohmaterial, das zu den Bedürfnissen führt.","phasen":["reflektieren","ankommen"],"ebenen":["person"],"modi":["selbstzugang","reflexion"],"formate":["coaching","workshop","fortbildung"],"dauer_min":15,"dauer_max":45,"gruppe_min":1,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["schriftlich","strukturiert"],"blocktyp":["kern","reflexion"],"quellen":[{"typ":"online","titel":"PositivePsychology.com – Your Complete Nonviolent Communication Guide","url":"https://positivepsychology.com/non-violent-communication/"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001)"}],"wann_passt":["Vorbereitung auf ein schwieriges Gespräch: Bevor jemand in ein Klärungsgespräch, eine Konfrontation oder eine Verhandlung geht, hilft Selbstempathie, die eigenen Urteile (er ist unmöglich) in die dahinterliegenden Gefühle und Bedürfnisse zu übersetzen - das macht die eigene Kommunikation klarer und weniger reaktiv.","Mitten in einem laufenden Gespräch, wenn die Person merkt, dass sie sich schliesst oder hochkocht: Selbstempathie als kurze innere Pause (30-60 Sekunden), bevor man weiter spricht.","Coaching-Einstieg mit jemandem, der einen starken Ärger oder Vorwurf mitbringt: Erst die innere Lage klären, bevor über Strategien oder das Gegenüber gesprochen wird."],"wann_nicht":["Als Ersatz für berechtigten Protest oder Grenzziehung: Selbstempathie soll den Kontakt zu eigenen Bedürfnissen herstellen, nicht Bedürfnisse wegregulieren.","Bei akuter Dissoziation oder schwerem Trauma: Dann braucht es fachliche psychologische Begleitung, keine NVC-Technik.","Als Pflichtуебung in Gruppen: Selbstempathie wirkt nur, wenn die Person sie selbst will - erzwungene Innerlichkeit erzeugt Widerstand."],"fokusfragen":["Was sage ich mir gerade innerlich - welche Urteile tauchen auf? (Urteile benennen, nicht überspringen)","Was fühle ich dabei - welches Gefühl ist da, wenn ich diese Urteile beiseitelege? (Schicht darunter erreichen)","Was brauche ich gerade - welches Bedürfnis ist unerfullt? (Bedürfnis identifizieren)","Was möchte ich als nächstes tun - aus diesem Bedürfnis heraus? (Handlungsimpuls klären)"],"beispiel":"Person kommt aufgewühlt ins Coaching und sagt, ihre Kollegin habe sie heute vor allen blossgestellt - die sei einfach rücksichtslos. Coach: Ich höre, dass da gerade viel ist. Was spürst du, wenn du das sagst? Person: Ich bin wütend. Coach: Wuetend - und was steckt unter der Wut? Was war dir in diesem Moment wichtig, das nicht da war? Person überlegt: Respekt. Ich will respektvoll behandelt werden, besonders vor anderen. Coach: Und wenn du das weisst - was möchtest du als nächstes mit dieser Wut und diesem Bedürfnis machen? Zweck: Die Person muss die Urteile nicht loswerden; sie werden zum Material, das zu Gefühl und Bedürfnis führt. Dann kommt eine handlungsfähige Antwort statt Reaktion.","mini_form":"Stille Selbstempathie-Minute: Vor einem schwierigen Gespräch 60 Sekunden still sitzen, drei Fragen beantworten: Was erlebe ich gerade innerlich? Was fühle ich? Was brauche ich? Keine Antwort aufschreiben nötig - das innere Durchlaufen reicht.","anlass_typen":["coaching","schwieriges_gespraech","konfliktklaerung"],"typ":"werkzeug","gruppen_sweetspot":"Einzelperson; kann als angeleitete Stille in Gruppen bis 20 Personen gemacht werden","stimmung_geeignet":["angespannt","belastet","müde"]},{"id":"empathisches-zuhoeren","name":"Empathisches Zuhören","feld":"E","kurz":"Einem Menschen die Erfahrung geben, mit Gefühl und Bedürfnis vollständig gehört zu werden.","schritte":["Paare bilden, A erzählt eine belastende Situation","B hört nur zu – volle Präsenz, kein Rat, kein Trost, keine eigene Geschichte","B spiegelt als Vermutung: Bist du … (Gefühl), weil dir … (Bedürfnis) wichtig ist?","A korrigiert oder vertieft – B bleibt im Spiegeln, bis A sich verstanden fühlt","Rollenwechsel","Auswertung: Wie war es, so gehört zu werden?"],"zweck":"Einem Menschen die Erfahrung geben, mit Gefühl und Bedürfnis vollständig gehört zu werden.","hinweise":"Der Ratschlag-Reflex ist der häufigste Stolperstein – vorher explizit verbieten. Vermutungen anbieten, nicht diagnostizieren. Wann NICHT: bei akutem Trauma im Laiensetting.","phasen":["vertiefen","konflikt"],"ebenen":["person","team"],"modi":["verbindung","klaerung"],"formate":["workshop","coaching","fortbildung"],"dauer_min":30,"dauer_max":60,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"PuddleDancer Press – NVC Empathy","url":"https://nonviolentcommunication.com/learn-nonviolent-communication/nvc-empathy/"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001)"}],"wann_passt":["Jemand ist emotional aufgewühlt, verletzt oder in einer Krise und braucht zuerst Gehörtwerden - bevor irgendeine Problemlösung, Strategie oder Perspektive angeboten wird. Empathisches Zuhören schafft die Verbindung, die danach Sachdialog möglich macht.","Peer-Support-Kontext (Kolleg:in mit schwerem Tag, Freund:in nach Konflikterfahrung): Keine Therapie, kein Ratschlag, nur volle Präsenz und gelegentliche Vermutungen als Angebot.","Mediations-Vorgespräch mit jeder Partei einzeln: Bevor die Parteien zusammenkommen, braucht jede das Gefühl, vollständig gehört worden zu sein. Empathisches Zuhören im Vorkreis trägt den ganzen Mediationsprozess."],"wann_nicht":["Bei akutem Trauma oder psychischer Krise im Laiensetting: Dann braucht die Person professionelle psychologische Unterstützung - empathisches Zuhören durch Unbefugte kann Schaden anrichten.","Wenn die zuhörende Person selbst emotional aktiviert ist: Dann zuerst Selbstempathie, sonst wird das Zuhören unecht oder die eigene Reaktion mischt sich ein.","Wenn die Person gerade explizit Rat oder Information sucht: Dann empathisches Zuhören als Antwort wäre eine Form von Missachten."],"fokusfragen":["Schätze ich richtig, dass du gerade [Gefühl] bist, weil dir [Bedürfnis] wichtig ist? (Vermutung anbieten, nicht behaupten)","Gibt es noch mehr, was ich verstehen sollte? (Raum halten, bevor vorschnell Abschluss kommt)","Was wäre jetzt für dich hilfreich - weiter sprechen, oder etwas anderes? (aktiv fragen, was gebraucht wird)"],"beispiel":"Kollege sagt: Ich bin so frustriert, der Workshop heute war ein totales Desaster. Empathisches Zuhören: Das klingt nach einem harten Tag. Bist du frustriert, weil dir wichtig ist, dass du gute Arbeit ablieferst und das heute nicht so gelaufen ist, wie du es dir vorgestellt hattest? Kollege: Ja genau, und ich hatte das Gefühl, die Teilnehmenden waren überhaupt nicht dabei. Anschluss: Du hättest dir mehr Verbindung und Resonanz gewünscht - und das hat sich heute nicht eingestellt? Zweck: Die Vermutung öffnet, ohne festzulegen. Wenn sie falsch ist, korrigiert die Person. Die zweite Vermutung geht tiefer. Kein Ratschlag folgt - erst wenn die Person signalisiert: Hast du eine Idee, was ich anders machen könnte?","mini_form":"3-Minuten-Empathie: Person spricht 2 Minuten über etwas, das sie bewegt. Zuhörende:r antwortet ausschliesslich mit einer Vermutung (Gefühl + Bedürfnis) - kein Ratschlag, kein eigener Beitrag. Person bestätigt oder korrigiert.","anlass_typen":["schwieriges_gespraech","coaching","konfliktklaerung"],"typ":"werkzeug","gruppen_sweetspot":"Dyaden (2 Personen); in Lernformaten bis 20 als Parübung","stimmung_geeignet":["angespannt","belastet","müde"]},{"id":"wolfs-giraffensprache","name":"Wolfs-/Giraffensprache","feld":"E","kurz":"Den Unterschied zwischen trennender und verbindender Sprache am eigenen Sprachmaterial erfahrbar machen.","schritte":["Typische Urteils- und Vorwurfssätze aus dem Alltag der Gruppe sammeln","Anatomie der Wolfssprache zeigen: Urteil, Verallgemeinerung, Forderung, Schuldzuweisung","Jeden Satz in die vier Schritte übersetzen","In Paaren üben: eine Person spricht Wolf, die andere übersetzt in Giraffe","Vergleichen: Wie kommt dieselbe Botschaft jeweils an?"],"zweck":"Den Unterschied zwischen trennender und verbindender Sprache am eigenen Sprachmaterial erfahrbar machen.","hinweise":"Wolfssprache nicht moralisch abwerten – sie ist Ausdruck unerfüllter Bedürfnisse. Humor hilft; die Tiermetaphern nicht jeder Zielgruppe zumuten (Alternative: trennende/verbindende Sprache).","phasen":["verstehen","vertiefen"],"ebenen":["person","team"],"modi":["klaerung"],"formate":["workshop","fortbildung"],"dauer_min":30,"dauer_max":90,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["gespraechsnah","spielerisch"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Wikipedia – Nonviolent Communication (Abschnitt Jackal/Giraffe Language)","url":"https://en.wikipedia.org/wiki/Nonviolent_Communication"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001)"}],"wann_passt":["Einführungsworkshop in GFK: Die Tiermetaphern machen den Unterschied zwischen trennender und verbindender Sprache schnell und humorvoll erfahrbar - gut als Einstieg, bevor die vier Schritte erarbeitet werden.","Trainingseinheit für Führungskräfte oder Moderator:innen: Eigenes Sprachmaterial übersetzen - was klingt wolfig, was giraffish? Sehr konkret und praxisnah.","Jugendarbeit oder Schule: Die Tierbilder sind niedrigschwellig und einprägsam, erfordern kein NVC-Vorwissen."],"wann_nicht":["Mit Zielgruppen, die die Tiermetaphern infantil oder befremdlich finden (manche Unternehmenskontexte, bestimmte kulturelle Kontexte): Dann besser trennende / verbindende Sprache ohne die Tiere.","Als alleinstehendes Format: Das Üben von Wolfs- und Giraffensprache braucht die vier NVC-Schritte als Grundlage, sonst bleibt es Oberfläche.","Wenn die Wolfsprache moralisch abgewertet wird: Wolfssprache ist Ausdruck unerfüllter Bedürfnisse, nicht Böswilligkeit - wer das nicht klar einrahmt, erzeugt Scham statt Lernen."],"fokusfragen":["Welchen Satz kennen Sie aus Ihrem Alltag, der typisch wolfig klingt - und was steckt dahinter? (Eigene Beispiele sammeln)","Wie würde derselbe Satz klingen, wenn er aus der Giraffe käme - mit Beobachtung, Gefühl, Bedürfnis, Bitte? (Übersetzung üben)"],"beispiel":"Wolfssatz: Du hörst nie zu. Giraffenübersetzung: Ich habe gerade erzählt, dass mir das wichtig ist, und du hast auf dein Handy geschaut (Beobachtung). Da war ich enttäuscht (Gefühl), weil mir Kontakt und echtes Zuhören in dem Moment wichtig waren (Bedürfnis). Würdest du das Handy weglegen, wenn ich etwas erzähle, was mich bewegt (Bitte)? Zweck: Der Wolfssatz erzeugt Rechtfertigung. Der Giraffensatz lädt zur Antwort ein. Anschlussfrage: Wie klingt die Giraffenversion - was verändert sich, wenn du sie hörst?","mini_form":"Übersetzungs-Duell (5 Minuten): Eine Person sagt einen Wolfssatz, Partner:in übersetzt ihn spontan in Giraffensprache. Dann wechseln. Gelingt es, ohne Vorwurfssprache dasselbe auszudrücken?","anlass_typen":["lernformat","konfliktklaerung","teamtag"],"typ":"werkzeug","gruppen_sweetspot":"beliebig für Demonstration; Übung in Paaren oder Kleingruppen (4-6)","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"bitte-vs-forderung","name":"Bitte vs. Forderung","feld":"E","kurz":"Machtdynamik aus Anliegen nehmen – ein Nein willkommen heißen können, ohne das Anliegen aufzugeben.","schritte":["Unterschied erklären: Die Reaktion auf ein Nein verrät, ob es eine Bitte oder eine Forderung war","Eigene typische Bitten sammeln und testen: Was passiert in mir, wenn die Antwort Nein ist?","Verdeckte Forderungen erkennen (Schuld, Druck, Rückzug nach dem Nein)","In echte Bitten umformulieren: konkret, positiv, im Hier-und-Jetzt erfüllbar","Verbindungsbitten kennenlernen"],"zweck":"Machtdynamik aus Anliegen nehmen – ein Nein willkommen heißen können, ohne das Anliegen aufzugeben.","hinweise":"In Hierarchien besonders heikel: Eine Bitte der Führungskraft ist oft strukturell eine Forderung – das ehrlich benennen statt schönreden.","phasen":["vertiefen","konflikt"],"ebenen":["person","team"],"modi":["klaerung","konflikt"],"formate":["workshop","coaching","fortbildung"],"dauer_min":30,"dauer_max":60,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"PuddleDancer Press – Learn Nonviolent Communication","url":"https://nonviolentcommunication.com/learn-nonviolent-communication/"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001)"}],"wann_passt":["Wenn jemand ein Anliegen hat, das die andere Seite als Druck erlebt: Die Bitte-Forderung-Unterscheidung hilft zu prüfen, ob das eigene Anliegen wirklich offen für ein Nein ist - und falls nicht, was das über das eigene Bedürfnis sagt.","Führungskräfteentwicklung: Führungskräfte lernen zu erkennen, dass ihre Bitten oft strukturell Forderungen sind - und wie sie damit ehrlich umgehen können, statt Pseudo-Partizipation zu inszenieren.","Mediations-Vorbereitung: Wenn eine Partei Forderungen als Bitten verkleidet, kann die Unterscheidung helfen, ehrlichere Kommunikation zu etablieren."],"wann_nicht":["Als Technik, um das eigene Anliegen als Bitte zu framen, obwohl es eine Forderung ist: Das ist manipulativ und untergrabt Vertrauen.","In Notfallsituationen, wo echte Handlungsanforderungen gelten: Nicht alles muss als Bitte formuliert werden - manche Sicherheitsanweisungen sind Forderungen und sollen es bleiben."],"fokusfragen":["Wenn die andere Person Nein sagt - was wäre dann in mir? Waere ich wirklich offen dafür oder würde ich Druck aufbauen? (Bitte oder Forderung prüfen)","Wenn es eine Forderung ist - was brauche ich wirklich, das ich schützen will? Kann ich das direkt ansprechen, statt es als Bitte zu verkleiden? (Ehrlichkeit über eigenes Bedürfnis)"],"beispiel":"Teamleitung zu Mitarbeiter: Waerst du bereit, das Protokoll zu übernehmen? - klingt wie eine Bitte, ist aber strukturell eine Forderung. Bitte-Prüfung: Waere ein Nein wirklich willkommen? Wenn nicht: Ehrlichere Variante: Ich brauche jemanden für das Protokoll - du bist heute dran. Gibt es einen Grund, warum das für dich heute schwierig wäre? Das ist offen, ohne eine Bitte zu simulieren, die keine ist. Zweck: Ehrliche Forderungen respektieren Würde mehr als verkleidete Forderungen. Anschlussfrage: Was brauchtest du, damit das fair verteilt ist?","mini_form":"Bitte-Test (3 Minuten): Jemand formuliert ein Anliegen. Frage: Wenn die andere Person Nein sagt - wie reagierst du innerlich? Wenn die Antwort Druck oder Enttäuschung ist: Es ist eine Forderung. Was bedeutet das für die nächste Formulierung?","anlass_typen":["schwieriges_gespraech","coaching","lernformat"],"typ":"werkzeug","gruppen_sweetspot":"Dyaden oder Kleingruppen (4-8); auch als Impuls in Grossgruppe mit Selbstreflexion","stimmung_geeignet":["neugierig","angespannt"]},{"id":"aergerprozess","name":"Ärgerprozess","feld":"E","kurz":"Ärger vollständig ernst nehmen und als Wegweiser zum dahinterliegenden Bedürfnis nutzen.","schritte":["Eine reale Ärger-Situation wählen","Innehalten und atmen – nicht handeln","Die Urteilsgedanken identifizieren, die den Ärger erzeugen","Hinter den Urteilen das unerfüllte Bedürfnis finden","Wahrnehmen, wie sich der Ärger wandelt, sobald das Bedürfnis im Fokus ist","Ggf. Ausdruck oder Bitte formulieren"],"zweck":"Ärger vollständig ernst nehmen und als Wegweiser zum dahinterliegenden Bedürfnis nutzen.","hinweise":"Ärger nicht wegmachen wollen – er trägt die Energie für das Bedürfnis. Nicht in akuter Rage anleiten, erst Grundregulation. Wann NICHT: als Ersatz für berechtigten Protest gegen reale Übergriffe framen.","phasen":["reflektieren","vertiefen"],"ebenen":["person"],"modi":["selbstzugang","reflexion"],"formate":["coaching","workshop"],"dauer_min":30,"dauer_max":60,"gruppe_min":1,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"PuddleDancer Press – Nonviolent Communication for Anger","url":"https://nonviolentcommunication.com/learn-nonviolent-communication/nvc-anger/"},{"typ":"buch","titel":"Marshall Rosenberg: The Surprising Purpose of Anger (2005)"}],"wann_passt":["Coaching oder Einzelbegleitung, wenn jemand mit starkem Ärger zu einem Konflikt kommt: Der Ärgerprozess lädt ein, unter dem Ärger das unerfüllte Bedürfnis zu finden - das macht aus Reaktivität einen Ausgangspunkt für Handlung.","Supervisionsgruppe, wo ein Teammitglied über eine andere Person wütend ist: Den Ärger als Gruppenthema bearbeiten, ohne die abwesende Person zu verurteilen.","Reflexionsrunde nach einem schwierigen Ereignis (Sitzung, Intervention, Konflikt): Was hat mich geärgert - und was sagt das über das, was mir wichtig ist?"],"wann_nicht":["Als Ersatz für berechtigten Protest gegen reale Übergriffe oder strukturelle Ungerechtigkeiten: Ärger als nur ein Bedürfnis umzudeuten, wenn er auf echtes Unrecht zeigt, ist politisch und ethisch problematisch.","Bei akuter emotionaler Hochregulation (heisse Rage): Zuerst Grundregulation (Atemübung, Pause), dann erst den Ärgerprozess angehen.","In der Gruppe, wenn die Person, über die Ärger besteht, anwesend ist und kein sicherer Rahmen da ist - dann wird der Ärgerprozess zur unstrukturierten Anklage."],"fokusfragen":["Welche Urteile formuliere ich über die andere Person, wenn ich an die Situation denke? (Urteile ernst nehmen, nicht überspringen)","Was hätte die Person tun oder nicht tun sollen, damit ich nicht wütend wäre - was war meine Erwartung? (Forderung hinter dem Ärger sichtbar machen)","Welches Bedürfnis war in mir unerfüllt - was war mir in diesem Moment wichtig? (Kern des Ärgers finden)","Was möchte ich jetzt mit diesem Bedürfnis tun - wie kann ich dafür sorgen, dass es erfüllt wird? (Handlungsimpuls)"],"beispiel":"Coaching: Person ist wütend auf Kollegin, die ihre Präsentation in einem Meeting unterbrochen hat. Ärgerprozess: Was sagen Sie über die Kollegin? - Die ist arrogant und respektiert mich nicht. - Wenn die Kollegin sich anders verhalten hätte - was hätte sie getan? - Sie hätte mich ausreden lassen. - Und was war Ihnen in diesem Moment wichtig, das nicht da war? - Person hält inne: Ich wollte gehört werden. Mir war wichtig, dass meine Arbeit gesehen wird. - Coach: Der Ärger zeigt uns also: Gehörtwerden und Anerkennung sind gerade ein unerfülltes Bedürfnis. Was möchten Sie daraus machen - wollen Sie das Gespräch mit Ihrer Kollegin suchen? Zweck: Aus die ist arrogant wird ich brauche Anerkennung - das schafft Handlungsfähigkeit.","mini_form":"Zwei-Fragen-Blitz (5 Minuten): Wer oder was ärgert dich gerade - und was sagt das über das, was dir wichtig ist? In Paaren durchspielen - 2 Minuten pro Person.","anlass_typen":["coaching","konfliktklaerung","retro"],"typ":"werkzeug","gruppen_sweetspot":"Einzelperson bis Kleingruppe (6-10) in Supervision/Reflexion","stimmung_geeignet":["angespannt","belastet"]},{"id":"trauer-feiern","name":"Trauer & Feiern","feld":"E","kurz":"Aus Fehlern lernen ohne Selbstbestrafung und Gelungenes so würdigen, dass es Energie gibt.","schritte":["Eine Situation wählen: etwas Misslungenes/Verlorenes (Trauern) oder etwas Gelungenes (Feiern)","Trauern: die unerfüllten Bedürfnisse und die Gefühle dazu benennen – ohne Selbstvorwurf","Feiern: die erfüllten Bedürfnisse benennen und konkret würdigen","In Paaren oder Runde teilen","Wahrnehmen: Beide Bewegungen vertiefen das Bedürfnisbewusstsein"],"zweck":"Aus Fehlern lernen ohne Selbstbestrafung und Gelungenes so würdigen, dass es Energie gibt.","hinweise":"Trauern in der GFK ist kein Therapie-Ersatz – Begriffe sauber einführen. Feiern wird oft übersprungen, dabei trägt es die Motivation.","phasen":["reflektieren","reflektieren"],"ebenen":["person","team"],"modi":["reflexion","selbstzugang"],"formate":["workshop","coaching","reflexionsrunde"],"dauer_min":20,"dauer_max":45,"gruppe_min":1,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["reflexion","abschluss"],"quellen":[{"typ":"online","titel":"PuddleDancer Press – NVC Mourning","url":"https://nonviolentcommunication.com/learn-nonviolent-communication/nvc-mourning/"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001)"}],"wann_passt":["Retroformat nach einem gescheiterten Projekt oder einem schwierigen Abschnitt: Trauer und Feiern gibt dem Misserfolg Würde, ohne in Selbstbestrafung zu fallen - und dem Gelungenen einen echten Platz.","Abschluss einer langen Zusammenarbeit oder eines Programms: Trauer um das, was endet - und Feier des Weges. Beides explizit zu machen, statt den Abschluss zu neutralisieren.","Team nach einem Verlust (Kollege verlässt das Team, Projekt verliert Förderung): Emotionale Verarbeitung als Gruppenformat - gibt dem Gefühl Raum, bevor die Gruppe weitermacht."],"wann_nicht":["Als Kurzformat: Trauern braucht Zeit und Sicherheit; eine 5-Minuten-Runde erzeugt nur Oberflächlichkeit.","Wenn der Begriff Trauer in der Gruppe als zu therapeutisch oder fremd empfunden wird: Dann Framing anpassen (Was hat uns Kraft gekostet - und was war gut?).","Als Pflichtübung ohne echtes Gefühl: Erzwungenes Feiern von Misserfolgen erzeugt Zynismus."],"fokusfragen":["Was hat diese Zeit Kraft gekostet - was ist nicht gelungen oder verloren gegangen? (Trauer-Runde)","Was war wirklich gut - was hat funktioniert, was hat euch stolz gemacht, was wollt ihr nicht vergessen? (Feier-Runde)","Was nehmt ihr mit - aus beidem? (Integration)"],"mini_form":"Zwei-Runden-Blitz (10 Minuten): Erste Runde: Was hat nicht funktioniert, was lassen wir los? - jede Person einen Satz. Kurze Stille. Zweite Runde: Was war gut, was nehmen wir mit? - jede Person einen Satz. Kein Kommentar dazwischen.","anlass_typen":["retro","teamtag","konfliktklaerung"],"typ":"werkzeug","gruppen_sweetspot":"3-15 ideal; auch solo als Schreibübung","stimmung_geeignet":["belastet","müde","angespannt"]},{"id":"restorative-circles","name":"Restorative Circles (Barter)","feld":"E","kurz":"Gemeinschaftskonflikte so bearbeiten, dass Verstehen, Verantwortung und Wiedergutmachung von der Gemeinschaft selbst getragen werden.","schritte":["Vorkreis: Mit allen Beteiligten einzeln klären, was geschehen ist, wer dazugehört, Freiwilligkeit sichern","Kreis Phase 1 – gegenseitiges Verständnis: Jede Person spricht, das Gegenüber gibt wieder, bis sich die sprechende Person verstanden fühlt","Phase 2 – Selbstverantwortung: Was hat jede:r beigetragen, was war die Absicht hinter dem Handeln?","Phase 3 – Vereinbartes Handeln: konkrete, überprüfbare Abmachungen","Nachkreis: Vereinbarungen überprüfen"],"zweck":"Gemeinschaftskonflikte so bearbeiten, dass Verstehen, Verantwortung und Wiedergutmachung von der Gemeinschaft selbst getragen werden.","hinweise":"Lebt vom Systemaufbau in der Gemeinschaft, nicht von der Einzelanwendung. Wann NICHT: bei akuten Straftaten oder Gewaltgefahr ohne professionellen Rahmen; nie ohne Vorkreise.","phasen":["konflikt","verstetigen"],"ebenen":["team","organisation"],"modi":["konflikt","klaerung"],"formate":["prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":5,"gruppe_max":20,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Restorative Circles (Dominic Barter)","url":"https://www.restorativecircles.org/"}],"wann_passt":["Schulen, Gemeinden oder Organisationen, die ein eigenes System zur Konfliktbearbeitung aufbauen wollen: Restorative Circles ist kein Einzelformat, sondern ein Systemaufbau - es wirkt, wenn die Gemeinschaft selbst Facilitator:innen ausbildet und das Verfahren verankert.","Nachgang zu einem ernsthaften Vorfall (Streit, Sachschaden, Vertrauensbruch) in einer Gemeinschaft, die miteinander weiterleben muss: Die drei Kreise (Vor-Kreis / Haupt-Kreis / Nach-Kreis) stellen sicher, dass alle drei Seiten gehört werden.","Organisationen mit NVC-Kultur, die Konflikte nicht durch externe Mediation, sondern intern und nach gemeinsamen Prinzipien bearbeiten wollen."],"wann_nicht":["Bei akuten Straftaten oder Gewaltgefahr ohne professionellen rechtlichen Rahmen: Restorative Circles ersetzt keine strafrechtlichen Schutzmassnahmen.","Als Ad-hoc-Einzelanwendung ohne Systemaufbau in der Gemeinschaft: Der Haupt-Kreis ohne Vorkreise ist wie eine Operation ohne Vorbereitung - die Vorkreise sind nicht optional.","Wenn die handelnde Person keine Verantwortung übernimmt und auch nicht bereit ist, am Kreis teilzunehmen: Dann braucht es andere Verfahren."],"fokusfragen":["Was ist passiert - aus deiner Sicht? (Vor-Kreis mit jeder Partei einzeln)","Was hat das Geschehene für dich bedeutet - wie war die Wirkung? (Haupt-Kreis: Betroffene:r)","Was brauchst du jetzt, damit du dich in dieser Gemeinschaft wieder sicher und verbunden fühlen kannst? (Haupt-Kreis: Gemeinschaftsbedürfnisse)"],"mini_form":"Kein sinnvolles Mini-Format: Restorative Circles braucht alle drei Kreise und den Systemaufbau. Eine abgekürzte Version ohne Vorkreis und Gemeinschaftspräsenz ist ein anderes Format.","anlass_typen":["konfliktklaerung","teamtag","dialograum"],"typ":"methode","gruppen_sweetspot":"3 Parteien-Gruppen (Handelnde:r + Betroffene:r + Gemeinschaft); Hauptkreis 5-20 Personen","stimmung_geeignet":["angespannt","belastet"]},{"id":"gfk-mediation","name":"GFK-Mediation durch Dritte","feld":"E","kurz":"Konfliktparteien über wechselseitige Empathie wieder in Kontakt bringen, bevor über Lösungen gesprochen wird.","schritte":["Beide Parteien nacheinander empathisch hören – Mediator:in spiegelt Gefühl und Bedürfnis jeder Seite","Die Bedürfnisse beider Seiten sichtbar nebeneinander stellen (Flipchart)","Gegenseitiges Wiedergeben anleiten bis beide sich gehört fühlen","Erst dann: Lösungsideen sammeln, die beide Bedürfnislagen adressieren","Vereinbarung als konkrete, verhandelbare Bitten formulieren"],"zweck":"Konfliktparteien über wechselseitige Empathie wieder in Kontakt bringen, bevor über Lösungen gesprochen wird.","hinweise":"Mediator:in gibt Empathie, keine Urteile und keine eigenen Lösungen. Der Drang der Parteien, früh zu Lösungen zu springen, ist der Hauptstolperstein. Wann NICHT: bei Gewaltgefahr oder starkem Machtgefälle ohne Schutzvorkehrungen.","phasen":["konflikt"],"ebenen":["person","team"],"modi":["konflikt","klaerung"],"formate":["coaching","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":8,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Center for Nonviolent Communication","url":"https://www.cnvc.org/"},{"typ":"buch","titel":"Marshall Rosenberg: Gewaltfreie Kommunikation (2001), Kap. Mediation"}],"wann_passt":["Zwei Parteien in einem Teamkonflikt, die nicht mehr direkt miteinander sprechen können: GFK-Mediation durch Dritte schafft einen Raum, in dem jede Seite zuerst Empathie empfängt, bevor sie Lösungen verhandelt.","Paar- oder Partnerschaftskonflikt (professionell, beruflich oder privat), wo beide Seiten grundsätzlich weiter miteinander arbeiten oder leben wollen: Die Empathie-Phase macht den Kontakt als Grundlage wieder möglich.","Wenn eine klassische Mediation bisher keinen Durchbruch erzeugt hat, weil die Parteien sofort in Verhandlungsmode gehen: GFK-Mediation verlangsamt bewusst und fragt zuerst nach dem inneren Erleben."],"wann_nicht":["Bei Gewalt in der Beziehung oder starkem Machtgefälle ohne Schutzvorkehrungen: Empathie kann Verantwortung verwischen; hier braucht es zuerst Sicherheitsmassnahmen.","Wenn eine Partei nicht bereit ist, am Prozess teilzunehmen oder die Grundlage des Verfahrens ablehnt.","Wenn die Mediator:in selbst in den Konflikt involviert ist oder eine persönliche Meinung hat: GFK-Mediation erfordert echte Allparteilichkeit.","Ab Glasl-Stufe 6+: Dann braucht es professionelle Konfliktintervention, nicht nur Mediationsangebot."],"fokusfragen":["Was ist in Ihnen, wenn Sie an die Situation denken - was fühlen Sie? (Empathie-Einstieg mit Partei A)","Was haben Sie gebraucht in dieser Situation, das nicht da war? (Bedürfnisebene öffnen)","Was hören Sie, wenn Partei B das sagt - was nehmen Sie von dem wahr, was sie gerade ausgeführt hat? (Wechselseitiges Empathie-Angebot)"],"mini_form":"Empathie-Runde (15 Minuten): Mediator:in gibt beiden Parteien reihum Empathie (Gefühl + Bedürfnis spiegeln), ohne Lösungsdruck. Erst wenn beide signalisieren, dass sie sich gehört fühlen, wird gefragt: Was braucht es jetzt? - Lösungsraum öffnet sich von selbst.","anlass_typen":["konfliktklaerung","schwieriges_gespraech","coaching"],"typ":"methode","gruppen_sweetspot":"2 Parteien + 1 Mediator:in; selten mehr als 3-4 Personen","stimmung_geeignet":["angespannt","belastet"]},{"id":"tanz-der-beduerfnisse","name":"Tanz der Bedürfnisse","feld":"E","kurz":"Den GFK-Prozess körperlich erfahrbar machen – Bewegung im Raum vertieft die innere Bewegung.","schritte":["Bodenanker auslegen: Felder für Beobachtung, Gefühl, Bedürfnis, Bitte (zwei Spuren: Selbstempathie / Empathie)","Eine Person bringt ein reales Anliegen mit und geht physisch von Feld zu Feld","Auf jedem Feld laut artikulieren, was dort lebendig ist – Begleiter:in fragt unterstützend nach","Zwischen Selbst- und Empathie-Spur wechseln, wenn der Prozess stockt","Abschluss: Was hat sich durch die Bewegung verändert?"],"zweck":"Den GFK-Prozess körperlich erfahrbar machen – Bewegung im Raum vertieft die innere Bewegung.","hinweise":"Entwickelt von Bridget Belgrave und Gina Lawrie (NVC Dance Floors). Braucht Raum und Bereitschaft, sich vor anderen zu zeigen. Gut als Demonstration mit einer Person und beobachtender Gruppe.","phasen":["vertiefen"],"ebenen":["person"],"modi":["selbstzugang","klaerung"],"formate":["workshop","fortbildung"],"dauer_min":30,"dauer_max":90,"gruppe_min":2,"gruppe_max":12,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"aktivierend","stil":["koerperlich","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"NVC Dance Floors (Belgrave/Lawrie)","url":"https://nvcdancefloors.com/"}],"wann_passt":["GFK-Fortbildung, die mehr als kognitive Vermittlung will: Der Tanz der Bedürfnisse (NVC Dance Floors, entwickelt von Bridget Belgrave und Gina Lawrie) macht den inneren Prozess körperlich erfahrbar.","Demonstration mit einer Freiwilligen vor einer Gruppe: Eine Person geht ihren eigenen Konflikt am Dance Floor durch - die Gruppe beobachtet und lernt durch Witnessing.","Integrationsübung nach mehreren GFK-Einheiten: Wenn die vier Schritte kognitiv bekannt sind, aber noch nicht fliessen - der körperliche Durchgang durch die Felder verankert."],"wann_nicht":["Wenn Teilnehmende sich nicht bereit fühlen, sich körperlich zu exponieren: Das Format setzt Bereitschaft voraus, sich vor anderen in einem Prozess zu zeigen.","Online: Das Format verliert ohne physischen Raum und Körperbewegung seinen zentralen Wirkmechanismus.","Als Einführungsformat ohne GFK-Grundkenntnisse: Ohne Kenntnis der vier Schritte ist die körperliche Navigation bedeutungslos."],"fokusfragen":["Welche Situation möchtest du durch das Tanzfeld führen - was ist die konkrete Auslösesituation? (Thema festlegen)","Wo stehst du gerade auf dem Feld - bei der Beobachtung, beim Gefühl, beim Bedürfnis oder bei der Bitte? (Körperliche Verortung)","Was verändert sich, wenn du physisch von einem Feld ins andere trittst? (Körperliche Erfahrung benennen)"],"mini_form":"Dance-Floor-Demonstration (15 Minuten): Eine Freiwillige nimmt ein konkretes Thema, die Moderation begleitet durch die vier Felder (Beobachtung - Gefühl - Bedürfnis - Bitte) mit je einer Frage pro Feld. Gruppe beobachtet still.","anlass_typen":["lernformat","coaching"],"typ":"methode","gruppen_sweetspot":"1 Person aktiv + Gruppe als Witnessing; Gruppe 5-20 Personen","stimmung_geeignet":["neugierig","frisch"]},{"id":"harvard-konzept","name":"Harvard-Konzept","feld":"E","kurz":"Sachgerecht verhandeln – hart in der Sache, weich zu den Menschen, Nutzen für beide Seiten schaffen.","schritte":["Menschen und Problem trennen: Beziehungsthemen benennen und separat behandeln","Hinter den Positionen die Interessen erfragen: Wofür ist dir das wichtig?","Optionen für gegenseitigen Nutzen entwickeln – erst sammeln, dann bewerten","Objektive Kriterien für die Bewertung vereinbaren","Eigene BATNA prüfen und Entscheidung treffen"],"zweck":"Sachgerecht verhandeln – hart in der Sache, weich zu den Menschen, Nutzen für beide Seiten schaffen.","hinweise":"BATNA vor der Verhandlung klären, nicht währenddessen. Bei reinen Verteilungskonflikten mit großem Machtgefälle stößt das Konzept an Grenzen – dann schützt nur die eigene Alternative.","phasen":["entscheiden","konflikt"],"ebenen":["person","team","organisation"],"modi":["entscheidung","klaerung"],"formate":["coaching","workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":2,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Program on Negotiation (Harvard) – Principled Negotiation","url":"https://www.pon.harvard.edu/daily/negotiation-skills-daily/principled-negotiation-focus-interests-create-value/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"buch","titel":"Roger Fisher / William Ury: Getting to Yes (1981; dt. Das Harvard-Konzept)"}],"wann_passt":["Verhandlung mit einem klaren Sachthema und mindestens zwei Parteien mit unterschiedlichen Interessen: Harvard trennt Positionen von Interessen und schafft so Raum für kreative Lösungen, die beide Seiten gewinnen lassen.","Vorbereitung auf schwierige Vertragsverhandlungen: BATNA klären, Interessen der anderen Seite antizipieren, Kriterien für faire Lösungen sammeln - das gibt Sicherheit statt Reaktivität.","Fortbildung für alle, die regelmäßig verhandeln (Einkauf, Projektmanagement, Tarifverhandlungen): Das Vier-Prinzipien-Modell ist pragmatisch und transferfähig."],"wann_nicht":["Bei reinen Verteilungskonflikten mit massivem Machtgefälle: Wenn eine Seite keine realistische BATNA hat, schützt sie nur ihre Alternative - Harvard-Prinzipien helfen dann kaum.","Wenn die Beziehungsebene so beschädigt ist, dass sachliches Verhandeln nicht möglich ist: Dann zuerst GFK-Mediation oder Beziehungsklärung, danach Harvard.","Bei Wertkonflikten ohne Sachsubstanz: Harvard löst Interessenkonflikte, keine fundamentalen Wertdifferenzen."],"fokusfragen":["Was ist Ihre Position - und was ist das Interesse dahinter? (Positions-Interessen-Trennung)","Was wäre ein objektives Kriterium, an dem wir eine faire Lösung messen könnten? (Sachkriterien entwickeln)","Was ist Ihre beste Alternative, wenn diese Verhandlung scheitert - Ihre BATNA? (Verhandlungsmacht realistisch einschätzen)"],"mini_form":"Interessen-Kartierung (10 Minuten): Jede Partei schreibt ihre Position auf und darunter drei Interessen, die dahinterstecken. Dann vergleichen: Gibt es überlappende Interessen, die eine gemeinsame Lösung ermöglichen?","anlass_typen":["entscheidungstreffen","konfliktklaerung","schwieriges_gespraech"],"typ":"methode","gruppen_sweetspot":"2 Parteien + ggf. Moderation; für Fortbildungen bis 20 Personen","stimmung_geeignet":["angespannt","skeptisch","neugierig"]},{"id":"phasenmodell-mediation","name":"Phasenmodell der Mediation","feld":"E","kurz":"Konfliktparteien in einem strukturierten, allparteilichen Verfahren zu einer selbst erarbeiteten Vereinbarung führen.","schritte":["Einleitung: Arbeitsbündnis, Rollen, Regeln, Freiwilligkeit klären","Themensammlung: Sichtweisen anhören, Themenliste erstellen, Reihenfolge vereinbaren","Interessenklärung (Herzstück): Interessen, Gefühle und Bedürfnisse hinter den Positionen herausarbeiten","Optionen: Lösungsideen kreativ sammeln, dann bewerten","Vereinbarung: tragfähige Lösung schriftlich festhalten, Umsetzung und Überprüfung vereinbaren"],"zweck":"Konfliktparteien in einem strukturierten, allparteilichen Verfahren zu einer selbst erarbeiteten Vereinbarung führen.","hinweise":"Der häufigste Fehler ist das Springen von Phase 2 direkt zu Lösungen – Phase 3 trägt die Nachhaltigkeit. Wann NICHT: ohne Freiwilligkeit beider Seiten, bei Gewalt in der Beziehung oder ab hoher Eskalation (Glasl 7+).","phasen":["konflikt"],"ebenen":["person","team","organisation"],"modi":["konflikt","klaerung","entscheidung"],"formate":["prozessbegleitung"],"dauer_min":90,"dauer_max":240,"gruppe_min":3,"gruppe_max":8,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Deutsche Stiftung Mediation – Phasen einer Mediation","url":"https://stiftung-mediation.de/phasen-einer-mediation/"},{"typ":"buch","titel":"Christoph Besemer: Mediation – Vermittlung in Konflikten (1993)"}],"wann_passt":["Strukturierter Mediationsprozess zwischen zwei oder mehr Parteien, die eine Vereinbarung anstreben: Das Phasenmodell (Eröffnung - Schilderung - Vertiefung - Lösungsraum - Vereinbarung) gibt dem Prozess einen nachvollziehbaren Rahmen und Sicherheit.","Ausbildungskontext für angehende Mediator:innen: Das Phasenmodell ist das Grundgerüst, das alle anderen Mediationstechniken integriert.","Komplexere Mehrparteien-Mediationen (z.B. Nachbarschaftsstreit, innerbetrieblicher Konflikt): Die Phasen sorgen dafür, dass die Vertiefungsphase (Phase 3) nicht übersprungen wird."],"wann_nicht":["Ohne echte Freiwilligkeit beider Seiten: Erzwungene Mediation erzeugt keine nachhaltigen Vereinbarungen.","Bei häuslicher Gewalt oder massivem Machtgefälle in der Beziehung: Mediation setzt Waffengleichheit voraus.","Ab Glasl-Stufe 7+: Dort greifen andere Verfahren (Schiedsspruch, Machteingriff); Mediation ist nicht mehr sicher möglich."],"fokusfragen":["Was ist aus Ihrer Sicht passiert - was beschäftigt Sie an dieser Situation? (Phase 2: Schilderung, je Partei)","Was war in Ihnen, als das passiert ist - was hat es mit Ihnen gemacht? (Phase 3: Vertiefung - nicht überspringen!)","Was brauchten Sie von der anderen Seite, damit Sie aus diesem Raum gehen und sagen können: Es hat sich gelohnt, hier gewesen zu sein? (Übergang zu Phase 4)"],"mini_form":"Phasen-Bewusstsein als Intervention: In einer laufenden Mediation kurz pausieren und transparent machen, in welcher Phase sich der Prozess befindet - Wir sind jetzt in der Vertiefungsphase, bevor wir zu Lösungen gehen. Das ist bewusst so. Schafft Vertrauen und verlangsamt das Drücken zu Lösungen.","anlass_typen":["konfliktklaerung","schwieriges_gespraech"],"typ":"methode","gruppen_sweetspot":"2-4 Parteien + Mediator:in; bei Mehrparteien-Mediation bis 8 Personen","stimmung_geeignet":["angespannt","belastet"]},{"id":"transformative-mediation","name":"Transformative Mediation (Bush/Folger)","feld":"E","kurz":"Den Konflikt als Chance nutzen, dass Parteien Selbstwirksamkeit und Anerkennung des Gegenübers zurückgewinnen.","schritte":["Rahmen setzen: Die Parteien bestimmen Themen, Tempo und Ausgang – Mediator:in folgt","Gespräch der Parteien begleiten, ohne es zu strukturieren","Empowerment-Momente unterstützen: Wenn eine Partei Klarheit gewinnt, Raum geben","Recognition-Momente unterstützen: Wenn eine Partei beginnt, die andere zu sehen, behutsam verstärken","Vereinbarung nur, wenn die Parteien sie wollen – sie ist nicht das Erfolgskriterium"],"zweck":"Den Konflikt als Chance nutzen, dass Parteien Selbstwirksamkeit (Empowerment) und Anerkennung des Gegenübers (Recognition) zurückgewinnen.","hinweise":"Erfolg ist hier nicht die Einigung, sondern die veränderte Interaktion – Auftraggeber:innen vorab darauf einstellen. Wann NICHT: wenn schnell eine Sachlösung gebraucht wird oder Parteien klare Verfahrensführung erwarten.","phasen":["konflikt"],"ebenen":["person","team"],"modi":["konflikt","selbstzugang"],"formate":["prozessbegleitung","coaching"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":6,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Beyond Intractability – Transformative Mediation","url":"https://www.beyondintractability.org/essay/transformative_mediation"},{"typ":"buch","titel":"Robert Baruch Bush / Joseph Folger: The Promise of Mediation (1994)"}],"wann_passt":["Konflikte, wo es nicht primär um eine Vereinbarung geht, sondern um die Qualität der Beziehung und die Selbstwirksamkeit der Parteien: Transformative Mediation verfolgt Empowerment (Stärkung der eigenen Handlungsfähigkeit) und Recognition (Anerkennung des Gegenüber) als Ziele - nicht Einigung.","Organisationskonflikte, wo Hierarchiedynamiken und Würdeverletzungen die Sachebene überlagern: Das Format gibt beiden Seiten Raum, ihre eigene Position zu stärken und die andere Seite wirklich zu hören.","Wenn klassische Mediation immer wieder zu Vereinbarungen führt, die nicht gehalten werden: Das zeigt, dass die Beziehung das eigentliche Problem ist - Transformative Mediation setzt dort an."],"wann_nicht":["Wenn schnell eine Sachlosung gebraucht wird: Transformative Mediation ist langsam und beziehungsorientiert - für dringende Sachfragen ist das Harvard-Konzept besser geeignet.","Wenn Auftraggeber:innen (z.B. HR-Abteilung) Einigung als Erfolgskriterium setzen: Dann vorab klären, dass Transformation kein Einigungsgarant ist.","Wenn eine Partei klare Verfahrensführung durch die Moderation erwartet: Transformative Mediation ist weniger direktiv als klassische Mediation."],"fokusfragen":["Was wäre für Sie ein Zeichen, dass Sie in diesem Gespräch etwas Wichtiges erreicht haben - nicht als Vereinbarung, sondern als Erfahrung? (Erwartung klären)","Was möchten Sie der anderen Seite jetzt sagen - in Ihren eigenen Worten? (Empowerment: eigene Sprache finden)","Was haben Sie gehört, als Partei B das sagte - was ist bei Ihnen angekommen? (Recognition: die andere Seite wirklich hören)"],"mini_form":"Empowerment-Pause (5 Minuten): Wenn eine Partei in der Mediation abblockt oder schweigt, eine kurze Empowerment-Frage stellen: Was möchten Sie in diesem Moment sagen - was ist Ihnen jetzt wichtig? Kein Druck zur Lösung, nur Raum für die eigene Stimme.","anlass_typen":["konfliktklaerung","coaching","schwieriges_gespraech"],"typ":"methode","gruppen_sweetspot":"2 Parteien + Mediator:in","stimmung_geeignet":["angespannt","belastet","skeptisch"]},{"id":"restorative-justice","name":"Restorative Justice / TOA","feld":"E","kurz":"Auf Unrecht mit Schadenswiedergutmachung, Verantwortung und Beziehungsklärung antworten statt allein mit Strafe.","schritte":["Getrennte Vorgespräche: Freiwilligkeit, Erwartungen und Sicherheit beider Seiten klären","Begegnung: Die geschädigte Person schildert Tat und Folgen","Verantwortungsübernahme: Die verursachende Person hört, antwortet, übernimmt Verantwortung","Bedürfnisklärung: Was braucht es zur Wiedergutmachung – materiell und symbolisch?","Vereinbarung schließen","Erfüllung nachverfolgen"],"zweck":"Auf Unrecht mit Schadenswiedergutmachung, Verantwortung und Beziehungsklärung antworten statt allein mit Strafe.","hinweise":"Niemals ohne gründliche Vorbereitung beider Seiten zusammenbringen. Wann NICHT: wenn die verursachende Seite keine Verantwortung übernimmt, bei Gefahr erneuter Viktimisierung oder wenn Geschädigte nur unter Druck teilnehmen.","phasen":["konflikt"],"ebenen":["team","organisation","feld"],"modi":["konflikt","klaerung"],"formate":["prozessbegleitung"],"dauer_min":90,"dauer_max":180,"gruppe_min":3,"gruppe_max":10,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Servicebüro für Täter-Opfer-Ausgleich und Konfliktschlichtung","url":"https://www.toa-servicebuero.de/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"buch","titel":"Howard Zehr: The Little Book of Restorative Justice (2002)"}],"wann_passt":["Täter-Opfer-Ausgleich (TOA) in strafrechtlichem Kontext: Wenn eine Person Verantwortung für eine Tat übernehmen will und die geschädigte Person bereit ist, in Dialog zu treten - mit professioneller Begleitung und vollständiger Freiwilligkeit beider Seiten.","Schulkonflikte oder organisationsinterne Verstöße, wo eine geschädigte Partei gehört werden will und die verursachende Partei Verantwortung übernehmen kann: Restorative Justice als Alternative zu rein disziplinarischen Massnahmen.","Gemeinschaftsprozesse nach einem Vorfall, der mehrere Personen betroffen hat: Kreis-basierte RJ-Verfahren geben der Gemeinschaft eine Rolle, nicht nur den direkt Beteiligten."],"wann_nicht":["Wenn die verursachende Person keine Verantwortung übernimmt oder das Geschehene verleugnet: RJ braucht als Mindestvoraussetzung ein Anerkennen des Geschehens.","Wenn die geschädigte Person nur unter sozialem oder institutionellem Druck teilnimmt: Erzwungene RJ-Verfahren retraumatisieren.","Bei Gefahr erneuter Viktimisierung (z.B. Beziehungsgewalt, wo die verursachende Person noch Macht über die geschädigte Person hat).","Als schnelles oder obligatorisches Verfahren ohne Vorbereitung beider Seiten."],"fokusfragen":["Was ist passiert - aus deiner Sicht? (Geschaedigte:r erzählt zuerst)","Was hat das Geschehene für dich bedeutet - wie hat es dein Leben beeinflusst? (Wirkung der Tat für Geschaedigte:n)","Was brauchst du jetzt, damit etwas wiederhergestellt werden kann? (Schadenswiedergutmachung definieren)"],"mini_form":"Kein sinnvolles Mini-Format: Restorative Justice braucht vollständige Vorbereitung und Begleitung - ein abgekürztes Verfahren ohne Vorkreis und Sicherheitspruefung kann Schaden anrichten.","anlass_typen":["konfliktklaerung","dialograum"],"typ":"methode","gruppen_sweetspot":"2-5 direkt Beteiligte + Facilitator:in; Community Circles größer","stimmung_geeignet":["angespannt","belastet"]},{"id":"oral-history","name":"Oral History","feld":"E","kurz":"Gelebte Erinnerung als Quelle sichern und Menschen als Zeug:innen ihrer eigenen Geschichte würdigen.","schritte":["Erzähler:in und thematischen Fokus wählen","Einverständnis klären: Zweck, Aufzeichnung, Verwendung, Rückzugsrecht","Offenes biografisches Interview führen – chronologisch einsteigen, wenig unterbrechen, Erzählfluss halten","Aufzeichnen (Audio/Video) und Kernpassagen dokumentieren","Freigabe der Erzähler:in einholen","Archivieren bzw. vereinbarte Weitergabe"],"zweck":"Gelebte Erinnerung als Quelle sichern und Menschen als Zeug:innen ihrer eigenen Geschichte würdigen.","hinweise":"Datenhoheit bleibt bei den Erzählenden – Freigabe ist nicht verhandelbar. Bei Gewalterfahrungen Trauma-sensibel interviewen (keine Detailausfragerei, Pausen anbieten).","phasen":["verstehen"],"ebenen":["person","feld"],"modi":["selbstzugang"],"formate":["prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":2,"gruppe_max":3,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Oral History Association – Do Oral History","url":"https://oralhistory.org/about/do-oral-history/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"online","titel":"Oral History Association - Trauma-Informed Interviewing","url":"https://oralhistory.org/"},{"typ":"buch","titel":"Peacebuilding Practice (Woman PeaceMaker Program, 2023) – Chapter 3: Transitional Justice / Testimony"}],"wann_passt":["Kontexte mit unterdrückter oder gespaltener Erinnerung (Konfliktnachbearbeitung, Transitional Justice): Oral History gibt Menschen die Möglichkeit, ihre Version der Geschichte zu erzählen und damit Würde zurückzugewinnen — besonders wirksam mit Zeug:innen von Menschenrechtsverletzungen.","Community-Forschung als PAR (Participatory Action Research): Wenn die Community selbst ihre Geschichte erforscht, werden Teilnehmende zu Forscher:innen und durchbrechen die Trennung zwischen Wissenden und Unwissenden.","Intergenerationelle Dialogformate: Ältere Menschen erzählen, jüngere hören zu und dokumentieren — der Prozess selbst baut Brücken zwischen Generationen."],"wann_nicht":["Ohne Einwilligung und Datenschutz: Oral History-Aufnahmen können Menschen gefährden, besonders in autoritären Kontexten.","Als Alibiprozess: Wenn Geschichten gesammelt, aber nie an die Community zurückgespiegelt werden, entsteht Extraktivismus statt Empowerment."],"fokusfragen":["„Erzähl mir von [einer bestimmten Zeit/einem bestimmten Ereignis] — was hast du erlebt, wer war dabei, was hat sich danach verändert?“ (offene narrative Einladung)","„Was möchtest du, dass die nächste Generation über diese Zeit weiß?“ (Würde und Relevanz stärken)","„Wenn du damals gewusst hättest was du heute weißt — was hättest du anders gemacht?“ (Reflexionsebene öffnen)"],"mini_form":"Mini-Interview in 15 Minuten: Je zwei Personen, eine interviewt, eine antwortet auf genau eine Frage: 'Erzähl mir von dem Moment, der dich in dieser Arbeit am meisten geprägt hat.' Keine Unterbrechung, keine Kommentare. Danach: Welche ein Satz aus dem Gehörten bleibt dir?","anlass_typen":["dialograum","lernformat","beteiligung"],"typ":"methode","gruppen_sweetspot":"6–20 Personen, auch als 1:1","stimmung_geeignet":["belastet","neugierig"]},{"id":"narrative-mediation","name":"Narrative Mediation (Winslade/Monk)","feld":"E","kurz":"Konfliktparteien von ihrer Konfliktgeschichte trennen und eine alternative, gemeinsame Erzählung der Beziehung ermöglichen.","schritte":["Beide Konfliktgeschichten ausführlich hören – mit double listening: auch hören, was der Konflikt nicht erfasst","Den Konflikt externalisieren: ihn als eigenständiges Drittes benennen (der Streit, das Misstrauen)","Wirkungen kartieren: Was richtet der Konflikt bei beiden an?","Ausnahmen suchen (unique outcomes): Momente, in denen die Beziehung anders war","Aus den Ausnahmen gemeinsam eine Gegen-Geschichte der Beziehung aufbauen"],"zweck":"Konfliktparteien von ihrer Konfliktgeschichte trennen und eine alternative, gemeinsame Erzählung der Beziehung ermöglichen.","hinweise":"Externalisierung ist sprachliche Präzisionsarbeit – konsequent durchhalten (der Konflikt will …, nie du machst …). Funktioniert schlecht, wenn eine Partei die Konfliktgeschichte als Identität braucht.","phasen":["konflikt"],"ebenen":["person","team"],"modi":["konflikt","klaerung"],"formate":["prozessbegleitung","coaching"],"dauer_min":60,"dauer_max":180,"gruppe_min":3,"gruppe_max":8,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"UNM Ombuds – Narrative Mediation: Re-authoring Conflict Stories (PDF)","url":"https://ombudsfac.unm.edu/Article_Summaries/Narrative_Mediation.pdf"},{"typ":"buch","titel":"John Winslade / Gerald Monk: Narrative Mediation (2000)"},{"typ":"online","titel":"Beyond Intractability - Narrative Mediation (Winslade/Monk)","url":"https://www.beyondintractability.org/bksum/winslade-narrative"}],"wann_passt":["Konflikte, wo beide Seiten stark mit ihrer Version der Geschichte identifiziert sind und Positionen wie Identitätspanzer wirken: Narrative Mediation externalisiert den Konflikt (der Konflikt will... statt du machst...) und macht die Geschichte besprechbar, ohne die Person anzugreifen.","Langandauernde Konflikte, die trotz Sachklärungen immer wiederkehren: Das zeigt oft, dass die Konflikt-Geschichte selbst das Problem ist, nicht nur die Sachfragen.","Wenn eine Partei die Konfliktgeschichte als Identität trägt: Narrative Mediation schafft Raum für eine alternative Geschichte der Beziehung, ohne die bisherige zu leugnen."],"wann_nicht":["Wenn eine Partei die Konfliktgeschichte als Identität braucht und nicht bereit ist, eine alternative Erzählung zu entwickeln: Das Format funktioniert nur, wenn mindestens eine Seite Offenheit mitbringt.","Wenn schnelle Sachlosung gebraucht wird: Narrative Mediation ist langsam und sprachlich präzise - für dringende Sachkonflikte andere Formate bevorzugen.","Ohne konsequente Externalisierungssprache der Moderation: Sobald die Moderation wieder zu du hast oder sie hat wechselt, bricht der Mechanismus zusammen."],"fokusfragen":["Wie würden Sie den Konflikt nennen, wenn er eine eigene Persönlichkeit hätte - was wäre sein Charakter? (Externalisierung einführen)","Wann hat der Konflikt weniger Macht über Ihre Beziehung gehabt - was war in diesen Momenten anders? (Unique Outcomes / Ausnahmen suchen)","Wie würde eine andere Geschichte Ihrer Beziehung klingen, in der der Konflikt weniger Raum einnimmt? (Alternative Geschichte entwickeln)"],"mini_form":"Externalisierungs-Einstieg (5-10 Minuten): Den Konflikt benennen lassen - Nennen wir es den alten Streit - und dann fragen: Was will der alte Streit, wenn er auftaucht - was gewinnt er? Schafft Distanz zur Geschichte, ohne sie zu leugnen.","anlass_typen":["konfliktklaerung","coaching","dialograum"],"typ":"methode","gruppen_sweetspot":"2 Parteien + Mediator:in; selten mehr als 4-5 Personen","stimmung_geeignet":["angespannt","skeptisch","belastet"]},{"id":"testimony-zeugenschaft","name":"Testimony / Zeugenschaft","feld":"E","kurz":"Erlebtes Unrecht öffentlich bezeugen – persönliche Würdigung und gesellschaftliche Anerkennung verbinden.","schritte":["Sicheren Rahmen und absolute Freiwilligkeit herstellen, Begleitung sichern","Die Person erzählt ihr erlebtes Unrecht – die Erzählung wird wörtlich dokumentiert","Gemeinsames Redigieren: Aus dem Rohtext wird eine kohärente, von der Person autorisierte Aussage","Würdigende Übergabe oder Verlesung (oft als kleine Zeremonie mit Zeug:innen)","Verwendung nur mit Einwilligung: Advocacy, Archiv, öffentliches Erinnern"],"zweck":"Erlebtes Unrecht öffentlich bezeugen – persönliche Würdigung und gesellschaftliche Anerkennung verbinden.","hinweise":"Retraumatisierungsrisiko ernst nehmen: nur mit Begleitstruktur und nie unter Zeitdruck. Wann NICHT: als Übung mit Unbeteiligten simulieren oder ohne Klarheit, was mit dem Zeugnis geschieht.","phasen":["verstehen"],"ebenen":["person","feld"],"modi":["selbstzugang"],"formate":["prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":2,"gruppe_max":15,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"MIT Press Reader – Of Trauma, Testimony, and the Power of Human Rights Voices","url":"https://thereader.mitpress.mit.edu/of-trauma-testimony-and-the-power-of-human-rights-voices/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"online","titel":"Trauma-Informed Peacebuilding - PMC Review","url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC12930582/"}],"wann_passt":["Öffentliche Würdigung von Überlebenden: Testimony als Teil eines Gedenkformats, einer Ausstellung oder eines Versöhnung sprozesses - wenn die erzählende Person selbst entschieden hat, zu sprechen, und eine Begleitstruktur vorhanden ist.","Bildungskontext mit Zeitzeug:innen: Wenn Überlebende in Schulen, Universitäten oder Fortbildungen ihre Geschichte teilen - mit klarem Rahmen, Freiwilligkeit und Würdigung durch die Zuhörenden.","Wahrheitskommissionen und institutionelle Aufarbeitungsprozesse: Testimony als formaler Akt der gesellschaftlichen Anerkennung."],"wann_nicht":["Als Übung mit Unbeteiligten, die so tun, als hätten sie etwas erlebt: Das simuliert Würde statt sie herzustellen - und kann das Format beschädigen.","Ohne klare Struktur, was mit dem Zeugnis geschieht: Erzählende müssen wissen, ob das Zeugnis aufgezeichnet, veröffentlicht oder vertraulich behandelt wird.","Unter Zeitdruck oder als Programmpunkt zwischen anderen Aktivitäten: Testimony braucht vor und nach dem Zeugnis Zeit - für Ankunft und für Nachsorge.","Bei akutem, unbearbeitetem Trauma ohne psychologische Begleitstruktur: Das Risiko der Retraumatisierung ist ohne Vorbereitung und Nachbegleitung erheblich."],"fokusfragen":["Was möchten Sie, dass die Menschen in diesem Raum aus Ihrem Zeugnis mitnehmen - was ist die Botschaft hinter der Geschichte? (Absicht der erzählenden Person klären)","Was haben Sie als Zuhörende gehört - was nimmt einen Platz in Ihnen ein? (Würdigung durch die Gruppe)","Was bleibt - was verändert dieses Zeugnis für Sie? (Wirkung der Zeugenschaft)"],"mini_form":"Kein sinnvolles Mini-Format: Testimony braucht vollständigen Rahmen (Vorbereitung, Zeugnis, Würdigung, Nachsorge). Ein abgekürztes Format ohne diese Elemente ist kein Testimony.","anlass_typen":["dialograum","lernformat"],"typ":"methode","gruppen_sweetspot":"1 Zeug:in + Gruppe; Gruppe 10-100 Personen je nach Kontext","stimmung_geeignet":["belastet","neugierig"]},{"id":"storytelling-for-peace","name":"Storytelling for Peace","feld":"E","kurz":"Über persönliche Geschichten Empathie zwischen verfeindeten oder entfremdeten Gruppen aufbauen.","schritte":["Sicheren Rahmen schaffen: Erzählregeln (Ich-Perspektive, keine Debatte, Vertraulichkeit)","Leitfrage stellen, die persönliche Erfahrung öffnet","Geschichten über Konfliktlinien hinweg erzählen – abwechselnd aus beiden Gruppen","Zuhören ohne Kommentar, dann Resonanzrunde: Was hat mich berührt?","Gemeinsame Motive sammeln – wo ähneln sich die Erfahrungen?"],"zweck":"Über persönliche Geschichten Empathie zwischen verfeindeten oder entfremdeten Gruppen aufbauen.","hinweise":"Keine Diskussion über die Wahrheit der Geschichten zulassen – Erfahrung ist nicht verhandelbar. Balance der Gruppen und Erzählzeiten wahren. Wann NICHT: bei akuter Gewalt zwischen Anwesenden oder wenn eine Seite die Bühne dominieren würde.","phasen":["oeffnen","konflikt"],"ebenen":["netzwerk","feld"],"modi":["verbindung","vertrauen"],"formate":["workshop","grossgruppe"],"dauer_min":60,"dauer_max":180,"gruppe_min":6,"gruppe_max":25,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Peace Insight – Storytelling for peace","url":"https://www.peaceinsight.org/en/articles/storytelling-peace/"},{"typ":"online","titel":"Lederach - The Moral Imagination: Summary","url":"https://www.beyondintractability.org/bksum/lederach-imagination"},{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Epilog: Wissensmanagement als gemeinsames Lernen"}],"wann_passt":["Lernformat oder Community-Prozess (10–40 Personen), in dem Erfahrungen mit Gewalt, Verlust oder Ungerechtigkeit geteilt werden sollen, ohne zu retraumatisieren — strukturiertes Storytelling gibt Rahmen und Sicherheit.","Monitoring und Evaluation als MSC-Ergänzung: Geschichten von Transformation (z.B. 'Was hat sich in Ihrer Gemeinschaft verändert?') machen Wirkung greifbar, die Zahlen nicht erfassen.","Netzwerktreffen mit heterogener Gruppe: Wenn Menschen aus sehr verschiedenen Kontexten zusammenkommen, kann eine strukturierte Geschichte-Runde ('Erzähl von einem Moment, in dem du Frieden erlebt hast') verbinden, ohne auf gemeinsame Fakten angewiesen zu sein."],"wann_nicht":["Ohne Sicherheitsrahmen in Gruppen mit frischen Traumata: Stories über Gewalt oder Verlust brauchen klare Vorbereitung, Freiwilligkeit und die Bereitschaft der Moderator:in zur Nachsorge.","Wenn Storytelling als PR-Übung missbraucht wird: 'Teilt uns eine Erfolgsgeschichte' — das erzeugt Auswahl-Bias und kein echtes Wirkungsbild."],"fokusfragen":["„Erzähl von einem konkreten Moment — was hast du gesehen, gehört, gefühlt? Wann war das, wo warst du?“ (Konkretheit einladen, keine Abstraktion)","„Was hat sich durch diesen Moment verändert — in dir, in deiner Beziehung, in deiner Gemeinschaft?“ (Verbindung zu Transformation)","„Wenn du diese Geschichte jemandem erzählst, der noch nie von Peacebuilding gehört hat — was soll er daraus mitnehmen?“ (Destillat und Transferfrage)"],"mini_form":"2-Minuten-Geschichte-Runde als Check-in: Alle teilen in 2 Minuten eine Situation, in der sie erlebt haben, dass Kommunikation/Dialog etwas verändert hat. Ohne Kommentar der anderen. Reicht als Einstieg in ein Reflexionsformat.","anlass_typen":["lernformat","dialograum","beteiligung","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"8–30 Personen","stimmung_geeignet":["belastet","neugierig","muede"]},{"id":"perspektivuebernahme","name":"Perspektivübernahme (Walk in my shoes)","feld":"E","kurz":"Die Innenperspektive der anderen Seite nicht nur verstehen, sondern probeweise bewohnen – Empathie durch Verkörperung.","schritte":["Paare über die Differenz-/Konfliktlinie hinweg bilden","A erzählt eine prägende Erfahrung, B hört aufmerksam zu","Perspektivwechsel: B spricht in der Ich-Form als A – stellt sich vor oder beantwortet Fragen aus A's Sicht","A korrigiert und ergänzt","Rollenwechsel","Reflexion: Was hat sich im Blick auf die andere Person verschoben?"],"zweck":"Die Innenperspektive der anderen Seite nicht nur verstehen, sondern probeweise bewohnen – Empathie durch Verkörperung.","hinweise":"Hohe emotionale Intensität – klare Entrollung am Ende. Stellvertretendes Sprechen vorher ausdrücklich erlauben lassen. Wann NICHT: bei frischem Trauma oder wenn das stellvertretende Sprechen als Vereinnahmung erlebt würde.","phasen":["vertiefen","konflikt"],"ebenen":["person","netzwerk"],"modi":["verbindung","selbstzugang"],"formate":["workshop","fortbildung"],"dauer_min":45,"dauer_max":90,"gruppe_min":2,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah","koerperlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Greater Good Science Center – Empathy: Definition & Practices","url":"https://greatergood.berkeley.edu/topic/empathy/definition"}],"wann_passt":["Empathietraining für Berufsgruppen, die mit Menschen in schwierigen Situationen arbeiten (Sozialarbeiter:innen, Ärzt:innen, Mediator:innen): Perspektivübernahme durch Rollenspiel oder guided imagination erzeugt ein körperliches Verstehen, das über kognitives Wissen geht.","Konfliktklärung als Vorbereitung: Jede Partei nimmt vor dem eigentlichen Gespräch die Perspektive der anderen ein - was reduziert Verteidigungsbereitschaft.","Dialogprogramme mit gegnerischen Gruppen: Walk-in-my-shoes-Übungen als Einstieg, um die Innenperspektive der anderen Seite probeweise zu bewohnen - nicht im Sinne von Zustimmung, sondern von Nachvollziehbarkeit."],"wann_nicht":["Bei frischem Trauma oder wenn stellvertretendes Sprechen als Vereinnahmung der Leidensgeschichte erlebt wird: Dann ist das Format potenziell retraumatisierend und respektlos.","Ohne klare Entrollung am Ende: Die Intensität der Perspektivübernahme braucht einen bewussten Ausstieg - ohne diesen bleibt die Person in der Rolle hängen.","Wenn eine Gruppe das stellvertretende Sprechen nicht ausdrücklich erlaubt hat: Explizites Einverständnis der dargestellten Gruppe ist Voraussetzung."],"fokusfragen":["Wenn Sie [Person/Gruppe X] wären - was würden Sie in dieser Situation fühlen, was wäre Ihnen wichtig? (Perspektivübernahme einleiten)","Was war überraschend oder ungewohnt an der Perspektive, die Sie eingenommen haben? (Entrollung und Reflexion)","Was verändert sich für Sie in Ihrem eigenen Standpunkt, nachdem Sie diese Perspektive eingenommen haben? (Transfer)"],"mini_form":"3-Minuten-Perspektivwechsel: Stellen Sie sich vor, Sie sind die andere Seite. Was würden Sie jetzt in diesem Raum brauchen? - 1 Minute still nachdenken, dann zu zweit teilen. Kein vollständiges Rollenspiel nötig.","anlass_typen":["lernformat","konfliktklaerung","dialograum"],"typ":"werkzeug","gruppen_sweetspot":"beliebig für Imagination; 6-20 für strukturierte Rollenspiele","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"empathic-deep-listening","name":"Empathic / Deep Listening","feld":"E","kurz":"Zuhören als eigenständige Intervention erfahren – Gehörtwerden verändert Sprechende wie Zuhörende.","schritte":["Paare oder Kleingruppen, klare Redezeiten (3–5 Min) vereinbaren","Eine Person spricht, die andere hört mit voller Präsenz – ohne Unterbrechung, ohne innerlich die Antwort vorzubereiten","Eigenen Deutungsrahmen bewusst zurückstellen, Stille aushalten","Zurückspiegeln, was gehört wurde – Inhalt und Ton, nicht Interpretation","Rollentausch","Meta-Reflexion: Was macht solches Zuhören mit dem Gespräch?"],"zweck":"Zuhören als eigenständige Intervention erfahren – Gehörtwerden verändert Sprechende wie Zuhörende.","hinweise":"Die Versuchung, zu deuten oder zu helfen, ist der Hauptstolperstein. Qualität sinkt bei Müdigkeit stark – eher kurz und konzentriert als lang.","phasen":["vertiefen","ankommen"],"ebenen":["person","team"],"modi":["verbindung"],"formate":["workshop","coaching"],"dauer_min":20,"dauer_max":60,"gruppe_min":2,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Beyond Intractability – Empathic Listening (Richard Salem)","url":"https://www.beyondintractability.org/essay/empathic_listening"},{"typ":"buch","titel":"Peacebuilding Practice (Woman PeaceMaker Program, 2023) – Chapter 13: Facilitative Listening Design"}],"wann_passt":["Dialograum oder Mediationssetting, wo eine Partei zuerst wirklich gehört werden muss, bevor Lösungen besprochen werden — Deep Listening schafft den Raum, der NVC-Kommunikation erst möglich macht.","Forschungs- und Feldarbeit in Konfliktkontexten: Die Facilitative Listening Design (FLD)-Variante aus Kambodscha zeigt, dass strukturiertes Zuhören (Be there / Listen carefully / Accept them / Stay with them / Trust them) Perzeptionen über 'den Anderen' verändern kann — auch ohne Konfrontation.","Check-in in belasteten Gruppen: 3–5 Minuten echtes Zuhören (ohne Ratschläge, ohne Wertung) als Einstieg in ein schwieriges Meeting senkt Verteidigungshaltung."],"wann_nicht":["Wenn die zuhörende Person selbst emotional stark aktiviert ist — dann zuerst Selbstregulation (Atemübung, kurze Pause), bevor Deep Listening versucht wird.","Als Technik ohne echtes Interesse: Paraphrasieren allein ist nicht Deep Listening. Wenn die zuhörende Person innerlich schon bei der Antwort ist, fühlt die Sprechende das."],"fokusfragen":["„Was ist das, was du wirklich sagen willst — hinter den Worten?“ (einladend, nicht analytisch)","„Was ist die eine Sache, die du möchtest, dass ich wirklich verstehe?“ (fokussiert das Wesentliche)","„Ich habe gehört, dass... Ist das, was du meinst?“ (Paraphrase als Verstehensprüfung, nicht als Zusammenfassung)"],"beispiel":"FLD-Gesprächseinstieg: Zwei Personen aus verfeindeten Gruppen sitzen zusammen. Listener beginnt: 'Wir möchten verstehen, wie das Leben hier für Sie ist. Erzählen Sie uns — was beschäftigt Sie gerade am meisten in Ihrer Gemeinschaft?' Kein Kommentar, keine Gegenargumentation. Wenn die Person etwas sagt, das falsch oder übertrieben klingt: 'Das klingt schwierig. Haben Sie das selbst erlebt?' — Die Frage prüft ohne zu konfrontieren und öffnet oft den Raum für nuanciertere Perspektiven.","mini_form":"Listening-Runde in 10 Minuten: Paare, je 4 Minuten. Person A spricht über etwas das sie beschäftigt. Person B hört zu ohne zu sprechen, keine Ratschläge, am Ende ein Satz: 'Das, was ich gehört habe ist...' — keine Interpretation. Dann wechseln. Reflexionsfrage: Was war schwer am Zuhören?","anlass_typen":["dialograum","konfliktklaerung","lernformat","coaching"],"typ":"werkzeug","gruppen_sweetspot":"1:1 bis 20 (in Paaren oder Kleingruppen)","stimmung_geeignet":["angespannt","belastet","skeptisch"]},{"id":"erzaehlcafe","name":"Erzählcafé","feld":"E","kurz":"Biografisches Erzählen und gemeinschaftliches Zuhören verbinden – Lebensgeschichten als geteilten Reichtum erfahrbar machen.","schritte":["Thema mit biografischem Bezug wählen","Café-Atmosphäre herstellen: Getränke, kleine Runden, niedrigschwellig","Moderation lädt zum Erzählen ein – ausdrücklich erzählen, nicht diskutieren","Erzählrunden mit behutsamen Nachfragen; alle dürfen, niemand muss","Gemeinsames Zuhören würdigen, Verbindungen zwischen den Geschichten aufzeigen","Würdigender Abschluss"],"zweck":"Biografisches Erzählen und gemeinschaftliches Zuhören verbinden – Lebensgeschichten als geteilten Reichtum erfahrbar machen.","hinweise":"Moderation schützt vor Diskussion und Bewertung – das ist ihre Hauptaufgabe. Thema so wählen, dass alle Generationen/Gruppen andocken können.","phasen":["oeffnen","ankommen"],"ebenen":["netzwerk","feld"],"modi":["verbindung"],"formate":["grossgruppe","workshop"],"dauer_min":90,"dauer_max":150,"gruppe_min":6,"gruppe_max":20,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Netzwerk Erzählcafé – Leitfaden Erzählcafés veranstalten (PDF)","url":"https://netzwerk-erzaehlcafe.ch/wp-content/uploads/2019/06/Leitfaden_zweite-Auflage_06_2019.pdf"}],"wann_passt":["Intergenerationelle Begegnung in Gemeinden, sozialen Einrichtungen oder Organisationen: Das Erzählcafe gibt Menschen unterschiedlicher Generationen oder Hintergründe einen würdigen Rahmen, um Lebenserinnerungen zu teilen - ohne Wertung oder Diskussion.","Neue Gruppen oder Netzwerke, die sich noch nicht kennen und Verbindung jenseits des Sachthemas aufbauen wollen: Biografisches Erzählen zu einem gemeinsamen Thema schafft Verbindung und gegenseitiges Verständnis schnell.","Abschluss oder Übergangsritual in Gemeinschaften: Wenn etwas endet oder sich verändert - ein Erzählcafe, das die gemeinsame Geschichte sammelt."],"wann_nicht":["Wenn die Moderation nicht klar interveniert, sobald Diskussion oder Bewertung entsteht: Das Erzählcafe lebt davon, dass Erzählungen nebeneinanderstehen dürfen, ohne verglichen oder bewertet zu werden.","Mit einem Thema, das strukturell bestimmte Gruppen ausschliesst (z.B. Erzählen Sie von Ihrer Kindheit auf dem Land, wenn viele Stadtmenschen anwesend sind).","Als Schnellformat in einem vollgepackten Programm: Erzählcafes brauchen Atmosphäre, Musse und ausreichend Zeit - mindestens 60-90 Minuten."],"fokusfragen":["Erzählen Sie von einem Moment, in dem Sie [Thema] zum ersten Mal wirklich erlebt haben - konkret, persönlich. (Thematischer Einstieg)","Was war das Wichtigste an dieser Erfahrung - was möchten Sie, dass andere davon wissen? (Vertiefung)","Was verbindet Sie mit den Geschichten, die Sie gerade gehört haben? (Brücke zwischen Erzählenden)"],"mini_form":"Mini-Erzählrunde (15 Minuten): Ein Gegenstand wird in die Mitte gelegt (Foto, Alltagsgegenstand). Jede Person erzählt einen einzigen Satz dazu: Dieser Gegenstand erinnert mich an... Kein Kommentar, keine Diskussion. Atmosphäre des gemeinsamen Erinnerns entstehen lassen.","anlass_typen":["dialograum","netzwerktreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"8-20 ideal; bei größeren Gruppen Untergruppen bilden und am Ende Highlights teilen","stimmung_geeignet":["neugierig","frisch","müde","belastet"]},{"id":"strukturaufstellungen","name":"Strukturaufstellungen (Sparrer/Varga v. Kibéd)","feld":"E","kurz":"Die Struktur eines Systems sichtbar und probeweise veränderbar machen – auch verdeckt, ohne Inhalte offenzulegen.","schritte":["Anliegen im Vorgespräch klären","Relevante Elemente abstrakt definieren (Fokus, Ziel, Hindernis, Ressource – keine realen Personen nötig)","Repräsentant:innen wählen und intuitiv im Raum stellen","Wahrnehmungen der Repräsentant:innen abfragen (repräsentierende Wahrnehmung)","Testinterventionen: Umstellen, Prozessworte, lösende Sätze","Lösungsbild verankern, sorgfältige Entrollung"],"zweck":"Die Struktur eines Systems sichtbar und probeweise veränderbar machen – auch verdeckt, ohne Inhalte offenzulegen.","hinweise":"Braucht ausgebildete Leitung. Aufstellungsbilder sind Hypothesen, keine Wahrheitsbeweise – so auch einführen. Wann NICHT: bei akuten psychischen Krisen von Beteiligten oder als Spektakel ohne Auftrag.","phasen":["verstehen","vertiefen"],"ebenen":["person","team","organisation"],"modi":["klaerung","selbstzugang"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":5,"gruppe_max":20,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["koerperlich","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"SySt-Institut München (Sparrer/Varga von Kibéd)","url":"https://www.syst.info/"},{"typ":"buch","titel":"Insa Sparrer / Matthias Varga von Kibéd: Ganz im Gegenteil (2000)"}],"wann_passt":["Coaching oder Beratung mit jemandem, der ein komplexes System (Organisation, Netzwerk, Familienunternehmen) verstehen will, ohne alle Inhalte offenzulegen: Strukturaufstellungen (Sparrer/Varga v. Kibed) können verdeckt arbeiten - die Repräsentant:innen kennen den Inhalt nicht.","Strategieprozesse mit einer kleinen Gruppe, die ein Systemphänomen sichtbar machen will: Wo stecken Lösungen, die noch nicht gedacht wurden? Die Aufstellung gibt dem System eine Stimme.","Ausbildungskontext für systemisches Arbeiten: Strukturaufstellungen als Lernformat, um Systemdynamiken körperlich zu erfahren."],"wann_nicht":["Ohne ausgebildete Leitung: Das Format erzeugt intensive Erfahrungen (körperliche Resonanz, Repräsentationsphaenomene) - ohne Ausbildung sind Fehlinterpretationen und Schäden möglich.","Bei akuten psychischen Krisen von Beteiligten: Das Format ist kontraindiziert, wenn jemand im Raum in einem akuten labilen Zustand ist.","Als Spektakel oder Unterhaltung ohne klaren Auftrag der aufstellenden Person.","Wenn Aufstellungsbilder als Wahrheit statt als Hypothese kommuniziert werden: Das ist die häufigste ethische Grenzüberschreitung in der Praxis."],"fokusfragen":["Was ist die Frage, die Sie durch diese Aufstellung klären möchten - was soll sichtbar werden? (Auftragsklarung)","Was spüren Sie in dieser Position - was zieht Sie an, was drückt weg? (Repräsentant:in befragen)","Was verändert sich, wenn wir dieses Element verschieben - was wird leichter oder schwerer? (Lösungssuche in der Aufstellung)"],"mini_form":"Drei-Stühle-Aufstellung (10-15 Minuten): Drei Stühle repräsentieren z.B. Status quo, Widerstand, Lösung. Aufstellende Person setzt sich nacheinander auf alle drei, spürt in jede Position hinein und beschreibt die Wahrnehmung. Keine Repräsentant:innen nötig.","anlass_typen":["coaching","strategie","konfliktklaerung"],"typ":"methode","gruppen_sweetspot":"1 aufstellende Person + 3-10 Repräsentant:innen + Beobachtende; gesamt 5-20","stimmung_geeignet":["neugierig","belastet","angespannt"]},{"id":"soziometrie-aufstellung","name":"Soziometrie / Aufstellung im Raum (Moreno)","feld":"E","kurz":"Unterschiede, Beziehungen und Verteilungen in der Gruppe schnell körperlich sichtbar machen.","schritte":["Frage oder Dimension wählen (Zustimmung, Erfahrung, Herkunft, Nähe zum Thema)","Raum definieren: Linie, Skala, Landkarte oder Kreis","Alle positionieren sich gleichzeitig","Einzelne Positionen interviewen: Warum stehst du hier?","Ggf. zweite Frage oder Umstellung","Sichtbar gewordene Gruppenstruktur gemeinsam auswerten"],"zweck":"Unterschiede, Beziehungen und Verteilungen in der Gruppe schnell körperlich sichtbar machen.","hinweise":"Fragen mit Vorsicht wählen – Positionierung exponiert (keine Fragen, die Einzelne bloßstellen). Online mit Whiteboard-Punkten machbar, verliert aber Körperdimension.","phasen":["ankommen","verstehen"],"ebenen":["team","organisation"],"modi":["verbindung","energie"],"formate":["workshop","teamentwicklung"],"dauer_min":10,"dauer_max":45,"gruppe_min":6,"gruppe_max":50,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich","beteiligend"],"blocktyp":["einstieg","kern"],"quellen":[{"typ":"online","titel":"Werner Stangl – Was ist Soziometrie?","url":"https://arbeitsblaetter.stangl-taller.at/FORSCHUNGSMETHODEN/Soziometrie.shtml"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"}],"wann_passt":["Gruppe, die sich noch nicht kennt und schnell ein körperliches Bild von Gemeinsamkeiten und Unterschieden bekommen soll: Soziometrie macht Vielfalt sichtbar, ohne dass jemand reden muss - Körperbewegung reicht.","Check-in bei Grossgruppen: Statt alle sprechen zu lassen, positionieren sich alle - wo im Raum stehe ich zu dieser Frage? Das ist schnell, inklusiv und erzeugt Energie.","Teamtag oder Kickoff: Wer ist wie lange dabei? Wer kommt woher? Wer hat welche Erfahrung mit dem Thema? Soziometrie als spielerische Eröffnung."],"wann_nicht":["Mit Fragen, die Einzelne exponieren oder beschämen könnten: Wer hat sich hier in der letzten Woche unwohl gefühlt? positioniert Einzelne sichtbar - das braucht sehr hohes Vertrauen.","Online ohne alternatives Instrument (Whiteboard, Mentimeter): Die Körperdimension fehlt und das Format verliert seinen Hauptvorteil.","Bei hocheskalierten Konflikten, wo räumliche Positionierung als Lagerbildung erlebt wird."],"fokusfragen":["Stellt euch im Raum danach auf: Wer hat [Eigenschaft/Erfahrung]? Je mehr ihr das kennt, desto weiter in diese Ecke. (Positionierungs-Einladung)","Schaut euch um - was seht ihr? Was überrascht euch? (Reflexion der Verteilung)"],"mini_form":"Positions-Check (5 Minuten): Eine Frage, alle stellen sich auf einer imaginären Linie (links = wenig, rechts = viel) auf. Blick in den Raum. Eine Person aus jeder Seite sagt einen Satz. Fertig.","anlass_typen":["kickoff","teamtag","lernformat","netzwerktreffen"],"typ":"werkzeug","gruppen_sweetspot":"8-50 Personen ideal; unter 6 verliert es Wirkung","stimmung_geeignet":["neugierig","frisch","müde"]},{"id":"genogramm","name":"Genogramm / Family tree","feld":"E","kurz":"Mehrgenerationen-Muster sichtbar machen, die im aktuellen Verhalten und Anliegen weiterwirken.","schritte":["Mindestens drei Generationen mit Standardsymbolen aufzeichnen","Basisdaten ergänzen: Geburten, Tode, Trennungen, Berufe, prägende Ereignisse","Beziehungsqualitäten markieren (eng, konflikthaft, abgebrochen)","Muster erkunden: Wiederholungen, Brüche, Familienaufträge, Tabus","Hypothesen bilden und mit dem aktuellen Anliegen verbinden"],"zweck":"Mehrgenerationen-Muster sichtbar machen, die im aktuellen Verhalten und Anliegen weiterwirken.","hinweise":"Gehört ins geschützte Beratungssetting, nicht ins Plenum. Tempo der erzählenden Person respektieren – hinter jedem Symbol steht eine Geschichte.","phasen":["verstehen"],"ebenen":["person"],"modi":["selbstzugang","klaerung"],"formate":["coaching"],"dauer_min":45,"dauer_max":120,"gruppe_min":1,"gruppe_max":3,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"GenoPro – Introduction to the Genogram","url":"https://genopro.com/genogram/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up (Family Tree)"},{"typ":"buch","titel":"Monica McGoldrick / Randy Gerson: Genograms – Assessment and Intervention (1985)"}],"wann_passt":["Einzelcoaching oder systemische Beratung, wo Muster aus der Herkunftsfamilie aktuelles Verhalten prägen: Das Genogramm macht Mehrgenerationenmuster sichtbar, die anders kaum besprechbar wären.","Familienberatung oder -therapie: Standardwerkzeug, um Loyalitäten, Verluste, Wiederholungsmuster und Ressourcen über Generationen zu kartieren.","Führungskräfteentwicklung (tiefes Format, nicht Standardcoaching): Wenn jemand verstehen will, welche Führungsbilder aus der Herkunftsfamilie sein eigenes Führungsverhalten prägen."],"wann_nicht":["Im Plenum oder in Gruppen ohne expliziten Therapie-/Beratungsauftrag: Genogramme berühren sehr persönliches Material - sie gehören ins geschützte Einzel- oder Kleingruppenformat.","Wenn die Person nicht ausdrücklich eingewilligt hat, biografisch tief zu gehen: Das Tempo der erzählenden Person respektieren.","Als diagnostisches Instrument ohne systemische Ausbildung: Genogramme lesen zu können, braucht Kontext und Ausbildung - sonst werden Muster fehlgedeutet."],"fokusfragen":["Wer war in Ihrer Familie besonders wichtig - eine Person, die Ihre Prägung stark beeinflusst hat? (Einstieg ohne Druck zur Vollständigkeit)","Welches Thema oder Muster taucht in Ihrer Familie immer wieder auf - über Generationen? (Mehrgenerationen-Muster benennen)","Was haben Sie von diesen Menschen mitbekommen, das Sie heute noch tragen - als Ressource oder als Last? (Ressourcen und Lasten kartieren)"],"mini_form":"Genogramm-Einstieg (15 Minuten): Drei Generationen skizzieren (Grosseltern, Eltern, ich). Eine Frage: Wer in dieser Karte hat dich am stärksten geprägt - und wie? Kein vollständiges Genogramm, aber der Einstieg in Mehrgenerationen-Denken.","anlass_typen":["coaching"],"typ":"methode","gruppen_sweetspot":"Einzelperson; in Kleingruppen (3-5) nur mit hohem Vertrauen","stimmung_geeignet":["neugierig","belastet"]},{"id":"skulpturarbeit","name":"Skulpturarbeit (Satir)","feld":"E","kurz":"Beziehungsdynamik als Körperbild verdichten – Kommunikationsmuster werden fühlbar statt nur besprechbar.","schritte":["Anliegen und darzustellendes System klären","Die fallgebende Person stellt Mitglieder körperlich auf: Haltung, Distanz, Blickrichtung, Gestik – ohne Worte","Skulptur einfrieren, alle spüren nach","Aussagen aus den Positionen abfragen","Veränderung zur Wunsch-Skulptur gestalten","Entrollung und gemeinsame Reflexion"],"zweck":"Beziehungsdynamik als Körperbild verdichten – Kommunikationsmuster werden fühlbar statt nur besprechbar.","hinweise":"Die Sprachlosigkeit ist der Wirkmechanismus – nicht zwischendurch zerreden. Körperliche Berührung nur mit Einverständnis. Sorgfältige Entrollung.","phasen":["verstehen","vertiefen"],"ebenen":["person","team"],"modi":["klaerung","selbstzugang"],"formate":["workshop","prozessbegleitung"],"dauer_min":30,"dauer_max":90,"gruppe_min":4,"gruppe_max":15,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["koerperlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Systemisches Netzwerk – Methodensammlung: Skulpturarbeit","url":"https://systemischesnetzwerk.de/methodensammlung/skulpturarbeit/"}],"wann_passt":["Familienberatung oder Einzel-/Gruppentherapie: Skulpturarbeit (Virginia Satir) macht Kommunikationsmuster körperlich erfahrbar - die Stresshaltungen (Beschwichtiger:in, Ankläger:in, Super-Vernünftige:r, Ablenker:in) sind sofort erkennbar, wenn sie verkörpert werden.","Ausbildungskontext für Therapeut:innen, Berater:innen oder Mediator:innen: Eigene Kommunikationsmuster durch Verkörperung kennenlernen - nachhaltig, weil körperlich.","Team-Entwicklungsformat mit hohem Vertrauensniveau: Wenn ein Team bereit ist, Beziehungsdynamiken nicht nur zu besprechen, sondern körperlich sichtbar zu machen."],"wann_nicht":["Ohne sorgfältige Entrollung und Abschlussritual: Körperliche Verkörperung von Rollen braucht einen klaren Ausstieg - sonst wirkt die Körperhaltung nach.","Wenn körperliche Berührung nicht einvernehmlich ist: Skulpturarbeit beinhaltet oft das Positionieren von Menschen - nur mit explizitem Einverständnis.","In Teams ohne ausreichendes Vertrauen: Das Format macht Verletzlichkeit sichtbar und braucht einen sicheren Rahmen."],"fokusfragen":["Welche Haltung erkennst du in dieser Skulptur - was zeigt sie über die Beziehung? (Skulptur deuten lassen)","Was spürst du in dieser Körperhaltung - was sagt dir dein Körper? (Erzählende:r in der Skulptur befragen)","Wie würde die Skulptur aussehen, wenn die Beziehung so wäre, wie du sie dir wünschst? (Lösungsbild entwickeln)"],"mini_form":"Haltungs-Demonstration (5 Minuten): Moderation demonstriert eine Satir-Stresshaltung (z.B. Beschwichtiger:in - Körper klein, Kopf gesenkt, Hände offen nach oben). Gruppe beobachtet. Frage: Wann kennt ihr diese Haltung - bei euch oder anderen? Kein Rollenspiel, nur Demonstration als Erkenntnis-Trigger.","anlass_typen":["coaching","lernformat"],"typ":"methode","gruppen_sweetspot":"1-6 Personen aktiv; Gruppe als Witnessing bis 20","stimmung_geeignet":["neugierig","belastet"]},{"id":"organisationsaufstellung","name":"Organisationsaufstellung","feld":"E","kurz":"Verdeckte Dynamiken einer Organisation – Loyalitäten, Macht, Rollenkonflikte – räumlich erfahrbar machen.","schritte":["Anliegen klären und relevante Systemelemente bestimmen (Rollen, Abteilungen, Ziele, Kund:innen)","Repräsentant:innen wählen und nach innerem Bild positionieren","Wahrnehmungen abfragen","Hypothesen zu Loyalitäten, Macht, Rollenklarheit entwickeln","Probeinterventionen: Umstellungen, klärende Sätze","Transfer: Was bedeutet das Bild für reale Entscheidungen? Entrollung"],"zweck":"Verdeckte Dynamiken einer Organisation – Loyalitäten, Macht, Rollenkonflikte – räumlich erfahrbar machen.","hinweise":"Vertraulichkeit klären, wenn reale Kolleg:innen dargestellt werden. Ergebnisse sind Hypothesen. Wann NICHT: zur Personalbewertung oder als Entscheidungsersatz; nicht mit anwesenden Beteiligten eines eskalierten Konflikts ohne Schutzrahmen.","phasen":["verstehen","vertiefen"],"ebenen":["organisation"],"modi":["klaerung"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":180,"gruppe_min":6,"gruppe_max":20,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["koerperlich","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"socialnet Lexikon – Aufstellung","url":"https://www.socialnet.de/lexikon/Aufstellung"}],"wann_passt":["Beratung einer Führungskraft zu einer verdeckten Systemdynamik (Loyalitätskonflikte, Machtfragen, blinde Flecken in der Organisation): Die Aufstellung gibt dem System eine räumliche Stimme, die bisher nicht artikuliert werden konnte.","Team-Coaching bei anhaltenden Spannungen, die trotz Gesprächen nicht auflösbar sind: Wenn das Reden allein nicht reicht, kann die Aufstellung zeigen, was strukturell wirkt.","Organisationsentwicklung in Veränderungsprozessen: Welche Kräfte wirken für und gegen die Veränderung? Die Aufstellung macht Systemkräfte sichtbar, bevor Strategien entwickelt werden."],"wann_nicht":["Zur Personalbewertung oder Entscheidung über Einzelpersonen: Das wäre eine ethisch inakzeptable Nutzung eines projektiven Formats.","Als Entscheidungsersatz: Aufstellungsbilder sind Hypothesen, keine Wahrheiten - wer die Aufstellung als Entscheidungsgrundlage behandelt, überschreitet ethische Grenzen.","Mit anwesenden Beteiligten eines eskalierten Konflikts ohne Schutzrahmen und ausgebildete Leitung.","Wenn Vertraulichkeit nicht gesichert ist: Reale Kolleg:innen werden dargestellt - das braucht einen klaren Vertraulichkeitsrahmen."],"fokusfragen":["Was ist die konkrete Frage, die Sie durch die Aufstellung klären wollen - was soll sichtbar werden? (Auftragsklarung)","Was spüren Sie in dieser Position - was zieht, was drückt, was fehlt? (Repräsentant:in in der Aufstellung)","Was verändert sich für das System, wenn diese Person oder dieses Element anders positioniert wird? (Lösungssuche)"],"mini_form":"Symbol-Aufstellung (10 Minuten): Statt Personen werden Gegenstände (Tassen, Karten, Steine) als Repräsentant:innen platziert. Die aufstellende Person ordnet die Objekte im Raum an und beschreibt die Beziehungen. Günstigere Variante für Coaching ohne Gruppe.","anlass_typen":["coaching","strategie","konfliktklaerung"],"typ":"methode","gruppen_sweetspot":"1 aufstellende Person + 3-12 Repräsentant:innen; gesamt bis 20 Personen","stimmung_geeignet":["angespannt","skeptisch","neugierig"]},{"id":"after-action-review","name":"After Action Review (AAR)","feld":"F","kurz":"Direkt nach einer Aktion das Lernen sichern, solange die Erinnerung frisch und die Umsetzung nah ist.","schritte":["Zeitnah nach der Aktion alle Beteiligten versammeln","Frage 1: Was sollte passieren? (Ziel/Plan rekonstruieren)","Frage 2: Was ist tatsächlich passiert? (Fakten, keine Schuld)","Frage 3: Warum gab es Abweichungen? (Ursachen, mehrere Perspektiven)","Frage 4: Was lernen wir – was machen wir beim nächsten Mal anders?","Erkenntnisse festhalten und konkret terminieren"],"zweck":"Direkt nach einer Aktion das Lernen sichern, solange die Erinnerung frisch und die Umsetzung nah ist.","hinweise":"Schuldfreiheit ist die Geschäftsgrundlage – sobald Rechtfertigungen dominieren, Moderation nachschärfen. Kurz halten, Routine schlägt Perfektion.","phasen":["reflektieren"],"ebenen":["team","organisation"],"modi":["reflexion"],"formate":["meeting","workshop"],"dauer_min":15,"dauer_max":60,"gruppe_min":2,"gruppe_max":15,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["reflexion","abschluss"],"quellen":[{"typ":"online","titel":"BetterEvaluation – After Action Review","url":"https://www.betterevaluation.org/methods-approaches/methods/after-action-review"},{"typ":"online","titel":"US Army AAR Guide – the original format","url":"https://www.aca.army.mil/Portals/119/AAR%20Guide.pdf"}],"wann_passt":["Direkt nach einer abgeschlossenen Aktion, einem Event oder einer kritischen Entscheidung – solange Erinnerung und Emotionen noch frisch sind: Projektabschluss, Veranstaltung, schwierige Sitzung.","Als kurzes Teamritual nach jeder Iteration, nicht nur nach Fehlschlägen: der AAR wirkt am besten als Routine, nicht als Ausnahme nach Krisen.","Wenn ein Team unter Zeitdruck steht und keine vollständige Retrospektive möglich ist: 15 Minuten AAR sichern das Wesentliche."],"wann_nicht":["Wenn psychologische Sicherheit fehlt und die Gruppe eher Schuldzuweisung als Lernen erwartet – dann erst Rahmung schärfen, bevor AAR gestartet wird.","Als Ersatz für eine tiefere Retrospektive bei längerem Prozess: der AAR ist aktionsnah, keine Teamentwicklung.","In sehr hierarchischen Settings ohne explizite Schuldfreiheits-Rahmung – die Moderation muss aktiv intervenieren, wenn Rechtfertigung dominiert."],"fokusfragen":["„Was sollte passieren – was war der Plan, das Ziel??","„Was ist tatsächlich passiert – was beobachten wir, ohne zu werten??","„Warum gab es Abweichungen – was waren die Ursachen aus verschiedenen Perspektiven??","„Was nehmen wir mit – was machen wir beim nächsten Mal konkret anders??"],"beispiel":"Nach einem Workshop: 15 Minuten AAR. Frage 1: ‚Was haben wir uns für heute vorgenommen?' (Plan rekonstruieren). Frage 2: ‚Was ist wirklich passiert – was hat sich von Anfang an anders angefühlt?' (Fakten, keine Schuld). Frage 3: ‚Warum lief der erste Block besser als der zweite?' (Ursachen, mehrere Perspektiven). Frage 4: ‚Wenn wir das morgen wieder machen: Was tun wir konkret anders?' (Transfer, sofort terminieren). Unterschied zur Retrospektive: AAR fokussiert auf eine einzelne Aktion, ist kürzer, und die Erkenntnisse bleiben aktionsnah – keine Teamdynamik-Diagnose.","mini_form":"Zwei-Fragen-Blitz in 5 Minuten: ‚Was lief heute gut?' und ‚Was würden wir morgen ändern?' – schriftlich auf Post-its, dann 3 Nennungen pro Frage im Plenum. Kein vollständiger AAR, aber das Lernen wird gesichert.","anlass_typen":["retro","regeltermin","lernformat"],"typ":"methode","gruppen_sweetspot":"3–12 Personen ideal; bis 15 mit Moderationsunterstützung","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"retrospektive","name":"Retrospektive (Start/Stop/Continue, Sailboat, 4Ls)","feld":"F","kurz":"Das Wie der Zusammenarbeit regelmäßig verbessern – in kleinen, umsetzbaren Schritten.","schritte":["Set the stage: Check-in und Fokus der Retro klären","Daten sammeln mit einer Struktur – z. B. Sailboat (Wind/Anker/Felsen/Insel) oder Start/Stop/Continue, 4Ls","Muster und Einsichten gemeinsam herausarbeiten","Maximal 2–3 konkrete Maßnahmen beschließen (Verantwortliche, Termin)","Retro kurz abschließen (Check-out, Feedback zur Retro)"],"zweck":"Das Wie der Zusammenarbeit regelmäßig verbessern – in kleinen, umsetzbaren Schritten.","hinweise":"Weniger Maßnahmen, dafür umgesetzte. Formate rotieren (Retromat), sonst nutzt sich das Ritual ab. Alte Maßnahmen zu Beginn prüfen.","phasen":["reflektieren"],"ebenen":["team"],"modi":["reflexion"],"formate":["meeting","teamentwicklung"],"dauer_min":45,"dauer_max":90,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["reflexion","abschluss"],"quellen":[{"typ":"online","titel":"Retromat – Retrospektive-Formate-Baukasten","url":"https://retromat.org/"},{"typ":"buch","titel":"Aus der Methodensammlung von Impact Up"},{"typ":"buch","titel":"Esther Derby / Diana Larsen: Agile Retrospectives (2006)"}],"wann_passt":["Am Ende einer Arbeitsphase, eines Sprints oder Projekts: wenn das Team die Zusammenarbeit selbst verbessern will – nicht den Inhalt, sondern das Wie.","Als wiederkehrendes Ritual im Teamrhythmus (monatlich oder quartalsweise): die Retrospektive braucht Kontinuität, um Vertrauen und Tiefe zu entwickeln.","Wenn konkrete Spannungen in der Zusammenarbeit spürbar sind, aber kein Konfliktformat angemessen ist – Retro ist niedrigschwelliger als Konfliktklärung."],"wann_nicht":["Nach einem einzelnen Event, bei dem noch keine Teamroutine etabliert ist: dann eher AAR (aktionsnah, strukturierter).","Wenn die Maßnahmen aus der letzten Retro nicht umgesetzt wurden – erst prüfen und transparent machen, bevor neue gesammelt werden.","Wenn die Hierarchie im Raum so stark ist, dass ehrliches Feedback nicht möglich ist – dann erst psychologische Sicherheit aufbauen."],"fokusfragen":["„[Start/Stop/Continue] Was sollen wir anfangen, aufhören, beibehalten??","„[Sailboat] Was treibt uns voran (Wind), was hält uns zurück (Anker), was gefährdet uns (Felsen), wo wollen wir hin (Insel)??","„[4Ls] Was haben wir gelernt, gemocht, vermisst, was fehlt noch (Longed for)??"],"beispiel":"Unterschied AAR vs. Retrospektive: Der AAR fragt nach einer einzelnen Aktion (Was sollte passieren? Was ist passiert?), die Retrospektive fragt nach dem Wie der Zusammenarbeit über einen Zeitraum. AAR ist kürzer, aktionsnäher, ohne Teamentwicklungs-Agenda. Die Retrospektive hat mehr Struktur (5 Phasen nach Derby/Larsen: Set the Stage / Gather Data / Generate Insights / Decide What to Do / Close), schließt immer mit konkreten Maßnahmen ab und ist auf Wiederholung ausgelegt. Format Sailboat in 45 Minuten: Check-in (5 Min) → Kategorie-Visualisierung auf Flipchart → jede:r schreibt Post-its in Stille (10 Min) → clustern und besprechen (15 Min) → max. 3 Maßnahmen beschließen mit Verantwortlichen und Termin (10 Min) → Check-out (5 Min).","mini_form":"One-Question-Retro in 10 Minuten: Eine einzige Frage – z.B. ‚Was hat uns diese Woche am meisten Kraft gekostet?' – jede:r schreibt eine Antwort, 3 werden geteilt, eine Maßnahme wird benannt. Kein vollständiges Format, aber Reflexion findet statt.","anlass_typen":["retro","teamtag","regeltermin"],"typ":"methode","gruppen_sweetspot":"4–12 Personen ideal; bis 15 mit Untergruppen","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"kolb-learning-cycle","name":"Kolb Learning Cycle","feld":"F","kurz":"Lernen als vollständigen Zyklus gestalten – Erfahrung wird erst durch Reflexion und Anwendung zu Kompetenz.","schritte":["Konkrete Erfahrung: eine Übung, Simulation oder reale Aufgabe durchleben","Reflektierendes Beobachten: Was ist passiert, was habe ich wahrgenommen?","Abstrakte Konzeptualisierung: Muster benennen, mit Modellen und Begriffen verbinden","Aktives Experimentieren: konkreten Transfer planen und beim nächsten Mal erproben"],"zweck":"Lernen als vollständigen Zyklus gestalten – Erfahrung wird erst durch Reflexion und Anwendung zu Kompetenz.","hinweise":"Die meisten Trainings überspringen Phase 2 oder 4 – beide explizit einplanen. Lernende steigen an unterschiedlichen Punkten ein, der Zyklus muss trotzdem ganz durchlaufen werden.","phasen":["reflektieren","planen"],"ebenen":["person","team"],"modi":["reflexion"],"formate":["fortbildung","workshop"],"dauer_min":30,"dauer_max":120,"gruppe_min":1,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert"],"blocktyp":["reflexion"],"quellen":[{"typ":"online","titel":"Simply Psychology – Kolb's Learning Styles and Experiential Learning Cycle","url":"https://www.simplypsychology.org/learning-kolb.html"},{"typ":"buch","titel":"David Kolb: Experiential Learning (1984)"}],"wann_passt":["In Fortbildungen oder Trainings, bei denen eine Übung oder Simulation gemacht wurde – Kolb strukturiert die anschließende Reflexion, damit Erfahrung zu Lernen wird.","Als Rahmen für die gesamte Lernarchitektur eines Tages: Erfahrung (Übung) → Reflexion (AAR/Retro-Elemente) → Konzeptualisierung (Input-Block) → Transfer (was tue ich nächste Woche?).","Wenn ein Team aus gemachten Erfahrungen lernen will, nicht nur Wissen anhäufen – Kolb macht den Unterschied zwischen Wissenstransfer und Kompetenzentwicklung sichtbar."],"wann_nicht":["Wenn Phase 2 (Reflexion) oder Phase 4 (Transfer) aus Zeitdruck gestrichen werden – dann lieber auf eine vollständigere Methode verzichten und den Zyklus konsequent kleiner durchführen.","Als Erklärungs-Folie ohne Konsequenz für das Design – das Modell muss im Ablauf sichtbar sein, nicht nur im Kopf der Trainer:in.","Wenn reine Wissensvermittlung gefragt ist (Regelkunde, Compliance) – hier ist der Erfahrungs-Zyklus überdimensioniert."],"fokusfragen":["„[Phase 2 – Reflexion] Was haben Sie wahrgenommen – was ist Ihnen aufgefallen, überrascht, berührt??","„[Phase 3 – Konzeptualisierung] Welches Muster steckt dahinter – wie erklären Sie sich das, was passiert ist??","„[Phase 4 – Transfer] Was nehmen Sie konkret mit – was werden Sie beim nächsten Mal anders machen??"],"beispiel":"Unterschied Kolb vs. Gibbs: Kolb ist ein Lernzyklus (für Trainer:innen als Designrahmen, für Gruppen als Lernarchitektur), Gibbs ist ein Reflexionsformat für Einzelne (schriftlich, 6 Stufen mit expliziter Gefühls- und Analysephase). Kolb eignet sich, wenn eine Gruppe aus einer gemeinsamen Erfahrung lernt. Gibbs, wenn eine Einzelperson eine spezifische Situation durcharbeitet. In Kolbs Phase 3 (Abstrakte Konzeptualisierung) Input-Block platzieren: Trainer:in gibt das Modell, nachdem die Gruppe selbst Muster benennt – dann hat der Input Andockpunkte.","mini_form":"Blitz-Zyklus in 15 Minuten: nach jeder Übung direkt 3 Fragen stellen: ‚Was ist passiert?' (Erfahrung) → ‚Was fällt euch auf?' (Reflexion) → ‚Was nehmt ihr für euren Alltag mit?' (Transfer). Phase 3 (Konzeptualisierung) weglassen wenn nötig – aber Transfer nie streichen.","anlass_typen":["lernformat","retro","teamtag"],"typ":"rahmenmodell","gruppen_sweetspot":"2–30 Personen; flexibel","stimmung_geeignet":["neugierig","frisch"]},{"id":"gibbs-reflective-cycle","name":"Gibbs Reflective Cycle","feld":"F","kurz":"Eine einzelne Erfahrung schriftlich und systematisch in sechs Stufen durcharbeiten.","schritte":["Beschreibung: Was ist passiert? (nur Fakten)","Gefühle: Was habe ich gefühlt und gedacht?","Bewertung: Was war gut, was schwierig?","Analyse: Wie erkläre ich mir das – welche Faktoren wirkten?","Schlussfolgerung: Was hätte ich anders tun können?","Aktionsplan: Was tue ich in einer ähnlichen Situation konkret? – schriftlich einzeln, danach optional Austausch in Paaren"],"zweck":"Eine einzelne Erfahrung schriftlich und systematisch in sechs Stufen durcharbeiten.","hinweise":"Stärke ist die erzwungene Trennung von Gefühl, Bewertung und Analyse – Stufen nicht vermischen lassen. Gut als wiederkehrendes Lernjournal-Format.","phasen":["reflektieren"],"ebenen":["person"],"modi":["reflexion","selbstzugang"],"formate":["coaching","fortbildung"],"dauer_min":30,"dauer_max":60,"gruppe_min":1,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["schriftlich","strukturiert"],"blocktyp":["reflexion"],"quellen":[{"typ":"online","titel":"University of Edinburgh – Gibbs' Reflective Cycle (Reflection Toolkit)","url":"https://www.ed.ac.uk/reflection/reflectors-toolkit/reflecting-on-experience/gibbs-reflective-cycle"}],"wann_passt":["Eine Person will eine konkrete, emotional aufgeladene Situation systematisch verarbeiten – die erzwungene Trennung von Fakten, Gefühlen und Analyse verhindert, dass alles vermengt wird.","In Fortbildungen, in denen Reflexionskompetenz explizit entwickelt werden soll (Lehramtsstudium, Pflegeausbildung, OE-Ausbildung) – Gibbs gibt dafür eine schriftliche Lernjournal-Struktur.","Nach einer schwierigen Moderations- oder Beratungssituation: die 6 Stufen verhindern vorschnelle Urteile (‚Das war ein Fehler') und führen zu differenzierter Selbstreflexion."],"wann_nicht":["Als Gruppenformat ohne schriftliche Einzelarbeit: ohne das Schreiben fehlt die erzwungene Trennung der Stufen.","Wenn die Person eher einen Austausch sucht als strukturierte Reflexion – dann Intervision oder Kollegiale Beratung.","Bei sehr kurzen Ereignissen ohne emotionalen Gehalt: der Zyklus ist für bedeutsame, herausfordernde Erfahrungen konzipiert."],"fokusfragen":["„[Stufe 1 – Beschreibung] Was ist genau passiert – wer, was, wann, wie??","„[Stufe 2 – Gefühle] Was habe ich in diesem Moment gefühlt und gedacht – ehrlich, ohne Bewertung??","„[Stufe 6 – Aktionsplan] Was tue ich konkret in einer ähnlichen Situation – in einem Satz, mit Verb??"],"beispiel":"Unterschied Gibbs vs. Kolb: Gibbs ist ein Einzel-Reflexionsformat (schriftlich, 6 Stufen, fokussiert auf eine spezifische Erfahrung, explizit mit Gefühlen). Kolb ist ein Lernzyklus (Gruppen oder Einzel, Designrahmen für Trainings). Gibbs eignet sich für: ‚Ich hatte gerade eine schwierige Situation – ich will sie durcharbeiten.' Kolb eignet sich für: ‚Wir haben gerade eine Übung gemacht – was lernen wir daraus als Gruppe?' In der Praxis: Gibbs als Lerntagebuch-Vorlage nach jeder Beratungseinheit in einer OE-Ausbildung – Stufen als Überschriften, 20 Minuten Schreibzeit, dann optional Austausch in Paaren.","mini_form":"Drei-Stufen-Blitz in 10 Minuten: Nur Stufe 1 (Was ist passiert?), Stufe 2 (Was habe ich gefühlt?) und Stufe 6 (Was mache ich nächstes Mal?) – schriftlich, dann optional Austausch. Kein vollständiger Gibbs, aber das Reflexions-Muster wird aktiviert.","anlass_typen":["lernformat","coaching","retro"],"typ":"methode","gruppen_sweetspot":"1–20 Personen; als Einzelarbeit mit Paar-Austausch","stimmung_geeignet":["neugierig","belastet"]},{"id":"double-loop-learning","name":"Double-Loop Learning (Argyris)","feld":"F","kurz":"Statt Fehler immer besser zu korrigieren, die Annahmen hinterfragen, die die Fehler erzeugen.","schritte":["Ein wiederkehrendes Problem wählen, das trotz Korrekturen wiederkommt","Bisherige Korrekturen sammeln – das ist Single-Loop: Handeln anpassen, Annahmen behalten","Die zugrundeliegenden Annahmen, Ziele und Werte explizit machen","Diese Annahmen selbst hinterfragen: Stimmen sie noch?","Neue Handlungstheorie formulieren und einen Test vereinbaren"],"zweck":"Statt Fehler immer besser zu korrigieren, die Annahmen hinterfragen, die die Fehler erzeugen.","hinweise":"Stößt auf defensive Routinen – Menschen verteidigen ihre Grundannahmen. Braucht psychologische Sicherheit und Zeit. Leitfrage Was dürfte hier nicht in Frage gestellt werden? öffnet oft die Tür.","phasen":["reflektieren","verstehen"],"ebenen":["team","organisation"],"modi":["reflexion","klaerung"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern","reflexion"],"quellen":[{"typ":"online","titel":"infed.org – Chris Argyris: Theories of Action, Double-Loop Learning and Organizational Learning","url":"https://infed.org/mobi/chris-argyris-theories-of-action-double-loop-learning-and-organizational-learning/"},{"typ":"buch","titel":"Chris Argyris / Donald Schön: Organizational Learning (1978)"}],"wann_passt":["Ein Team löst dasselbe Problem zum dritten Mal – das Symptom kehrt trotz Korrekturen zurück: jetzt lohnt es sich, die zugrundeliegenden Annahmen zu hinterfragen.","In einer Strategieklausur, in der alte Entscheidungen überprüft werden sollen: ‚Welche Annahmen haben unsere letzten Entscheidungen geleitet – stimmen sie noch?'","In einer OE-Begleitung, wenn eine Organisation defensive Routinen entwickelt hat: Double-Loop Learning schafft Sprache dafür und öffnet den Reflexionsraum."],"wann_nicht":["Ohne psychologische Sicherheit: das Infragestellen von Grundannahmen löst defensive Routinen aus und braucht ausreichend Vertrauen.","Bei akuten operativen Problemen, die schnelle Lösung brauchen – Single-Loop reicht hier.","Wenn die Gruppe noch nicht versteht, was Single-Loop ist: der Unterschied muss erst erfahrbar werden (z.B. durch eine Übung oder ein Beispiel)."],"fokusfragen":["„Was haben wir bereits versucht – und warum hat es nicht gehalten??","„Welche Annahmen stecken hinter unseren bisherigen Lösungsversuchen – was haben wir für selbstverständlich gehalten??","„Was dürfte hier nicht in Frage gestellt werden – und was wäre, wenn genau das der springende Punkt ist??"],"beispiel":"Team klagt zum dritten Mal über schlechte Kommunikation. Single-Loop-Antwort: neues Kommunikationsformat einführen (hat nicht gehalten). Double-Loop: ‚Welche Annahme steckt dahinter, dass das Problem bei der Kommunikationsform liegt – nicht bei der Beziehung oder der Entscheidungsstruktur?' Frage in die Runde: ‚Was dürfte hier nicht in Frage gestellt werden?' (Argyris' Öffnungsfrage). Wenn jemand sagt ‚Die Hierarchie, das wird nie verändert' – genau das ist die Annahme, die geprüft werden muss. Anschlussfrage: ‚Wenn wir diese Annahme für einen Moment ausklammern: Was würden wir dann versuchen?'","mini_form":"Annahmen-Blitz in 10 Minuten: Zu einem wiederkehrenden Problem fragen: ‚Welche Annahmen haben wir bisher gemacht, wenn wir dieses Problem gelöst haben?' (2 Min still notieren, dann teilen). Reicht, um den Double-Loop-Modus anzuschalten, ohne das volle Konzept einzuführen.","anlass_typen":["retro","strategie","lernformat"],"typ":"rahmenmodell","gruppen_sweetspot":"4–12 Personen; mit Vertrauensgrundlage","stimmung_geeignet":["neugierig","belastet"]},{"id":"intervision","name":"Intervision / Kollegiale Beratung","feld":"F","kurz":"Berufliche Fälle in der Peer-Gruppe systematisch beraten – ohne externe Autorität, mit verteilten Rollen.","schritte":["Rollen verteilen: Fallgeber:in, Moderation, Berater:innen","Fallschilderung (5–10 Min), Berater:innen hören zu","Fallgeber:in formuliert eine Schlüsselfrage","Methode für die Beratungsrunde wählen (Hypothesenrunde, Resonanzrunde, Brainstorming)","Berater:innen beraten – Fallgeber:in hört nur zu","Fallgeber:in meldet zurück, was hilfreich war; kurzer Abschluss"],"zweck":"Berufliche Fälle in der Peer-Gruppe systematisch beraten – ohne externe Autorität, mit verteilten Rollen.","hinweise":"Struktur strikt einhalten (besonders das Zuhören-ohne-Verteidigen der Fallgeber:in) – sie ist der Schutz vor Kaffeerunden-Beliebigkeit. Feste Gruppe und Rhythmus erhöhen die Tiefe.","phasen":["reflektieren","vertiefen"],"ebenen":["person","team"],"modi":["reflexion","klaerung"],"formate":["reflexionsrunde","prozessbegleitung"],"dauer_min":45,"dauer_max":90,"gruppe_min":4,"gruppe_max":9,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern","reflexion"],"quellen":[{"typ":"online","titel":"Kollegiale Beratung (Kim-Oliver Tietze)","url":"https://www.kollegiale-beratung.de/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO)"},{"typ":"buch","titel":"Kim-Oliver Tietze: Kollegiale Beratung (2003)"},{"typ":"online","titel":"Intervision – Methoden und Phasen (Socialnet)","url":"https://www.socialnet.de/lexikon/Intervision"}],"wann_passt":["Eine feste Peer-Gruppe von Fachpersonen (Berater:innen, Trainer:innen, Führungskräfte) trifft sich regelmäßig zur gegenseitigen Fallberatung – Intervision braucht eine etablierte Gruppe und einen festen Rhythmus.","Als professioneller Reflexionsrahmen in einer OE-Ausbildung, bei der Lernende reale Beratungssituationen mitbringen – das Phasenmodell gibt dem Gespräch Struktur und verhindert Kaffeerunden-Beliebigkeit.","Wenn externe Supervision nicht verfügbar oder zu teuer ist: Intervision bietet ähnliche Reflexionstiefe bei verfügbarer Peer-Intelligenz."],"wann_nicht":["Bei Einzelpersonen ohne feste Gruppe – Intervision braucht mindestens 4 stabile Mitglieder.","Wenn die Gruppe noch keine gemeinsame Haltung für das Format hat: ohne klare Rollenverteilung (Moderation, Fallgeber:in) und Strukturdisziplin wird es beliebig.","Für akute Krisen: Intervision ist kein Kriseninterventionsformat – die Fallberatung ist auf Distanz und Reflexion ausgelegt."],"fokusfragen":["„[Schlüsselfrage] Was genau wünscht sich die Fallgeber:in von der Gruppe – eine Hypothese, eine Empfehlung, Resonanz??","„[Hypothesenrunde] Welche Funktion könnte dieses Verhalten für das geschilderte System haben??","„[Abschluss] Was von dem Gehörten war für Sie am wertvollsten – und was lassen Sie bewusst liegen??"],"beispiel":"Phasenmodell Kollegiale Beratung (nach Tietze): 1. Fallschilderung (5–7 Min) – Fallgeber:in erzählt, Gruppe hört ohne Unterbrechung. 2. Schlüsselfrage formulieren (2–3 Min) – Fallgeber:in formuliert, was sie von der Gruppe braucht (Hypothesen? Empfehlungen? Resonanz?). 3. Methodenwahl (1 Min) – Moderation wählt Format: Hypothesenrunde, Brainstorming, Rollenspiel. 4. Beratungsphase (15 Min) – Gruppe berät, Fallgeber:in hört nur zu, notiert. 5. Fallgeber:in meldet zurück (3 Min) – was war hilfreich, was nicht. 6. Abschluss. Unterschied zu Reflecting Team: Beim Reflecting Team kommentiert ein Teil der Gruppe die Beobachtungen der anderen (Meta-Ebene), beim Reflecting Team sind Rollen fließender. Intervision/Kollegiale Beratung hat klarere Phasendisziplin und ist besser für Praxis-Peer-Gruppen ohne Facilitation-Erfahrung.","mini_form":"Blitz-Intervision in 20 Minuten: Fallschilderung 5 Min, Schlüsselfrage 1 Min, Hypothesenrunde 10 Min (Fallgeber:in schweigt), Rückmeldung 4 Min. Kein vollständiges Format, aber der Kern wirkt.","anlass_typen":["lernformat","coaching","retro"],"typ":"methode","gruppen_sweetspot":"4–8 Personen ideal; 9 noch handhabbar","stimmung_geeignet":["neugierig","belastet","muede"]},{"id":"johari-fenster","name":"Johari-Fenster","feld":"F","kurz":"Blinde Flecken und Verborgenes sichtbar machen – die Fläche gemeinsamen Wissens übereinander vergrößern.","schritte":["Die vier Fenster erklären: öffentlich, blinder Fleck, Fassade (verborgen), unbekannt","Selbstbild erheben (z. B. Adjektivauswahl)","Fremdbild erheben: Kolleg:innen wählen Adjektive für die Person","Abgleich: Feedback verkleinert den blinden Fleck, Selbstoffenbarung die Fassade","Austausch in Paaren oder Kleingruppe mit Feedbackregeln","Persönliche Vornahmen festhalten"],"zweck":"Blinde Flecken und Verborgenes sichtbar machen – die Fläche gemeinsamen Wissens übereinander vergrößern.","hinweise":"Feedbackregeln vorher etablieren (konkret, wertschätzend, erbeten). Freiwilligkeit beim Grad der Offenlegung. Nicht als Beurteilungsinstrument einsetzen.","phasen":["reflektieren","verstehen"],"ebenen":["person","team"],"modi":["selbstzugang","reflexion"],"formate":["workshop","teamentwicklung","fortbildung"],"dauer_min":45,"dauer_max":90,"gruppe_min":3,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Communication Theory – The Johari Window Model","url":"https://www.communicationtheory.org/the-johari-window-model/"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Selbstreflektion"}],"wann_passt":["In einem Teamtag oder Teamentwicklungs-Workshop, bei dem gegenseitiges Verständnis und Feedback-Kultur gestärkt werden sollen – Johari macht das Konzept des blinden Flecks erfahrbar.","In einer Fortbildung zu Selbstreflexion und Führungspersönlichkeit: das Modell ist gut verständlich und hat sofort praktische Konsequenzen.","Als Einstieg in eine Feedback-Kultur: bevor anonyme oder formalisierte Feedback-Prozesse eingeführt werden, schafft Johari ein gemeinsames Bild davon, warum Feedback überhaupt nützlich ist."],"wann_nicht":["Wenn Vertrauen und psychologische Sicherheit in der Gruppe noch nicht ausreichend sind – die Selbstoffenbarung und das Feedback brauchen eine sichere Basis.","Als schnelles Team-Warming-Up: das Format braucht Zeit und Feedbackregeln, sonst entsteht Oberfläche statt Tiefe.","In sehr hierarchischen Kontexten, in denen Feedback an Vorgesetzte riskant erscheint – dann andere Formate wählen oder Anonymität sichern."],"fokusfragen":["„Was von mir ist für andere sichtbar – was zeige ich bewusst??","„Was höre ich heute, das mich überrascht – was war mir über mich selbst nicht bewusst??","„Was möchte ich von der Fassade in den öffentlichen Raum bringen – was will ich bewusst zeigen??"],"beispiel":"Adjektivliste-Variante in 45 Minuten: Jede:r wählt aus einer Liste von 56 Adjektiven (offen, geduldig, introvertiert …) 5–6, die auf sich zutreffen. Gleichzeitig wählen die anderen je 5–6 Adjektive für die Person. Abgleich: Überschneidungen = öffentliches Fenster. Adjektive nur bei der Person = blinder Fleck. Adjektive nur von der Person selbst = Fassade. Austausch in Paaren: ‚Was überrascht dich bei deinem blinden Fleck?' (5 Min). Wichtig: Feedbackregeln vorab etablieren – konkret, wertschätzend, beschreibend (nicht bewertend).","mini_form":"Blinder-Fleck-Frage in 10 Minuten: Eine einzige Frage in die Runde oder in Paaren: ‚Was ist etwas, das andere an mir sehen, das ich selbst oft nicht wahrnehme?' – freiwillig teilen. Öffnet Johari-Dynamik ohne das vollständige Format.","anlass_typen":["teamtag","lernformat","coaching"],"typ":"methode","gruppen_sweetspot":"4–12 Personen; in Paaren oder Dreiergruppen aufgeteilt","stimmung_geeignet":["neugierig","frisch"]},{"id":"inneres-team","name":"Inneres Team (Schulz von Thun)","feld":"F","kurz":"Innere Vielstimmigkeit externalisieren und aus innerem Durcheinander eine geklärte, integrierte Haltung entwickeln.","schritte":["Anliegen oder Entscheidungssituation benennen","Innere Stimmen dazu sammeln und benennen","Stimmen visualisieren oder mit Gegenständen/Karten aufstellen","Jede Stimme sprechen lassen – auch die leisen und verbannten","Teamkonferenz: Das Oberhaupt (Ich) moderiert die Stimmen und sucht eine integrierte Antwort","Ergebnis festhalten"],"zweck":"Innere Vielstimmigkeit externalisieren und aus innerem Durcheinander eine geklärte, integrierte Haltung entwickeln.","hinweise":"Verbannte Stimmen (Stimmen im Keller) tragen oft die wichtigste Information. In Gruppen als angeleitete Einzelarbeit mit freiwilligem Austausch gestalten.","phasen":["reflektieren","entscheiden"],"ebenen":["person"],"modi":["selbstzugang","klaerung"],"formate":["coaching","workshop"],"dauer_min":45,"dauer_max":90,"gruppe_min":1,"gruppe_max":12,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"hoch","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Schulz von Thun Institut – Das Innere Team","url":"https://www.schulz-von-thun.de/die-modelle/das-innere-team"},{"typ":"buch","titel":"Bildungsmaterial der systemischen OE-Fortbildung (WISPO) – Selbstreflektion"},{"typ":"buch","titel":"Friedemann Schulz von Thun: Miteinander reden 3 (1998)"}],"wann_passt":["Eine Person ist innerlich zerrissen bei einer wichtigen Entscheidung – das Innere Team externalisiert die verschiedenen Stimmen und macht sie besprechbar.","In einem Coaching, bei dem jemand immer wieder an denselben inneren Widersprüchen scheitert (‚Ich will X, aber ein Teil von mir …').","In Fortbildungen zu Kommunikation und Selbstführung: das Modell macht innere Vielstimmigkeit normalisierbar und handhabbar."],"wann_nicht":["Bei akutem psychischem Druck oder Trauma-Nähe: das Format führt tief nach innen und braucht eine klare psychologische Sicherheitsbasis.","Als kurze Gruppenübung ohne ausreichend Zeit: das Format braucht 45–90 Minuten, damit die verbannten Stimmen auftauchen können.","Wenn die Person eher pragmatisch an eine Entscheidung herangeht und innere Vielstimmigkeit als fremd erlebt – dann andere Entscheidungsformate."],"fokusfragen":["„Welche Stimmen melden sich, wenn Sie an diese Situation denken – was sagt jede??","„Welche Stimme kommt selten zu Wort – was wäre, wenn Sie ihr mehr Raum gäben??","„Was würde das Oberhaupt – Ihr integriertes Ich – entscheiden, wenn alle Stimmen gehört wurden??"],"beispiel":"In einem Coaching zu einer Berufswechsel-Entscheidung: Person benennt innere Stimmen: ‚Sicherheitssuchende' (bleibt lieber), ‚Abenteuerlust' (will wechseln), ‚Innerem Kritiker' (traut sich nicht). Visualisierung: Karten mit Namen auf dem Tisch. Jede Stimme sprechen lassen: ‚Was will die Sicherheitssuchende?' Dann verbannte Stimme: ‚Gibt es eine Stimme, die noch nicht gesprochen hat – vielleicht eine leise, die Sie lieber nicht hören?' Teamkonferenz: ‚Was würde das Oberhaupt entscheiden, wenn alle Stimmen sagen durften, was sie brauchen?' Anschlussfrage: ‚Was braucht jede Stimme, damit sie die Entscheidung tragen kann?'","mini_form":"Stimmen-Blitz in 15 Minuten: ‚Benennen Sie 3–4 innere Stimmen zu dieser Entscheidung – was sagt jede in einem Satz?' Dann: ‚Welche Stimme wird meist überhört?' Keine vollständige Teamkonferenz, aber die Vielstimmigkeit wird sichtbar.","anlass_typen":["coaching","lernformat"],"typ":"methode","gruppen_sweetspot":"1–3 Personen im Coaching; als Einzel-Reflexion in Gruppen bis 12","stimmung_geeignet":["belastet","neugierig"]},{"id":"harvesting","name":"Harvesting (Art of Hosting)","feld":"F","kurz":"Kollektives Wissen aus Großgruppenprozessen ernten und über das Event hinaus nutzbar machen.","schritte":["Vor der Session: Harvest planen – welche Fragen, welche Artefakte (Karten, Graphic Recording, Fotos, Zitate), für wen?","Während der Session sichtbar dokumentieren – die Gruppe sieht ihr Denken entstehen","Verdichten: Muster und Kernerkenntnisse gemeinsam benennen","Artefakt erstellen, das ohne Anwesenheit verständlich ist","Feedback-Schleife: Ernte in den nächsten Prozessschritt einspeisen"],"zweck":"Kollektives Wissen aus Großgruppenprozessen ernten und über das Event hinaus nutzbar machen.","hinweise":"Harvest wird beim Design mitgeplant, nicht hinterher improvisiert. Artefakt + Feedback-Schleife gehören zusammen – ein schönes Protokoll ohne Weiterverwendung ist keine Ernte.","phasen":["reflektieren","verstetigen"],"ebenen":["team","organisation","netzwerk"],"modi":["reflexion"],"formate":["grossgruppe","workshop"],"dauer_min":20,"dauer_max":60,"gruppe_min":4,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["reflexion","abschluss"],"quellen":[{"typ":"online","titel":"Chris Corrigan – The Art of Harvesting","url":"https://www.chriscorrigan.com/parkinglot/the-art-of-harvesting/"}],"wann_passt":["Großgruppenprozesse (Open Space, World Café, Future Search), bei denen viel Wissen entsteht, das sonst verloren geht – Harvesting stellt sicher, dass Erkenntnisse über das Event hinaus nutzbar bleiben.","In längeren Begleitprozessen (Strategie-Entwicklung, OE-Prozess), bei denen mehrere Sessions aufeinander aufbauen – Harvesting sichert den Wissensfluss zwischen den Phasen.","Wenn eine Gruppe nach einem intensiven Dialog ‚Was haben wir eigentlich gelernt?' nicht beantworten kann – ein geplanter Harvest verhindert dieses ‚Plenums-Vergessen'."],"wann_nicht":["Als nachträgliche Improvisation: Harvesting muss beim Design mitgeplant sein – was soll wie für wen geerntet werden?","Wenn kein Feedback-Loop in den Prozess eingeplant ist: ein Harvest-Artefakt ohne Weiterverwendung ist verschwendete Energie.","Bei kleinen Meetings oder kurzen Sessions: der Aufwand des Harvesting steht nicht im Verhältnis – Protokoll reicht."],"fokusfragen":["„Was soll geerntet werden – Erkenntnisse, Energien, Spannungsfelder, Commitments??","„Für wen ist die Ernte bestimmt – wer braucht das Artefakt in welcher Form??","„Wie fließt die Ernte zurück in den Prozess – wer entscheidet auf Basis der geernteten Erkenntnisse??"],"beispiel":"Harvesting in einem zweitägigen Strategieprozess: Vor dem Event: Harvest-Plan (Was? Für wen? In welcher Form?). Während der Sessions: Graphic Facilitator visualisiert live, Moderations-Karten werden fotografiert, Kernzitate werden gesammelt. Ende Tag 1: Verdichtungsrunde (15 Min) – Gruppe benennt 3 zentrale Erkenntnisse, die auf einer Seite landen. Ende Tag 2: Harvest-Rückspiegel – die verdichtete Seite wird der Gruppe zurückgespielt: ‚Ist das, was wir beschlossen haben?' Weiterverwendung im Protokoll und in der nächsten Sitzung als Startpunkt.","mini_form":"Drei-Sätze-Harvest in 10 Minuten: Am Ende einer Session jede:r eine Karte: ‚Was nehme ich mit – in einem Satz?' Karten vorlesen, clustern, 3 Kernerkenntnisse benennen. Kein aufwendiges Artefakt, aber das Wesentliche wird gesichert.","anlass_typen":["beteiligung","strategie","lernformat","retro"],"typ":"werkzeug","gruppen_sweetspot":"Kein klassisches Gruppenformat – Planungs-Werkzeug für die Prozessgestaltung; wirkt in Gruppen jeder Größe","stimmung_geeignet":["neugierig","frisch","muede"]},{"id":"most-significant-change","name":"Most Significant Change","feld":"F","kurz":"Wirkung über bedeutsame Veränderungsgeschichten erfassen statt nur über vordefinierte Indikatoren.","schritte":["Leitfrage stellen: Was war aus deiner Sicht die bedeutsamste Veränderung im Zeitraum X?","Geschichten sammeln – schriftlich oder als kurze Interviews, mit Begründung der Bedeutsamkeit","In Gruppen die bedeutsamste Geschichte auswählen und die Auswahlkriterien dokumentieren","Auswahl ggf. über mehrere Ebenen wiederholen (Team â†’ Programm â†’ Steuerung)","Feedback an die Erzählenden: Welche Geschichte wurde warum gewählt?","Erkenntnisse für Steuerung nutzen"],"zweck":"Wirkung über bedeutsame Veränderungsgeschichten erfassen statt nur über vordefinierte Indikatoren – inklusive der Werte-Debatte, was bedeutsam heißt.","hinweise":"Der Auswahlprozess mit seiner Diskussion ist der eigentliche Lerngewinn – Kriterien dokumentieren. Erfasst systematisch das Auffällige, nicht das Repräsentative – mit anderen Daten kombinieren.","phasen":["reflektieren","verstetigen"],"ebenen":["organisation","netzwerk","feld"],"modi":["reflexion"],"formate":["workshop","prozessbegleitung"],"dauer_min":60,"dauer_max":120,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern","reflexion"],"quellen":[{"typ":"online","titel":"BetterEvaluation – Most Significant Change","url":"https://www.betterevaluation.org/methods-approaches/approaches/most-significant-change"},{"typ":"buch","titel":"Rick Davies / Jess Dart: The Most Significant Change Technique – A Guide to Its Use (2005, frei verfügbar)"},{"typ":"online","titel":"Rick Davies & Jess Dart: The MSC Guide (2005, frei verfügbar)","url":"https://www.mande.co.uk/docs/MSCGuide.pdf"},{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 8: Evaluation / MSC"}],"wann_passt":["Programm-Monitoring in Kontexten, wo quantitative Indikatoren die eigentliche Veränderung verfehlen — MSC sammelt Geschichten der 'bedeutsamsten Veränderung' von Teilnehmenden selbst und lässt dann Teams gemeinsam entscheiden, welche davon die relevanteste ist.","Evaluationsphase mit Partnerorganisationen (10–30 Personen): Wenn das Programm viele nicht-intendierte aber wichtige Wirkungen hatte, die kein Logframe erfassen kann — MSC macht das Unerwartete sichtbar.","Teamreflexion nach einem längeren Prozess: Jede:r teilt die Geschichte 'der bedeutsamsten Veränderung, die ich in diesem Projekt erlebt habe' — entlastet von Berichtspflicht und erzeugt gemeinsames Bewusstsein für Wirkung.","Beteiligungsformate mit Communities: Wenn die Perspektive der betroffenen Menschen zur Hauptquelle für Wirkungseinschätzung werden soll, nicht die Perspektive der Programmgebenden."],"wann_nicht":["Als einziges Monitoring-Instrument: MSC braucht Ergänzung durch Prozessindikatoren — es erfasst Wirkung, aber nicht ob das Programm wie geplant umgesetzt wurde.","Wenn Geldgeber:innen ausschließlich aggregierte quantitative Daten verlangen: MSC-Geschichten lassen sich schlecht in Balkendiagramme überführen.","In Gruppen mit starkem Hierarchiegefälle, wo Teilnehmende nur erzählen was die Führung hören will — dann zuerst psychologische Sicherheit aufbauen."],"fokusfragen":["„In den vergangenen [3/6/12] Monaten: Was war die bedeutsamste Veränderung in deinem Leben/deiner Gemeinschaft, die du auf dieses Programm zurückführst?“ (Kern-Frage MSC)","„Warum war gerade diese Veränderung für dich die bedeutsamste — was macht sie wichtiger als andere?“ (zwingt zur Begründung und macht Werte sichtbar)","„Wenn ihr diese Geschichten vergleicht: Welche davon repräsentiert am besten das, was wir mit diesem Programm erreichen wollten — und warum?“ (Auswahlrunde im Team)"],"beispiel":"MSC-Runde in einem Programm-Review (15 Personen): Alle bekommen 5 Minuten um eine Geschichte aufzuschreiben. Dann Kleingruppen zu 4–5, jede Gruppe wählt die eine Geschichte aus, die sie als bedeutsamste erachtet, und begründet es. Großrunde: Jede Kleingruppe stellt ihre Auswahl vor. Die Moderation notiert die Begründungen — sie sind oft aufschlussreicher als die Geschichten selbst: Sie zeigen, was die Gruppe für wirklich relevant hält.","mini_form":"Solo-MSC in 10 Minuten als Check-in: 'Schreib in 3 Sätzen: Was ist die eine Veränderung, die du in diesem Projekt nie vergessen wirst?' Teilen in der Großrunde ohne Diskussion — reicht als Stimmungsbarometer und Einstieg in eine Retro.","anlass_typen":["retro","lernformat","beteiligung"],"typ":"methode","gruppen_sweetspot":"8–30 Personen, mit ausreichend Zeit (min. 60 Min. für die vollständige Methode)","stimmung_geeignet":["neugierig","belastet","muede"]},{"id":"mini-bodyscan-im-sitzen","name":"Mini-Bodyscan im Sitzen","feld":"F","kurz":"Geführte Aufmerksamkeitsreise durch den Körper (Füße, Beine, Rumpf, Schultern, Gesicht) im Sitzen auf dem Stuhl. Holt die Gruppe aus dem Kopf in die Wahrnehmung und markiert Übergänge zwischen Denkblöcken.","schritte":["Anmoderation: „Bevor wir in den nächsten Block gehen, drei Minuten Konzentrations-Reset. Setzt euch bequem hin, Füße auf den Boden. Augen können offen oder geschlossen sein.\"","Langsam durch den Körper führen: Füße – Sitzfläche – Rücken – Schultern („dürfen die ein Stück sinken?\") – Gesicht. Pro Station 20–30 Sekunden, ruhige Alltagsstimme.","Abschluss: „Einmal tief einatmen, ausatmen – und wieder hier im Raum ankommen.\""],"zweck":"Aufmerksamkeit bündeln, Anspannung lösen, Übergang zwischen Denkblöcken körperlich markieren.","hinweise":"Säkular als „Konzentrations-Reset\" rahmen. Trauma-sensibel: Augen offen ist okay, Körperregionen nur benennen, Opt-out anbieten. Gut nach der Mittagspause oder hitzigen Diskussionen; als allererste Übung in skeptischen Gruppen lieber mit Dehnen oder Atmung starten.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["selbstzugang"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":3,"dauer_max":7,"gruppe_min":1,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Body Scan Meditation – Greater Good in Action (UC Berkeley)","url":"https://ggia.berkeley.edu/practice/body_scan_meditation"}],"wann_passt":["Nach der Mittagspause oder nach einem langen Denk-Block: die Aufmerksamkeit wird aus dem ‚Post-Lunch-Dip' geholt, ohne zu aktivieren.","Als Übergang zwischen zwei inhaltlich unterschiedlichen Blöcken: der Bodyscan markiert den Wechsel körperlich und gibt dem Gehirn eine Sortier-Pause.","Wenn die Gruppe nach einer hitzigen Diskussion runterkommen muss, bevor ein neues Thema begonnen wird."],"wann_nicht":["Als allererste Übung in einer Gruppe, die sich noch nicht kennt oder methodenskeptisch ist: Bodyscan wirkt bei unbekannter Gruppe seltsam – besser mit Dehnen oder Atemübung starten.","Wenn die Gruppe stark aktiviert werden muss (nach langer Sitzphase, früher Morgen): dann eher Bewegungsübung.","Online, wenn die Kameraerwartung Teilnehmende hemmt: Kamera-aus-Ansage vorab hilft, aber bei schwierigen Gruppen trotzdem zögerlich einsetzen."],"beispiel":"Anmoderation bei skeptischer Gruppe: ‚Bevor wir in den nächsten Block gehen, machen wir einen 3-Minuten-Konzentrations-Reset – das ist keine Meditation, sondern eine bewusste Aufmerksamkeitslenkung, die aus der Neurowissenschaft kommt. Augen auf oder zu, egal. Ich führe kurz durch.' Dann die Körperstationen benennen: Füße → Sitzfläche → Rücken → Schultern → Gesicht, je 20–30 Sek., ruhige Stimme. Abschluss: ‚Einmal tief ein- und ausatmen, und wir sind zurück.'","mini_form":"Schultern-Gesicht-Reset in 2 Minuten: Nur zwei Stationen – Schultern (‚dürfen die ein Stück sinken?') und Gesicht (‚Kiefer locker, Zunge vom Gaumen lösen'). Reicht als kurze Aufmerksamkeits-Rückkehr.","anlass_typen":["lernformat","teamtag","regeltermin"],"typ":"methode","gruppen_sweetspot":"1–100 Personen; universell","stimmung_geeignet":["muede","angespannt","belastet"]},{"id":"physiological-sigh","name":"Physiological Sigh","feld":"F","kurz":"Zweimal hintereinander durch die Nase einatmen (tief, dann kurz nachatmen), dann lang durch den Mund ausatmen. Schnellste bekannte Einzeltechnik gegen akute Anspannung – wirkt schon nach 1–3 Wiederholungen.","schritte":["Anmoderation: „Kurzer Trick aus der Stanford-Stressforschung – das ist das, was der Körper bei einem Schluchzer automatisch macht, nur bewusst eingesetzt.\"","Vormachen: tief durch die Nase einatmen, oben einen kurzen zweiten Zug nachatmen, dann langsam und vollständig durch den Mund ausatmen.","Gemeinsam 3 Durchgänge, danach kurz nachspüren lassen: „Merkt jemand einen Unterschied in der Schulterpartie?\""],"zweck":"Akute Stressreaktion physiologisch herunterregeln (Herz- und Atemfrequenz) – in unter einer Minute.","hinweise":"Ideal vor schwierigen Gesprächen, nach Konfliktmomenten, vor Präsentationen. Säkulare Rahmung eingebaut: explizit Physiologie, keine Atemtradition – die Stanford-Studie (Balban et al. 2023) überzeugt skeptische Gruppen. Bei Schwindelneigung im Sitzen, weniger tief atmen. Opt-out anbieten.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["selbstzugang"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":5,"gruppe_min":1,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Cyclic sighing can help breathe away anxiety – Stanford Medicine","url":"https://med.stanford.edu/news/insights/2023/02/cyclic-sighing-can-help-breathe-away-anxiety.html"},{"typ":"online","titel":"Balban et al. 2023 – Cell Reports Medicine (Originalstudie)","url":"https://www.cell.com/cell-reports-medicine/fulltext/S2666-3791(22)00474-8"}],"wann_passt":["Direkt vor einer schwierigen Entscheidung oder einem Konfliktgespräch: die akute Stressreaktion wird in unter einer Minute physiologisch heruntergeregelt.","Nach einem Konfliktmoment oder einer emotionalen Eskalation: als Sofort-Reset, bevor das Gespräch weitergeht.","In sehr skeptischen Gruppen (Militär, Feuerwehr, Verwaltung), die keine Entspannungsübungen machen wollen: die Stanford-Studie und die Navy-SEAL-Verortung öffnen die Tür."],"wann_nicht":["Als einzige Atemtechnik im Repertoire: der Physiological Sigh beruhigt akut, ist aber nicht für Fokusarbeit oder Ausdauer geeignet – dann Box Breathing.","Bei Personen mit Angst- oder Panikerfahrung ohne vorherige Opt-out-Ansage: das kurze Nachziehen kann unangenehm sein.","Als längere Übung (über 5 Runden): wenige Wiederholungen reichen – mehr erzeugt Schwindel."],"beispiel":"Anmoderation bei skeptischer Gruppe: ‚Kurzer Trick aus der Stanford-Stressforschung – das macht der Körper bei einem Schluchzer automatisch, nur bewusst eingesetzt. Zwei Sekunden.' Vormachen: tief durch die Nase einatmen, kurz nachziehen, dann langsam durch den Mund ausatmen. Gemeinsam 3 Durchgänge. Danach: ‚Merkt jemand einen Unterschied in der Schulterpartie?' – die Frage macht die Wirkung bewusst und legitimiert das Format rückwirkend.","mini_form":"Ein einzelner Physiological Sigh als Sofort-Reset: In einem Moment von Anspannung (eigene oder Gruppe) einen einzigen Durchgang machen – einatmen, nachziehen, ausatmen. Wirkt bereits nach einer Wiederholung.","anlass_typen":["konfliktklaerung","schwieriges_gespraech","entscheidungstreffen","krisensitzung"],"typ":"methode","gruppen_sweetspot":"1–200 Personen; universell","stimmung_geeignet":["angespannt","belastet"]},{"id":"box-breathing","name":"Box Breathing (4-4-4-4)","feld":"F","kurz":"Atmen im Quadrat: 4 Sekunden einatmen, 4 halten, 4 ausatmen, 4 halten. Bekannt als Trainingsmethode der Navy SEALs – das macht sie für methodenskeptische Berufsgruppen sofort anschlussfähig.","schritte":["Anmoderation: „Eine Minute Fokus-Technik – die nutzen Einsatzkräfte und Chirurg:innen, um vor schwierigen Situationen ruhig zu bleiben.\"","Rhythmus ansagen oder mit der Hand ein Quadrat in die Luft zeichnen: einatmen (4) – halten (4) – ausatmen (4) – halten (4).","4–6 Runden gemeinsam, dann normal weiteratmen lassen."],"zweck":"Nervensystem beruhigen und gleichzeitig Konzentration schärfen – Fokus statt Entspannung als Frame.","hinweise":"Gut vor Entscheidungs- und Verhandlungssituationen und als ruhiger Einstieg. Säkulare Rahmung über die Herkunft (Tactical Breathing) – wirkt bei „Eso-Allergie\" entwaffnend. Atemanhalten kann bei Angst-/Panikerfahrung unangenehm sein: Alternative ohne Halten anbieten – das ist das Opt-out.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["selbstzugang"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":4,"gruppe_min":1,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["koerperlich"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"How Box Breathing Can Help You Destress – Cleveland Clinic","url":"https://health.clevelandclinic.org/box-breathing-benefits"}],"wann_passt":["Vor einer Entscheidungs- oder Verhandlungssituation: Box Breathing schärft Fokus und reguliert das Nervensystem gleichzeitig – der Frame ist Leistung, nicht Entspannung.","Als ruhiger Einstieg am Morgen eines Intensivtages (Klausur, Kick-off): setzt den Ton für konzentriertes Arbeiten.","Bei methodenskeptischen, leistungsorientierten Gruppen: die Herkunft (Navy SEALs, Chirurgie) macht das Format anschlussfähig."],"wann_nicht":["Bei Personen mit Angst- oder Panikerfahrung ohne Opt-out: das Atemanhalten kann unangenehm sein – Alternative ohne Halten anbieten.","Wenn die Gruppe akut beruhigt werden muss (nach Konflikt, Eskalation): dann 4-6-Atmung oder Physiological Sigh – Box Breathing fokussiert, beruhigt weniger stark.","Mehr als 6–8 Runden ohne Pause: Hyperventilationsgefahr, besonders bei Anfänger:innen."],"beispiel":"Anmoderation bei leistungsorientierten Gruppen: ‚Eine Minute Fokus-Technik – die nutzen Einsatzkräfte und Chirurg:innen, um vor schwierigen Situationen ruhig und konzentriert zu bleiben. Vier Sekunden einatmen, vier halten, vier ausatmen, vier halten. Ich zeichne das Quadrat mit, ihr folgt mit dem Atem.' Mit der Hand ein Quadrat in die Luft zeichnen, Rhythmus ansagen. 4–6 Runden, dann: ‚Normal weiteratmen.' Kein Kommentar danach nötig – direkt in den nächsten Block.","mini_form":"Zwei-Runden-Fokus-Reset: Nur 2 vollständige Boxen (2 × 16 Sekunden) als individuelle Kurzpause – für Einzelpersonen vor schwierigen Gesprächen, ohne Gruppe. Wirkt auch solo.","anlass_typen":["entscheidungstreffen","konfliktklaerung","kickoff"],"typ":"methode","gruppen_sweetspot":"1–200 Personen; universell","stimmung_geeignet":["angespannt","frisch","muede"]},{"id":"vier-sechs-atmung","name":"4-6-Atmung (verlängerte Ausatmung)","feld":"F","kurz":"4 Sekunden einatmen, 6 Sekunden ausatmen – die verlängerte Ausatmung aktiviert den Parasympathikus. Einfachste Atemtechnik überhaupt: ohne Anhalten, ohne Zähl-Akrobatik.","schritte":["Anmoderation: „Das Prinzip ist simpel: Ausatmen beruhigt. Wenn die Ausatmung länger ist als die Einatmung, schaltet der Körper messbar einen Gang runter.\"","Gemeinsam 5–8 Atemzüge: einatmen auf 4, ausatmen auf 6 (laut mitzählen oder still).","Optional steigern auf 4–8. Abschluss: normal weiteratmen, kurz nachspüren."],"zweck":"Erregungsniveau der Gruppe senken – nach Konflikten, vor heiklen Tagesordnungspunkten, am Tagesende.","hinweise":"Die niedrigschwelligste Atemübung, funktioniert auch beiläufig. Säkulare Rahmung über Physiologie. Die Stanford-Vergleichsstudie fand ausatmungsbetonte Atmung wirksamer als Meditation – gutes Argument für Skeptiker:innen. Opt-out anbieten; keine Kontraindikationen bei moderatem Tempo.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["selbstzugang"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":5,"gruppe_min":1,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Cyclic sighing tops other breathing methods for calming down – Stanford Medicine Magazine","url":"https://stanmed.stanford.edu/cyclic-sighing-stress-relief/"}],"wann_passt":["Am Tagesende nach intensiver Arbeit oder als Übergang aus einem emotionalen Block: die verlängerte Ausatmung aktiviert zuverlässig den Parasympathikus.","Nach einem Konfliktmoment, wenn die Gruppe runterkommen muss, bevor ein neues Thema beginnt – niedrigschwelliger als andere Atemtechniken.","Als allererste Atemübung in einer Gruppe, die noch keine Erfahrung mit Körperpraktiken hat: keine Anhalte-Phase, keine Zählakrobatik, kein esoterisches Flair."],"wann_nicht":["Wenn Aktivierung gebraucht wird: die verlängerte Ausatmung beruhigt, nicht fokussiert – dann Physiological Sigh oder Box Breathing.","Wenn die Gruppe im Tiefpunkt der Energie ist und wieder aktiv werden soll – dann Bewegungsübung zuerst.","Als Fokus-Vorbereitung vor einer anspruchsvollen Aufgabe: dafür ist Box Breathing besser geeignet."],"beispiel":"Anmoderation bei Skeptiker:innen: ‚Das Prinzip ist simpel: Ausatmen beruhigt. Wenn die Ausatmung länger ist als die Einatmung, schaltet der Körper messbar einen Gang runter – das zeigen auch die Stanford-Daten. Wir machen 5 Atemzüge: einatmen auf 4, ausatmen auf 6. Ich zähle laut.' Laut mitzählen oder Finger auf dem Tisch klopfen. Abschluss: ‚Normal weiteratmen, kurz nachspüren.' Kein Aufhebens – direkt weiter.","mini_form":"Drei-Atemzüge-Reset: Nur 3 verlängerte Ausatmungen (4 ein, 6 aus) – als stille Einzelpause zwischen zwei belastenden Situationen. Reicht physiologisch als Sofort-Regulierung.","anlass_typen":["konfliktklaerung","schwieriges_gespraech","teamtag"],"typ":"methode","gruppen_sweetspot":"1–200 Personen; universell","stimmung_geeignet":["angespannt","belastet","muede"]},{"id":"schulter-nacken-reset","name":"Schulter-Nacken-Reset am Schreibtisch","feld":"F","kurz":"Drei kurze Lockerungen für Schultern, Nacken und Handgelenke – im Sitzen, ohne aufzustehen. Das Format für Online-Meetings und sitzlastige Arbeitstreffen.","schritte":["Anmoderation: „90 Minuten Bildschirm – der Nacken hat eine Pause verdient. Macht mit, so weit es für euch angenehm ist.\"","Sequenz ansagen und mitmachen: Schultern hochziehen, 3 Sek. halten, fallen lassen (3×) – Kopf je Seite 10 Sek. neigen – Schultern rückwärts kreisen (5×) – Hände ausschütteln.","Abschluss: einmal tief durchatmen, weiter im Programm."],"zweck":"Verspannung aus langen Sitzphasen lösen und Aufmerksamkeit auffrischen, ohne den Arbeitsmodus zu verlassen.","hinweise":"Universell einsetzbar, auch in den konservativsten Kontexten – das ist Ergonomie, keine Methode. Online besonders wertvoll (Kamera darf dafür aus). Ansagen: nur so weit dehnen, wie es angenehm ist; bei Nackenproblemen kleine Bewegungen.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["energie"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":4,"gruppe_min":1,"gruppe_max":500,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Desk stretches: Video collection – Mayo Clinic","url":"https://www.mayoclinic.org/healthy-lifestyle/adult-health/in-depth/office-stretches/art-20046041"}],"wann_passt":["Nach 90+ Minuten Bildschirmarbeit oder Sitzen im Meeting: Verspannungsabbau als kurzes Ritual, ohne den Arbeitsmodus zu verlassen.","In Online-Meetings, in denen die Gruppe seit Stunden sitzt – besonders wertvoll, weil Bewegung am Bildschirm schwerer ist als im Raum.","In der konservativsten Gruppe und im formellsten Kontext: das ist Ergonomie, keine Methode – keine Vorerklärung nötig."],"wann_nicht":["Wenn Nackenbeschwerden in der Gruppe bekannt sind: dann explizit ‚nur so weit, wie es angenehm ist' ansagen und kleine Bewegungen empfehlen.","Als Aktivierungsformat: der Reset beruhigt und löst Verspannungen, belebt aber nicht – bei Energietiefs eher Aufstehen & Strecken.","Wenn es als Pause missbraucht wird, um inhaltliche Arbeit hinauszuzögern – dann lieber direkten Blockwechsel ohne Körpereinheit."],"beispiel":"Anmoderation universell: ‚90 Minuten Bildschirm – der Nacken hat eine Pause verdient. Macht mit, so weit es für euch angenehm ist.' Dann ansagen und mitmachen: Schultern hochziehen → halten → fallen lassen (3×) → Kopf zur Seite neigen (links/rechts, 10 Sek.) → Schultern rückwärts kreisen (5×) → Hände ausschütteln. Abschluss: ‚Einmal tief durchatmen.' Kein Kommentar – direkt weiter im Programm.","mini_form":"Schultern-Reset in 60 Sekunden: Nur Schultern hochziehen-halten-fallen (3×) und Schulterkreisen (5×) rückwärts. Unsichtbar auch im Meeting möglich – als stille Einzelpause.","anlass_typen":["regeltermin","lernformat","teamtag"],"typ":"methode","gruppen_sweetspot":"1–500 Personen; universell","stimmung_geeignet":["muede","angespannt","frisch"]},{"id":"aufstehen-und-strecken","name":"Aufstehen & Strecken zwischen Blöcken","feld":"F","kurz":"Alle stehen auf, strecken sich nach oben, zur Seite, lassen die Arme fallen – 2 Minuten Standdehnung als fester Blockwechsel-Marker.","schritte":["Anmoderation: „Blockwechsel – alle einmal aufstehen, das Gehirn dankt es uns.\"","Ansagen und vormachen: Arme über den Kopf strecken (gähnen erlaubt) – Seitneigung links/rechts je 10 Sek. – Schultern kreisen – vornüber hängen lassen, langsam aufrollen.","Optional: am Platz 10× auf die Zehenspitzen wippen. Dann direkt in den nächsten Block."],"zweck":"Kreislauf aktivieren, Sitzmüdigkeit unterbrechen, Übergänge im Tagesablauf körperlich markieren.","hinweise":"Funktioniert in jeder Gruppe; je selbstverständlicher und kürzer die Ansage, desto höher die Beteiligung. Als wiederkehrendes Ritual ankündigen, dann sinkt die Hemmschwelle ab Runde zwei. Sitzende Variante immer mit anbieten (Opt-out bei eingeschränkter Mobilität). Steigerung: Shake Down.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["energie"],"formate":["meeting","workshop","klausur","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":3,"gruppe_min":2,"gruppe_max":500,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich"],"blocktyp":["energizer"],"quellen":[{"typ":"online","titel":"Desk stretches: Video collection – Mayo Clinic","url":"https://www.mayoclinic.org/healthy-lifestyle/adult-health/in-depth/office-stretches/art-20046041"},{"typ":"online","titel":"Shake Down – SessionLab","url":"https://www.sessionlab.com/methods/shake-down"}],"wann_passt":["Als fester Blockwechsel-Marker nach 60–90 Minuten Sitzen: die Körperbewegung markiert den Übergang und aktiviert den Kreislauf.","In Ganztages-Workshops oder Klausuren, in denen Energie-Management wichtig ist – als wiederkehrendes Ritual ab der zweiten Runde sinkt die Hemmschwelle stark.","Als explizit inklusiver Energizer: Sitzende Variante immer mitanbieten – ‚oder bleibt ihr sitzen und streckt die Arme über den Kopf'."],"wann_nicht":["Als Ersatz für eine echte Pause: wenn die Gruppe physisch und mental erschöpft ist, reichen 2 Minuten Strecken nicht – dann echte Pause einplanen.","In sehr formellen Kontexten (Konferenz mit externen Stakeholdern, Anhörung), wo Aufstehen deplatziert wirkt – dann eher Schulter-Nacken-Reset im Sitzen.","Wenn Barrierefreiheit nicht mitgedacht ist: immer Sitz-Alternative anbieten."],"beispiel":"Anmoderation selbstverständlich halten: ‚Blockwechsel – alle einmal aufstehen, das Gehirn dankt es uns.' Sofort mitmachen: Arme über den Kopf strecken (gähnen erlaubt) → Seitneigung links/rechts (10 Sek.) → Schultern kreisen → vornüber hängen lassen und langsam aufrollen. Optional: 10× auf die Zehenspitzen wippen. Dann direkt in den nächsten Block – keine Weichspülung, keine lange Ansage.","mini_form":"Streck-und-gähn in 60 Sekunden: Arme strecken, gähnen erlaubt, Schultern kreisen – fertig. Als Mini-Ritual nach jedem Block.","anlass_typen":["lernformat","teamtag","regeltermin"],"typ":"methode","gruppen_sweetspot":"2–500 Personen; universell","stimmung_geeignet":["muede","frisch"]},{"id":"walk-and-talk","name":"Walk & Talk (Gehen als Denkpause)","feld":"F","kurz":"Zweiergespräche im Gehen statt am Tisch – 10–15 Minuten draußen oder im Flur, mit klarer Leitfrage. Gehen steigert nachweislich divergentes Denken (ca. 60 % mehr kreative Antworten, Stanford-Studie).","schritte":["Leitfrage sichtbar machen (Flipchart/Chat), z. B. „Was wäre der mutigste nächste Schritt für unser Vorhaben?\"","Anmoderation: „Die nächste Runde denkt ihr im Gehen – zu zweit, 15 Minuten. Die Stanford-Forschung ist eindeutig: Im Gehen fallen uns mehr und originellere Ideen ein.\"","Paare bilden („findet jemanden, mit dem ihr heute noch wenig gesprochen habt\"), Uhrzeit für die Rückkehr nennen.","Zurück im Raum: pro Paar die eine wichtigste Erkenntnis ins Plenum."],"zweck":"Ideenproduktion und informelle Beziehungsbildung gleichzeitig – Bewegung plus Zweiersituation senkt Gesprächshürden.","hinweise":"Geeignet für Ideen-, Strategie- und Reflexionsfragen; ungeeignet, wenn Notizen oder Material gebraucht werden. Wetter und Gehstrecke vorher prüfen; Sitz-Zweiergespräch am Fenster als gleichwertige Option anbieten (Inklusion). Online-Variante: telefonieren und dabei tatsächlich gehen.","phasen":["verstehen","reflektieren"],"ebenen":["person","team"],"modi":["verbindung","energie"],"formate":["workshop","klausur","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung"],"dauer_min":10,"dauer_max":20,"gruppe_min":4,"gruppe_max":60,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["koerperlich","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Stanford study finds walking improves creativity (Oppezzo & Schwartz 2014) – Stanford Report","url":"https://news.stanford.edu/stories/2014/04/walking-vs-sitting-042414"}],"wann_passt":["Wenn zu einer offenen Strategiefrage oder Reflexionsfrage mehr und originellere Ideen gebraucht werden als im Sitzen entstehen – Gehen steigert divergentes Denken nachweislich (Stanford-Studie: ~60 % mehr kreative Antworten).","In Zwischenphasen eines Workshops, wenn informelle Verbindung und Beziehungsaufbau gewünscht sind: Zweier-Gespräche beim Gehen senken Gesprächshürden.","In Fortbildungen oder Klausuren, wenn nach vielen Stunden Sitzen eine echte Bewegungspause gebraucht wird, die aber inhaltlich genutzt werden soll."],"wann_nicht":["Wenn Notizen, Material oder visuelles Arbeiten gebraucht werden – Walk & Talk eignet sich für Fragen, die man im Kopf bearbeiten kann.","Bei schlechtem Wetter ohne gangbare Alternative: Sitz-Variante am Fenster oder im Flur als gleichwertige Option immer anbieten.","Online: nur möglich, wenn die Person tatsächlich geht und telefoniert – als explizite Ansage möglich, aber nicht als Gruppen-Synchron-Format."],"fokusfragen":["„Was wäre der mutigste nächste Schritt für unser Vorhaben – was traut ihr euch im Gehen zu denken, was ihr sitzend nicht sagen würdet??","„Was bewegt euch an diesem Prozess – was habt ihr bisher nicht ausgesprochen??"],"beispiel":"Leitfrage sichtbar machen (Flipchart/Chat), dann: ‚Die nächste Runde denkt ihr im Gehen – zu zweit, 15 Minuten. Findet jemanden, mit dem ihr heute noch wenig gesprochen habt.' Uhrzeit für die Rückkehr nennen. Zurück: pro Paar eine Erkenntnis ins Plenum (max. 2 Minuten). Danach mit einer skalierenden Frage schließen: ‚Was von dem, was ihr gehört habt, überrascht euch am meisten?'","mini_form":"5-Minuten-Pair-Walk: Eine einzige Frage, 5 Minuten Gehen zu zweit, eine Erkenntnis zurück. Reicht als Denkpause und Beziehungsmoment.","anlass_typen":["strategie","teamtag","lernformat","dialograum"],"typ":"methode","gruppen_sweetspot":"4–60 Personen (Paare oder Dreier); ab 4 Personen sinnvoll","stimmung_geeignet":["muede","neugierig","frisch"]},{"id":"erdung-5-4-3-2-1","name":"Erdungsübung 5-4-3-2-1 (Sinnes-Anker)","feld":"F","kurz":"Nacheinander benennen: 5 Dinge, die ich sehe – 4, die ich spüre – 3, die ich höre – 2, die ich rieche – 1, das ich schmecke. Standardtechnik, um aus Grübeln oder Aufregung ins Hier und Jetzt zu kommen.","schritte":["Anmoderation: „Bevor wir in das schwierige Thema gehen, eine Minute Ankommen über die Sinne – das holt die Aufmerksamkeit zuverlässig in diesen Raum.\"","Still durchgehen lassen, Moderation gibt die Stufen vor: „Findet 5 Dinge, die ihr seht … 4, die ihr am Körper spürt … 3 Geräusche … 2 Gerüche … 1 Geschmack.\"","Kurzer Abschluss: „Einmal durchatmen – wir starten.\" Keine Auswertungsrunde nötig."],"zweck":"Selbstregulation vor belastenden oder konfliktreichen Gesprächssituationen; Aufmerksamkeit von innen (Gedankenkreisen) nach außen (Sinneswahrnehmung) lenken.","hinweise":"Bewährt vor Konfliktklärungen, schwierigen Feedbackrunden, nach aufwühlenden Inhalten. Komplett säkular formulierbar (Aufmerksamkeitslenkung, keine Innenschau). Trauma-sensibel gerade deshalb gut geeignet: führt nach außen statt nach innen. Riechen/Schmecken können entfallen (dann 5-4-3).","phasen":["ankommen","konflikt"],"ebenen":["person","team"],"modi":["selbstzugang"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":2,"dauer_max":4,"gruppe_min":1,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"The 5-4-3-2-1 Grounding Technique for Anxiety – Healthline","url":"https://www.healthline.com/health/anxiety/5-4-3-2-1-grounding-technique-for-anxiety"}],"wann_passt":["Direkt vor einer Konfliktklärung oder einem schwierigen Feedbackgespräch: die Übung holt die Aufmerksamkeit aus dem Gedankenkreisen in die Sinneswahrnehmung des Raumes.","Nach einem aufwühlenden Input oder einer emotionalen Schilderung: als kurzer Anker, bevor das Gespräch fortgesetzt wird.","In Gruppen mit Trauma-Nähe oder Belastungsthemen (Soziale Arbeit, Gesundheitswesen): die Übung führt nach außen statt nach innen – das ist trauma-sensibel und vermeidet Überwältigung."],"wann_nicht":["Als allgemeine Warm-Up-Übung ohne konkreten Anlass: die Übung hat ihre stärkste Wirkung, wenn sie zu einem Moment der Anspannung oder Aufgewühltheit passt.","In sehr kurzen Übergängen unter 2 Minuten: ohne ausreichend Zeit für alle 5 Stufen wirkt es abgehetzt.","Als Ersatz für psychologische Sicherheit: die Übung reguliert, löst aber keine strukturellen Konflikte oder Vertrauensdefizite."],"beispiel":"Anmoderation vor einem Konfliktgespräch: ‚Bevor wir in das schwierige Thema gehen, eine Minute Ankommen über die Sinne – das holt die Aufmerksamkeit zuverlässig in diesen Raum.' Still durchgehen lassen: ‚Findet 5 Dinge, die ihr seht – 4, die ihr am Körper spürt – 3 Geräusche – 2 Gerüche – 1 Geschmack.' Abschluss: ‚Einmal durchatmen – wir starten.' Keine Auswertungsrunde nötig – direkt ins Thema.","mini_form":"5-4-3-Kurzversion in 90 Sekunden: Nur Sehen (5), Spüren (4), Hören (3) – Riechen und Schmecken entfallen. Reicht als Anker.","anlass_typen":["konfliktklaerung","schwieriges_gespraech","coaching"],"typ":"methode","gruppen_sweetspot":"1–100 Personen; universell","stimmung_geeignet":["angespannt","belastet"]},{"id":"stille-mit-atem-anker","name":"Kurze Stille mit Atem-Anker","feld":"F","kurz":"Ein bis drei Minuten gemeinsame Stille; wer mag, nutzt den eigenen Atem als Aufmerksamkeits-Anker. Die minimalistischste aller Praktiken – und oft die wirkungsvollste vor Entscheidungen.","schritte":["Anmoderation: „Bevor wir entscheiden, zwei Minuten Stille – jede:r sortiert für sich. Wenn die Gedanken springen, hilft es, dem eigenen Atem zuzuhören. Ich sage Bescheid, wenn die Zeit um ist.\"","Zeit stoppen, selbst ruhig sitzen – die Moderation hält die Stille, indem sie sie selbst aushält.","Mit ruhiger Stimme beenden: „Danke. Wer möchte anfangen?\""],"zweck":"Tempo herausnehmen, Impulsentscheidungen vorbeugen, leisen Stimmen Vorbereitungszeit geben.","hinweise":"Geeignet vor Entscheidungen, nach emotionalen Beiträgen, als Abschlussmoment. Für ungeübte Gruppen mit 60 Sekunden beginnen und das Ende verlässlich ansagen. Säkulare Rahmung: „Denkpause\" oder „Sortier-Minute\". Trauma-sensibel: Augen offen ist okay; niemand wird aufgerufen.","phasen":["ankommen","entscheiden"],"ebenen":["person","team"],"modi":["selbstzugang"],"formate":["meeting","workshop","klausur","coaching","teamentwicklung","prozessbegleitung","reflexionsrunde","fortbildung","grossgruppe"],"dauer_min":1,"dauer_max":3,"gruppe_min":2,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["uebergang"],"quellen":[{"typ":"online","titel":"Mindful Breathing – Greater Good in Action (UC Berkeley)","url":"https://ggia.berkeley.edu/practice/mindful_breathing"}],"wann_passt":["Vor einer wichtigen Entscheidung: die Stille verhindert Impulsentscheidungen und gibt leisen Stimmen Vorbereitungszeit.","Nach emotionalen Beiträgen oder einer Eskalation: als Verarbeitungsmoment, bevor das Gespräch fortgesetzt wird.","Als Abschlussmoment am Ende eines intensiven Tages oder einer intensiven Session: die Stille rundet ab und ermöglicht inneres Sortieren."],"wann_nicht":["Als erste Übung in einer Gruppe, die noch keine Erfahrung mit Stille hat: 60 Sekunden als Einstieg – verlässliche Zeitansage ist entscheidend, sonst wird die Stille unangenehm.","Wenn akute Handlung gefragt ist (Krisensitzung, Eskalation ohne Pause): dann erst Atemübung, dann Stille.","In sehr großen Gruppen ohne deutliche Moderations-Haltung: die Moderation hält die Stille, indem sie sie selbst aushält – wer nervös wird, stört."],"beispiel":"Anmoderation vor Entscheidung: ‚Bevor wir entscheiden, zwei Minuten Stille – jede:r sortiert für sich. Wenn die Gedanken springen, hilft es, dem eigenen Atem zuzuhören. Ich sage Bescheid, wenn die Zeit um ist.' Zeit stoppen, selbst ruhig sitzen. Beenden: ‚Danke. Wer möchte anfangen?' – keine Auswertungsrunde, direkt in die Entscheidung. Die Stille hat gesprochen.","mini_form":"60-Sekunden-Sortier-Minute: ‚Einen Moment Stille – sortiert euch.' Kein Atemhinweis, keine Erklärung. Als kürzeste Variante der Stille-Praxis.","anlass_typen":["entscheidungstreffen","konfliktklaerung","dialograum"],"typ":"methode","gruppen_sweetspot":"2–200 Personen; universell","stimmung_geeignet":["angespannt","belastet","muede"]},{"id":"paarinterview-mit-vorstellung","name":"Paarinterview mit Vorstellung","feld":"C","kurz":"Zwei Personen interviewen sich gegenseitig (5 Min pro Richtung) und stellen danach die Partner:in im Plenum vor. Klassiker für Kennenlernen mit eingebautem Zuhör-Training.","schritte":["Paare bilden, gezielt mischen: „jemand, den ihr noch nicht kennt\".","Anmoderation: „Ihr habt je 5 Minuten, um euer Gegenüber kennenzulernen – danach stellt ihr einander vor. Drei Leitfragen hängen am Flipchart, ihr dürft frei erweitern.\"","Leitfragen niedrigschwellig wählen (Werdegang, aktuelles Projekt, „worüber kannst du stundenlang reden?\"). Wechsel nach 5 Minuten ansagen.","Plenum: jede Person stellt ihre Partner:in in 1 Minute vor."],"zweck":"Kontakt stiften und alle Stimmen früh in den Raum holen; Vorstellen-durch-andere senkt Selbstdarstellungsdruck und übt Zuhören.","hinweise":"Mindest-Vertrauenslage: keine – funktioniert mit völlig Fremden. Bei großen Gruppen Plenumsvorstellung in Vierergruppen statt im Großkreis (Zeit). Leitfragen steuern die Öffnungstiefe: berufsbezogen = niedrig, biografisch = mittel. Jede Person entscheidet selbst, was vorgestellt wird.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["verbindung","vertrauen"],"formate":["workshop","klausur","teamentwicklung","prozessbegleitung","fortbildung"],"dauer_min":15,"dauer_max":30,"gruppe_min":6,"gruppe_max":40,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["gespraechsnah","strukturiert"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"67 engaging icebreakers (Abschnitt Interview-Icebreaker) – SessionLab","url":"https://www.sessionlab.com/blog/icebreaker-games/"}],"wann_passt":["Klausur oder Workshop, bei dem Menschen aus verschiedenen Kontexten zusammenkommen und sich gegenseitig wirklich kennenlernen sollen – Vorstellung durch die andere Person erzeugt Zuhörqualität, die Selbstvorstellung nicht erreicht.","Fortbildungsstart: Das Format macht sofort klar, dass hier zuhören und aufeinander eingehen erwartet wird.","Netzwerk-Treffen mit Wunsch nach echter Verbindung statt Speed-Networking-Feeling."],"wann_nicht":["Wenn die Gruppe sich schon sehr gut kennt – dann ist die Übung redundant.","Über 40 Personen ohne Anpassung: Plenum-Vorstellungen aller dauern zu lang; dann Vorstellung in Vierergruppen.","Wenn Vorbereitungszeit fehlt oder Inhalte sofort starten müssen."],"fokusfragen":["„Stellt euch drei Leitfragen: Wer bist du, was bewegt dich gerade, und was sieht man dir nicht an?' (Interview-Einladung)","„Was hat euch an eurem Gegenüber am meisten überrascht?' (Plenum-Einstieg)"],"mini_form":"Ein-Frage-Interview (10 Min): Je 3 Min pro Richtung mit einer einzigen Frage ('Was bringt dich wirklich her?'), Vorstellung in einem Satz. Genug für ersten Kontakt.","anlass_typen":["kickoff","netzwerktreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"6–30; über 30 Plenum-Vorstellung in Untergruppen","stimmung_geeignet":["frisch","neugierig","skeptisch"]},{"id":"appreciative-interviews","name":"Appreciative Interviews (Liberating Structures)","feld":"C","kurz":"Paarinterviews zu einer konkreten Erfolgsgeschichte; in Vierergruppen wird die Geschichte der Partner:in nacherzählt und nach Erfolgsbedingungen durchsucht.","schritte":["Anmoderation: „Wir starten beim Gelingen: Erzählt eurem Gegenüber eine konkrete Situation, in der ihr hier etwas erfolgreich hinbekommen habt – und was es möglich gemacht hat.\"","Paare: je 7–10 Min Interview pro Richtung.","Vierergruppen: jede Person erzählt die Geschichte ihrer Partner:in nach; Gruppe notiert wiederkehrende Erfolgsbedingungen.","Plenum: Muster sammeln – „Was taucht in mehreren Geschichten auf?\""],"zweck":"Vertrauen über positive gemeinsame Selbsterzählung aufbauen und dabei nutzbares Wissen über Gelingensbedingungen heben.","hinweise":"Mindest-Vertrauenslage: gering – die Erfolgs-Rahmung schützt, niemand muss Schwäche zeigen. Nacherzählen vorher ankündigen („sagt, wenn etwas im Paar bleiben soll\"). Sehr gut als Auftakt für Strategie- oder Teamprozesse; ungeeignet mitten in akuten Konflikten (wirkt dann beschönigend).","phasen":["ankommen","oeffnen"],"ebenen":["person","team","organisation","netzwerk"],"modi":["vertrauen","verbindung"],"formate":["workshop","klausur","teamentwicklung","prozessbegleitung","fortbildung","grossgruppe"],"dauer_min":40,"dauer_max":60,"gruppe_min":8,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","strukturiert","beteiligend"],"blocktyp":["einstieg","kern"],"quellen":[{"typ":"online","titel":"Appreciative Interviews (AI) – Liberating Structures","url":"https://www.liberatingstructures.com/5-appreciative-interviews-ai/"}],"wann_passt":["Teamtag oder Klausur, bei der die Gruppe Energie und Richtung braucht und kein weiteres Problemlösungs-Meeting will – Appreciative Interviews starten beim Gelingen und bauen Vertrauen über positive gemeinsame Geschichte.","Strategie-Kick-off einer Organisation: Discovery-Schritt aus Appreciative Inquiry als eigenständiger Baustein – holt heraus, was schon funktioniert, bevor Zukünftiges geplant wird.","Netzwerk-Treffen mit Teilnehmenden aus verschiedenen Organisationen, die miteinander produktiv werden sollen – die Nacherzzählung der Geschichte der anderen erzeugt Perspektivwechsel."],"wann_nicht":["Mitten in einem akuten Konflikt – wirkt dann wie Schönreden und verliert Glaubwürdigkeit.","Wenn die Gruppe so belastet ist, dass keine positiven Geschichten da sind oder sie unehrlich wirken – dann ist GFK-Ansatz oder Konfliktklärung zuerst dran.","Als oberflächlicher Energie-Booster ohne echtes Zuhören – wenn die Nacherzähl-Phase fehlt, ist es nur ein nettes Gespräch."],"fokusfragen":["„Erzähl mir von einem Moment, in dem unsere Zusammenarbeit wirklich gut war – was war anders als sonst?' (Interview-Kernfrage)","„Was in dieser Geschichte war die entscheidende Bedingung – was hat es möglich gemacht?' (Erfolgsbedingungen heben)"],"mini_form":"Einzelinterview zu dritt (15 Min): A interviewt B (7 Min), C hört zu und notiert Schlüsselworte. Dann: C erinnert, was C gehört hat. Ohne Nacherzähl-Runde in Vierergruppen, aber Dreier-Dynamik funktioniert gut.","anlass_typen":["kickoff","teamtag","strategie"],"typ":"methode","gruppen_sweetspot":"8–80; skaliert über Kleingruppen","stimmung_geeignet":["muede","belastet","skeptisch"]},{"id":"impromptu-networking","name":"Impromptu Networking (Liberating Structures)","feld":"C","kurz":"Drei schnelle Zweiergespräche à 4–5 Minuten zu einer Doppelfrage, nach jeder Runde Partner:innenwechsel. Alle sprechen in den ersten 15 Minuten mit drei Menschen.","schritte":["Doppelfrage sichtbar machen und auf das Sessionthema zuschneiden, z. B. „Was bringt dich her? Was erhoffst du dir – und was bringst du mit?\"","Anmoderation: „Drei kurze Gespräche, je 4 Minuten zu zweit – beide kommen dran. Wenn der Gong kommt: neue Partner:in.\"","Drei Runden laufen lassen, Zeit straff halten.","Optional kurze Plenum-Ernte: „Was hat euch überrascht?\""],"zweck":"In Minuten ein Beziehungsnetz über die ganze Gruppe legen und die Erwartungen aller hörbar machen – Grundlage für alles Weitere.","hinweise":"Mindest-Vertrauenslage: keine. Funktioniert hierarchie- und persönlichkeitsunabhängig, weil die Struktur alle gleich behandelt. Bei ungerader Personenzahl eine Dreiergruppe zulassen. Online mit zufälligen 2er-Breakouts in drei Runden.","phasen":["ankommen"],"ebenen":["person","team","netzwerk"],"modi":["verbindung"],"formate":["workshop","klausur","teamentwicklung","fortbildung","grossgruppe"],"dauer_min":15,"dauer_max":20,"gruppe_min":8,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["gespraechsnah","strukturiert","beteiligend"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"Impromptu Networking – Liberating Structures","url":"https://www.liberatingstructures.com/impromptu-networking"}],"wann_passt":["Veranstaltungsbeginn mit einer Gruppe, die sich noch nicht kennt – drei schnelle Gespräche mit drei verschiedenen Menschen legen in 15 Minuten ein Beziehungsnetz über die ganze Gruppe.","Wenn die Erwartungen und Mitbringsel aller sichtbar werden sollen, bevor das Programm startet – die Doppelfrage ('Was erhoffst du dir, was bringst du mit?') gibt der Moderation ein reales Bild.","Als schneller Übergang nach einem langen Vortrag oder einer Präsentation, um die Energie wieder aufzuwecken."],"wann_nicht":["Wenn die Gruppe sich schon gut kennt und die Fragen zu bekannt sind – dann stärkere Fragen wählen oder andere Struktur.","Wenn die Frage nicht zur Doppel-Struktur passt – Impromptu Networking lebt von einer guten Einladungsfrage, die sowohl Einbringen als auch Erhoffen anspricht.","In sehr kleinen Gruppen (unter 8): drei Runden mit denselben Menschen werden seltsam."],"fokusfragen":["„Was bringt dich wirklich her – und was erhoffst du dir für dich aus diesem Tag?' (Doppelfrage Einladungsformel)","„Was hat dich in diesen drei Gesprächen überrascht?' (optionale Plenum-Ernte nach drei Runden)"],"mini_form":"Zwei Runden statt drei (10 Min): Reicht für ersten Kontakt, spart 5 Minuten.","anlass_typen":["kickoff","netzwerktreffen","beteiligung"],"typ":"methode","gruppen_sweetspot":"10–200; ab 30 unbedingt mit Gong/Signal für Wechsel","stimmung_geeignet":["frisch","neugierig","skeptisch","muede"]},{"id":"drei-dinge-gemeinsam","name":"Drei Dinge gemeinsam","feld":"C","kurz":"Paare oder Kleingruppen haben 3–5 Minuten, um drei möglichst überraschende Gemeinsamkeiten zu finden – Offensichtliches wie „wir arbeiten beide hier\" zählt nicht.","schritte":["Anmoderation: „Findet zu zweit drei Dinge, die ihr gemeinsam habt – und zwar Dinge, die man euch nicht ansieht. Je überraschender, desto besser.\"","3–5 Minuten suchen lassen.","Plenum oder Nachbargruppe: die überraschendste Gemeinsamkeit teilen.","Optional zweite Runde mit neuen Paaren oder als Vierergruppe („findet eine Gemeinsamkeit aller vier\")."],"zweck":"Ähnlichkeit erzeugt Sympathie und Vertrauen – die Übung produziert systematisch Gemeinsamkeits-Erlebnisse über Abteilungs- und Statusgrenzen hinweg.","hinweise":"Mindest-Vertrauenslage: keine. Die Öffnungstiefe regulieren die Paare selbst (Hobby vs. Biografie). Kompetitive Variante für Energie: „Welches Paar findet in 3 Minuten die meisten Gemeinsamkeiten?\" Gut kombinierbar mit Soziometrie als Anschluss.","phasen":["ankommen"],"ebenen":["person","team"],"modi":["verbindung"],"formate":["meeting","workshop","klausur","teamentwicklung","fortbildung","grossgruppe"],"dauer_min":5,"dauer_max":15,"gruppe_min":4,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["gespraechsnah","spielerisch"],"blocktyp":["einstieg","energizer"],"quellen":[{"typ":"online","titel":"Three Things in Common Game – icebreaker-games.org","url":"https://icebreaker-games.org/three-things-in-common"}],"wann_passt":["Erstes gemeinsames Treffen von Gruppen mit stark unterschiedlichen Hintergründen (Alter, Berufsfeld, Organisation) – die Übung durchbricht Silo-Wahrnehmung zuverlässig.","Knappe Zeit (5–10 Min) für einen Kennenlerneinstieg: Drei Dinge gemeinsam ist das effizienteste Format für minimale Zeit und maximale Verbindungseffekte.","Als Energizer nach einem Stillblock – die aktive Suche und Freude über überraschende Gemeinsamkeiten hebt die Stimmung schnell."],"wann_nicht":["Wenn die Gruppe sich schon sehr gut kennt – die Gemeinsamkeiten sind dann nicht mehr überraschend.","In kulturellen Kontexten, in denen persönliche Offenbarungen (Hobbys, Biografie) nicht üblich oder nicht sicher sind.","Als Ersatz für echtes Kennenlernen bei sensiblen Themen – die Methode öffnet oberflächlich, nicht tief."],"fokusfragen":["„Findet drei Dinge, die ihr gemeinsam habt – aber nichts Offensichtliches. Je überraschender, desto besser.' (Aufgabenstellung)","„Was war die überraschendste Gemeinsamkeit, die ihr gefunden habt?' (Plenum-Abschluss)"],"mini_form":"Ist selbst Minimalformat (5 Min). Noch kürzer: Eine Gemeinsamkeit in 2 Minuten. Gut als 60-Sekunden-Sitzungsöffnung.","anlass_typen":["kickoff","netzwerktreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"4–60; über 60 nur mit zufälligen Paarungen","stimmung_geeignet":["frisch","neugierig","skeptisch","muede"]},{"id":"low-tech-social-network","name":"Low-Tech Social Network","feld":"C","kurz":"Alle malen sich als „Avatar\" auf eine Karte, kleben sie an die Wand und ziehen Verbindungslinien zu Menschen, die sie kennen – eine analoge Netzwerk-Karte der Gruppe entsteht.","schritte":["Material bereitlegen: Moderationskarten, Stifte, Klebeband/Pinnwand.","Anmoderation: „Wir bauen unser eigenes soziales Netzwerk – ohne Server. Malt euch selbst als einfaches Porträt, Name dazu, und 'ladet euch hoch': Karte an die Wand.\"","Verbindungen ziehen: Linien zu Personen, die man kennt, mit Beschriftung („Studium\", „Projekt X\").","Gemeinsam betrachten: Wo sind Cluster? Wer verbindet Gruppen? Wo sind wenige Linien – und wen will ich heute kennenlernen?"],"zweck":"Vorhandene Beziehungen sichtbar machen und Lücken im Netz als Einladung markieren – besonders wertvoll bei Netzwerk-Treffen und multidisziplinären Gruppen.","hinweise":"Mindest-Vertrauenslage: keine. Selbstporträt niedrigschwellig halten („Strichmännchen ausdrücklich erwünscht\"). Karte hängen lassen – sie wächst über die Veranstaltung weiter. Online-Ersatz: gemeinsames Whiteboard (Miro/Mural) mit Foto- oder Emoji-Avataren.","phasen":["ankommen"],"ebenen":["person","team","netzwerk"],"modi":["verbindung"],"formate":["workshop","klausur","teamentwicklung","prozessbegleitung","grossgruppe"],"dauer_min":20,"dauer_max":40,"gruppe_min":10,"gruppe_max":100,"online":"eingeschraenkt","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["spielerisch","schriftlich","beteiligend"],"blocktyp":["einstieg"],"quellen":[{"typ":"online","titel":"Low-Tech Social Network – Gamestorming","url":"https://gamestorming.com/low-tech-social-network/"}],"wann_passt":["Netzwerk-Treffen oder Tagung mit Teilnehmenden aus verschiedenen Organisationen, die herausfinden wollen, wer wen kennt und wo Verbindungen fehlen – die analoge Netzwerk-Karte macht das sichtbar, ohne Software.","Workshop-Beginn, bei dem Vernetzung selbst ein Ziel ist (z.B. Community-Building, regionale Netzwerke) – die Karte bleibt hängen und wächst über den Tag.","Wenn das abstrakte 'Wir sind ein Netzwerk' zur sichtbaren Erfahrung werden soll."],"wann_nicht":["Online ohne sehr gutes Whiteboard-Tool – die physische Analogie (Karte anheften, Linie ziehen) verliert digital an Wirkung.","Wenn kein Platz für eine Pinnwand vorhanden ist oder die Karte nicht die ganze Veranstaltung hängen bleiben kann – dann lohnt der Aufwand nicht.","In zeitkritischen Settings ohne 20–30 Minuten."],"fokusfragen":["„Schau auf die Karte: Wen kennst du – und wen möchtest du heute unbedingt kennenlernen?' (Betrachtungs-Einladung)","„Welche Verbindungen siehst du, die noch nicht gezogen sind – und die wichtig wären?' (strategische Netzwerk-Reflexion)"],"mini_form":"Nur Name-Karte hängen ohne Verbindungslinien (5 Min): Alle kleben ihre Karte, sehen: wer ist alles hier. Verbindungslinien können im Laufe des Tages freiwillig ergänzt werden.","anlass_typen":["netzwerktreffen","kickoff","beteiligung"],"typ":"methode","gruppen_sweetspot":"12–60; über 60 wird die Karte unleserlich","stimmung_geeignet":["frisch","neugierig"]},{"id":"blind-fuehren-trust-walk","name":"Blind führen (Trust Walk)","feld":"C","kurz":"Eine Person schließt die Augen, die Partner:in führt sie sicher durch den Raum – erst per Hand, dann nur per Stimme. Vertrauen wird körperlich erfahrbar: Kontrolle abgeben, Verantwortung übernehmen.","schritte":["Anmoderation mit explizitem Opt-out: „Diese Übung verlangt, Kontrolle abzugeben – das ist ihr Kern. Wer das heute nicht möchte, beobachtet und steigt bei der Auswertung ein.\"","Sicherheitsregeln: Führende sind zu 100 % verantwortlich; langsames Tempo; keine Hindernis-Scherze.","Runde 1 (3 Min): Führen mit Handkontakt. Runde 2 (3 Min): nur mit Stimme. Dann Rollenwechsel.","Auswertung in den Paaren, dann Plenum: „Was war leichter – führen oder geführt werden? Was hat Vertrauen erzeugt, was hat es gekostet?\""],"zweck":"Vertrauen und Verantwortung als körperliche Erfahrung statt als Konzept; ergiebige Auswertung zu Führung, Kommunikation, Kontrollabgabe.","hinweise":"Mindest-Vertrauenslage: gewachsen – nie als Eröffnungsübung mit Fremden. Trauma-sensibel: Augen schließen, Berührung, Kontrollverlust – dreifache Zumutung; Opt-out gesichtswahrend, Augenbinde nie verpflichtend, Paare selbst wählen. Ungeeignet bei akutem Konflikt und starker Hierarchie.","phasen":["oeffnen","vertiefen"],"ebenen":["person","team"],"modi":["vertrauen"],"formate":["workshop","klausur","teamentwicklung","fortbildung"],"dauer_min":15,"dauer_max":30,"gruppe_min":4,"gruppe_max":30,"online":"nein","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["koerperlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Facilitation Tools (Trust-Building Games) – Seeds for Change","url":"https://www.seedsforchange.org.uk/tools"},{"typ":"online","titel":"Tools for Meetings and Workshops (PDF) – Seeds for Change","url":"https://www.seedsforchange.org.uk/downloads/tools.pdf"}],"wann_passt":["Teamklausur nach mindestens einem gemeinsamen Tag, in der Vertrauen und Führung als explizite Themen bearbeitet werden – der Trust Walk liefert das gelebte Erlebnis, über das dann konzeptuell gesprochen werden kann.","Fortbildung zu Führung, Kommunikation oder Vertrauen: Die Auswertung ('Was hat Vertrauen erzeugt, was hat es gekostet?') ist direkt auf Organisationsfragen übertragbar.","Wenn eine Gruppe über Kontrollabgabe und Verantwortungsübernahme sprechen will und abstrakte Diskussionen nichts mehr bringen."],"wann_nicht":["Früh in einem Prozess oder bei unbekannten Gruppen – Augen schließen + Körperkontakt + Kontrollverlust ist dreifache Zumutung; misslungene Übung schädigt nachhaltig.","Bei starkem Hierarchiegefälle: Chef:in und Mitarbeitende führen sich blind – erzeugt keine symmetrische Vertrauenserfahrung.","Traumasensibel ohne explizite Clearing-Phase: Kontrollverlust und Körperkontakt können triggern.","Online – nicht durchführbar."],"fokusfragen":["„Was war leichter – führen oder geführt werden – und was sagt dir das über dich?' (Auswertung nach Rollenwechsel)","„Was hat Vertrauen in dieser Übung erzeugt – und was davon könnt ihr in eure Zusammenarbeit übertragen?'"],"mini_form":"Rücken-an-Rücken statt Blindführen (5 Min): Paare setzen sich Rücken an Rücken, spüren die Verbindung, atmen synchron. Kein Augen schließen nötig, kein Bewegungsraum. Sanfteste Form körperlicher Verbundenheit.","anlass_typen":["teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"6–24; immer in Paaren","stimmung_geeignet":["frisch","neugierig"]},{"id":"human-knot","name":"Human Knot (Gordischer Knoten)","feld":"C","kurz":"Die Gruppe steht im Kreis, alle greifen kreuz und quer zwei fremde Hände – dann entwirrt sich die Gruppe ohne loszulassen zurück zum Kreis. Kooperationsaufgabe ohne jedes Material.","schritte":["Gruppen à 7–10 Personen bilden.","Anmoderation: „Streckt beide Hände in die Mitte und greift zwei verschiedene Hände – nicht die der Nachbar:innen. Aufgabe: Entknotet euch zu einem Kreis, ohne loszulassen. Umgreifen erlaubt.\"","5–10 Minuten Zeit; bei Stillstand Tipp geben („übersteigen und drunter durchtauchen ist erlaubt\").","Kurze Auswertung: „Wer hat koordiniert? Was hat geholfen – Reden, Ausprobieren, Zuhören?\" Variante: zweite Runde stumm oder mit „Manager:in\" außen."],"zweck":"Kooperation, Kommunikation und Selbstorganisation körperlich erlebbar machen – das Erfolgserlebnis schweißt zusammen.","hinweise":"Mindest-Vertrauenslage: erste gemeinsame Stunden – wegen Körperkontakt nichts für die allererste Minute mit Fremden. Körperkontakt ankündigen, Opt-out anbieten (Beobachter:innen-Rolle). Kulturelle Normen zu Berührung beachten. Ab 12 Personen pro Kreis oft unlösbar – lieber zwei Kreise.","phasen":["ankommen","oeffnen"],"ebenen":["person","team"],"modi":["vertrauen","energie"],"formate":["workshop","klausur","teamentwicklung","fortbildung"],"dauer_min":10,"dauer_max":20,"gruppe_min":7,"gruppe_max":30,"online":"nein","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["koerperlich","spielerisch"],"blocktyp":["energizer","kern"],"quellen":[{"typ":"online","titel":"Human Knot – SessionLab","url":"https://www.sessionlab.com/methods/human-knot-zmabvk"}],"wann_passt":["Erste oder zweite gemeinsame Stunde einer neuen Gruppe, nachdem bereits ein einfaches Kennenlernen stattgefunden hat – der Knoten erzeugt schnell Kooperations-Erlebnis und Lachen ohne Inhaltsbezug.","Energizer nach längerem Sitzen, wenn die Gruppe körperlich aktiviert werden muss – Human Knot ist besser als Warp Speed, wenn Körperkontakt in der Gruppe vertraut ist.","Teambuilding-Tag als niedrigschwelliger Kooperations-Starter, bevor anspruchsvollere Aufgaben kommen."],"wann_nicht":["Bei der allerersten Begegnung mit völlig Fremden – Körperkontakt (Hände halten über Kreuz) braucht ein Minimum an Voranwärmen.","Über 12 Personen pro Kreis: die Aufgabe wird geometrisch unlösbar; lieber zwei Kreise bilden.","Wenn kulturelle Normen Körperkontakt unter Fremden verbieten oder einschränken.","Online – nicht möglich."],"fokusfragen":["„Wer hat koordiniert – explizit oder implizit? Wer hat gehört, wer wurde überhört?' (Debriefing-Kern)","„Was habt ihr ausprobiert, was nicht funktioniert hat – und was hat euch bewogen, die Strategie zu wechseln?'"],"mini_form":"Stumme Runde (10 Min): Human Knot ohne Sprechen. Erzeugt intensiveres Kooperations-Erleben und stärkere Auswertung: 'Wie habt ihr euch ohne Worte verständigt?'","anlass_typen":["kickoff","teamtag"],"typ":"methode","gruppen_sweetspot":"7–12 pro Kreis ideal; über 12 in Untergruppen","stimmung_geeignet":["frisch","neugierig","muede"]},{"id":"marshmallow-challenge","name":"Marshmallow Challenge (Turmbau-Kurzvariante)","feld":"C","kurz":"Teams à 4 bauen in 18 Minuten den höchsten freistehenden Turm aus 20 Spaghetti, 1 m Klebeband, 1 m Schnur – der Marshmallow muss obendrauf. Kooperations- und Prototyping-Klassiker (Skillman/Wujec).","schritte":["Material pro Team bereitlegen. Alltagsvariante ohne Einkauf: 20 Blatt Papier + 1 m Klebeband, Ziel höchster freistehender Papierturm in 10 Min.","Anmoderation: „18 Minuten, höchster freistehender Turm, Marshmallow ganz oben – er ist schwerer, als er aussieht. Los.\"","Zeit laut runterzählen (12 – 9 – 5 – 2 – 1 Min). Messen, Applaus.","Auswertung: „Wer hat früh getestet, wer hat bis Minute 17 geplant?\" – Pointe: Kindergartenkinder schlagen MBA-Teams, weil sie iterativ prototypen statt lange zu planen."],"zweck":"Zusammenarbeit unter Zeitdruck erlebbar machen; Iteration vor Perfektionsplanung als gemeinsame Lernpointe.","hinweise":"Mindest-Vertrauenslage: keine – Wettbewerb plus Aufgabe schützt vor Persönlichem, deshalb ideal für skeptische, aufgabenorientierte Gruppen. Teams quer zu Hierarchien mischen. Die Auswertung trägt die eigentliche Wirkung – 10 Min einplanen. Online nur als Einzel- oder Haushaltsvariante.","phasen":["ankommen","oeffnen"],"ebenen":["person","team"],"modi":["verbindung","energie"],"formate":["workshop","klausur","teamentwicklung","fortbildung"],"dauer_min":30,"dauer_max":45,"gruppe_min":8,"gruppe_max":60,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["spielerisch","beteiligend"],"blocktyp":["energizer","kern"],"quellen":[{"typ":"online","titel":"Marshmallow Challenge – Tom Wujec","url":"https://www.tomwujec.com/marshmallow-challenge"},{"typ":"online","titel":"Marshmallow Challenge with Debriefing – SessionLab","url":"https://www.sessionlab.com/methods/marshmallow-challenge-with-debriefing"}],"wann_passt":["Gruppe mit aufgabenorientierter oder skeptischer Haltung gegenüber Teambuilding – die Wettbewerbs-Logik und die klare Aufgabe umgehen die Abwehr und erzeugen echtes Kooperationserleben.","Workshop zu Innovation, Prototyping oder Agilität: Die Auswertungs-Pointe (Kindergartenkinder schlagen MBA-Teams, weil sie iterieren statt planen) ist direkt und einprägsam.","Kickoff eines neuen Projekt-Teams: Die Challenge erzeugt in 30 Minuten mehr über Teamdynamik als ein halber Tag Assessment."],"wann_nicht":["Online ohne Haushalt-Variante: Die Originalaufgabe braucht physisches Material; digitale Simulationen verlieren den entscheidenden 'Schwere des Marshmallows'-Überraschungseffekt.","In sehr kleinen Gruppen (unter 8): Zu wenige Teams für den Wettbewerbs-Effekt.","Als Abschluss-Energizer ohne Auswertung – ohne Debriefing ist es nur Spaß."],"fokusfragen":["„Wann habt ihr das erste Mal getestet – am Anfang, in der Mitte oder am Ende? Was hat das über eure Herangehensweise verraten?' (Debriefing-Kern)","„Was übertragt ihr aus dieser Erfahrung in euer aktuelles Projekt – wo baut ihr zu lange, bevor ihr testet?'"],"mini_form":"Papiertürme in 10 Minuten (je 3 Personen, 10 Blatt Papier): Keine Spaghetti, kein Einkauf. Gleiche Dynamik, sofort durchführbar in jedem Büro.","anlass_typen":["kickoff","teamtag","lernformat"],"typ":"methode","gruppen_sweetspot":"8–40 ideal; Teams à 4–5 Personen","stimmung_geeignet":["skeptisch","frisch","neugierig"]},{"id":"lebenslinien-sharing-triaden","name":"Lebenslinien-Sharing in Triaden (Life Map)","feld":"C","kurz":"Jede Person zeichnet ihren Lebens- oder Berufsweg als Linie mit Hoch- und Tiefpunkten und teilt ihn in einer Dreiergruppe; die anderen hören zu, ohne zu kommentieren oder zu beraten.","schritte":["Einzelarbeit (10 Min): „Zeichnet eure Linie – Stationen, Wendepunkte, Höhen und Tiefen. Ihr entscheidet selbst, was draufkommt; eine reine Berufslinie ist genauso richtig wie eine Lebenslinie.\"","Triaden: je 7–10 Min erzählen; Zuhörende fragen höchstens nach („Verständnisfragen ja, Ratschläge nein\").","Kurzer Abschluss in der Triade: „Was hat mich am meisten berührt oder überrascht?\"","Plenum nur auf Meta-Ebene („Wie war das Format?\"), Inhalte bleiben in der Triade."],"zweck":"Tiefes gegenseitiges Verstehen und belastbares Vertrauen aufbauen – Menschen hinter den Rollen sichtbar machen.","hinweise":"Mindest-Vertrauenslage: gewachsen – mehrtägiges Format oder Teamklausur. Vertraulichkeit explizit vereinbaren. Öffnungstiefe selbstgesteuert anbieten (Berufslinie als gesichtswahrendes Opt-out). Trauma-sensibel: nie zu Tiefpunkten nachbohren; Triaden sich selbst finden lassen.","phasen":["oeffnen","vertiefen"],"ebenen":["person","team"],"modi":["vertrauen","selbstzugang"],"formate":["klausur","teamentwicklung","workshop","fortbildung"],"dauer_min":40,"dauer_max":60,"gruppe_min":3,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"hoch","energie":"beruhigend","stil":["gespraechsnah","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Life map – SessionLab","url":"https://www.sessionlab.com/methods/life-map"},{"typ":"online","titel":"Life maps (Variante) – SessionLab","url":"https://www.sessionlab.com/methods/life-maps"}],"wann_passt":["Mehrtägige Teamklausur oder Fortbildung, in der echte Tiefe und Vertrauen entstehen sollen – Lebenslinien bauen in einer Stunde mehr Verbundenheit auf als viele oberflächliche Kennenlernen.","Gruppe, die schon erste gemeinsame Stunden hatte und bereit ist, hinter die Rolle zu schauen – nicht für völlig Fremde.","Supervisionsgruppe oder Lerngruppe, die eine neue Phase ihrer Zusammenarbeit bewusst gestalten will."],"wann_nicht":["Früh in einem Prozess ohne aufgewärmtes Vertrauen – Lebenslinien brauchen Sicherheit, die sich nicht erzwingen lässt.","Wenn das Format nicht explizit freiwillig ist: Niemand sollte genötigt sein, Biografie zu teilen.","In Gruppen mit akutem Konflikt – das Format öffnet emotional; in aufgeladenen Situationen kann das destabilisieren.","Online ohne separates Breakout und ausreichend Zeit – das Format braucht Ruhe und Vertraulichkeit, die in großen Video-Calls kaum gegeben ist."],"fokusfragen":["„Zeichne deinen Lebens- oder Berufsweg als Linie – Hochs und Tiefs, Wendepunkte. Du entscheidest, was draufkommt.' (Einzelarbeits-Einladung)","„Was hat euch in den Geschichten, die ihr gehört habt, am meisten berührt oder überrascht?' (Abschluss in der Triade)"],"mini_form":"Berufslinien (30 Min): Nur der Berufsweg, keine Lebenslinie – senkt die Öffnungstiefe deutlich. Jede:r erzählt 5 Min, andere hören nur zu. Kein Plenum. Gut als Einstieg in längere Prozesse.","anlass_typen":["teamtag","lernformat","dialograum"],"typ":"methode","gruppen_sweetspot":"6–24; immer in Triaden","stimmung_geeignet":["frisch","neugierig","belastet"]},{"id":"pecha-kucha-ueber-mich","name":"Pecha Kucha über mich","feld":"C","kurz":"Kurzpräsentation im PechaKucha-Stil über die eigene Person: Bilder laufen automatisch weiter, die Person erzählt dazu. Kompaktformat: 10 Bilder × 20 Sekunden statt der klassischen 20×20.","schritte":["Vorab-Aufgabe (oder 20 Min Vorbereitung): „Wählt 10 Bilder, die etwas über euch erzählen – Orte, Projekte, Menschen, Gegenstände. Pro Bild 20 Sekunden, die Folien laufen automatisch weiter.\"","Reihenfolge losen, pro Person 3:20 Min plus kurzer Applaus.","Nach jeweils 3–4 Präsentationen kurze Murmelrunde: „Was nehme ich über diese Kolleg:innen neu mit?\""],"zweck":"Persönliches Kennenlernen mit klarer Form – der starre Takt schützt vor Selbstdarstellungs-Marathon und macht Zuhören leicht.","hinweise":"Mindest-Vertrauenslage: erste gemeinsame Stunden; die Bildauswahl steuert die Öffnungstiefe. Gut für neue Teams, Onboarding, Netzwerk-Retreats; braucht Technik (Beamer/Screenshare) und Vorbereitungszeit – vorab ankündigen. Variante für skeptische Gruppen: „Mein Arbeitsjahr in 10 Bildern\".","phasen":["ankommen","oeffnen"],"ebenen":["person","team"],"modi":["verbindung","vertrauen"],"formate":["klausur","teamentwicklung","workshop","fortbildung"],"dauer_min":25,"dauer_max":80,"gruppe_min":4,"gruppe_max":16,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["einstieg","kern"],"quellen":[{"typ":"online","titel":"Our 20x20 Format – PechaKucha","url":"https://pechakucha.zendesk.com/hc/en-us/articles/4408778681485-Our-20x20-Format"}],"wann_passt":["Neues Team in Onboarding oder nach Reorganisation, das sich wirklich kennenlernen will – Pecha Kucha über mich gibt Persönlichkeit einen Auftritt, den verbale Vorstellungsrunden nicht haben.","Fortbildung oder Klausur mit vorab bekannter Gruppe: Als Einstieg, der durch die Bildauswahl automatisch persönliche Tiefe erzeugt.","Netzwerk-Retreats mit Menschen, die sich nur beruflich kennen und mehr voneinander sehen wollen."],"wann_nicht":["Ohne vorab kommunizierte Vorbereitung – 10 Bilder sammeln und zusammenstellen braucht Zeit, die im Meeting nicht da ist.","Für sehr große Gruppen (>16) ohne Anpassung: Alle Präsentationen hintereinander dauern zu lang.","Wenn Technik (Beamer, Screenshare, automatisch laufende Folien) nicht zuverlässig ist – das Format bricht zusammen, wenn die Folien nicht automatisch wechseln."],"fokusfragen":["„Wählt 10 Bilder, die etwas über euch erzählen – Orte, Menschen, Gegenstände, Momente. Was man euch nicht ansieht.' (Vorab-Aufgabe)","„Was habt ihr über diese Person durch die Bilder erfahren, das ihr durch Gespräch nicht erfahren hättet?' (Murmelrunde nach je 3–4 Präsentationen)"],"mini_form":"Drei-Bilder-Vorstellung (5 Min pro Person): Statt 10 Folien nur 3 Bilder, je 1 Min, kein automatischer Wechsel nötig. Smartphone reicht. Gut als unvorbereitete Variante ('zeigt drei Bilder aus eurem Handy').","anlass_typen":["kickoff","teamtag","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"4–16; über 16 in Untergruppen","stimmung_geeignet":["frisch","neugierig"]},{"id":"appreciation-runde","name":"Appreciation-Runde (Wertschätzungs-Abschluss)","feld":"C","kurz":"Strukturierte Abschlussrunde, in der Teilnehmende einander konkrete Wertschätzung aussprechen – z. B. als Satzanfang „Was ich an deiner Mitarbeit heute geschätzt habe …\".","schritte":["Anmoderation: „Zum Abschluss eine Runde Wertschätzung – konkret und auf heute bezogen, keine Allgemeinplätze. Format: 'Was ich heute an dir geschätzt habe, ist …'\"","Formvariante wählen: a) Kreis – jede Person würdigt die Person links von sich; b) Popcorn – wer mag, spricht, bis alle genannt wurden; c) schriftlich – jede:r schreibt allen.","Empfangende antworten nur mit „Danke\" – kein Abwiegeln."],"zweck":"Positives Beziehungssignal zum Abschluss; gesehen werden für konkretes Verhalten stärkt psychologische Sicherheit nachhaltiger als allgemeines Lob.","hinweise":"Mindest-Vertrauenslage: ein gemeinsamer Arbeitstag reicht. Bei Popcorn darauf achten, dass niemand leer ausgeht – für unsichere Gruppen Kreis- oder Schriftvariante. „Nur Danke sagen\" nimmt die Verlegenheit. Nüchterne Rahmung: „Feedback: Was hat funktioniert – personenbezogen\".","phasen":["reflektieren"],"ebenen":["person","team"],"modi":["vertrauen","verbindung"],"formate":["meeting","workshop","klausur","teamentwicklung","reflexionsrunde","fortbildung"],"dauer_min":10,"dauer_max":25,"gruppe_min":4,"gruppe_max":25,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah","strukturiert"],"blocktyp":["abschluss"],"quellen":[{"typ":"online","titel":"Appreciation Workshop Activities (Sammlung) – SessionLab","url":"https://www.sessionlab.com/library/appreciation"}],"wann_passt":["Abschluss eines gemeinsamen Arbeitstages oder Projekts: Wertschätzung für konkretes Verhalten ('was du heute getan hast') ist das wirksamste Signal für psychologische Sicherheit.","Team, das chronisch im Problemlösen steckt und den Blick auf das Gelingende verloren hat – die Runde reorientiert ohne Diskussion.","Mehrtägige Fortbildung am letzten Abend: Als Abschlussritual, das die gemeinsame Geschichte würdigt."],"wann_nicht":["Wenn die Beziehungen so belastet sind, dass Wertschätzung unecht wirkt oder zynisch aufgenommen wird – dann zuerst Klärung.","In sehr großen Gruppen ohne Strukturierung: Popcorn-Variante führt leicht dazu, dass einige nie genannt werden.","Wenn Lob zur Leistungssteuerung eingesetzt wird – Appreciation-Runde verliert ihre Kraft, wenn sie als Motivationsinstrument von Führung inszeniert wird."],"fokusfragen":["„Was habe ich heute an dir geschätzt – konkret und auf heute bezogen.' (Satzanfang für alle)","„Was hat mich an der Arbeit dieser Gruppe besonders beeindruckt – ein Moment, ein Verhalten.' (Gruppen-Variante)"],"mini_form":"Schriftliche Variante (10 Min): Alle schreiben allen anderen einen Satz auf eine Karte – dann werden die Karten ausgeteilt. Jede:r liest schweigend. Kein Vortragen, keine Peinlichkeit. Besonders wirksam in Gruppen, die mündliche Wertschätzung schwierig finden.","anlass_typen":["teamtag","retro","lernformat"],"typ":"methode","gruppen_sweetspot":"4–20 ideal; über 25 schriftliche Variante","stimmung_geeignet":["muede","belastet","neugierig","frisch"]},{"id":"soziometrische-aufstellung-spectogram","name":"Soziometrische Aufstellung / Spectogram","feld":"C","kurz":"Der Raum wird zur Skala oder Landkarte: Teilnehmende positionieren sich körperlich zu Aussagen (Zustimmung, Herkunftsorte, Jahre im Feld) und kommen über ihre Position ins Gespräch.","schritte":["Achse erklären: „Diese Wand heißt 'stimme voll zu', die gegenüber 'überhaupt nicht'. Ich lese eine Aussage vor – stellt euch dorthin, wo ihr steht. Es gibt kein richtig.\"","Mit harmlosen Fragen aufwärmen (Anreiseweg, Kaffee/Tee), dann thematisch steigern („Ich glaube, unser Netzwerk kennt seine Wirkung\").","Pro Aufstellung 2–3 Stimmen von verschiedenen Positionen interviewen: „Was siehst du von da, wo du stehst?\"","Nachbarschafts-Murmeln: 2 Minuten mit der Person nebenan. Mehrere Runden; Beobachtungen am Ende sammeln."],"zweck":"Unterschiede und Gemeinsamkeiten sichtbar und besprechbar machen, alle in Bewegung und ins Sprechen bringen – Vertrauensbildung durch sichtbares „Ich zeige, wo ich stehe\".","hinweise":"Mindest-Vertrauenslage: keine für Sachfragen, gewachsen für heikle Fragen – die Fragenwahl bestimmt das Risiko. Niemand muss die Position erklären (Opt-out; wer nicht stehen mag, zeigt per Handzeichen oder Karte). Online als Spectogram: Skala im Whiteboard, Stempel oder Zahl 1–10 im Chat.","phasen":["ankommen","verstehen"],"ebenen":["person","team","netzwerk"],"modi":["verbindung","vertrauen"],"formate":["workshop","klausur","teamentwicklung","prozessbegleitung","fortbildung","grossgruppe"],"dauer_min":10,"dauer_max":30,"gruppe_min":8,"gruppe_max":100,"online":"ja","braucht_raum":true,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["koerperlich","beteiligend"],"blocktyp":["einstieg","energizer","kern"],"quellen":[{"typ":"online","titel":"10 Ways to Use A Spectogram Online – Training for Change","url":"https://www.trainingforchange.org/training_tools/spectograms-online/"},{"typ":"online","titel":"Tool-Bibliothek – Training for Change","url":"https://www.trainingforchange.org/tools/"}],"wann_passt":["Zu Beginn eines Workshops oder Netzwerk-Treffens als körperlicher Einstieg: Alle bewegen sich, positionieren sich, kommen ins Gespräch – besser als jeder Icebreaker, der sitzen bleibt.","Wenn Meinungsvielfalt sichtbar werden soll, ohne dass eine Seite dominiert – die Körperposition macht alle Positionen gleichzeitig sichtbar und gibt ruhigen Stimmen Sichtbarkeit.","Diagnose zu Beginn eines Teamentwicklungstages: 'Wie wohl fühlt ihr euch in unserem Team?' auf der Skala zeigt sofort das Bild, ohne lange Diskussion."],"wann_nicht":["Bei heiklen Fragen ohne gewachsenes Vertrauen: 'Vertraue ich meiner Führungskraft?' als erste Frage kann Vertrauen zerstören statt aufbauen.","In engen Räumen ohne Möglichkeit, sich wirklich zu positionieren – die körperliche Dimension ist der Kern.","Wenn Teilnehmende körperliche Einschränkungen haben, ohne Alternativoption (Handzeichen, Karte) angeboten zu haben."],"fokusfragen":["„Diese Wand heißt 'stimme voll zu', die gegenüber 'stimme überhaupt nicht zu'. Stellt euch dorthin, wo ihr steht – es gibt kein richtig.' (Einstiegsformulierung)","„Was siehst du von dort, wo du stehst – was siehst du von dort drüben nicht?' (Positions-Interview, 2–3 Personen aus verschiedenen Positionen)"],"mini_form":"Handzeichen-Spectogram (5 Min): Alle zeigen gleichzeitig 1–5 Finger statt sich zu positionieren. Kein Raum nötig, funktioniert online. Verliert die körperliche Dimension, behält die Meinungs-Sichtbarkeit.","anlass_typen":["kickoff","teamtag","beteiligung","retro"],"typ":"methode","gruppen_sweetspot":"8–60 ideal; über 100 nur für Sachfragen mit einfachen Positionen","stimmung_geeignet":["skeptisch","neugierig","frisch","muede"]},{"id":"troika-consulting","name":"Troika Consulting (Liberating Structures)","feld":"C","kurz":"Drei Personen rotieren als Beratene und Beratende: Eine Person bringt eine echte Frage, dreht sich weg, die anderen zwei beraten laut – dann dreht die Person sich um und hört, was angekommen ist.","schritte":["Dreiergruppen bilden. Person A nennt ihre echte Frage oder Herausforderung (2 Min).","A dreht sich weg oder schließt die Augen – B und C beraten laut, als ob A nicht da wäre (4–5 Min).","A dreht sich um, teilt mit, was sie gehört hat – was neu war, was sie mitnimmt (2 Min).","Rollenwechsel: B bringt ihre Frage, C und A beraten. Dann C."],"zweck":"Kollegiale Beratung zu echten Fragen ohne Rechtfertigungsdruck; das Wegdrehen unterbricht Erklärungs- und Verteidigungsschleifen und erzeugt überraschend präzise Außenperspektiven.","hinweise":"Die echte Frage muss vorher feststehen – Zeit für Formulierung einplanen. Das Wegdrehen ist der Wirkmechanismus, nicht weglassen. Funktioniert online über Mute + abgewandtes Kamerabild oder in Breakouts.","phasen":["vertiefen","reflektieren"],"ebenen":["person","team"],"modi":["klaerung","reflexion"],"formate":["workshop","fortbildung","teamentwicklung","coaching"],"dauer_min":20,"dauer_max":40,"gruppe_min":6,"gruppe_max":60,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Troika Consulting – Liberating Structures","url":"https://www.liberatingstructures.com/8-troika-consulting/"}],"wann_passt":["Führungskräfte- oder OE-Fortbildung, in der alle mit echten Praxisfragen kommen – Troika Consulting gibt in 40 Minuten jedem drei externe Perspektiven auf das, was ihn oder sie wirklich beschäftigt.","Team, das immer wieder über dieselbe Frage kreist, ohne voranzukommen – das Wegdrehen unterbricht Rechtfertigungsschleifen und bringt frische Formulierungen.","Intervisions-Format: Als Standardstruktur für Peer-Beratung besser als freies Gespräch, weil die Rollen klar getrennt sind."],"wann_nicht":["Bei sehr sensiblen oder persönlichen Fragen in Gruppen ohne gewachsenes Vertrauen – die Beratung zu zweit, ohne die Person direkt anzusprechen, kann sich entpersönlichend anfühlen.","Wenn alle dieselbe Frage haben – dann ist Troika Consulting zu aufwändig; 1-2-4-All reicht.","Unter 6 Personen: keine vollständige Rotation möglich."],"fokusfragen":["„Was ist die eine Frage, die dich gerade wirklich beschäftigt – konkret und dein, nicht die Frage deiner Organisation?' (Frageformulierung, Vorbereitung)","„Was hast du gehört, was neu war – und was nimmst du mit?' (Rückkehr-Schritt nach dem Wegdrehen)"],"beispiel":"Person A fragt: 'Wie kann ich mein Team für Veränderungen motivieren, ohne Druck auszuüben?' A dreht sich weg. B zu C: 'Ich frage mich, ob A überhaupt weiß, was das Team wirklich bremst – hat A die Leute direkt gefragt?' C: 'Vielleicht liegt das Problem nicht bei Motivation sondern bei Klarheit über das Ziel.' A dreht sich um: 'Ich habe gehört, ich sollte zuerst fragen statt erklären – und dass das Ziel vielleicht nicht klar genug ist. Das war neu für mich.'","mini_form":"Zwei-Runden-Troika (25 Min): Nur zwei der drei Personen bringen eine Frage. Spart eine Runde, behält die Wirkung.","anlass_typen":["coaching","lernformat","teamtag"],"typ":"methode","gruppen_sweetspot":"9–30 ideal (Dreiergruppen)","stimmung_geeignet":["neugierig","muede","skeptisch"]},{"id":"triz-ls","name":"TRIZ (Liberating Structures)","feld":"C","kurz":"Gruppe fragt zuerst, wie sie das Gegenteil des Gewünschten garantieren könnte – dann kehren sie die Antworten um und finden dadurch blockierte Verbesserungen, die direkte Fragen nicht ergeben hätten.","schritte":["Kontrafaktische Frage stellen: 'Was müssten wir tun, um X mit Sicherheit zu verhindern / das Gegenteil von Y zu garantieren?' (5 Min still notieren)","In Paaren oder Vierergruppen: Ideen sammeln, freimütig und ohne Selbstzensur (5 Min).","Plenum: Alle Ideen sichtbar machen – was tun wir davon bereits, unbewusst oder aus Gewohnheit?","Umkehren: Aus jeder problematischen Praxis das positive Gegenteil ableiten – was wäre stattdessen hilfreich?","Priorisieren: Welche ein oder zwei Inversionen haben das höchste Hebelpotenzial?"],"zweck":"Blockaden und kontraproduktive Gewohnheiten sichtbar machen, indem man sie erst bewusst verstärkt – die Umkehr erzeugt dann ungewöhnlich ehrliche Verbesserungsvorschläge.","hinweise":"Der Witz liegt in der provokanten Eingangsfrage; diese muss mutig formuliert sein ('Wie garantieren wir, dass unsere Strategiesitzung nichts verändert?'). Halb gemeintes TRIZ erzeugt Beliebigkeit.","phasen":["vertiefen","reflektieren","planen"],"ebenen":["team","organisation"],"modi":["reflexion","klaerung"],"formate":["workshop","klausur","teamentwicklung"],"dauer_min":30,"dauer_max":60,"gruppe_min":8,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["strukturiert","spielerisch","beteiligend"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"TRIZ – Liberating Structures","url":"https://www.liberatingstructures.com/6-making-space-with-triz/"}],"wann_passt":["Retro oder Strategietag, bei dem die Gruppe nie wirklich unbequeme Wahrheiten ausspricht – TRIZ macht das durch Humor und Übertreibung sicherer, ohne die Wahrheiten wegzuschönen.","Workshop, in dem die Gruppe weiß, was nicht funktioniert, aber es nicht direkt benennt – TRIZ gibt eine Sprache für die unausgesprochenen Elefanten.","Organisations-Review, bei dem echte Dysfunktionen sichtbar werden sollen: 'Was tun wir, um Kooperation zu verhindern?' erzeugt ehrlichere Antworten als 'Was hindert uns an Kooperation?'"],"wann_nicht":["In Gruppen ohne psychologische Sicherheit: TRIZ braucht die Bereitschaft, eigene Dysfunktionen zu benennen – unter Beobachtung durch Führung kann das riskant sein.","Als Spaßformat ohne echte Konsequenz: Wenn die Inversionen nicht ernst genommen werden, ist TRIZ nur Unterhaltung.","Bei Gruppen, die noch nicht genug gemeinsame Geschichte haben, um kontraproduktive Muster zu kennen."],"fokusfragen":["„Was müssten wir tun, um sicherzustellen, dass sich in unserem Team nichts verändert?' (TRIZ-Eingangsfrage – Beispiel)","„Was davon tun wir bereits – bewusst oder unbewusst?' (der schärfste Schritt in TRIZ)"],"beispiel":"In einem Teamretro: 'Was müssten wir tun, um sicherzustellen, dass unsere Meetings nichts bringen?' Antworten: 'Immer dieselbe Tagesordnung, Entscheidungen nie protokollieren, Führungskraft redet 80 % der Zeit.' Moderator:in: 'Was davon klingt vertraut?' Stille, dann Lachen, dann Gespräch. Inversion: 'Was wäre das Gegenteil von jedem Punkt?' – erzeugt konkreten Maßnahmenkatalog.","mini_form":"Einzel-TRIZ (10 Min): Nur die kontrafaktische Frage und still notieren, dann Sharing zu zweit. Kein Plenum, keine Inversion im Plenum – Impulse mitnehmen und privat invertieren.","anlass_typen":["retro","teamtag","strategie"],"typ":"methode","gruppen_sweetspot":"8–40; über 40 in Kleingruppen mit gemeinsamer Ernte","stimmung_geeignet":["skeptisch","muede","neugierig"]},{"id":"15percent-solutions","name":"15% Solutions (Liberating Structures)","feld":"C","kurz":"Jede:r identifiziert den Handlungsspielraum, den sie oder er jetzt schon hat – ohne Erlaubnis, Budget oder externe Hilfe. 15 % ist der Anteil, den jede:r kontrolliert, auch in eingeschränkten Systemen.","schritte":["Frage stellen: 'Was ist dein 15 % – was kannst du jetzt schon tun, ohne Erlaubnis oder zusätzliche Ressourcen?' (2 Min still notieren)","Paare (7 Min): Antworten teilen, Nachfragen für Konkretisierung: 'Was genau, wann, mit wem?'","Vierergruppen (5 Min): Muster und Überraschungen teilen.","Plenum: Wer möchte, nennt ein konkretes 15-%-Commitment."],"zweck":"Handlungsfähigkeit aktivieren, indem Aufmerksamkeit weg von Hindernissen und hin zu vorhandenem Spielraum gelenkt wird – Gegenmittel gegen kollektive Lähmung und Warten auf Erlaubnis.","hinweise":"Der Witz ist die Bescheidenheit der Frage – 'nicht 100 %, nur 15 %' senkt Aktivierungsschwelle erheblich. Die Konkretisierung im Paargespräch ist entscheidend: vage 15-%-Antworten helfen nicht.","phasen":["planen","entscheiden"],"ebenen":["person","team","organisation"],"modi":["klaerung","energie"],"formate":["meeting","workshop","klausur","fortbildung"],"dauer_min":20,"dauer_max":30,"gruppe_min":4,"gruppe_max":200,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","beteiligend"],"blocktyp":["kern","abschluss"],"quellen":[{"typ":"online","titel":"15% Solutions – Liberating Structures","url":"https://www.liberatingstructures.com/7-15-solutions/"}],"wann_passt":["Nach einem langen Strategie- oder Problem-Analyse-Block, wenn die Gruppe in Lähmung oder Ohnmacht zu kippen droht – 15% Solutions bricht den Bann und erzeugt sofort Handlungsimpulse.","Abschluss eines Workshops, der viel Diagnose und wenig Entscheidung hatte: Was nimmst du konkret mit – und was machst du nächste Woche?","Team mit starker Fixierung auf externe Hindernisse ('wir können nicht, weil...'): Die Frage lenkt Aufmerksamkeit auf das, was tatsächlich möglich ist."],"wann_nicht":["Als Ersatz für echte strukturelle Veränderungen: 15% Solutions macht handlungsfähig, löst aber keine systemischen Probleme – nicht als Trost-Pflaster einsetzen.","Wenn die tatsächlichen Handlungsspielräume sehr klein sind und die Frage zynisch wirkt ('was soll ich denn tun, wenn alles entschieden ist?') – dann zuerst Rahmenbedingungen klären.","Für komplexe Entscheidungen mit vielen Abhängigkeiten – 15% ist für individual-kontrollierbare Handlungen, nicht für kollektive Entscheidungen."],"fokusfragen":["„Was kannst du in deinem eigenen Einflussbereich tun – ohne Erlaubnis, ohne Budget, ohne Hilfe von oben?' (Kernfrage)","„Was würdest du konkret bis wann tun – und mit wem?' (Konkretisierungs-Anschlussfrage im Paar)"],"beispiel":"Nach einem Strategie-Workshop, der viele Erkenntnisse, aber keine Entscheidungen gebracht hat: '2 Minuten still: Was ist dein 15 % – was kannst du in deinem Verantwortungsbereich nächste Woche tun?' Person A: 'Ich kann mein Team wöchentlich 10 Minuten über den Strategieprozess informieren.' Person B: 'Ich kann die Verbindung zu Team C herstellen, die wir bisher vermieden haben.' – Konkrete Handlungsschritte, die keine Freigabe brauchen.","mini_form":"Einzel-Notiz (5 Min): Still notieren, Karte mit dem 15-%-Commitment an die Tür kleben beim Rausgehen. Commitment sichtbar ohne Sharing-Druck.","anlass_typen":["strategie","retro","lernformat","entscheidungstreffen","krisensitzung"],"typ":"methode","gruppen_sweetspot":"6–200; skaliert beliebig","stimmung_geeignet":["muede","belastet","skeptisch"]},{"id":"what-so-what-now-what","name":"What? So What? Now What? (Liberating Structures)","feld":"C","kurz":"Drei-Phasen-Reflexion: Was ist passiert? (Beobachtung) – Was bedeutet das? (Interpretation) – Was tun wir jetzt? (Konsequenz). Trennt Wahrnehmung, Deutung und Handlung in geführten Sequenzen.","schritte":["What? (Beobachtungsebene, 5 Min): 'Was habt ihr beobachtet, gehört, getan – ohne Bewertung?' In Paaren oder Kleingruppen, dann Plenum.","So What? (Bedeutungsebene, 5 Min): 'Was bedeutet das – für uns, unser Projekt, unsere Zusammenarbeit?' Muster benennen.","Now What? (Handlungsebene, 5 Min): 'Was folgt daraus – was tun wir, wer tut was bis wann?' Konkrete Commitments."],"zweck":"Lernen aus Erfahrungen strukturieren und sicherstellen, dass Beobachtung, Interpretation und Konsequenz nicht vermischt werden – Standardfehler in Debriefings.","hinweise":"Die Trennung der drei Ebenen ist der Wirkmechanismus: nicht in 'So What' gehen, bevor 'What' ausreichend gefüllt ist. Bewertungen in der 'What'-Phase unterbrechen und auf die nächste Ebene verweisen.","phasen":["reflektieren","planen"],"ebenen":["person","team","organisation"],"modi":["reflexion","klaerung"],"formate":["meeting","workshop","klausur","teamentwicklung","fortbildung","reflexionsrunde"],"dauer_min":15,"dauer_max":45,"gruppe_min":3,"gruppe_max":100,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["reflexion","abschluss"],"quellen":[{"typ":"online","titel":"What, So What, Now What? – Liberating Structures","url":"https://www.liberatingstructures.com/9-what-so-what-now-what-w/"}],"wann_passt":["Debriefing nach einem Erlebnis (Übung, Simulation, Projekt-Abschnitt): Was? So Was? Jetzt Was? gibt der Reflexion Struktur und verhindert das Schwimmen in vagen Eindrücken.","Retro mit einer Gruppe, die bisher immer direkt in 'Was machen wir besser?' springt, ohne zu beobachten – die Trennung von Beobachtung und Interpretation ist oft überraschend schärfend.","Lernformat nach Außeneinsatz oder Feldarbeit: Was habt ihr beobachtet, was schließt ihr daraus, was tut ihr?"],"wann_nicht":["Als Ersatz für eine tiefe Retro mit expliziten Methoden (Vier-Felder, Timeline etc.) – What/So What/Now What ist gut für schnelle Reflexion, nicht für tiefe Auswertung.","Wenn die Gruppe keine gemeinsame Erfahrung hat, auf die sie sich bezieht – die Frage 'Was habt ihr beobachtet?' hat dann keinen gemeinsamen Anker.","Wenn die 'Now What'-Phase nicht ernst genommen wird – dann lieber eine Methode wählen, die bei Konsequenzen endet und nicht dort anfängt."],"fokusfragen":["„Was habt ihr konkret beobachtet, gehört, getan – ohne Bewertung, nur Fakten?' (What-Phase)","„Was bedeutet das – für euch, für die Gruppe, für das Projekt?' (So-What-Phase)","„Was tut ihr jetzt konkret – wer, was, bis wann?' (Now-What-Phase)"],"beispiel":"Nach einer Übung zu Kommunikation in Konflikten: What: 'A hat B unterbrochen, C ist still geworden.' So What: 'Unterbrechung hat Stille erzeugt – wir verlieren Stimmen, wenn wir nicht aktiv zuhören.' Now What: 'In unserem nächsten Meeting experimentieren wir mit einer Unterbrechungsregel – wer unterbricht, bemerkt es selbst und gibt zurück.' Konkreter Lernzyklus in 15 Minuten.","mini_form":"Schreibblitz (10 Min): Alle drei Fragen auf einem Blatt, 3 Min pro Frage still schreiben, dann Karte zur Hand behalten. Kein Sharing nötig.","anlass_typen":["retro","lernformat","teamtag"],"typ":"methode","gruppen_sweetspot":"4–40; über 40 in Kleingruppen mit Plenum-Ernte","stimmung_geeignet":["neugierig","muede","frisch"]},{"id":"25-10-crowd-sourcing","name":"25/10 Crowd Sourcing (Liberating Structures)","feld":"C","kurz":"Alle schreiben ihre mutigste Idee auf eine Karte, tauschen dann fünf Mal blind, lesen und bewerten jede Karte (1–5) – nach fünf Runden offenbaren die höchsten Wertungen die kollektiv gewünschten Ideen.","schritte":["Einladungsfrage formulieren: 'Was wäre deine mutigste Idee, die X wirklich voranbringen würde?' (2 Min still schreiben, eine Karte pro Person)","Blind tauschen: Alle laufen umher, tauschen Karten mit Fremden fünf Mal – jede:r liest die Karte, die sie oder er hält, und vergibt eine Bewertung 1–5 (oben auf die Karte schreiben).","Nach fünf Runden: Die Zahlen auf der Karte addieren. Wer eine Karte mit hoher Summe hält, liest sie vor.","Top-Ideen sichten und gemeinsam priorisieren."],"zweck":"In großen Gruppen viele Ideen schnell zu einem kollektiven Ranking verdichten – ohne Dominanz durch laute Stimmen oder Halo-Effekt der Urheberschaft.","hinweise":"Blind-Tausch ist entscheidend – die Bewertung erfolgt ohne zu wissen, von wem die Idee stammt. Ab 20 Personen besonders wirkungsvoll, darunter ist das Aufwand-Wirkungs-Verhältnis nicht optimal.","phasen":["vertiefen","entscheiden"],"ebenen":["team","organisation","netzwerk"],"modi":["klaerung","entscheidung"],"formate":["workshop","grossgruppe","klausur"],"dauer_min":20,"dauer_max":35,"gruppe_min":20,"gruppe_max":200,"online":"eingeschraenkt","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"aktivierend","stil":["strukturiert","beteiligend","spielerisch"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"25/10 Crowd Sourcing – Liberating Structures","url":"https://www.liberatingstructures.com/12-2510-crowd-sourcing/"}],"wann_passt":["Großgruppe (30–200) nach einem Ideenfindungs-Block, in dem viele Ideen im Raum sind und priorisiert werden soll – ohne Abstimmung per Handzeichen, die von Sozialdruck beeinflusst wird.","Offener Strategieprozess, bei dem wirklich mutige Ideen gewünscht sind, die in normalen Hierarchien nicht artikuliert würden – Anonymität der Urheberschaft schützt.","Netzwerk-Treffen mit großer Gruppe und Wunsch nach kollektivem Ausdruck: 'Was ist die eine Idee, die unser Netzwerk wirklich voranbringen würde?'"],"wann_nicht":["Unter 15 Personen: zu wenig Blind-Tausch-Effekt, besser direkte Priorisierung.","Online ohne geteiltes Whiteboard mit Sticky-Note-Funktionalität – der physische Karten-Tausch ist schwer digital zu replizieren.","Wenn Ideen komplex sind und Kontext brauchen – auf einer Karte passt nur eine prägnante Idee."],"fokusfragen":["„Was wäre deine mutigste Idee, die X wirklich voranbringen würde – eine Idee, eine Karte.' (Einladungsformel)","„Die Karten mit den höchsten Wertungen: Was sagen sie über das, was diese Gruppe wirklich will?' (Ernte-Einstieg)"],"beispiel":"","mini_form":"Drei Tausch-Runden statt fünf (15 Min): Ausreichend für 15–30 Personen; die Ranking-Validität sinkt, die Geschwindigkeit steigt.","anlass_typen":["beteiligung","strategie","netzwerktreffen"],"typ":"methode","gruppen_sweetspot":"20–150; unter 15 nicht sinnvoll","stimmung_geeignet":["neugierig","frisch","skeptisch"]},{"id":"wise-crowds","name":"Wise Crowds (Liberating Structures)","feld":"C","kurz":"Eine Person sitzt als 'Client' vor vier oder mehr 'Berater:innen': Sie erklärt ihre Herausforderung, dreht sich weg – die Gruppe berät laut. Dann dreht sie sich um und hört Essenz. Troika Consulting in größerer Gruppe, simultane Parallelrunden skalieren es.","schritte":["Gruppen à 5–6 bilden: eine Client-Person, 4–5 Consulting-Personen.","Client erklärt Herausforderung (2–3 Min), dreht sich weg.","Consulting-Gruppe berät laut (5–7 Min), ohne den Client zu adressieren.","Client dreht sich um, teilt, was angekommen ist (2 Min).","Rollenwechsel – je nach Zeit 2–3 Personen als Client pro Gruppe."],"zweck":"Kollegiale Beratung skalieren: Viele Clients bekommen gleichzeitig in parallelen Kleingruppen externe Perspektiven – effizienter als sequenzielle Beratungsrunden.","hinweise":"Unterschied zu Troika: Größere Gruppe (5–6) statt Dreier, mehr Perspektiven-Vielfalt; Unterschied zu klassischer Supervision: keine Moderation, die Gruppe trägt sich selbst. Das Wegdrehen ist zwingend.","phasen":["vertiefen","reflektieren"],"ebenen":["person","team"],"modi":["klaerung","reflexion"],"formate":["workshop","fortbildung","teamentwicklung"],"dauer_min":30,"dauer_max":60,"gruppe_min":10,"gruppe_max":60,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"neutral","stil":["strukturiert","gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Wise Crowds – Liberating Structures","url":"https://www.liberatingstructures.com/13-wise-crowds/"}],"wann_passt":["Lerngruppe oder Supervision mit 10–40 Personen, die alle kollegiale Beratung bekommen sollen – Wise Crowds gibt in 45 Minuten allen mindestens einer Beratungsrunde.","Führungskräfte-Workshop, in dem alle mit echten Herausforderungen kommen und nicht nur zuhören wollen – die simultanen Runden geben jedem Zeit für die eigene Frage.","Wenn Troika Consulting zu wenige Perspektiven bringt: 5 Beratende sehen mehr als 2."],"wann_nicht":["Unter 10 Personen: Troika Consulting ist dann effizienter.","Wenn Vertraulichkeit der Inhalte kritisch ist – in parallelen Gruppen teilen viele Personen Herausforderungen, die sich berühren können.","Online ohne gute Breakout-Organisation: Simultane Gruppen brauchen klare Raum-Logistik."],"fokusfragen":["„Was ist deine echte Herausforderung – formuliert als Frage, die du wirklich beantwortet haben möchtest?' (Client-Vorbereitung)","„Was von dem, was du gehört hast, war neu – und was nimmst du mit?' (Client-Rückkehr)"],"beispiel":"","mini_form":"Ein-Runden-Wise-Crowds (20 Min): Nur eine Person pro Gruppe ist Client – alle anderen beraten. Kein Rollenwechsel. Gut als Schnell-Demo oder wenn nur eine Person dringende Beratung braucht.","anlass_typen":["coaching","lernformat","teamtag"],"typ":"methode","gruppen_sweetspot":"10–40; Gruppen à 5–6 Personen","stimmung_geeignet":["neugierig","muede","skeptisch"]},{"id":"conversation-cafe","name":"Conversation Café (Liberating Structures / Viant)","feld":"C","kurz":"Moderiertes Tischgespräch mit klaren Rollen und zwei Gesprächsrunden: Runde 1 jede:r reihum, Runde 2 offen – ein Talking Object übergibt das Wort, niemand wird unterbrochen.","schritte":["Gruppe à 5–8 an einem Tisch; Talking Object (Tasse, Stein) in der Mitte.","Frage formulieren und teilen: Eine offene, persönliche Einladung zur Reflexion.","Runde 1: Reihum, jede:r hält das Talking Object und spricht ohne Unterbrechung (2–3 Min); andere hören nur zu.","Runde 2: Offenes Gespräch – wer sprechen will, nimmt das Talking Object; niemand ohne Objekt in der Hand spricht.","Abschluss-Runde: Je ein Satz, was jede:r mitnimmt."],"zweck":"Tiefes Gespräch über ein bedeutsames Thema ermöglichen, in dem alle zu Wort kommen und niemand dominiert – Qualität über Quantität der Beiträge.","hinweise":"Das Talking Object ist der Schutz-Mechanismus – konsequent halten. Fragen müssen persönlich und offen sein: keine Ja/Nein-Fragen, keine Sach-Debatten. Für kontroverse Themen gut geeignet, wenn das Gespräch Verständigung und nicht Überzeugung zum Ziel hat.","phasen":["oeffnen","vertiefen"],"ebenen":["person","team","netzwerk"],"modi":["verbindung","reflexion","klaerung"],"formate":["workshop","klausur","teamentwicklung","fortbildung","grossgruppe"],"dauer_min":30,"dauer_max":60,"gruppe_min":5,"gruppe_max":60,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"beruhigend","stil":["gespraechsnah","strukturiert"],"blocktyp":["kern"],"quellen":[{"typ":"online","titel":"Conversation Café – Liberating Structures","url":"https://www.liberatingstructures.com/17-conversation-cafe/"},{"typ":"online","titel":"Conversation Café – conversationcafe.org","url":"https://www.conversationcafe.org/"}],"wann_passt":["Netzwerk-Treffen oder Tagung, bei der ein kontroverseres Thema nicht debattiert, sondern verstanden werden soll – Conversation Café ist das Format für Verständigungsgespräch statt Meinungsschlacht.","Workshop mit heterogener Gruppe (verschiedene Hintergründe, Meinungen), in der alle eine Stimme bekommen sollen ohne Moderations-Schiedsrichter:in.","Wenn World Café zu viele Rotationen hat und eine Frage eine tiefe Einstündige Bearbeitung verdient."],"wann_nicht":["Für Entscheidungsfindung – Conversation Café erzeugt Verständigung, keine Entscheidungen.","Mit Gruppen, die das Talking Object nicht ernst nehmen oder die Reihum-Regel untergraben – dann kollabiert das Format.","Online ohne starkes Facilitator-Signal für das Talking Object (z.B. eingeschaltetes Mikro als Talking Object): Unterbrechungen sind schwerer zu verhindern."],"fokusfragen":["„Was bewegt dich zu diesem Thema – was machst du dir Sorgen, was erhoffst du dir?' (Runde-1-Frage, persönlich formuliert)","„Was hast du heute gehört, das dich überrascht oder berührt hat?' (Abschluss-Runde)"],"beispiel":"","mini_form":"Nur Runde 1 (20 Min, 5–7 Personen): Reihum alle mit Talking Object, keine offene Runde. Gibt allen eine Stimme ohne die Risiken der offenen Runde. Gut als Check-in-Variante für sensible Themen.","anlass_typen":["dialograum","netzwerktreffen","teamtag"],"typ":"methode","gruppen_sweetspot":"5–8 pro Tisch; parallele Tische für größere Gruppen","stimmung_geeignet":["angespannt","skeptisch","neugierig","belastet"]},{"id":"rpp-matrix","wann_passt":["Strategische Planung für Friedens- und Entwicklungsprogramme (5–15 Personen), wenn geprüft werden soll, ob die Aktivitäten wirklich zum Frieden beitragen — die RPP-Matrix (Reflecting on Peace Practice) stellt vier Quadranten auf: Viele Menschen/individuell (A), Schlüsselpersonen/individuell (B), Viele Menschen/sozio-politisch (C), Schlüsselpersonen/sozio-politisch (D) — und fragt, ob das Programm in allen vier Feldern vertreten ist.","Pflichtinstrument für ZFD/CPS-Projekte (GIZ Civil Peace Service): Jedes Projekt muss seine Verbindung zu den fünf RPP-Wirksamkeitskriterien darlegen — RPP-Matrix macht diese Verbindung sichtbar und kommunizierbar.","Reflexion nach Programmphasen (8–20 Personen): In welchem Quadranten haben wir hauptsächlich gearbeitet — und was haben wir vernachlässigt? Strategische Blindstellen werden sichtbar."],"wann_nicht":["Als bürokratisches Formular ohne inhaltliche Reflexion: die Matrix lebt von der ehrlichen Auseinandersetzung mit der Frage, ob das Programm wirklich in mehreren Quadranten wirkt — nicht nur im einfachsten.","In frühen Kontaktphasen, bevor eine Konfliktanalyse vorliegt: Die Matrix setzt voraus, dass klar ist, wer die Schlüsselakteur:innen sind und welche sozio-politischen Strukturen verändert werden sollen."],"fokusfragen":["„In welchem der vier RPP-Quadranten (A/B/C/D) arbeiten wir am meisten — und warum?“ (Ist-Analyse)","„Welche der fünf Wirksamkeitskriterien sprechen unsere Aktivitäten direkt an — und welche gar nicht?“ (Lückenanalyse)","„Wer sind die Schlüsselakteur:innen in diesem Kontext, die wir für eine strategische Verbindung gewinnen müssten — und wie kommen wir an sie heran?“ (Quadrant B/D)"],"beispiel":"RPP-Matrix in einer Programm-Reflexion: Das Team trägt alle aktuellen Aktivitäten in die vier Quadranten ein. Ergebnis: 80% in Quadrant A (viele Menschen / individuell — z.B. Trainings, Workshops). Quadrant D (Schlüsselpersonen / sozio-politisch) ist leer. Die Frage: 'Haben wir einen Zugang zu politischen Entscheidungsträger:innen oder lokalen Autoritäten — und wenn nicht, wer könnte diese Brücke bauen?' eröffnet die strategische Diskussion. Das ist der Kern des 'Strategic Connection Principle' der RPP.","mini_form":"Schnell-Verortung in 10 Minuten: Vier Quadranten auf einem Flipchart. Jede:r klebt Post-its mit den Hauptaktivitäten in den Quadranten, wo sie ihrer Meinung nach wirken. Dann: Wo ist die Häufung? Was fehlt? Reicht als Impulseinstieg für eine Strategie-Reflexion.","anlass_typen":["strategie","lernformat","retro"],"typ":"werkzeug","gruppen_sweetspot":"5–15 Personen, Programmteam oder Feldmitarbeiter:innen","stimmung_geeignet":["neugierig","frisch","skeptisch"],"name":"RPP-Matrix (Reflecting on Peace Practice)","feld":"A","kurz":"Strategie-Check für Friedens- und Wandel-Programme: Alle Aktivitäten werden in vier Quadranten verortet (viele Menschen vs. Schlüsselpersonen × individuelle vs. sozio-politische Veränderung). Sichtbar wird, wo das Programm wirkt – und welches Feld leer bleibt.","schritte":["Matrix aufzeichnen: x-Achse „viele Menschen ↔ Schlüsselpersonen“, y-Achse „individuelle ↔ sozio-politische Veränderung“ (Quadranten A–D).","Alle laufenden Aktivitäten auf Karten schreiben und gemeinsam in die Quadranten hängen.","Muster lesen: Wo häuft sich die Arbeit? Welcher Quadrant ist leer – und ist das eine bewusste Entscheidung?","Strategic Connection prüfen: Welche Verbindung führt von individueller Veränderung zur sozio-politischen Ebene (und von vielen Menschen zu Schlüsselpersonen)?","1–2 strategische Konsequenzen festhalten: Was bauen wir aus, was verbinden wir neu?"],"zweck":"Macht strategische Blindstellen eines Programms in 60 Minuten sichtbar und kommunizierbar – Grundlage der fünf RPP-Wirksamkeitskriterien.","hinweise":"Lebt von ehrlicher Selbstkritik, nicht vom Ausfüllen. Vorher klären, wer im Kontext Schlüsselakteur:in ist – sonst bleibt Quadrant B/D spekulativ.","phasen":["planen","verstehen","reflektieren"],"ebenen":["organisation","netzwerk"],"modi":["klaerung"],"formate":["workshop","klausur","reflexionsrunde"],"dauer_min":45,"dauer_max":120,"gruppe_min":4,"gruppe_max":20,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"niedrig","energie":"neutral","stil":["strukturiert","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 6: RPP Matrix"},{"typ":"online","titel":"CDA: Reflecting on Peace Practice (RPP) Basics – Resource Manual","url":"https://www.cdacollaborative.org/publication/reflecting-on-peace-practice-rpp-basics-a-resource-manual/"}]},{"id":"zukunftsvision-filmskript","wann_passt":["Strategieprozess für Friedensprogramme oder Community-Projekte (8–20 Personen), wenn eine gemeinsame Vorstellung des gewünschten Friedenszustands fehlt — die Methode nutzt narrative Zukunftsbeschreibung ('Stell dir vor, es sind drei Jahre vergangen und Frieden ist eingetreten: Was siehst du, was hörst du, wer ist dabei?') um Vision konkret und sinnlich zu machen.","Kickoff oder Relaunch-Prozess, wenn eine Gruppe ihre Werte und Richtung neu justieren muss: Das Filmskript-Format (Wunderfragen-Logik: Was wäre, wenn das Problem gelöst wäre?) erzeugt positive Energie und Orientierung, ohne die Realität auszublenden.","Parallel zur Konfliktanalyse (PME Station 1+2): Konfliktanalyse zeigt, WO das Problem liegt. Zukunftsvision zeigt, WO wir hinwollen — beide zusammen erzeugen die Spannung, die Motivation für Handeln."],"wann_nicht":["Als Flucht vor der Analyse: Zukunftsvision ohne Konfliktanalyse kann zu naiver Planung führen — die Realität des Kontexts muss vorher verstanden sein.","Wenn die Gruppe noch keinen gemeinsamen Problemrahmen hat — dann zuerst Konfliktanalyse/Connectors-Dividers.","In Gruppen, die in akuter Not sind und erst ihre unmittelbaren Bedürfnisse klären müssen — Zukunftsvisionen wirken dann zynisch."],"fokusfragen":["„Stell dir vor, drei Jahre sind vergangen. Der Konflikt ist nicht einfach verschwunden, aber er wird anders ausgetragen. Was siehst du, wenn du aus dem Fenster schaust — was hat sich verändert?“ (sensorische Zukunftseinladung)","„Wer ist an diesem zukünftigen Ort dabei, der heute noch nicht dabei ist — und was macht diese Person?“ (Akteur:innen der Transformation)","„Was war der erste kleine Schritt, der diese Veränderung möglich gemacht hat — was war der Wendepunkt?“ (Rückwärts vom Ziel in die Gegenwart)"],"beispiel":"Filmskript-Runde in einem Strategie-Workshop: Moderator:in lädt ein: 'Schließt die Augen. Ihr seid in drei Jahren. Das Programm hat seine Wirkung entfaltet. Ihr geht durch eure Zielgemeinschaft — was seht ihr? Was hört ihr? Wer spricht miteinander, der früher nicht gesprochen hat?' 5 Minuten schreiben. Dann in Kleingruppen teilen: Was taucht auf? Muster sammeln. Ergebnis: Die Gruppe destilliert gemeinsam das Bild, auf das sie hinarbeitet. Dieses Bild wird Bezugspunkt für die Theory of Change.","mini_form":"Wunderfrage in 10 Minuten: 'Stell dir vor, heute Nacht passiert ein Wunder, und morgen früh wachst du auf und der Konflikt/das Problem ist gelöst — woran würdest du es als erstes merken? Was wäre anders?' Jede:r antwortet in 2–3 Sätzen. Teilen in der Runde. Reicht als Vision-Check-in.","anlass_typen":["strategie","kickoff","dialograum"],"typ":"methode","gruppen_sweetspot":"8–25 Personen","stimmung_geeignet":["neugierig","frisch","muede"],"name":"Zukunftsvision als Filmskript","feld":"A","kurz":"Narrative Visionsarbeit: Die Gruppe beschreibt den gewünschten Zustand in drei Jahren als sinnliche Szene („Was siehst du, was hörst du, wer ist dabei?“) statt als Zielkatalog. Wunderfragen-Logik für Strategie- und Auftaktprozesse.","schritte":["Einladung: „Drei Jahre sind vergangen, unsere Arbeit hat gewirkt. Du gehst durch den Ort des Geschehens – was siehst du, was hörst du, wer spricht mit wem?“","5–10 Minuten still schreiben: jede:r notiert die eigene Szene wie ein kurzes Filmskript.","In Paaren oder Triaden vorlesen und zuhören – noch ohne Bewertung.","Muster ernten: Welche Bilder tauchen mehrfach auf? Was überrascht?","Gemeinsames Zukunftsbild destillieren (3–5 Kernsätze) – Bezugspunkt für Theory of Change oder Planung.","Rückwärts fragen: „Was war der erste kleine Schritt, der das möglich gemacht hat?“"],"zweck":"Erzeugt ein gemeinsames, konkretes Zukunftsbild und Motivation – die produktive Spannung zwischen Analyse (wo stehen wir) und Vision (wo wollen wir hin).","hinweise":"Braucht eine vorausgegangene Analyse, sonst wird es naiv. In akut belasteten Gruppen erst Grundbedürfnisse klären – sonst wirkt die Vision zynisch.","phasen":["planen","oeffnen","ankommen"],"ebenen":["team","organisation","netzwerk","feld"],"modi":["klaerung","energie","verbindung"],"formate":["workshop","klausur","grossgruppe"],"dauer_min":30,"dauer_max":90,"gruppe_min":4,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":false,"selbstoeffnung":"mittel","energie":"aktivierend","stil":["gespraechsnah","schriftlich"],"blocktyp":["kern"],"quellen":[{"typ":"buch","titel":"PME Guidelines for Projects and Programmes of GIZ Civil Peace Service – Station 2: Vision for Peace / Film Script"}]},{"id":"facilitative-listening-design","wann_passt":["Kontexte mit negativen Stereotypen zwischen Gruppen (ethnische Spannungen, Generationskonflikte, Konflikt zwischen Institutionen und Zivilgesellschaft): FLD (Facilitative Listening Design) bringt Mitglieder beider Gruppen als Forscher:innen zusammen, die die jeweils andere Gruppe interviewen — durch das Forschen entsteht Perspektivenwechsel ohne Konfrontation.","Community-Peacebuilding-Programme, die nachhaltige Beziehungsveränderung statt punktueller Workshops anstreben: FLD-Prozesse über mehrere Monate erzeugen laut Evidenz aus Kambodscha dauerhaften Einstellungswandel.","PAR-basierte (Participatory Action Research) Begleitung von Konflikten, wo externe Expert:innen nicht die Hauptwissensquelle sind, sondern die Community selbst Wissen produziert."],"wann_nicht":["Als Einmal-Event: FLD braucht mehrere Runden (Interview → Analyse → Austausch zwischen Gruppen → Iteration) — als Workshop-Modul ohne Follow-up verliert es seine Wirkung.","Wenn eine der Gruppen nicht bereit ist, zuzuhören — Teilnahme muss freiwillig und intrinsisch motiviert sein.","In akuten Gewaltkontexten, wo physische Sicherheit nicht gewährleistet ist."],"fokusfragen":["„Was beschäftigt die Menschen in Ihrer Gemeinschaft gerade am meisten — was sind die drängendsten Themen?“ (offener Gesprächseinstieg ohne Lenkung auf Konflikt)","„Haben Sie das selbst erlebt, oder haben Sie davon gehört?“ (sanfte Prüfung ohne Konfrontation — öffnet oft nuanciertere Antworten)","„Was wünschen Sie sich für die Beziehung zwischen den Gruppen — was wäre ein erster kleiner Schritt?“ (Zukunftsorientierung am Ende)"],"beispiel":"FLD-Mini-Runde: Zwei Teams à 3 Personen aus unterschiedlichen Gruppen werden zu Forscher:innen. Jedes Team interviewt Mitglieder der anderen Gruppe mit drei offenen Fragen (ohne Konfrontation mit negativen Stereotypen). Nach dem Interview: Teams tauschen Befunde aus, nicht Meinungen. Was haben wir gehört? Was überrascht uns? — die Basis für echten Dialog.","mini_form":"Listening-Pair in 20 Minuten: Zwei Personen aus unterschiedlichen 'Lagern'. Person A stellt Person B drei offene Fragen über ihr Leben, ihre Sorgen, ihre Hoffnungen. Person B stellt die gleichen Fragen an A. Am Ende je ein Satz: 'Das hätte ich vorher nicht erwartet...'","anlass_typen":["dialograum","konfliktklaerung","lernformat","beteiligung"],"typ":"methode","gruppen_sweetspot":"10–30 Personen in zwei oder mehr Gruppen","stimmung_geeignet":["skeptisch","angespannt","neugierig"],"name":"Facilitative Listening Design (FLD)","feld":"E","kurz":"Zuhören als Brücke zwischen Gruppen mit Vorbehalten: Mitglieder beider Seiten werden zu Forscher:innen, die die jeweils andere Gruppe mit offenen Fragen interviewen. Perspektivwechsel entsteht durch das Forschen selbst – ohne Konfrontation.","schritte":["Zwei (oder mehr) Teams aus den beteiligten Gruppen bilden – Teilnahme freiwillig.","Gemeinsam 3 offene Interviewfragen entwickeln (Leben, Sorgen, Hoffnungen – keine Konflikt-Konfrontation).","Teams interviewen Mitglieder der jeweils anderen Gruppe und notieren, was sie hören.","Befunde austauschen statt Meinungen: Was haben wir gehört? Was überrascht uns?","Gemeinsam nächste Fragen oder Schritte entwickeln – FLD wirkt über mehrere Runden."],"zweck":"Verändert Einstellungen zwischen Gruppen nachhaltig, weil Menschen einander als Quelle von Wissen statt als Gegner begegnen (Participatory Action Research).","hinweise":"Kein Einmal-Event – ohne Folgerunden verpufft die Wirkung. Freiwilligkeit ist Bedingung; in akuten Gewaltkontexten zuerst Sicherheit klären.","phasen":["verstehen","konflikt","vertiefen"],"ebenen":["team","netzwerk","feld"],"modi":["konflikt","verbindung","vertrauen"],"formate":["prozessbegleitung","workshop"],"dauer_min":60,"dauer_max":180,"gruppe_min":6,"gruppe_max":30,"online":"ja","braucht_raum":false,"vertrauensbildend":true,"selbstoeffnung":"mittel","energie":"neutral","stil":["gespraechsnah"],"blocktyp":["kern"],"quellen":[{"typ":"buch","titel":"Peacebuilding Practice (Woman PeaceMaker Program, 2023) – Kap. 13"},{"typ":"online","titel":"FLD Handbook – Women Peace Makers Cambodia","url":"https://wpmcambodia.org/project/the-fld-handbook/"}]}];